window.NZ_OPISY=window.NZ_OPISY||{};window.NZ_OPISY["m"]={"Michał": "<b>Michał</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִיכָאֵל&#8206; – Mîchā’ēl) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, wywodzące się od <a href=\"https://pl.wikipedia.org/wiki/Archanio%C5%82_Micha%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">jednego z archaniołów</a>. Po hebrajsku znaczy „któż [jest taki] jak Bóg”. Forma żeńska to <a href=\"https://pl.wikipedia.org/wiki/Michalina\" target=\"_blank\" rel=\"noopener noreferrer\">Michalina</a>.", "Marcin": "<b>Marcin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od wyrażenia <i>Martinus</i> oznaczającego „należący do boga <a href=\"https://pl.wikipedia.org/wiki/Mars_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Marsa</a>”.", "Marek": "<b>Marek</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, należące do wąskiej grupy najstarszych <a href=\"https://pl.wikipedia.org/wiki/Imiona_%C5%82aci%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imion rzymskich</a> (imion właściwych, <i>praenomen</i>, por. <a href=\"https://pl.wikipedia.org/wiki/Tyberiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Tyberiusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Aulus\" target=\"_blank\" rel=\"noopener noreferrer\">Aulus</a>, <a href=\"https://pl.wikipedia.org/wiki/Maniusz\" target=\"_blank\" rel=\"noopener noreferrer\">Maniusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Gajusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Gajusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Lucjusz\" target=\"_blank\" rel=\"noopener noreferrer\">Lucjusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Publiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Publiusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Tytus\" target=\"_blank\" rel=\"noopener noreferrer\">Tytus</a>, <a href=\"https://pl.wikipedia.org/wiki/Serwiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Serwiusz</a>), utworzone z <i>*Mart-ico-s</i> od imienia boga <i><a href=\"https://pl.wikipedia.org/wiki/Mars_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Mars</a></i>, <i>Martis</i> i oznaczające „należący do Marsa, związany z Marsem”. W Polsce imię to jest notowane od <a href=\"https://pl.wikipedia.org/wiki/XIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIII wieku</a>, choć poza współczesnością nie było często spotykane, w formach <i><b>Marek</b></i>, <i><b>Marko</b></i>, <i><b>Margusz</b></i>, <i><b>Markusz</b></i>, <i><b>Merkusz</b></i>. Zapisana została także żeńska <b>Marka</b> (<a href=\"https://pl.wikipedia.org/wiki/1263\" target=\"_blank\" rel=\"noopener noreferrer\">1263</a>) – żeński odpowiednik imienia Marek lub zdrobnienie od imion żeńskich rozpoczynających się na Mar-, takich jak <i>Margorzata</i> (= <a href=\"https://pl.wikipedia.org/wiki/Ma%C5%82gorzata_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Małgorzata</a>) lub <a href=\"https://pl.wikipedia.org/wiki/Maria\" target=\"_blank\" rel=\"noopener noreferrer\">Maria</a> – oraz <a href=\"https://pl.wikipedia.org/wiki/Markus%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Markusław</a>, staropolskie imię utworzone od imienia Marek poprzez dodanie typowej dla imion słowiańskich cząstki -sław. Imię to według danych 2022 r. jest na 10 miejscu najpopularniejszych imion męskich.", "Mateusz": "<b>Mateusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>, wywodzące się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מַתִּתְיָהוּ&#8206;, imienia <i>Matanjah</i>, <i>Matisyahu</i> oznaczającego „dar Boga”, „dar <a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a>”. W dawnych źródłach polskich występowało jako: <i>Mathaeus</i>, <i>Matyjasz</i>, <i>Matitiasz</i>, <i>Matyja</i>, <i>Matys(z)</i>, <i>Matoz</i>, <i>Matusz</i>. Do XVI wieku imiona <a href=\"https://pl.wikipedia.org/wiki/Maciej\" target=\"_blank\" rel=\"noopener noreferrer\">Maciej</a> i Mateusz nie były w języku polskim rozróżniane.", "Mariusz": "<b>Mariusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od nazwy rzymskiego rodu Mariuszów lub imienia boga wojny Marsa. W Polsce od <a href=\"https://pl.wikipedia.org/wiki/XIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIII wieku</a>.", "Maciej": "<b>Maciej</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, pochodzenia hebrajskiego: <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מַתִּתְיָהוּ&#8206; <i>Mattitjahu</i>, oznaczające „dar <a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a>”.", "Marian": "<b>Marian</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> od imienia <i>Marius</i> lub nazwy rodu <i>Marii</i>. Oznacza „należący do Mariusza, rodu Mariuszów”. Występuje w Polsce od 1332 roku, jako <b>Marzyjan</b>. Forma Marian pojawiła się w Polsce w XVI wieku. W języku angielskim używane jest jako imię żeńskie. W Polsce w żeńskim użyciu w 2025 roku wystąpiło 35 razy.", "Mirosław": "<b>Mirosław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie imię</a> męskie. Imię <i>Mirosław</i> jest przykładem <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staropolski\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskiego</a>, złożonego, osobowego imienia dwuczłonowego, które jest <a href=\"https://pl.wikipedia.org/wiki/Relikt\" target=\"_blank\" rel=\"noopener noreferrer\">reliktem</a> <a href=\"https://pl.wikipedia.org/wiki/Poganie\" target=\"_blank\" rel=\"noopener noreferrer\">pogańskich</a> imion używanych we wczesnym średniowieczu przez <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie\" target=\"_blank\" rel=\"noopener noreferrer\">Słowian</a>. Składa się z członów <i>Miro-</i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pras%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">ps.</a> <i>*mirъ</i> „pokój”, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staropolski\" target=\"_blank\" rel=\"noopener noreferrer\">stpol.</a> <i>mir</i>, <i>mier</i> - „pokój, bezpieczeństwo, przyjaźń”) oraz <i>-sław</i> („sława”). Mogło oznaczać „ten, który sławi pokój” albo „ten, który zdobywa sławę poprzez zaprowadzenie porządku, pokoju”. <a href=\"https://pl.wikipedia.org/wiki/Witold_Taszycki\" target=\"_blank\" rel=\"noopener noreferrer\">Witold Taszycki</a> zaliczył je do grupy najstarszych polskich imion osobowych&#8201;.", "Mikołaj": "<b>Mikołaj</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Νικόλαος, <i>Nikólaos</i>, od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;νίκη + λαός/<i>lassos</i>, tj. „zwycięstwo” + „lud”; to samo znaczenie ma imię <a href=\"https://pl.wikipedia.org/wiki/Nikodem\" target=\"_blank\" rel=\"noopener noreferrer\">Nikodem</a> od νίκη + δήμος) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia greckiego.", "Mieczysław": "<b>Mieczysław</b> – dwuczłonowe <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, które powstało najprawdopodobniej w wyniku błędnego odczytania słowiańskiego imienia złożonego <a href=\"https://pl.wikipedia.org/wiki/Miecis%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Miecisław</a> (którego najstarszy zapis pochodzi z 1257).", "Maksymilian": "<b>Maksymilian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa <i>maximus</i> oznaczającego „największy” oraz nazwiska <a href=\"https://pl.wikipedia.org/wiki/Staro%C5%BCytny_Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">rzymskiego</a> rodu <a href=\"https://pl.wikipedia.org/wiki/Emiliusze\" target=\"_blank\" rel=\"noopener noreferrer\">Emiliuszów</a>. Żeńskie odpowiedniki tego imienia to <a href=\"https://pl.wikipedia.org/wiki/Maksymiliana\" target=\"_blank\" rel=\"noopener noreferrer\">Maksymiliana</a> i <a href=\"https://pl.wikipedia.org/wiki/Maksymiliana\" target=\"_blank\" rel=\"noopener noreferrer\">Maksymilianna</a>.", "Marcel": "<b>Marceli</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od nazwy jednej z gałęzi rzymskiego <a href=\"https://pl.wikipedia.org/wiki/Klaudiusze\" target=\"_blank\" rel=\"noopener noreferrer\">rodu Klaudiuszów</a>, <i>Marcelli</i>. Imię to bywa nadawane także w formie <b>Marcel</b>, jakkolwiek pojawia się ona w wydawnictwach poprawnościowych jako nieakceptowana. Żeńskim odpowiednikiem jest <a href=\"https://pl.wikipedia.org/wiki/Marcela\" target=\"_blank\" rel=\"noopener noreferrer\">Marcela</a>.", "Miłosz": "<b>Miłosz</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a> oznaczające „tego, który jest miłowany”, będące pierwotnie zdrobnieniem dwuczłonowych imion takich jak: <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82obor\" target=\"_blank\" rel=\"noopener noreferrer\">Miłobor</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82obrat\" target=\"_blank\" rel=\"noopener noreferrer\">Miłobrat</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82ogost_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miłogost</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82ogost_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miłgost</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82orad\" target=\"_blank\" rel=\"noopener noreferrer\">Miłorad</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82os%C5%82aw_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miłosław</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82os%C5%82aw_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miełosław</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82ostryj\" target=\"_blank\" rel=\"noopener noreferrer\">Miłostryj</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82owit\" target=\"_blank\" rel=\"noopener noreferrer\">Miłowit</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82owit\" target=\"_blank\" rel=\"noopener noreferrer\">Miłwit</a>. Forma Miłosz została zapisana już w <a href=\"https://pl.wikipedia.org/wiki/1136\" target=\"_blank\" rel=\"noopener noreferrer\">1136</a> roku w <a href=\"https://pl.wikipedia.org/wiki/Bulla_gnie%C5%BAnie%C5%84ska\" target=\"_blank\" rel=\"noopener noreferrer\">Bulli gnieźnieńskiej</a>.", "Maksym": "<b>Maksym</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, utworzone od przymiotnika <i>maximus</i> oznaczający \"największy\", przydomka <a href=\"https://pl.wikipedia.org/wiki/Jowisz_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Jowisza</a>. Istnieją liczni święci prawosławni i katoliccy o tym imieniu: <a href=\"https://pl.wikipedia.org/wiki/Maksym_Wyznawca\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym Wyznawca</a>, <a href=\"https://pl.wikipedia.org/wiki/Maksym_Grek\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym Grek</a>, <a href=\"https://pl.wikipedia.org/wiki/Maksym_Brankowicz\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym Wołoski</a>, <a href=\"https://pl.wikipedia.org/wiki/Maksym_Gorlicki\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym Gorlicki</a>, <a href=\"https://pl.wikipedia.org/wiki/Maksym_z_Riez\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym z Riez</a> i wielu innych.", "Mykola": "<p>Mykola jest ukraińską wariantą męskiego nazwiska \"Nicholas\", co oznacza \"wygrę narodu\". Może odnosić się do:</p>", "Mykhailo": "<p>Mykhailo lub Mykhaylo to ukraińskie męskie imię, równoważne angielskim Michałowi. Wśród znanych osób z nazwiskiem są: Mykhaylo Berkos (1861-1919), rosyjski i ukraiński artysta pochodzenia greckiego Mykhayilo Bolotskykh (ur. 1960), ukraiński polityk i wojskowy, pułkownik generalny (Służba Obrony Cywilnej) Mykhayło Brodskyy (ur. 1959), ukraiński polityk, przywódca Partii Wolnych Demokratów i biznesmen Mykhayla Chemberzhi,...</p>", "Michael": "<p>Michael: Botanika Michael - skrócie botaniczne, oznaczające, że autorem taksy jest Edmund Michael. Muzyka ⁇ Michael ⁇ - piosenka grupy Franz Ferdinand, wydana w 2004 roku.</p>", "Milan": "<b>Milan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię słowiańskie</a>. Jedno z licznych <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">zdrobnień od imion słowiańskich</a> zaczynających się na <i>Miło-</i>, takich jak <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82obor\" target=\"_blank\" rel=\"noopener noreferrer\">Miłobor</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82obrat\" target=\"_blank\" rel=\"noopener noreferrer\">Miłobrat</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82ogost_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miłogost</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82ogost_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miłgost</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82orad\" target=\"_blank\" rel=\"noopener noreferrer\">Miłorad</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82os%C5%82aw_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miłosław</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82os%C5%82aw_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miełosław</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82ostryj\" target=\"_blank\" rel=\"noopener noreferrer\">Miłostryj</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82owit\" target=\"_blank\" rel=\"noopener noreferrer\">Miłowit</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82owit\" target=\"_blank\" rel=\"noopener noreferrer\">Miłwit</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82osz\" target=\"_blank\" rel=\"noopener noreferrer\">Miłosz</a>. Obecnie imię Milan używane jest także samodzielnie.", "Martin": "<p>William Charles Lynne Martin (1798 - 1864) - angielski naturalista. Martin był kuratorem muzeum London Zoological Society od 1830 do 1838 roku, aż do czasu, gdy stracił pracę w wyniku zmniejszenia finansowania.</p>", "Maria": "<b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mieszko": "<b>Mieszko</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, najprawdopodobniej forma skrócona imienia <a href=\"https://pl.wikipedia.org/wiki/Miecis%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Miecisław</a>. Imię popularne w <a href=\"https://pl.wikipedia.org/wiki/Piastowie\" target=\"_blank\" rel=\"noopener noreferrer\">dynastii piastowskiej</a>, pierwotnie niewystępujące poza nią i nieposiadające nazewniczych równoważników słowiańskich.", "Marceli": "<b>Marceli</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od nazwy jednej z gałęzi rzymskiego <a href=\"https://pl.wikipedia.org/wiki/Klaudiusze\" target=\"_blank\" rel=\"noopener noreferrer\">rodu Klaudiuszów</a>, <i>Marcelli</i>. Imię to bywa nadawane także w formie <b>Marcel</b>, jakkolwiek pojawia się ona w wydawnictwach poprawnościowych jako nieakceptowana. Żeńskim odpowiednikiem jest <a href=\"https://pl.wikipedia.org/wiki/Marcela\" target=\"_blank\" rel=\"noopener noreferrer\">Marcela</a>.", "Maximilian": "<p>Maksymilian Tebeski (lat. Maximilian; 274 - 295, Tevest, Imperium Rzymskie) - wczesnie chrześcijański święty męczennik, który poniósł cierpienie przy cesarzu Diokletyanie za otwartą wyznawanie chrześcania i odmowę służby w armii.</p>", "Maurycy": "<b>Maurycy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> <i>Mauritius</i>. Wywodzi się od słowa oznaczającego „pochodzący z Mauretanii”, „Maur”.", "Mikhail": "<p>Michał (Hebrajskie: מִיכָאֵל; Aramejski: ⁇ , romanized: Mīkhāʼēl) jest powszechnym męskim imieniem, które zazwyczaj uważa się za pochodzące z hebrajskiego pytania retorycznego מי כאל (mī kāʼēl), \"Kto [jest] podobny do [Hebrajskiego boga] El?\", a więc jest nazwiskiem teoforycznym, którego odpowiedź brzmi \"nie ma nikogo podobnego do El\", lub \"nie słynny i potężny jak Bóg\".[is] Paradoksalnie, nazwisko jest czasami interpretowane jako \"Jeden...</p>", "Mikalai": "<p>Mikalai to męskie białoruskie imię. Znani ludzie z imieniem to: Mikalai Barkouski, białoruska judoka Mikalai Kamianchuk (ur. 1987), białoruskie pary skater Mikalai Novikau (ur. 1986), białorski ciężarosta Mikalai Sharlap (ur. 1994), białoruśski remarka Mikalai Shubianok (ur. 1985), białorowski dekathlete Mikalai Zhukavets (ur. 1986), białoruski windsurfer</p>", "Max": "<p>Max (wymawia się: max) - niejednoznaczny termin. Max - w matematyce i językach programowania oznacza funkcję wyboru maksymalnego ze swoich argumentów, (Max (3, 6, 1) = 6).</p>", "Matthew": "<p>William Diller Matthew (ang. William Diller; 19 lutego 1871 - 24 września 1930 w Berkeley) - kanadyjski i amerykański naukowiec-geolog, paleontolog, biogeograf, kurator Muzeum Historii Naturalnej Ameryki, profesor Uniwersytetu Kalifornijskiego w Berkeley, znany popularyzator nauki.</p>", "Miron": "<b>Miron</b> (<i>Myron</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa <i>myron</i> oznaczającego „wonny olejek, pachnidło”.", "Mohamed": "<p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Marko": "<b>Marek</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, należące do wąskiej grupy najstarszych <a href=\"https://pl.wikipedia.org/wiki/Imiona_%C5%82aci%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imion rzymskich</a> (imion właściwych, <i>praenomen</i>, por. <a href=\"https://pl.wikipedia.org/wiki/Tyberiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Tyberiusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Aulus\" target=\"_blank\" rel=\"noopener noreferrer\">Aulus</a>, <a href=\"https://pl.wikipedia.org/wiki/Maniusz\" target=\"_blank\" rel=\"noopener noreferrer\">Maniusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Gajusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Gajusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Lucjusz\" target=\"_blank\" rel=\"noopener noreferrer\">Lucjusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Publiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Publiusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Tytus\" target=\"_blank\" rel=\"noopener noreferrer\">Tytus</a>, <a href=\"https://pl.wikipedia.org/wiki/Serwiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Serwiusz</a>), utworzone z <i>*Mart-ico-s</i> od imienia boga <i><a href=\"https://pl.wikipedia.org/wiki/Mars_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Mars</a></i>, <i>Martis</i> i oznaczające „należący do Marsa, związany z Marsem”. W Polsce imię to jest notowane od <a href=\"https://pl.wikipedia.org/wiki/XIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIII wieku</a>, choć poza współczesnością nie było często spotykane, w formach <i><b>Marek</b></i>, <i><b>Marko</b></i>, <i><b>Margusz</b></i>, <i><b>Markusz</b></i>, <i><b>Merkusz</b></i>. Zapisana została także żeńska <b>Marka</b> (<a href=\"https://pl.wikipedia.org/wiki/1263\" target=\"_blank\" rel=\"noopener noreferrer\">1263</a>) – żeński odpowiednik imienia Marek lub zdrobnienie od imion żeńskich rozpoczynających się na Mar-, takich jak <i>Margorzata</i> (= <a href=\"https://pl.wikipedia.org/wiki/Ma%C5%82gorzata_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Małgorzata</a>) lub <a href=\"https://pl.wikipedia.org/wiki/Maria\" target=\"_blank\" rel=\"noopener noreferrer\">Maria</a> – oraz <a href=\"https://pl.wikipedia.org/wiki/Markus%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Markusław</a>, staropolskie imię utworzone od imienia Marek poprzez dodanie typowej dla imion słowiańskich cząstki -sław. Imię to według danych 2022 r. jest na 10 miejscu najpopularniejszych imion męskich.", "Manfred": "<b>Manfred</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słów z języka staro-wysoko-niemieckiego <i>man</i> – człowiek i <i>frid</i> – opieka, pokój. Zatem Manfred to osoba „zapewniająca pokój i ochronę”.", "Manuel": "<b>Emanuel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od słowa עִמָּנוּאֵל oznaczającego „Bóg z nami”. Imię mesjasza oraz kilku świętych katolickich. Żeński odpowiednik to <a href=\"https://pl.wikipedia.org/wiki/Emanuela\" target=\"_blank\" rel=\"noopener noreferrer\">Emanuela</a>.", "Marco": "<b>Marek</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, należące do wąskiej grupy najstarszych <a href=\"https://pl.wikipedia.org/wiki/Imiona_%C5%82aci%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imion rzymskich</a> (imion właściwych, <i>praenomen</i>, por. <a href=\"https://pl.wikipedia.org/wiki/Tyberiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Tyberiusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Aulus\" target=\"_blank\" rel=\"noopener noreferrer\">Aulus</a>, <a href=\"https://pl.wikipedia.org/wiki/Maniusz\" target=\"_blank\" rel=\"noopener noreferrer\">Maniusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Gajusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Gajusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Lucjusz\" target=\"_blank\" rel=\"noopener noreferrer\">Lucjusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Publiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Publiusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Tytus\" target=\"_blank\" rel=\"noopener noreferrer\">Tytus</a>, <a href=\"https://pl.wikipedia.org/wiki/Serwiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Serwiusz</a>), utworzone z <i>*Mart-ico-s</i> od imienia boga <i><a href=\"https://pl.wikipedia.org/wiki/Mars_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Mars</a></i>, <i>Martis</i> i oznaczające „należący do Marsa, związany z Marsem”. W Polsce imię to jest notowane od <a href=\"https://pl.wikipedia.org/wiki/XIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIII wieku</a>, choć poza współczesnością nie było często spotykane, w formach <i><b>Marek</b></i>, <i><b>Marko</b></i>, <i><b>Margusz</b></i>, <i><b>Markusz</b></i>, <i><b>Merkusz</b></i>. Zapisana została także żeńska <b>Marka</b> (<a href=\"https://pl.wikipedia.org/wiki/1263\" target=\"_blank\" rel=\"noopener noreferrer\">1263</a>) – żeński odpowiednik imienia Marek lub zdrobnienie od imion żeńskich rozpoczynających się na Mar-, takich jak <i>Margorzata</i> (= <a href=\"https://pl.wikipedia.org/wiki/Ma%C5%82gorzata_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Małgorzata</a>) lub <a href=\"https://pl.wikipedia.org/wiki/Maria\" target=\"_blank\" rel=\"noopener noreferrer\">Maria</a> – oraz <a href=\"https://pl.wikipedia.org/wiki/Markus%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Markusław</a>, staropolskie imię utworzone od imienia Marek poprzez dodanie typowej dla imion słowiańskich cząstki -sław. Imię to według danych 2022 r. jest na 10 miejscu najpopularniejszych imion męskich.", "Maxim": "<p>Maxim - międzynarodowy męski (z elementami erotyki) czasopism, który ma w tym również wersję rosyjską. Założona w Wielkiej Brytanii w 1995 roku.</p>", "Mihail": "<p>Mihai (rumuńska wymowa: [miˈhaj]) jest rumuńskim nazwiskiem męskim lub nazwiskiem. To równoważne angielskiej imienia Michael.</p>", "Muhammad": "<b>Muhammad</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;مُحَمَّد&#8206;) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wariantami tego imienia są: Mohammed, Mehmed, Mamadu i Mahomet.", "Mykhaylo": "<p>Mykhailo lub Mykhaylo to ukraińskie męskie imię, równoważne angielskim Michałowi. Wśród znanych osób z nazwiskiem są: Mykhaylo Berkos (1861-1919), rosyjski i ukraiński artysta pochodzenia greckiego Mykhayilo Bolotskykh (ur. 1960), ukraiński polityk i wojskowy, pułkownik generalny (Służba Obrony Cywilnej) Mykhayło Brodskyy (ur. 1959), ukraiński polityk, przywódca Partii Wolnych Demokratów i biznesmen Mykhayla Chemberzhi,...</p>", "Miguel": "<p>Miguel (hisz. Miguel) - hiszpański odpowiednik imienia Michaila.</p>", "Mario": "<p>Mario (jap. Mario Mario, angielski.</p>", "Markus": "<p>Markus może odnosić się do: Markus Persson Markus Wolf</p>", "Myron": "<p>Myron z Eleutherae (Grzeczyzna: Μύρων) żył w latach 480-440 pne, był atenskim rzeźbiarzem z 5 wieku pne. Urodził się w Eleutherae, regionie granicznym między Boeotia i Atticą.</p>", "Mohammad": "<p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Mustafa": "<b>Mustafa</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia arabskiego, oznacza „wybrany”.", "Mohammed": "<p>Muhammad - muzułmańskie imię i nazwisko. Mahomet jest islamskim prorokiem.</p>", "Matteo": "<p>Matteo (italijsky Matteo) - włoska wersja męskiego imienia Matveja.</p>", "Michel": "<p>⁇ Michel ⁇ (niemieckie MICHEL-Briefmarken-Katalog) - największy i najbardziej znany katalog znaków pocztowych w niemieckojęzycznym świecie i Europie.</p>", "Matthias": "<p>Matvej (Mattias; nim. Matthias, węg.</p>", "Marc": "<p>Marc: MARC (ang. Machine-Readable Cataloging) - grupa formatów (MARC21, UNIMARC, RUSMAC itp.</p>", "Marcus": "<p>Mark (lat. - Marcus ?</p>", "Makary": "<b>Makary</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od słowa <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;μακάριος <i>makários</i> oznaczającego „szczęsny, błogosławiony”. Znaczeniowo odpowiadają mu imiona: <a href=\"https://pl.wikipedia.org/wiki/Feliks\" target=\"_blank\" rel=\"noopener noreferrer\">Feliks</a> (pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>) i <a href=\"https://pl.wikipedia.org/wiki/Szcz%C4%99sny\" target=\"_blank\" rel=\"noopener noreferrer\">Szczęsny</a>.", "Marius": "Pochodził z niższych warstw społecznych, miał być z zawodu rzemieślnikiem (kowalem), później przypuszczalnie służył w wojsku, lecz nie wiadomo w jakiej funkcji. Po stłumionej w początkach 269 roku rewolcie <a href=\"https://pl.wikipedia.org/wiki/Lelian_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Leliana</a> wzniecił kolejny bunt w <a href=\"https://pl.wikipedia.org/wiki/Moguncja\" target=\"_blank\" rel=\"noopener noreferrer\">Mogontiacum</a> przeciwko władzy <a href=\"https://pl.wikipedia.org/wiki/Wiktoryn_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Wiktoryna</a>, następcy <a href=\"https://pl.wikipedia.org/wiki/Postumus\" target=\"_blank\" rel=\"noopener noreferrer\">Postuma</a>. Według <i><a href=\"https://pl.wikipedia.org/wiki/Historia_Augusta\" target=\"_blank\" rel=\"noopener noreferrer\">Historia Augusta</a></i> jego rządy trwały zaledwie 2-3 dni, czemu jednak przeczy zachowana liczba jego monet. Najpewniej w mennicy w <a href=\"https://pl.wikipedia.org/wiki/Kolonia_(Niemcy)\" target=\"_blank\" rel=\"noopener noreferrer\">Kolonii</a> (<i>Colonia Agrippina</i>) <a href=\"https://pl.wikipedia.org/wiki/Emisja_pieni%C4%85dza\" target=\"_blank\" rel=\"noopener noreferrer\">emitował</a> w swym imieniu niskowartościowe <a href=\"https://pl.wikipedia.org/wiki/Antoninian\" target=\"_blank\" rel=\"noopener noreferrer\">antoniniany</a> typów: AEQUITAS, CONCORDIA MILIT(um), SAEC(uli) FELICITAS, VICTORIA AUG(usti), VIRTUS AUG(usti).", "Mike": "<p>Mike (ang. Mike): ⁇ Mike ⁇ - amerykański film dramatyczny z 1926 roku.</p>", "Md": "<b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Melchior": "Imię „Melchior” pochodzi od słowa oznaczającego „Bóg jest moją światłością”, „król światła”. Melchior wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> słowa <i>melech</i> i oznacza króla. Imię jest przypisywane jednemu z <a href=\"https://pl.wikipedia.org/wiki/Trzej_Kr%C3%B3lowie\" target=\"_blank\" rel=\"noopener noreferrer\">trzech mędrców</a> (królów, magów) z <a href=\"https://pl.wikipedia.org/wiki/Objawienie_Pa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">Nowego Testamentu</a>.", "Miroslav": "<p>Miroslav (chorwański) (zmarł w 949 roku) - król Chorwacji z dynastii Trpimirów, rządził w latach 945-949.</p>", "Muhammed": "<p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Moshe": "<p>Moshe jest hebrajską wersją męskiego imienia Mojżesza, w tym biblijnej postaci Mojżeszowej. Miano nosi: Moshe Arens (1925-2019), izraelski polityk Moshe Bar (zrównanie) Moshe Bejski (1921-2007), izraelski sędzia Moshe Brener (ur. 1971), izraelski piłkarz koszykówki Moshe Czerniak (1910-1984), izraelscy mistrz szachowców Moshe Dayan (1915-1981), izraelska wojskowa przywódca i polityk Moshe Erem (1896-1978), izraelsko...</p>", "Martyn": "<b>Marcin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od wyrażenia <i>Martinus</i> oznaczającego „należący do boga <a href=\"https://pl.wikipedia.org/wiki/Mars_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Marsa</a>”.", "Medard": "<b>Medard</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Powstało z członów <i>maht</i> – „potęga, władza, moc, męstwo” oraz <i>hart</i> – „silny, odważny, śmiały”.", "Matias": "<p>Matías to portugalska wersja Matthias. Matías jest bardzo popularny w Ameryce Łacińskiej, zwłaszcza w Argentynie.</p>", "Mathias": "<p>Mildred Esther Mathias Hassler (Mildred Esther Hassler; 1906 - 1995) - amerykański botanik.</p>", "Malkhaz": "<p>Malkhaz (georgijski: მალხაზ) to gruzińskie męskie imię. Znanymi osobami z nazwiska są: Malkhaz Abdushelishvili (1926-1998), gruziński naukowiec, antropolog i akademik Malkhaz Akishbaia (ur. 1972), Abchazo-georgiański polityk Malkhaz Arziani (ur. 1964), gruziński piłkarz Malkhaz Asatiani (ur., 1981), gruzijski piłkarze Malkhaz Cheishvili (ur. 19??), gruziany trener rugby Malkhaz Urjukashvili (ur., 1980), gruzi...</p>", "Mihai": "<p>Mihai (rumuńska wymowa: [miˈhaj]) jest rumuńskim nazwiskiem męskim lub nazwiskiem. To równoważne angielskiej imienia Michael.</p>", "Modest": "<b>Modest</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa <i>modestus, -a, -um</i> oznaczającego „umiarkowany, skromny”.", "Marcos": "<p>Marcos - brytyjski producent samochodów, który wyprodukował samochody sportowe w latach 1959-2007. Nazwa firmy powstała z pierwszych liter nazwisk współzałożycieli.</p>", "Mikolaj": "<p>Mikołaj jest polskim krewnym nazwiska Nicholas, używanego zarówno jako nazwisko i nazwisko. Może odnosić się do ludzi: w polskiej (lub polsko-litwskiej) szlachtze: Mikołaj Kamieniecki, polski szlachtańcy i pierwszy Wielki Hetman Korony Mikołj Krzysztof \"Sieroc\" Radziwiłł, polsko-litewski lord Mikołej Mielecki, polski szlachtański i polityk Mikołaz Ostroróg, polski Szlachtańczy Mikołasz Potocki, członek polskiej szlachtańskiej, magnat,...</p>", "Magnus": "<b>Magnus</b>, Magnusz – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od łac. słowa oznaczającego \"wielki\". W <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aredniowiecze\" target=\"_blank\" rel=\"noopener noreferrer\">średniowieczu</a> nosiło je szereg królów <a href=\"https://pl.wikipedia.org/wiki/Norwegia\" target=\"_blank\" rel=\"noopener noreferrer\">norweskich</a> i <a href=\"https://pl.wikipedia.org/wiki/Szwecja\" target=\"_blank\" rel=\"noopener noreferrer\">szwedzkich</a> oraz święci.", "Musa": "<p>Banán (lat. Músa) - rodzaj wieloletnich trawnic roślin z rodziny Bananowych (Musaceae), których największa różnorodność gatunkowa występuje w tropikach Południowo-Wschodniej Azji i w szczególności na archipelagu Malezji.</p>", "Milo": "<p>Milo - marka handlowa, pod którą firma Nestlé od 1934 roku produkuje firma napoju z słodkiem MILO - amerykański czasopism o sportach</p>", "Minh": "<p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Miłosław": "<b>Miłosław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie</a>/<a href=\"https://pl.wikipedia.org/wiki/Dzieje_imion_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie</a> imię męskie, złożone z członów <i>Miło-</i> (\"miły\", \"miłujący\") i <i>-sław</i> (\"sława\"). Znaczenie imienia: \"miły sławie\". Jednym ze stosowanych zdrobnień tego imienia, obok współczesnego \"Miłek\" i staropolskiego \"Miłko\", jest <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82osz\" target=\"_blank\" rel=\"noopener noreferrer\">Miłosz</a>.", "Mathieu": "<p>Matthew Albansky (Mathieu, O.S.B.Clun.) - katolicki cześciennik XII wieku. W młodości studiował teologię w Laene.</p>", "Malik": "<b>Malik</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;ملك&#8206; <i>malik</i> „król, suweren”) – w <a href=\"https://pl.wikipedia.org/wiki/Indie\" target=\"_blank\" rel=\"noopener noreferrer\">Indiach</a>: tytuł pochodzenia arabskiego, przyznawany osobistościom państwa <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmańskiego</a>, a także ludziom zasłużonym dla nauki. Forma żeńska brzmi <i>malika</i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;ملكة&#8206;). Z czasem tytuł ten stał się <a href=\"https://pl.wikipedia.org/wiki/Nazwisko_patronimiczne\" target=\"_blank\" rel=\"noopener noreferrer\">patronimikum</a>.", "Maximillian": "<p>Maksymilian lub Maximillian (Maximiliaan w języku holenderskim i Maximilien w językach francuskich) to męskie imię. Nazwa \"Max\" jest skróceniem \"Maximilian\" oraz kilku innych nazw, w tym, ale nie ograniczając się do Maxwell.</p>", "Matvey": "<p>Matvei lub Matvey (Матвей) jest rosyjską wersją Mateusza. Wśród znanych osób z nazwy są: Matvey Blanter (1903-1990), rosyjski kompozytor muzyki popularnej i filmowej Matvei Bronstein (1906-1938), radziecki fizyk teoretyczny Matvey Frantskevich (ur. 1995), białoruski piłkarz Matvei Gedenshtrom (r.</p>", "Mattia": "<p>Rindēra (lat. Rindēro) - rodzaj roślin kwiatowych z rodziny Buraków (Boraginaceae).</p>", "Maryan": "<b>Pinchas Burstein</b>, pseudonim <i>Maryan</i> (ur. <a href=\"https://pl.wikipedia.org/wiki/1_stycznia\" target=\"_blank\" rel=\"noopener noreferrer\">1 stycznia</a> <a href=\"https://pl.wikipedia.org/wiki/1927\" target=\"_blank\" rel=\"noopener noreferrer\">1927</a> w <a href=\"https://pl.wikipedia.org/wiki/Nowy_S%C4%85cz\" target=\"_blank\" rel=\"noopener noreferrer\">Nowym Sączu</a>, zm. <a href=\"https://pl.wikipedia.org/wiki/15_czerwca\" target=\"_blank\" rel=\"noopener noreferrer\">15 czerwca</a> <a href=\"https://pl.wikipedia.org/wiki/1977\" target=\"_blank\" rel=\"noopener noreferrer\">1977</a> w <a href=\"https://pl.wikipedia.org/wiki/Nowy_Jork\" target=\"_blank\" rel=\"noopener noreferrer\">Nowym Jorku</a>) – polski malarz i grafik pochodzenia żydowskiego.", "Michail": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mikhail</b>.</p><p>Michał (Hebrajskie: מִיכָאֵל; Aramejski: ⁇ , romanized: Mīkhāʼēl) jest powszechnym męskim imieniem, które zazwyczaj uważa się za pochodzące z hebrajskiego pytania retorycznego מי כאל (mī kāʼēl), \"Kto [jest] podobny do [Hebrajskiego boga] El?\", a więc jest nazwiskiem teoforycznym, którego odpowiedź brzmi \"nie ma nikogo podobnego do El\", lub \"nie słynny i potężny jak Bóg\".[is] Paradoksalnie, nazwisko jest czasami interpretowane jako \"Jeden...</p>", "Marie": "<p>Maria (francuski: Marie)  Marie, umysł.</p>", "Marcjan": "<b>Marcjan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> wywodzące się z <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#przydomek\" target=\"_blank\" rel=\"noopener noreferrer\">cognomen</a> <i>Martianus</i> (dla kobiet <i>Martiana</i>). Oznacza ono <i>należący do Marsa, poświęcony Marsowi</i>. <a href=\"https://pl.wikipedia.org/wiki/Ko%C5%9Bci%C3%B3%C5%82_katolicki\" target=\"_blank\" rel=\"noopener noreferrer\">Kościół katolicki</a> notuje wielu <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ty\" target=\"_blank\" rel=\"noopener noreferrer\">świętych</a> o tym imieniu.", "Mason": "<p>Mason Mason to skrócie botaniczne, oznaczające, że autorem taksy jest Mason, Francis.</p>", "Matvei": "<p>Matvei lub Matvey (Матвей) jest rosyjską wersją Mateusza. Wśród znanych osób z nazwy są: Matvey Blanter (1903-1990), rosyjski kompozytor muzyki popularnej i filmowej Matvei Bronstein (1906-1938), radziecki fizyk teoretyczny Matvey Frantskevich (ur. 1995), białoruski piłkarz Matvei Gedenshtrom (r.</p>", "Maxwell": "<p>Maxwell (ur. 23 maja 1973 w Brooklynie, Nowy Jork, USA) - amerykański piosenkarz rytmu-n-bluzowego, który odegrał kluczową rolę w kształtowaniu stylu neosoulu.</p>", "Mehdi": "<p>Mehdi lub Mahdi - islamskie imię, oznaczające ⁇ Bóg (Bóg) posłał Mesjasza ⁇</p>", "Mirza": "<p>Mirza (lat. Mirza) - rodzaj zwierząt mleczarzy z infraodrodu oddziału lemurowych prymatów.</p>", "Mahmut": "<p>Aidin Mahmutović (ur. 6 kwietnia 1986 r., Doba, SFRY) - bosnijski piłkarz, zawodnik.</p>", "Matei": "<p>Matei (rumuńska: [maˈtej]) jest rumuńskim męskim nazwiskiem i nazwiskiem. Jest odwzajemniony od nazwiska Matthias, a jest spokrewniony z angielską nazwą Matthew.</p>", "Malkhazi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Malkhaz</b>.</p><p>Malkhaz (georgijski: მალხაზ) to gruzińskie męskie imię. Znanymi osobami z nazwiska są: Malkhaz Abdushelishvili (1926-1998), gruziński naukowiec, antropolog i akademik Malkhaz Akishbaia (ur. 1972), Abchazo-georgiański polityk Malkhaz Arziani (ur. 1964), gruziński piłkarz Malkhaz Asatiani (ur., 1981), gruzijski piłkarze Malkhaz Cheishvili (ur. 19??), gruziany trener rugby Malkhaz Urjukashvili (ur., 1980), gruzi...</p>", "Mikhailo": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mykhaylo</b>.</p><p>Mykhailo lub Mykhaylo to ukraińskie męskie imię, równoważne angielskim Michałowi. Wśród znanych osób z nazwiskiem są: Mykhaylo Berkos (1861-1919), rosyjski i ukraiński artysta pochodzenia greckiego Mykhayilo Bolotskykh (ur. 1960), ukraiński polityk i wojskowy, pułkownik generalny (Służba Obrony Cywilnej) Mykhayło Brodskyy (ur. 1959), ukraiński polityk, przywódca Partii Wolnych Demokratów i biznesmen Mykhayla Chemberzhi,...</p>", "Miroslaw": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mirosława</b>.</p><b>Mirosława</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> żeńskie, złożone z członów <i>Miro-</i> (<i>pokój</i>, <i>spokój</i>, <i>dobro</i>) oraz <i>-sława</i> (<i>sława</i>). Mogło oznaczać <i>ta, która sławi pokój</i>. W źródłach polskich poświadczone od <a href=\"https://pl.wikipedia.org/wiki/1222\" target=\"_blank\" rel=\"noopener noreferrer\">1222</a> roku. <a href=\"https://pl.wikipedia.org/wiki/Anagram\" target=\"_blank\" rel=\"noopener noreferrer\">Anagram</a> tego imienia też jest żeńskim imieniem – <a href=\"https://pl.wikipedia.org/wiki/S%C5%82awomira\" target=\"_blank\" rel=\"noopener noreferrer\">Sławomira</a>.", "Mate": "<b>Mate</b>, matero, calabaza (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hiszpa%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">hiszp.</a> „dynia/tykwa”) – naczynie do picia <a href=\"https://pl.wikipedia.org/wiki/Yerba_mate\" target=\"_blank\" rel=\"noopener noreferrer\">yerba mate</a>. Słowo „mate” pochodzi od słowa <i>mati</i> w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_keczua\" target=\"_blank\" rel=\"noopener noreferrer\">języka keczua</a>, oznaczającego naczynie lub pojemnik do picia; z czasem stało się nazwą naczyń do picia yerba mate. Naczynia wykonywane są z <a href=\"https://pl.wikipedia.org/wiki/Drewno_(technika)\" target=\"_blank\" rel=\"noopener noreferrer\">drewna</a> (np. <a href=\"https://pl.wikipedia.org/wiki/Gwajakowiec_lekarski\" target=\"_blank\" rel=\"noopener noreferrer\">gwajakowca lekarskiego</a>, <a href=\"https://pl.wikipedia.org/wiki/Bursera_graveolens\" target=\"_blank\" rel=\"noopener noreferrer\">bursera graveolens</a> zwanego <i>palo santo</i>, a także z <a href=\"https://pl.wikipedia.org/wiki/Algarrobo_(drewno)\" target=\"_blank\" rel=\"noopener noreferrer\">algarrobo</a>, palo de rosa, <a href=\"https://pl.wikipedia.org/wiki/Lapacho\" target=\"_blank\" rel=\"noopener noreferrer\">lapacho</a>, drewna cytrynowego), z <a href=\"https://pl.wikipedia.org/wiki/Owoc\" target=\"_blank\" rel=\"noopener noreferrer\">owoców</a> <a href=\"https://pl.wikipedia.org/wiki/Dzbaniwo_kalebasowe\" target=\"_blank\" rel=\"noopener noreferrer\">dzbaniwa kalebasowego</a> (zwanych kalebasami lub tykwami), z metali (<a href=\"https://pl.wikipedia.org/wiki/Stal\" target=\"_blank\" rel=\"noopener noreferrer\">stal</a>, <a href=\"https://pl.wikipedia.org/wiki/Srebro\" target=\"_blank\" rel=\"noopener noreferrer\">srebro</a>) i ceramiki. Naczynia z drewna i <a href=\"https://pl.wikipedia.org/wiki/Kalabasa\" target=\"_blank\" rel=\"noopener noreferrer\">kalebasy</a> zmieniają smak <a href=\"https://pl.wikipedia.org/wiki/Napar\" target=\"_blank\" rel=\"noopener noreferrer\">naparu</a>. Nowe naczynia z kalebasy wymagają przejścia przez proces zwany <i>curado</i> (przygotowania porcji naparu w naczyniu i odstawienia na 24 godziny) w celu usunięcia resztek miąższu.", "Mykhail": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mikhail</b>.</p><p>Michał (Hebrajskie: מִיכָאֵל; Aramejski: ⁇ , romanized: Mīkhāʼēl) jest powszechnym męskim imieniem, które zazwyczaj uważa się za pochodzące z hebrajskiego pytania retorycznego מי כאל (mī kāʼēl), \"Kto [jest] podobny do [Hebrajskiego boga] El?\", a więc jest nazwiskiem teoforycznym, którego odpowiedź brzmi \"nie ma nikogo podobnego do El\", lub \"nie słynny i potężny jak Bóg\".[is] Paradoksalnie, nazwisko jest czasami interpretowane jako \"Jeden...</p>", "Meir": "<p>Meir (Hebrajsky: מֵאִיר) jest żydowskim imieniem męskim i okazjonalnym nazwiskiem. To znaczy \"który świeci\".</p>", "Maximus": "<p>Maximus: Maximus (BBS) - program komputerowy BBS Maximus (Maximus) - główny bohater filmu ⁇ Gladiator ⁇</p>", "Mirko": "<b>Mirosław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie imię</a> męskie. Imię <i>Mirosław</i> jest przykładem <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staropolski\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskiego</a>, złożonego, osobowego imienia dwuczłonowego, które jest <a href=\"https://pl.wikipedia.org/wiki/Relikt\" target=\"_blank\" rel=\"noopener noreferrer\">reliktem</a> <a href=\"https://pl.wikipedia.org/wiki/Poganie\" target=\"_blank\" rel=\"noopener noreferrer\">pogańskich</a> imion używanych we wczesnym średniowieczu przez <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie\" target=\"_blank\" rel=\"noopener noreferrer\">Słowian</a>. Składa się z członów <i>Miro-</i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pras%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">ps.</a> <i>*mirъ</i> „pokój”, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staropolski\" target=\"_blank\" rel=\"noopener noreferrer\">stpol.</a> <i>mir</i>, <i>mier</i> - „pokój, bezpieczeństwo, przyjaźń”) oraz <i>-sław</i> („sława”). Mogło oznaczać „ten, który sławi pokój” albo „ten, który zdobywa sławę poprzez zaprowadzenie porządku, pokoju”. <a href=\"https://pl.wikipedia.org/wiki/Witold_Taszycki\" target=\"_blank\" rel=\"noopener noreferrer\">Witold Taszycki</a> zaliczył je do grupy najstarszych polskich imion osobowych&#8201;.", "Mohan": "<p>Mohan to gmin i nagar panchayat z okręgu Unnao w stanie Uttar Pradesh, India.</p>", "Miraslau": "<p>Mirăslău to gmina w hrabstwie Alba w Rumunii. W 2002 roku liczba ludności wynosiła 2352.</p>", "Muzaffar": "<p>Muzaffar, Muzaffer lub Mozaffar (arabski: مظفر; \"Zwycięzcy\") mogą odnosić się do:</p>", "Mordechai": "<p>Mordechai to trzeci album studiowego amerykańskiego trójki Khruangbin z Houston (stan Texas), wydany 26 czerwca 2020 roku na wytwórniach Dead Oceans i Night Time Stories.</p>", "Mykolai": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mykola</b>.</p><p>Mykola jest ukraińską wariantą męskiego nazwiska \"Nicholas\", co oznacza \"wygrę narodu\". Może odnosić się do:</p>", "Manish": "<p>Manish (także Maneesh) (Devanagari: मनिष lub मनीष) jest powszechną indyjską nazwą męską, która dosłownie oznacza \"Bóg umysłu\" lub ten, który kontrolował i opanował swój umysł (reprezentuje intelektualistę, geniusz itp.), pochodząca z sanskrytów \"man\" (mann), co oznacza umysł i \"ish\", co odnosi się do Boga lub mistrza. Wielu hinduskich chłopców ma takie imię.</p>", "Marcelin": "<b>Marcelin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, utworzone od imienia <a href=\"https://pl.wikipedia.org/wiki/Marceli\" target=\"_blank\" rel=\"noopener noreferrer\">Marceli</a> za pomocą sufiksu oznaczającego przynależność lub pochodzenie. Istniało wielu świętych o tym imieniu.", "Miguel Angel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Miguel</b>.</p><p>Miguel (hisz. Miguel) - hiszpański odpowiednik imienia Michaila.</p>", "Matheus": "<p>Matheus (port. Matheus) - własne imię; rozpowszechnione w postaci nazwisk.</p>", "Mścisław": "<b>Mścisław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z dwóch członów: <i>Mści-</i> („mścić”), od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pras%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">psł.</a> <i>*mьstiti (sę)</i> – mścić (się), <i>*mьstь</i>/<i>*mьsta</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staropolski\" target=\"_blank\" rel=\"noopener noreferrer\">stpl.</a> <i>msta</i> – zemsta, pomsta i <i>-sław</i> („sława”). Mogło oznaczać „tego, który zdobywa sławę mszcząc się na swych wrogach”.", "Maurizio": "<p>Maurizio - to nazwa solowego projektu muzyka Moritz von Oswald i jednocześnie nazwa wytwórni, w której ten projekt wydawał się. W latach 1992-1997 wytwórnia była trwająca i wydała osiem vinylowych singli i jeden album na płytce kompakty.</p>", "Maciek": "<b>Maciej</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, pochodzenia hebrajskiego: <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מַתִּתְיָהוּ&#8206; <i>Mattitjahu</i>, oznaczające „dar <a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a>”.", "Metin": "<b>Grupa metinowa</b>, <b>metin</b> – trójwartościowa <a href=\"https://pl.wikipedia.org/wiki/Grupa_funkcyjna\" target=\"_blank\" rel=\"noopener noreferrer\">grupa funkcyjna</a> pochodząca od <a href=\"https://pl.wikipedia.org/wiki/Metan\" target=\"_blank\" rel=\"noopener noreferrer\">metanu</a>, z cząsteczki którego usunięto trzy atomy <a href=\"https://pl.wikipedia.org/wiki/Wod%C3%B3r\" target=\"_blank\" rel=\"noopener noreferrer\">wodoru</a>. W zależności od rodzaju wiązań, które tworzy z resztą cząsteczki, wyróżnić można trzy grupy:", "Mostafa": "<p>Mustafa sultan (tat. Mostafa, Mostafa; umysł.</p>", "Mahdi": "Według niektórych koncepcji (bliższych <a href=\"https://pl.wikipedia.org/wiki/Sunnizm\" target=\"_blank\" rel=\"noopener noreferrer\">sunnizmowi</a>) jedynym mahdim był <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Jezus</a> – <a href=\"https://pl.wikipedia.org/wiki/Isa_(Jezus)\" target=\"_blank\" rel=\"noopener noreferrer\">Isa</a>. Częściej jednak sunnici uważają, że mahdi i Isa połączą swoje siły w ostatecznej walce z <a href=\"https://pl.wikipedia.org/wiki/Antychryst\" target=\"_blank\" rel=\"noopener noreferrer\">antychrystem</a> (fałszywym <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorokiem</a>) Dadżdżalem. Przyjście mahdiego ma poprzedzać atak wojsk niewiernych na miejscowość <a href=\"https://pl.wikipedia.org/wiki/Lod\" target=\"_blank\" rel=\"noopener noreferrer\">Lod</a> w <a href=\"https://pl.wikipedia.org/wiki/Izrael\" target=\"_blank\" rel=\"noopener noreferrer\">Izraelu</a>. Większość <a href=\"https://pl.wikipedia.org/wiki/Szyizm\" target=\"_blank\" rel=\"noopener noreferrer\">szyitów</a> uważa mahdiego za inną osobę, która ma przyjść na ziemię tuż przed <a href=\"https://pl.wikipedia.org/wiki/S%C4%85d_Ostateczny\" target=\"_blank\" rel=\"noopener noreferrer\">Sądem Ostatecznym</a>, by zbawić/uratować ludzkość przed <a href=\"https://pl.wikipedia.org/wiki/Szatan\" target=\"_blank\" rel=\"noopener noreferrer\">Szatanem</a>. Część wyznawców <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">islamu</a> łączy obie koncepcje, twierdząc, że Jezus urodzi się ponownie w <a href=\"https://pl.wikipedia.org/wiki/Damaszek\" target=\"_blank\" rel=\"noopener noreferrer\">Damaszku</a>, by pokonać <a href=\"https://pl.wikipedia.org/wiki/Z%C5%82o\" target=\"_blank\" rel=\"noopener noreferrer\">zło</a>. Według zapowiedzi Proroka <a href=\"https://pl.wikipedia.org/wiki/Mahomet\" target=\"_blank\" rel=\"noopener noreferrer\">Mahometa</a>, mahdi pochodzić będzie z jego rodu. Dla <a href=\"https://pl.wikipedia.org/wiki/Szyizm\" target=\"_blank\" rel=\"noopener noreferrer\">szyitów</a> jest to bardzo ważna postać, łączona czasem z osobą ostatniego ukrytego <a href=\"https://pl.wikipedia.org/wiki/Imam_(szyizm)\" target=\"_blank\" rel=\"noopener noreferrer\">imama</a>, który ma poprzedzać Mahdiego, bądź nim być.", "Mitchell": "<p>Mitchell, Mitchell (ang. Mitchell, Mitchel) - angielskie nazwisko.</p>", "Moses": "<p>Moses (rz.: Mojżesz): ⁇ Moses ⁇ - piosenka brytyjskiej grupy Coldplay.</p>", "Maxym": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maxim</b>.</p><p>Maxim - międzynarodowy męski (z elementami erotyki) czasopism, który ma w tym również wersję rosyjską. Założona w Wielkiej Brytanii w 1995 roku.</p>", "Miran": "W pierwszych wiekach naszej ery Miran stanowił jeden z głównych grodów królestwa Shanshan i centrum jego rolniczej części. Został odkopany w latach 1901-1903 przez <a href=\"https://pl.wikipedia.org/wiki/Aurel_Stein\" target=\"_blank\" rel=\"noopener noreferrer\">Aurela Steina</a>. W ruinach osady zachowały się liczne freski o tematyce <a href=\"https://pl.wikipedia.org/wiki/Buddyzm\" target=\"_blank\" rel=\"noopener noreferrer\">buddyjskiej</a>, zdradzające wpływy sztuki grecko-rzymskiej. Przedstawione postaci mają rzymskie lub partyjskie ubiory i rysy twarzy, zaś autor jednego z malowideł podpisał się w piśmie <a href=\"https://pl.wikipedia.org/wiki/Kharoszthi\" target=\"_blank\" rel=\"noopener noreferrer\">kharoszthi</a> imieniem <i>Tita</i> – co odczytuje się jako „Tytus”.", "Morgan": "<p>Morgan - powszechne angielskie imię, często występujące również jako nazwisko.</p>", "Mustapha": "<p>⁇ Mustapha ⁇ - piosenka brytyjskiego zespołu rockowego Queen, napisana przez Freddie Mercury, wydana na albumie Jazz i jako singel w Boliwii, Niemczech, Hiszpanii i Jugosławii.</p>", "Malcolm": "<p>Malcolm (gerelski Máel Coluim) (zmarł w 997) - król Strткlajd (973 - 997), syn Donalda III.</p>", "Mikola": "<p>Mikola to nazwisko: Ananda Mikola (ur. 1980), indonezyjski kierowca samochodu wyścigowego István Mikola (r. 1947), węgierski lekarz i polityk, minister zdrowia od 2001 do 2002 roku Nándor Mikola (1911-2006), fiński-węgierski malarz Nazwa: Święty Mikołaj Mozhaiński lub Mikola Mozhaiski, rosyjska wariantka tradycji św. Mikola Abramchyk (1903-1970), białoruski dziennikarz i polityka Mikola Statkevich (ur. 1956),...</p>", "Mihály": "<p>Michaj Wengerski (Mihály) - rządca Księstwa Nitra z dynastii Arpadów.</p>", "Muslim": "<p>Muzułmanie (arabski: al-Muslimūn - muslimoni) to wyznawcy islamu - religii monoteistycznej pochodzącej od Abrahama. Wierzą, że Koran - religijny tekst, który stanowi podstawę islamu - jest objawieniem od Allaha i przekazanym Muhammadowi - i jest ostatnim posłańcem Boga.</p>", "Muhamad": "<p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Metody": "<b>Metody</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa <i>methodos</i> – „kroczący właściwą drogą”.", "Mukesh": "<p>Mukesh jest epitetem hinduskiego boga Shiwy i dosłownie oznacza \"podbiór demona Muka\". Jest powszechnie stosowany jako imię męskie w Indiach.</p>", "Man": "<p>man (od angielskiego manual - wytyczne) - polecenie Unix przeznaczone do formatowania i wyciągania stron odniesienia.</p>", "Matt": "<p>Matwiej Georgijewicz Korobow (ur. 7 stycznia 1983, Orotukan, Obs. Magadan) - rosyjski bokser-profesionalista.</p>", "Mircea": "<p>Mircea jest rumuńskim imieniem męskim, formą sławskiej nazwy Mirče (Мирче), która pochodzi od słowiańskiego słowa mir, co oznacza \"pokój\". Może odnosić się do:</p>", "Moritz": "<p>Moritz (niem. Moritz) - niemieckie imię pochodzące od francuskiego imienia Maurice.</p>", "Moustafa": "<p>Mustafa (arabski: مصطفى, romanized: Muṣṭafā) jest jednym z imion islamskiego proroka Mahometa. W arabskim oznacza \"wybrany, wybrany, wyznaczony, preferujący\".</p>", "Mindaugas": "<p>Mindaugas (niemiecki: Myndowen, łaciński: Mindowe, staroświeckie słowia: Мендог, białoruski: Міндоўг, (1203 - 12 września 1263) był pierwszym znanym jako Książę Litwy i Król Litwy. Niewiele wiadomo o jego pochodzeniu, dzieciństwie lub władzy; w 1219 r. w traktatu wspomniano o nim jako owego staruszka, a w 1236 r. jako o przywódcy wszystkich ludów Litwy.</p>", "Michaił": "<b>Michał</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִיכָאֵל&#8206; – Mîchā’ēl) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, wywodzące się od <a href=\"https://pl.wikipedia.org/wiki/Archanio%C5%82_Micha%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">jednego z archaniołów</a>. Po hebrajsku znaczy „któż [jest taki] jak Bóg”. Forma żeńska to <a href=\"https://pl.wikipedia.org/wiki/Michalina\" target=\"_blank\" rel=\"noopener noreferrer\">Michalina</a>.", "Min": "<p>Min to niejednoznaczny termin. min - w matematyce i językach programowania oznacza funkcję wyboru najmniejszego ze swoich argumentów, (Min (3, 6, 2) = 2).</p>", "Moise": "<p>Moise jest nazwiskiem i nazwiskiem, z różnymi pisowniami w jego francuskim i rumuńskim pochodzeniu, które oba pochodzą z imienia Mojżesz: Moïse jest francuskim pisownią Mojżesza, podczas gdy Moise jest rumuńskie pisownią. Jako nazwisko, Moisè i Mosè to włoskie pisownię Mojżesza.</p>", "Mourad": "<p>Murad lub Mourad (arabijski: مراد) to arabska nazwa. Jest również powszechne w językach armenijskim, azerbajdżanskim, bengalijskim, tureckim, perskim i berberskim jako męskie imię lub nazwisko i jest powszechnie stosowane w całym świecie muzułmańskim i na Bliskim Wschodzie.</p>", "Milen": "<p>Milen (bułgarski: Милен) to bułgarskie męskie imię. Wśród znanych osób z tej nazwy są: Milen Bonev (ur. 1986), bułgarski piłkarz, obecnie grający dla Kaliakra Kavarna jako obrońca Milen Dobrev (ur. 1980), bułgarski ciężarosta Milen Hristov (ur. 1977), bułgara piłkarza piłkarka, który obecnie gra dla Neftochimic Burgas jako półbrzeg Milen Lahchev (ur., 1987), bułgaria piłkarze, obecnie gry...</p>", "Makhmud": "<p>Mahmud jest transliteracją męskiego arabskiego nazwiska Mahmoud (Maḥmūd), powszechnego w większości części świata islamskiego. Pochodzi od arabskiego korzenia trójkononantalnego Ḥ-M-D, co oznacza chwałę, wraz z Mahometem.</p>", "Malek": "<p>Malek (czeski. Malek, go.</p>", "Maksimilian": "<p>Maksymilian lub Maximillian (Maximiliaan w języku holenderskim i Maximilien w językach francuskich) to męskie imię. Nazwa \"Max\" jest skróceniem \"Maximilian\" oraz kilku innych nazw, w tym, ale nie ograniczając się do Maxwell.</p>", "Misha": "<p>Misha (rosyjski: Миша), znana również jako Mishka (rosycki: Мишка) lub Mishka Olimpijski (rosyński: Олимпийский Мишка), to nazwisko rosyjskiego niedźwiedzia z 1980 r. Stwór został zaprojektowany przez malarza ilustrującego dziecięce książki Victora Chizhikowa.</p>", "Mieczyslaw": "<p>Mieczysław (polska: [mjɛˈt͡ʂ ⁇ .swaf]) to polskie imię męskie. Składa się z słowiańskich elementów miecz oznaczających \" miecz \" i sława oznacza \" chwała, sławę \".</p>", "Morten": "<b>Marcin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od wyrażenia <i>Martinus</i> oznaczającego „należący do boga <a href=\"https://pl.wikipedia.org/wiki/Mars_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Marsa</a>”.", "Mantas": "<p>Jeffrey Dunn (ang. Jeffrey Dunn; 22 kwietnia 1961, Newcastle-upon-Tyne, Wielka Brytania), znany również pod pseudonimem Mantas - brytyjski gitarzysta metalu i kompozytor, jeden z założycieli brytyjskiej grupy thrash/black-metalu Venom w 1979 roku.</p>", "Martinus": "<b>Marcin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od wyrażenia <i>Martinus</i> oznaczającego „należący do boga <a href=\"https://pl.wikipedia.org/wiki/Mars_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Marsa</a>”.", "Mendel": "<p>Gregor Johann Mendel (niem. Gregor Johann Mendel, Czechy.</p>", "Mamert": "<b>Mamert</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_italskie\" target=\"_blank\" rel=\"noopener noreferrer\">italskiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_oskijski\" target=\"_blank\" rel=\"noopener noreferrer\">oskijskiego</a> lub sabińskiego wariantu imienia boga <a href=\"https://pl.wikipedia.org/wiki/Mars_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Marsa</a> – <i>Mamers</i>, który w przypadkach zależnych (np. <i>Mamertis</i>) miał temat <i>Mamert</i>.", "Micheasz": "<b>Micheasz</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> <i><b>מִיכַיְהוּ</b></i> — Mîkhā’iah, <i><b>מִיכָה</b></i> — Mîkhā) — <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Imię to nosił <a href=\"https://pl.wikipedia.org/wiki/Micheasz_(autor_biblijny)\" target=\"_blank\" rel=\"noopener noreferrer\">prorok Micheasz</a>. Po hebrajsku znaczy „któż [jest taki] jak <a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a>?!” i stanowi synonim imienia <a href=\"https://pl.wikipedia.org/wiki/Micha%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Michał</a>. <a href=\"https://pl.wikipedia.org/wiki/Patron_(chrze%C5%9Bcija%C5%84stwo)\" target=\"_blank\" rel=\"noopener noreferrer\">Patronem</a> tego imienia w Kościele katolickim jest <a href=\"https://pl.wikipedia.org/wiki/Micheasz_(autor_biblijny)\" target=\"_blank\" rel=\"noopener noreferrer\">prorok Micheasz</a>, autor biblijny, a w Cerkwi prawosławnej jest kilku świętych Micheaszów, m.in. Micheasz z Radoneża (<i>Michej z Radoneża</i> lub <i>Michej Radoneżski</i>), zm. <a href=\"https://pl.wikipedia.org/wiki/1385\" target=\"_blank\" rel=\"noopener noreferrer\">1385</a>, święto <a href=\"https://pl.wikipedia.org/wiki/5_maja\" target=\"_blank\" rel=\"noopener noreferrer\">5</a> lub <a href=\"https://pl.wikipedia.org/wiki/19_maja\" target=\"_blank\" rel=\"noopener noreferrer\">19 maja</a>.", "Mikel": "<p>Mikel jest baskijską adaptacją nazwiska Michaela. Nazwa Mikel pochodzi od hebrajskiego słowa Micha'el, co oznacza \"Kto jest jak Bóg\".</p>", "Manu": "<p>Emmanuel Laurent Peti (francuski: Emmanuel Laurent Petit; urodz.</p>", "Mátyás": "<p>Matvej (Mattias; nim. Matthias, węg.</p>", "Mina": "<b>Mina</b> – imię rozmaitego pochodzenia. W niektórych kulturach posługuje się nim jako imieniem żeńskim, a w innych kulturach jest to imię męskie.", "Mika": "<b>Mika</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;みか, ミカ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a> i fińskie zdrobnienie od <a href=\"https://pl.wikipedia.org/wiki/Micha%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Michała</a>.", "Mukhtar": "<p>Khalid Sheikh Mohammed (arabski: خالد شيخ محمد, Khālid Shaykh Muḥammad; przerwa Khalid Shaikh Mohammed, znany również jako Sheikh Mohammed, lub Mukhtar i co najmniej 50 innych pseudonimów; urodzony w 1964 lub 1965) jest członkiem organizacji al-Qaeda, który jest zatrzymany przez amerykańską armię w więzieniu Guantanamo Bay za terrorystyczne działania i morderstwa w masowej liczbie. Został oskarżony przez komisję o 11 września 2001 roku o planowanie ataków terrorystycznych.</p>", "Mounir": "<p>Muneer (zwany również Moneer, Monir, Mounir lub Muneyr, w arabski: منير, oznaczające oświetlające, jasne, jasne i jasne) jest męskie arabskie imię, może odnosić się do:</p>", "Madan": "<p>Madan jest miastem w prowincji Smolyan, Bungaria. W 2011 roku liczba ludności wynosiła 5791.</p>", "Ming": "<p>Ming - biblioteka C do tworzenia plików Adobe Flash (.swf). Może być stosowany jako moduł PHP, pozwalając tworzyć dynamicznie (⁇ na lot ⁇) animację Flash.</p>", "Mohsin": "<p>Muhsin (zwanego również Mohsen, Mohsin, Mehsin lub Muhsen, arabski: محسن) jest męskim arabskim nazwiskiem. Pierwszą osobą, o której wiadomo, że nosi nazwę \"Muhsin\", był Muhsin ibn Ali, syn Ali ibn Abi Talib i Fatimah bint Muhammad.</p>", "Milano": "<p>Milan jest głównym miastem północnej Włoch. To globalne miasta.</p>", "Morris": "<p>Morris może być: Morris (1923-2001), belgijski artysta komiksów, autor Lucky Luke Morris (wówczas), ich rodzina Morris (komputery), jeden z pierwszych komórek komputerowych rozprzestrzenionych przez Internet Morris Motor Company, producent samochodów Morris the Cat, materiał zbierany z Morris Dance, tradycyjny brytyjski taniecki Morris College, szkóła sztuki w Sumterze, Karolina Południowa</p>", "Miklós": "<b>Melchior Cibinensis</b> – węgierski ksiądz katolicki piszący w I połowie <a href=\"https://pl.wikipedia.org/wiki/XVI_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XVI wieku</a>. Tożsamość Melchiora ciągle jest przedmiotem dyskusji. <a href=\"https://pl.wikipedia.org/wiki/Carl_Gustav_Jung\" target=\"_blank\" rel=\"noopener noreferrer\">Carl Gustav Jung</a> uważał, że chodzi tu o Nicolasa Melchiora Szebeniego, kapłana, od <a href=\"https://pl.wikipedia.org/wiki/1490\" target=\"_blank\" rel=\"noopener noreferrer\">1490</a> roku nadwornego <a href=\"https://pl.wikipedia.org/wiki/Astrologia\" target=\"_blank\" rel=\"noopener noreferrer\">astrologa</a> na dworze <a href=\"https://pl.wikipedia.org/wiki/W%C5%82adys%C5%82aw_II_Jagiello%C5%84czyk\" target=\"_blank\" rel=\"noopener noreferrer\">Władysława II</a>, króla Czech i Węgier. Inni uważają, że był to pseudonim Nicolausa Olahisa; jeszcze inni twierdzą, że chodzi tu o Menyhérta Miklósa. <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">Łaciński</a> przydomek \"Cibinensis\" wskazuje, że chodzi tu o człowieka pochodzącego z węgierskiego miasta Nagyszeben (obecnie <a href=\"https://pl.wikipedia.org/wiki/Sybin\" target=\"_blank\" rel=\"noopener noreferrer\">Sybin</a> w <a href=\"https://pl.wikipedia.org/wiki/Rumunia\" target=\"_blank\" rel=\"noopener noreferrer\">Rumunii</a>, (<a href=\"https://pl.wikipedia.org/wiki/Siedmiogr%C3%B3d\" target=\"_blank\" rel=\"noopener noreferrer\">Siedmiogród</a>)).", "Markian": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Marcian</b>.</p>Był jednym z wodzów w armii <a href=\"https://pl.wikipedia.org/wiki/Flawiusz_Ardaburiusz_Aspar\" target=\"_blank\" rel=\"noopener noreferrer\">Aspara</a>, <i>magistra militum</i>, czyli głównodowodzącego armii <a href=\"https://pl.wikipedia.org/wiki/Cesarstwo_Bizanty%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">bizantyńskiej</a>, pochodzącego z <a href=\"https://pl.wikipedia.org/wiki/Ludy_ira%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">irańskiego</a> ludu <a href=\"https://pl.wikipedia.org/wiki/Alanowie\" target=\"_blank\" rel=\"noopener noreferrer\">Alanów</a> (stanowiło to istotną przeszkodę w objęciu przez niego tronu). Cesarzem obrano Marcjana, gdy poślubił siostrę poprzednika, <a href=\"https://pl.wikipedia.org/wiki/Pulcheria_(cesarzowa)\" target=\"_blank\" rel=\"noopener noreferrer\">Pulcherię</a>, choć było to fikcyjne małżeństwo, a Pulcheria do końca życia pozostała dziewicą.", "Márk": "<p>Márk jest węgierską formą Marka (zwanego nazwiskiem), chociaż poza Markiem Ewangelizmem nazwa jest dość rzadka jako nazwa węgierska. Wśród znanych osób z tej nazwy są: Márk Opavszky (ur. 2001), węgierski kanosik Márk Rózsavölgyi (1787-1848), węgarski kompozytor i skrzypiec Márk Mosonyi</p>", "Maddox": "<b>Maddox</b> – głównie męskie imię używane w krajach anglojęzycznych wywodzące się od walijskiego nazwiska znaczącego „syn Madoca”. <a href=\"https://pl.wikipedia.org/wiki/Madoc_ab_Owain_Gwynedd\" target=\"_blank\" rel=\"noopener noreferrer\">Madoc</a> lub Madog był legendarnym walijskim księciem, który według walijskiego folkloru popłynął do <a href=\"https://pl.wikipedia.org/wiki/Nowy_%C5%9Awiat\" target=\"_blank\" rel=\"noopener noreferrer\">Nowego Świata</a> trzysta lat przed <a href=\"https://pl.wikipedia.org/wiki/Krzysztof_Kolumb\" target=\"_blank\" rel=\"noopener noreferrer\">Krzysztofem Kolumbem</a>. Imię oznacza „pomyślny/fortunny” i pochodzi od walijskiego słowa „mad”.", "Mahmood": "<p>Mahmud jest transliteracją męskiego arabskiego nazwiska Mahmoud (Maḥmūd), powszechnego w większości części świata islamskiego. Pochodzi od arabskiego korzenia trójkononantalnego Ḥ-M-D, co oznacza chwałę, wraz z Mahometem.</p>", "Matúš": "<p>Matus może być zarówno nazwiskiem, jak i nazwiskiem. Do powszechnych wariantów należą Matúš, Matuš i Matůš.</p>", "Micheal": "<p>Micheal to męskie imię. Czasami jest to anglicizowana forma irlandzkiego imienia Micheál, Mícheál i Michéal; lub szkockiego gaelickiego imienia Mìcheal.</p>", "Myhailo": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mihailo</b>.</p><p>Mihailo (Serbski cyrylski: Михаило) (\"\\mi-hail\\o\") jest sławskim nazwa męska. Jest to wariant hebrajskiej nazwy Michał, a jego krewni włączają Mihajlo i Mijailo.</p>", "Milad": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Milada</b>.</p><b>Miłosława</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> żeńskie, złożone z członów <i>Miło-</i> („miły”, „miłujący”) i <i>-sława</i> („sława”). Znaczenie imienia: „miła sławie”. Poświadczone w źródłach polskich jako Miłosława (XII wiek) i Miełosława (XIII–XIV wiek).", "Mykoła": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mikola</b>.</p><p>Mikola to nazwisko: Ananda Mikola (ur. 1980), indonezyjski kierowca samochodu wyścigowego István Mikola (r. 1947), węgierski lekarz i polityk, minister zdrowia od 2001 do 2002 roku Nándor Mikola (1911-2006), fiński-węgierski malarz Nazwa: Święty Mikołaj Mozhaiński lub Mikola Mozhaiski, rosyjska wariantka tradycji św. Mikola Abramchyk (1903-1970), białoruski dziennikarz i polityka Mikola Statkevich (ur. 1956),...</p>", "Marcio": "<p>Marcio to brazylijskie lub portugalskie imię męskie, marcio Melo (1906-1991), generał brazylijskiego sił powietrznych Márcio Rezende de Freitas (ur. 1960), brazylijski sędzia piłki nożnej Márcio Bittencourt (ur. 1964), brazylijski piłkarz i trener, marcio Santos (ur. 1969), brazylianki piłkarze, 1994 mistrz świata Márcio Garcia (ur. 1970), brazyliiński aktor i telewizyjny prezenter Márcio Rogério de Andrade (1971-2007),...</p>", "Mihailo": "<p>Mihailo (Serbski cyrylski: Михаило) (\"\\mi-hail\\o\") jest sławskim nazwa męska. Jest to wariant hebrajskiej nazwy Michał, a jego krewni włączają Mihajlo i Mijailo.</p>", "Mikko": "<p>Mikko to fińskie imię męskie i odpowiednik angielskiego imienia Michaela, które zostało pojęte w językach finskich. Nazwa Mikko jest podzielona przez następujących znanych osób: Mikko Alatalo, fiński muzyk i polityk Mikko Eloranta, fiński hokejista lewicowy Mikko Franck, fiński dyrygent Mikko Heiniö, fiński kompozytor Mikko Hirvonen, kierowca mistrzostw świata w rali, fiński guru bezpieczeństwa...</p>", "Mychailo": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mykhailo</b>.</p><p>Mykhailo lub Mykhaylo to ukraińskie męskie imię, równoważne angielskim Michałowi. Wśród znanych osób z nazwiskiem są: Mykhaylo Berkos (1861-1919), rosyjski i ukraiński artysta pochodzenia greckiego Mykhayilo Bolotskykh (ur. 1960), ukraiński polityk i wojskowy, pułkownik generalny (Służba Obrony Cywilnej) Mykhayło Brodskyy (ur. 1959), ukraiński polityk, przywódca Partii Wolnych Demokratów i biznesmen Mykhayla Chemberzhi,...</p>", "Mohd": "<p>Muhammad (arabski: مُحَمَّد, romanized: Muḥammad) to arabskie imię męskie oznaczające \"chwalone\". Nazwa pochodzi od pasywnego czasownika arabskiego ḥammada (حَمَّدَ), co oznacza \"chwalenie\", które samo pochodzi od trykonsonantalnego korzenia semitycznego Ḥ-M-D.</p>", "Michailo": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mikhailo</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mykhaylo</b>.</p><p>Mykhailo lub Mykhaylo to ukraińskie męskie imię, równoważne angielskim Michałowi. Wśród znanych osób z nazwiskiem są: Mykhaylo Berkos (1861-1919), rosyjski i ukraiński artysta pochodzenia greckiego Mykhayilo Bolotskykh (ur. 1960), ukraiński polityk i wojskowy, pułkownik generalny (Służba Obrony Cywilnej) Mykhayło Brodskyy (ur. 1959), ukraiński polityk, przywódca Partii Wolnych Demokratów i biznesmen Mykhayla Chemberzhi,...</p>", "Mário": "<p>Mario to włoska, francuska, chorwacka, czeska, norweska, słowacka, serbska, węgierska, słoweńska, polska, hiszpańska, duńska, portugalska, rumuńska, szwedzka, bułgarska, grecka, niemiecka, holenderska i angielska forma łacińskiego imienia Marius.</p>", "Mher": "<p>Mher jest armenijską męską nazwą, pochodzącą z perskiego imienia Mehr. Jest również śpieszone Mger.</p>", "Mordechay": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mordechai</b>.</p><p>Mordechai to trzeci album studiowego amerykańskiego trójki Khruangbin z Houston (stan Texas), wydany 26 czerwca 2020 roku na wytwórniach Dead Oceans i Night Time Stories.</p>", "Murtaz": "<p>Murtaz (georgijski: მურთაზ; rosyjski: Муртаз) to męskie imię. Wśród znanych osób z nazwiskiem są: Murtaz Daushvili (ur. 1989), gruziński piłkarz Murtaz Khurtsilava (ur. 1943), gruzijski obrońca piłki nożnej Murtaz Shelia (ur. 1969), gruzianski obrońca.</p>", "Marshall": "<p>Marshall - może oznaczać: Marshall - skrócie botaniczne, oznaczające, że autorem taksy jest Marshall, Humphrey. Marshall Amplification - angielska firma produkująca wzmacniacze dźwiękowe.</p>", "Mitko": "<p>Mitko (zirylicki: Митко lub Митько) to bułgarskie i makedonii męskie imię, krótka wersja Dimitar. Jest to także okazjonalne nazwisko, które może odnosić się do następujących osób: Nazwa: Mitko Bachev (ur. 1960), bułgarski jogger Mitko Čavkov (ur. 1963), minister spraw wewnętrznych Macedonii Mitko Dimitrov (ur. 1953), bułgarski Mitko Dobrev, bułgarski menedżer piłki nożnej Mitko Grablev, bułgarki ciężarostaj Mitko Kabakov (ur. ...</p>", "Matheo": "Współpraca przyniosła EP-kę, która ukazała się w 2004 w Magazynie Hip-Hop. Matheo, poza rapowaniem, zaczął tworzyć muzykę. Jego pracę pierwszy raz można było usłyszeć na <a href=\"https://pl.wikipedia.org/wiki/Nielegal\" target=\"_blank\" rel=\"noopener noreferrer\">nielegalu</a> z Maciejem „Hajdim” Hajdukiem (jednym z członków tworzących formację ZT Zasięg) pt. <i>Czas Nastał</i>. Przełomem w jego karierze był rok 2004. Wtedy został wyłoniony z konkursu dla producentów, organizowanym przez wytwórnię <a href=\"https://pl.wikipedia.org/wiki/Wielkie_Jo%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Wielkie Joł</a>, dzięki czemu wyprodukował jeden utwór na płytę <a href=\"https://pl.wikipedia.org/wiki/Tede\" target=\"_blank\" rel=\"noopener noreferrer\">Tedego</a> <i><a href=\"https://pl.wikipedia.org/wiki/Notes_(album)\" target=\"_blank\" rel=\"noopener noreferrer\">Notes</a></i>. Wtedy już producent nawiązał bliską współpracę z wytwórnią.", "Miro": "<p>Miro: Miro (mediaplayer) (dawniej znany jako Democracy Player i DTV) - wolny mediaplayer Miro (RealtimeBoard) - platforma online do wizualizacji i współpracy</p>", "Muhamed": "<p>Muhammad (arabski: مُحَمَّد, romanized: Muḥammad) to arabskie imię męskie oznaczające \"chwalone\". Nazwa pochodzi od pasywnego czasownika arabskiego ḥammada (حَمَّدَ), co oznacza \"chwalenie\", które samo pochodzi od trykonsonantalnego korzenia semitycznego Ḥ-M-D.</p>", "Micah": "<p>Micha (; hebrajskie: מִיכָה, nowoczesne: Mikha, tyberyjskie: Mî ⁇ ā) jest nazwiskiem. Micha jest nazwiskiem kilku ludzi w Tanakh, co oznacza \"Kto jest jak Bóg? \"Przecież to prawda\".</p>", "Masud": "<p>Masud (arabski: مسعود اِقرا: مَس عَود , romanized: fortunate, prosperous, lucky, happy, perskiego: مسعود خوانده شود:مسود) to nazwisko i nazwisko, powszechnie występujące na Bliskim Wschodzie i Azji. Do wybitnych osób z tym nazwiskiem należą:</p>", "Mansour": "<p>Mansour (arabickie: منصور, Manṣūr); również pisane Mounsor, Monsur (Bengali), Mansoor, Manser, Mansur, Mansyur (indonezyjski) lub Mensur (tyrki), to męskie arabskie imię oznaczające \"Ten, który zwycięża\", z arabskiego korzenia naṣr (نصر), oznaczające \"wygrę\". Pierwszym znanym nosicielem nazwy był Mansur ibn Sarjun, bizantyjski gubernator Damaszku pod koniec lat 500 i na początku lat 600, który poddał miasto muzułmanom w 635 r. Inni ludzie nazywają się Mansur...</p>", "Mamadou": "<p>Mamadou jest powszechną nazwą w Afryce Zachodniej wśród głównie muzułmańskich grup etnicznych, takich jak ludzie Mandé i Wolof. Jest to wariant arabskiego imienia Muhammad.</p>", "Mściwoj": "<b>Mściwoj</b>, <b>Mszczujwoj</b> – <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów „mścić (się)” i „woj”, oznaczające prawdopodobnie tego, który \"mści swoich współtowarzyszy\". Jego pomorskim odpowiednikiem może być <a href=\"https://pl.wikipedia.org/wiki/Miestwin\" target=\"_blank\" rel=\"noopener noreferrer\">Miestwin</a>. Na temat <a href=\"https://pl.wikipedia.org/wiki/Etymologia\" target=\"_blank\" rel=\"noopener noreferrer\">etymologii</a> patrz również wyjaśnienia pod hasłem <a href=\"https://pl.wikipedia.org/wiki/M%C5%9Bciwoj_I_gda%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">Mściwoj I</a>.", "Masoud": "<p>Masoud (arabski: مسعود, lit. 'szczęście, szczęśliwy, dobrodziejny, szczęśliwy') jest męskie imię i nazwisko pochodzące z arabskiego.</p>", "Milian": "<p>Milian - nazwisko.</p>", "Matin": "<p>Matin lub MATIN może odnosić się do: Al-Matin, imienia Boga w islamskim Morning (świt, wczesny dzień, przeddzień) w średniowiecznym angielskim</p>", "Martins": "<p>Martins to miasto w Brazylii. Miasto ma powierzchnię 169,466 km2, liczba ludności w 2007 roku wynosi 7551 mieszkańców, a jego gęstość 44,6 mieszkańców/km2.</p>", "Moisei": "<p>Moisei to gmina w hrabstwie Maramureș, Rumunii. W 2002 roku liczba ludności wynosiła 9031 osób.</p>", "M": "<b>M</b> (<i>em</i>, <a href=\"https://pl.wikipedia.org/wiki/Minusku%C5%82a\" target=\"_blank\" rel=\"noopener noreferrer\">minuskuła</a>: <b>m</b>) – trzynasta <a href=\"https://pl.wikipedia.org/wiki/Litera\" target=\"_blank\" rel=\"noopener noreferrer\">litera</a> <a href=\"https://pl.wikipedia.org/wiki/Alfabet_%C5%82aci%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu łacińskiego</a> i siedemnasta <a href=\"https://pl.wikipedia.org/wiki/Alfabet_polski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu polskiego</a>. Oznacza zwykle w danym języku <a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_nosowa_dwuwargowa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">spółgłoskę wargową nosową</a>, np. [<a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_nosowa_dwuwargowa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">m</a>].", "Mayank": "<p>Mayank to męskie imię znalezione w Indiach, co oznacza \"świecający księżyc\".</p>", "Mikolay": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mykolay</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mikolai</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mikola</b>.</p><p>Mikola to nazwisko: Ananda Mikola (ur. 1980), indonezyjski kierowca samochodu wyścigowego István Mikola (r. 1947), węgierski lekarz i polityk, minister zdrowia od 2001 do 2002 roku Nándor Mikola (1911-2006), fiński-węgierski malarz Nazwa: Święty Mikołaj Mozhaiński lub Mikola Mozhaiski, rosyjska wariantka tradycji św. Mikola Abramchyk (1903-1970), białoruski dziennikarz i polityka Mikola Statkevich (ur. 1956),...</p>", "Maximo": "<p>Maximo: Ghosts to Glory (znany również jako Maximo w Europie i Japonii) to 3D hack and slash platformer opracowany i wydany przez Capcom dla PlayStation 2. Gra jest oparta na wszechświecie Ghosts n' Goblins, ale zawiera oryginalne postacie stworzone przez manga Sussuma Matsushita.</p>", "Michelangelo": "<p>Michelangelo di Lodovico Buonarroti Simoni (6 marca 1475 - 18 lutego 1564), powszechnie znany jako Michelangelo, był włoskim renesansowym malarzem, rzeźbiarzem, architektem, poetą i inżynierem. Mimo niewielu przełomów poza sztuką, jego wdzięczność w dziedzinie osiągnęła taką stopnię, że był on uznany za człowieka, który zasługuje na tytuł rewansa, wraz z jego konkurentami i przyjaciółmi.</p>", "Mor": "Próchnica, a ściślej jej <a href=\"https://pl.wikipedia.org/wiki/Poziom_organiczny\" target=\"_blank\" rel=\"noopener noreferrer\">poziom organiczny</a> jest oznaczany w <a href=\"https://pl.wikipedia.org/wiki/Gleboznawstwo\" target=\"_blank\" rel=\"noopener noreferrer\">gleboznawstwie</a> literą O.", "Majk": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Majka</b>.</p><p>Majka, słowiańskie kobiece imię, pierwotnie diminutiw nazwiska Maria lub Maja, może być to zmiana pisowni Mayka.</p>", "Miras": "<p>Miras jest gminą w okręgu Devoll w Korce, Albania. W 2005 roku liczba ludności wynosiła 9413 osób.</p>", "Miller": "<p>Gerrit Smith Miller (ang. Gerrit Smith; 1869 - 1956) - amerykański zoolog i botanik.</p>", "Md Abdul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Moris": "<p>Giuseppe Giacinto Moris (włoski: Giuseppe Giacinta Moris; 1796 - 1869) - włoski botanik i polityk.</p>", "Mădălin": "<p>Mădălin to rumuńskie imię i nazwisko mężczyzny, które może odnosić się do: Mădăline Ciucă (ur. 1982), rumuński piłkarz Mădă Lin Lemnaru (ur. 1989), rumuński piłkarze rugby Mădă lin Marius Popa (ur. 1982) rumuński futbolista i menedżer Mădăilin Martin (ur. 1992), rumuńskiego piłkarza Mădălina Mihăescu (ur. 1988), rumuńczyka piłkarka Mădăl Murgan (ur. 1983), rumuńca piłkarzem Mădă l Popa (UR. 1983), rumunskiego piłkarta Mădălini Răileanu (ur....</p>", "Marino": "<p>Mauring (Moring, Marin; ł. Mauringus, Moringus, Ital.</p>", "Man Bahadur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Man</b>.</p><p>man (od angielskiego manual - wytyczne) - polecenie Unix przeznaczone do formatowania i wyciągania stron odniesienia.</p>", "Milán": "<p>Milan jest samodzielnym terenem w prowincji Caquetá w Kolumbii. Gmina Milan jest stolicą Milanie.</p>", "Mkrtich": "<p>Mkrtich to armenijska męska nazwa, oznaczająca na języku armenijskim Baptystę. Nazwa ta odnosi się pierwotnie do Jana Chrzciciela, znany jako Surb Hovhannes Mkrtich (Święty Jan Chrzciciel) w języku armenijskim.</p>", "Manas": "<p>Manas (stylownik: 玛纳斯县; substylownik; ślonski: 玛納斯县; ślony: Mǎnàsī Xiàn, vietnamski: Mǎnásī Xiàn; uygurski: Manas ناھىيىسى , ULY: Manas Nahiyisi, UPNY: Manas Nah ⁇ iyisi?) jest okręgem samorządu Azji narodowego muzułmańskiego, regionu samorządowego Tangiu, China. Obecnie mieści się w stanie Manas (玛纳斯), na brzegu rzeki Manas, wschodniej od Czarnogórza.</p>", "Mir": "<b>Mir</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskiego.</a> Powstało jako zdrobnienie imion np: <a href=\"https://pl.wikipedia.org/wiki/Miros%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Mirosław</a>, <a href=\"https://pl.wikipedia.org/wiki/Jaromir\" target=\"_blank\" rel=\"noopener noreferrer\">Jaromir</a>, <a href=\"https://pl.wikipedia.org/wiki/S%C5%82awomir\" target=\"_blank\" rel=\"noopener noreferrer\">Sławomir</a>, <a href=\"https://pl.wikipedia.org/wiki/Radomir\" target=\"_blank\" rel=\"noopener noreferrer\">Radomir</a>, Stanimir itd.", "Miodrag": "<p>Miodrag (sirylicki: Миодраг) to sławskie imię pochodzące z języka południowego, prawie wyłącznie z języka serbskiego, pochodzące od imion mio (\"miękkie, urocze\") i drag (\"miła, cenna\"), które są powszechne w słowiańskich nazwiskach.</p>", "Marten": "<p>Marten jest miastem w prowincji Ruse, Bungaria. W 2011 roku liczba ludności wynosiła 3632.</p>", "Moran": "<p>Moran to japoński zespół rockowy, który oficjalnie istniał w latach 2008-2015. Wykonywała muzykę w gatunku wizual-kay.</p>", "Mihajlo": "<p>Mihajlo (sirbski cyrylski: Михајло) jest południowsłowiańskim wariantem imienia Michał, często występującym wśród Serbów. Mijailo i Mijailo to między innymi imiona.</p>", "Mikolai": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mikola</b>.</p><p>Mikola to nazwisko: Ananda Mikola (ur. 1980), indonezyjski kierowca samochodu wyścigowego István Mikola (r. 1947), węgierski lekarz i polityk, minister zdrowia od 2001 do 2002 roku Nándor Mikola (1911-2006), fiński-węgierski malarz Nazwa: Święty Mikołaj Mozhaiński lub Mikola Mozhaiski, rosyjska wariantka tradycji św. Mikola Abramchyk (1903-1970), białoruski dziennikarz i polityka Mikola Statkevich (ur. 1956),...</p>", "Murray": "<p>Johan Andreas Murray (szwedzki: Johan Andreas Murray, 27 stycznia 1740 - 22 maja 1791) - szwedzki i niemiecki botanik, lekarz, profesor botanyki i medycyny, uczeń Carla Linnea.</p>", "Merlin": "Trzeci cykl walijskiej triady podaje, że Clas Myrrdin (Samotnia Merlina)&#160;była nazwą Wielkiej Brytanii. Według niektórych (A.O.H. Jarmana), słowo Myrddin jest walijską wersją rzymskiej nazwy Carmarthen. Kontrastuje to z popularnym, lecz fałszywym ludowym przekazem, że miasto zostało nazwane na cześć wieszcza. Nazwa Carmarthen wywodzi się od rzymskiej nazwy miasta Moridunum, które pochodzi od nazwy \"moridunon\" oznaczającej morską twierdzę.", "Memet": "<p>Mehmed lub Mehmet jest najczęstszą turecką formą arabskiego męskiego imienia Muhammad (arabski: محمد) (Muhammad i Muhammet są również używane, choć znacznie mniej) i zyskuje swoje znaczenie z imienia Muhammada, proroka islamu. Pierwotnie vokalów pośrednich w arabskim Muhammad został uzupełniony e w dostosowaniu do tureckiej fonotaktyki, która pisała Mehemmed, Mehemed i nazwa straciła centralną e z czasem.</p>", "Miljan": "<p>Miljan to męskie imię pochodzenia sławskiego południa. Do wybitnych osób z nazwiskiem należą: Miljan Goljović (ur. 1971), urodzony w Serbii emeryturę koszykarza słoneckiego Miljan Govedarica (ur. 1994), bosnianki piłkarz Miljan Miljanić (1930-2012), serbski trener piłki nożnej Miljan Mrdaković (ura. 1982), serbski piłkarze Miljan Pavković (urat. 1981), serbski koszykarz Miljana Radović (r. 1975), emeryturze piłki noży w Czarnogórze Miljan...</p>", "Malwin": "<b>Malwin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, stanowiące męski odpowiednik żeńskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Malwina\" target=\"_blank\" rel=\"noopener noreferrer\">Malwina</a>, pochodzenia literackiego.", "Maël": "<p>Mael (V wiek, Bretany lub Bretany, metropolia Francji - V wiek, Bardsi, Guinet) - święty odchodnik z Walii. Dzień Pamięci - 13 maja.</p>", "Minh Duc": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Malkolm": "<b>Malkolm</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_gaelicki_szkocki\" target=\"_blank\" rel=\"noopener noreferrer\">szkockiego</a>. Spolszczona forma imienia <i>Malcolm</i>. Wywodzi się od słów <i>Mael Coluim</i> oznaczających naśladujący świętego Kolomba lub podążający za nim. Nosiło je wielu królów <a href=\"https://pl.wikipedia.org/wiki/Szkocja\" target=\"_blank\" rel=\"noopener noreferrer\">Szkocji</a>, m.in. <a href=\"https://pl.wikipedia.org/wiki/Malcolm_III\" target=\"_blank\" rel=\"noopener noreferrer\">Malkolm III</a> uwieczniony w dramacie <a href=\"https://pl.wikipedia.org/wiki/William_Shakespeare\" target=\"_blank\" rel=\"noopener noreferrer\">Williama Shakespeare</a> <a href=\"https://pl.wikipedia.org/wiki/Makbet\" target=\"_blank\" rel=\"noopener noreferrer\">Makbet</a>.", "Morfeusz": "<b>Morfeusz</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> Μορφεύς, <i>Morpheus</i>, od <i>morphe</i> – <i>kształt</i>, <i>postać</i>, <i>forma</i>; <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Morpheus</em>) – w <a href=\"https://pl.wikipedia.org/wiki/Mitologia_grecka\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii greckiej</a> bóg i uosobienie marzeń sennych. Jego ojcem był <a href=\"https://pl.wikipedia.org/wiki/Hypnos_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Hypnos</a> Bóg snów, a stryjem <a href=\"https://pl.wikipedia.org/wiki/Tanatos_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Tanatos</a>, braćmi zaś <a href=\"https://pl.wikipedia.org/wiki/Fobetor\" target=\"_blank\" rel=\"noopener noreferrer\">Ikelos</a> oraz <a href=\"https://pl.wikipedia.org/wiki/Fantasos\" target=\"_blank\" rel=\"noopener noreferrer\">Fantasos</a>. Postać Morfeusza pojawia się w \"Metamorfozach\" Owidiusza, gdzie odgrywa kluczową rolę w historii <a href=\"https://pl.wikipedia.org/wiki/Alkione_(c%C3%B3rka_Eola)\" target=\"_blank\" rel=\"noopener noreferrer\">Alkione (córka Eola)</a> i Ceiksa. Miał zdolność przybierania wyglądu dowolnej ludzkiej formy i naśladowania typowych dla niej gestów i słów. Wyobrażano go sobie jako uskrzydloną postać o wielkich i szybkich skrzydłach, dzięki którym mógł się bezszelestnie przemieszczać na duże odległości.", "Miko": "<p>Węwice (巫女, Miko) to imię oznaczające \"trzymujący świątynię; święta pani\" służąca w templu Sześcian (świątyni Świątyni) w Japonii. Wcześniej Vu-Wem oznaczała \"wiastywa, męża, prorok\" i \"wiastwo proroków\".</p>", "Mati": "<p>Mati jest miastem w prowincji Davao Oriental, w Filipinach. To jest stolica prowincji.</p>", "Magdy": "<p>Majdy i Majdi lub Mejdi lub egipskie warianty Magdi lub Magdy (w arabskim مجدي) to arabskie męskie imię i nazwisko pochodzenia arabskiego. Do wybitnych osób z tym nazwiskiem należą:</p>", "Marouane": "<p>Marouane, Merouane lub ich odmiany to męskie imię i nazwisko pochodzenia arabskiego. Do wybitnych osób z tym nazwiskiem należą:</p>", "Marcjusz": "<b>Marcjusz</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskie</a>, powstałe od nazwy rodu <i>Marcii/Martii</i> (pol. Marcjusze), które pierwotnie stanowiło <a href=\"https://pl.wikipedia.org/wiki/Nazwisko_patronimiczne\" target=\"_blank\" rel=\"noopener noreferrer\">patronimik</a> od <a href=\"https://pl.wikipedia.org/wiki/Marek\" target=\"_blank\" rel=\"noopener noreferrer\">Marka</a>, oznaczając „syn Marka, przynależny do Marka”. Istnieje patron tego imienia, <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ty_Marcjusz\" target=\"_blank\" rel=\"noopener noreferrer\">św. Marcjusz</a>.", "Masahiro": "<b>Masahiro</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;まさひろ, マサヒロ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię japońskie</a>.", "Medhat": "<p>Medhat to męskie imię i nazwisko pochodzące z arabskiego. Do wybitnych osób z tym nazwiskiem należą:</p>", "Maxence": "<p>Maxence to francuska nazwa, pochodząca od łacińskiego Maxentius. Jako imię pierwsze, jest to głównie dane mężczyznom.</p>", "Min Bahadur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Min</b>.</p><p>Min to niejednoznaczny termin. min - w matematyce i językach programowania oznacza funkcję wyboru najmniejszego ze swoich argumentów, (Min (3, 6, 2) = 2).</p>", "Marcu": "<p>Marcu to rumuńska nazwisko i męskie nazwisko, które może odnosić się do: Dănuț Marcu Duiliu Marcu Gavorielle Marcu Valeriu Marcu Marcu Beza Mattias Marcu Petre Pandrea, urodzony Petre Ion Marcu</p>", "Mikhaylo": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mykhaylo</b>.</p><p>Mykhailo lub Mykhaylo to ukraińskie męskie imię, równoważne angielskim Michałowi. Wśród znanych osób z nazwiskiem są: Mykhaylo Berkos (1861-1919), rosyjski i ukraiński artysta pochodzenia greckiego Mykhayilo Bolotskykh (ur. 1960), ukraiński polityk i wojskowy, pułkownik generalny (Służba Obrony Cywilnej) Mykhayło Brodskyy (ur. 1959), ukraiński polityk, przywódca Partii Wolnych Demokratów i biznesmen Mykhayla Chemberzhi,...</p>", "Mansoor": "<p>Mansour (arabickie: منصور, Manṣūr); również pisane Mounsor, Monsur (Bengali), Mansoor, Manser, Mansur, Mansyur (indonezyjski) lub Mensur (tyrki), to męskie arabskie imię oznaczające \"Ten, który zwycięża\", z arabskiego korzenia naṣr (نصر), oznaczające \"wygrę\". Pierwszym znanym nosicielem nazwy był Mansur ibn Sarjun, bizantyjski gubernator Damaszku pod koniec lat 500 i na początku lat 600, który poddał miasto muzułmanom w 635 r. Inni ludzie nazywają się Mansur...</p>", "Makoto": "<b>Makoto</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;まこと, マコト) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a> noszone zarówno przez kobiety, jak i przez mężczyzn.", "Minh Khang": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Milosh": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Miłosz</b>.</p><b>Miłosz</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a> oznaczające „tego, który jest miłowany”, będące pierwotnie zdrobnieniem dwuczłonowych imion takich jak: <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82obor\" target=\"_blank\" rel=\"noopener noreferrer\">Miłobor</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82obrat\" target=\"_blank\" rel=\"noopener noreferrer\">Miłobrat</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82ogost_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miłogost</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82ogost_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miłgost</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82orad\" target=\"_blank\" rel=\"noopener noreferrer\">Miłorad</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82os%C5%82aw_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miłosław</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82os%C5%82aw_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miełosław</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82ostryj\" target=\"_blank\" rel=\"noopener noreferrer\">Miłostryj</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82owit\" target=\"_blank\" rel=\"noopener noreferrer\">Miłowit</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82owit\" target=\"_blank\" rel=\"noopener noreferrer\">Miłwit</a>. Forma Miłosz została zapisana już w <a href=\"https://pl.wikipedia.org/wiki/1136\" target=\"_blank\" rel=\"noopener noreferrer\">1136</a> roku w <a href=\"https://pl.wikipedia.org/wiki/Bulla_gnie%C5%BAnie%C5%84ska\" target=\"_blank\" rel=\"noopener noreferrer\">Bulli gnieźnieńskiej</a>.", "Misza": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Misha</b>.</p><p>Misha (rosyjski: Миша), znana również jako Mishka (rosycki: Мишка) lub Mishka Olimpijski (rosyński: Олимпийский Мишка), to nazwisko rosyjskiego niedźwiedzia z 1980 r. Stwór został zaprojektowany przez malarza ilustrującego dziecięce książki Victora Chizhikowa.</p>", "Marks": "<p>Obszar Marks (rosyjski: ? райо́н) jest okręgem samodzielnego zarządu (raion), w prowincji Saratov w Rosji.</p>", "Mariia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Madi": "<p>Madi to robak komputerowy, który atakuje komputery sterowane przez system operacyjny Microsoft Windows wersje XP, 7, Vista. Odkryto go przez firmę Seculert, wraz z firmą ⁇ Laboratorium Kasperskiego ⁇ .</p>", "Mustafo": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mustaf</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mustafa</b>.</p><b>Mustafa</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia arabskiego, oznacza „wybrany”.", "Morad": "<p>Murad lub Mourad (arabijski: مراد) to arabska nazwa. Jest również powszechne w językach armenijskim, azerbajdżanskim, bengalijskim, tureckim, perskim i berberskim jako męskie imię lub nazwisko i jest powszechnie stosowane w całym świecie muzułmańskim i na Bliskim Wschodzie.</p>", "Mikhal": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Michał</b>.</p><b>Michał</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִיכָאֵל&#8206; – Mîchā’ēl) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, wywodzące się od <a href=\"https://pl.wikipedia.org/wiki/Archanio%C5%82_Micha%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">jednego z archaniołów</a>. Po hebrajsku znaczy „któż [jest taki] jak Bóg”. Forma żeńska to <a href=\"https://pl.wikipedia.org/wiki/Michalina\" target=\"_blank\" rel=\"noopener noreferrer\">Michalina</a>.", "Moreno": "<p>Moreno to miasto w stanie Pernambuco w Brazylii. Miasto ma powierzchnię 192,14 km2, liczba ludności w 2007 roku wynosi 52780 osób, a jego gęstość 274,7 osób/km2.</p>", "Milos": "<p>Milos (Grzec. ?) jest samodzielnym terytorium w południowym Egeu, Grecja. Autonomiczna gmina Milos ma powierzchnię 160 km2, populacja według badania z 18 marca 2001 roku wynosi 4736 osób.</p>", "Mkhitar": "<p>Mkhitar lub Mekhitar lub Mechitar lub Latinized Mechitarius (armeńska: Մխիթար) to armenijska męska nazwisko. Zobacz Mխիթար dla więcej informacji na temat pochodzenia nazwy.</p>", "Mylan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Milan</b>.</p><b>Milan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię słowiańskie</a>. Jedno z licznych <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">zdrobnień od imion słowiańskich</a> zaczynających się na <i>Miło-</i>, takich jak <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82obor\" target=\"_blank\" rel=\"noopener noreferrer\">Miłobor</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82obrat\" target=\"_blank\" rel=\"noopener noreferrer\">Miłobrat</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82ogost_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miłogost</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82ogost_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miłgost</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82orad\" target=\"_blank\" rel=\"noopener noreferrer\">Miłorad</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82os%C5%82aw_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miłosław</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82os%C5%82aw_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miełosław</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82ostryj\" target=\"_blank\" rel=\"noopener noreferrer\">Miłostryj</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82owit\" target=\"_blank\" rel=\"noopener noreferrer\">Miłowit</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82owit\" target=\"_blank\" rel=\"noopener noreferrer\">Miłwit</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82osz\" target=\"_blank\" rel=\"noopener noreferrer\">Miłosz</a>. Obecnie imię Milan używane jest także samodzielnie.", "Md Abu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mehmet Ali": "<p>Mehmet Ali, Memet Ali lub Mehmed Ali () to tureckie imię dla mężczyzn. Mieszkańcy nazwiska to: Memet Ali Alabora (ur. 1977), turecki aktor Mehmet Ali Ağca (ur. 1958), turecki zabójca Mehmet Ali Aybar (1908-1995), turecki sprinter Mehmet Ali Birand (1941-2013), turecki dziennikarz Mehmet Ali Erbil (ur. 1957), turecki komiks Mehmet Ali İrtemçelik (ur. 1950), turecki polityk Mehmed Ali Gerede (ur. 1939), turecki politik...</p>", "Maverick": "<p>Maverick: AGM-65 Maverick - amerykańska rakieta taktyczna klasy ⁇ powietrze-powierzchnia ⁇ . Maverick (bronetransporter) - zbrojowiec produkcji RPA.</p>", "Mars": "<b>Mars</b> – czwarta od <a href=\"https://pl.wikipedia.org/wiki/S%C5%82o%C5%84ce\" target=\"_blank\" rel=\"noopener noreferrer\">Słońca</a> <a href=\"https://pl.wikipedia.org/wiki/Planeta\" target=\"_blank\" rel=\"noopener noreferrer\">planeta</a> <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_S%C5%82oneczny\" target=\"_blank\" rel=\"noopener noreferrer\">Układu Słonecznego</a>. Krąży między orbitą <a href=\"https://pl.wikipedia.org/wiki/Ziemia\" target=\"_blank\" rel=\"noopener noreferrer\">Ziemi</a> a <a href=\"https://pl.wikipedia.org/wiki/Pas_planetoid\" target=\"_blank\" rel=\"noopener noreferrer\">pasem planetoid</a> dzielącym go od orbity <a href=\"https://pl.wikipedia.org/wiki/Jowisz\" target=\"_blank\" rel=\"noopener noreferrer\">Jowisza</a>. Planeta została nazwana od imienia rzymskiego boga wojny – <a href=\"https://pl.wikipedia.org/wiki/Mars_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Marsa</a>, ze względu na <a href=\"https://pl.wikipedia.org/wiki/Barwa\" target=\"_blank\" rel=\"noopener noreferrer\">barwę</a>, która przy obserwacji z <a href=\"https://pl.wikipedia.org/wiki/Ziemia\" target=\"_blank\" rel=\"noopener noreferrer\">Ziemi</a> wydaje się rdzawo-czerwona i kojarzyła się starożytnym <a href=\"https://pl.wikipedia.org/wiki/Rzymianie\" target=\"_blank\" rel=\"noopener noreferrer\">Rzymianom</a> z pożogą wojenną. Odcień ten bierze się od <a href=\"https://pl.wikipedia.org/wiki/Tlenki_%C5%BCelaza\" target=\"_blank\" rel=\"noopener noreferrer\">tlenków żelaza</a> pokrywających powierzchnię. Mars jest <a href=\"https://pl.wikipedia.org/wiki/Planeta_wewn%C4%99trzna\" target=\"_blank\" rel=\"noopener noreferrer\">planetą wewnętrzną</a> z cienką <a href=\"https://pl.wikipedia.org/wiki/Atmosfera\" target=\"_blank\" rel=\"noopener noreferrer\">atmosferą</a>, o powierzchni usianej <a href=\"https://pl.wikipedia.org/wiki/Krater_uderzeniowy\" target=\"_blank\" rel=\"noopener noreferrer\">kraterami uderzeniowymi</a>, podobnie jak powierzchnia <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99%C5%BCyc\" target=\"_blank\" rel=\"noopener noreferrer\">Księżyca</a> i wielu innych ciał <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_S%C5%82oneczny\" target=\"_blank\" rel=\"noopener noreferrer\">Układu Słonecznego</a>. Powierzchnia wykazuje formy podobne do ziemskich: <a href=\"https://pl.wikipedia.org/wiki/Wulkan\" target=\"_blank\" rel=\"noopener noreferrer\">wulkany</a>, <a href=\"https://pl.wikipedia.org/wiki/Dolina\" target=\"_blank\" rel=\"noopener noreferrer\">doliny</a>, <a href=\"https://pl.wikipedia.org/wiki/Kanion\" target=\"_blank\" rel=\"noopener noreferrer\">kaniony</a>, <a href=\"https://pl.wikipedia.org/wiki/Pustynia\" target=\"_blank\" rel=\"noopener noreferrer\">pustynie</a> i polarne czapy lodowe. Okres obrotu wokół własnej osi jest niewiele dłuższy niż ziemski i wynosi 24,6229 godziny (24 h 37 m 22 s). Na Marsie znajduje się najwyższe <a href=\"https://pl.wikipedia.org/wiki/Wzniesienie\" target=\"_blank\" rel=\"noopener noreferrer\">wzniesienie</a> w Układzie Słonecznym – <a href=\"https://pl.wikipedia.org/wiki/Olympus_Mons\" target=\"_blank\" rel=\"noopener noreferrer\">Olympus Mons</a> i największy kanion – <a href=\"https://pl.wikipedia.org/wiki/Valles_Marineris\" target=\"_blank\" rel=\"noopener noreferrer\">Valles Marineris</a>. Gładki obszar równinny <a href=\"https://pl.wikipedia.org/wiki/Vastitas_Borealis\" target=\"_blank\" rel=\"noopener noreferrer\">Vastitas Borealis</a> na półkuli północnej, który obejmuje 40% powierzchni planety, może być pozostałością ogromnego uderzenia. W przeciwieństwie do <a href=\"https://pl.wikipedia.org/wiki/Ziemia\" target=\"_blank\" rel=\"noopener noreferrer\">Ziemi</a>, Mars jest mało aktywny <a href=\"https://pl.wikipedia.org/wiki/Geologia\" target=\"_blank\" rel=\"noopener noreferrer\">geologicznie</a> i nie zachodzą na nim zjawiska <a href=\"https://pl.wikipedia.org/wiki/Tektonika_p%C5%82yt\" target=\"_blank\" rel=\"noopener noreferrer\">tektoniczne</a>.", "Murtazi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Murtaz</b>.</p><p>Murtaz (georgijski: მურთაზ; rosyjski: Муртаз) to męskie imię. Wśród znanych osób z nazwiskiem są: Murtaz Daushvili (ur. 1989), gruziński piłkarz Murtaz Khurtsilava (ur. 1943), gruzijski obrońca piłki nożnej Murtaz Shelia (ur. 1969), gruzianski obrońca.</p>", "Mudassar": "<p>Mudassar, Mudassir, Modasser lub Mudasiru to męskie nazwiska i nazwiska pochodzące z arabskiego. Do wybitnych osób z tym nazwiskiem należą:</p>", "Mariyan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mariian</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Marian</b>.</p><b>Marian</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> od imienia <i>Marius</i> lub nazwy rodu <i>Marii</i>. Oznacza „należący do Mariusza, rodu Mariuszów”. Występuje w Polsce od 1332 roku, jako <b>Marzyjan</b>. Forma Marian pojawiła się w Polsce w XVI wieku. W języku angielskim używane jest jako imię żeńskie. W Polsce w żeńskim użyciu w 2025 roku wystąpiło 35 razy.", "Mohamed Ali": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohamed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Minh Tuan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Morales": "<p>Morales jest samorządem w prowincji Bolivar w Kolumbii. Głównym miastem Morales jest Morales.</p>", "Murodbek": "<p>Murat-bek lub Muhammad Murat-beck (z uzb. Murodbek; druga połowa XVIII wieku - 1842, Kądzieńskie khanstwo) - władca z rodu Katagan, założyciel Kądzieckich khanstw.</p>", "Mubarak": "<p>Muhammad Hosni Mubarak (arabski: محمد حسنى سيد مبارك), pełne nazwisko: Muhammad Hosni Sayyid Mubarak, zwykle znany jako Hosni Mubarek (4 maja 1928 - 25 lutego 2020), był prezydentem Egiptu od 6 października 1981 r. do 11 lutego 2011 r. Pod naciskem demonstracji społecznej, 11 lutego 2011 r. musiał odejść po 30 latach władzy (które prezydent przeprowadził w wyniku wojskowego zamachu), przekazać władzę wojskowi,...</p>", "Magdi": "<p>Majdy i Majdi lub Mejdi lub egipskie warianty Magdi lub Magdy (w arabskim مجدي) to arabskie męskie imię i nazwisko pochodzenia arabskiego. Do wybitnych osób z tym nazwiskiem należą:</p>", "Mile": "<p>Mile (brytyjski mil czasami jest skrócony jako mil, jednak należy również odróżnić go od starożytnej jednostki pomiaru stosowanej przez Wietnamatów, a przez Chiny również nazywanej mil) jest jednostką długości, często używaną do pomiaru odległości, w niektórych różnych systemach pomiarowych, w tym w systemie brytyjskim, amerykańskim i norwesko-szweckim milach. Długość każdego systemu różni się, ale ogólnie to ponad 1 km i mniej niż 3 km.</p>", "Mutlu": "<p>Mutlu (tur. Mutlu) - własne imię; rozpowszechnione w postaci nazwisk.</p>", "Maison": "<p>Mason (ang. Mason, Fr.</p>", "Mścigniew": "<b>Mścigniew</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie. Oznacza: ten, który mści, zwalcza swój gniew. Wspomniane w dokumentach z 1234 roku. Mścigniew <a href=\"https://pl.wikipedia.org/wiki/Imieniny\" target=\"_blank\" rel=\"noopener noreferrer\">imieniny</a> obchodzi <a href=\"https://pl.wikipedia.org/wiki/19_grudnia\" target=\"_blank\" rel=\"noopener noreferrer\">19 grudnia</a>.", "Matlab": "<p>MATLAB (skrócenie od angielskiego ⁇ Matrix Laboratory ⁇ , w języku rosyjskim wymawia się jako Matlab) - platforma do programowania i pakiet aplikacyjnych programów do rozwiązywania problemów obliczeń technicznych.</p>", "Makariy": "<p>Macarius jest łacińską formą starogrekskiego nazwiska Makarios (Μακάριος), co oznacza \"szczęśliwy, szczęśliwy, błogosławiony\"; porównaj latynskie beatus i felix. Starożytni Grecy stosowali do bogów epitety Makarios.</p>", "Miłowit": "<b>Miłowit</b>, <b>Miłwit</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Mił(o)-</i> (\"miły\") i <i>-wit</i> (\"pan, władca\"). Imię to mogło oznaczać np. \"miłujący władcę\" albo \"umiłowany przez władcę\".", "Menashe": "<p>Manasse lub Manasseh (; hebrajskie: מְנַשֶּׁה, Mənaše) jest biblijnym hebrajskim imieniem dla mężczyzn. Jest to imię siedmiu osób z Biblii, nazwisko plemienia Izraela i nazwisko jednego z apokryficznych pisma.</p>", "Matéo": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mate</b>.</p><b>Mate</b>, matero, calabaza (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hiszpa%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">hiszp.</a> „dynia/tykwa”) – naczynie do picia <a href=\"https://pl.wikipedia.org/wiki/Yerba_mate\" target=\"_blank\" rel=\"noopener noreferrer\">yerba mate</a>. Słowo „mate” pochodzi od słowa <i>mati</i> w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_keczua\" target=\"_blank\" rel=\"noopener noreferrer\">języka keczua</a>, oznaczającego naczynie lub pojemnik do picia; z czasem stało się nazwą naczyń do picia yerba mate. Naczynia wykonywane są z <a href=\"https://pl.wikipedia.org/wiki/Drewno_(technika)\" target=\"_blank\" rel=\"noopener noreferrer\">drewna</a> (np. <a href=\"https://pl.wikipedia.org/wiki/Gwajakowiec_lekarski\" target=\"_blank\" rel=\"noopener noreferrer\">gwajakowca lekarskiego</a>, <a href=\"https://pl.wikipedia.org/wiki/Bursera_graveolens\" target=\"_blank\" rel=\"noopener noreferrer\">bursera graveolens</a> zwanego <i>palo santo</i>, a także z <a href=\"https://pl.wikipedia.org/wiki/Algarrobo_(drewno)\" target=\"_blank\" rel=\"noopener noreferrer\">algarrobo</a>, palo de rosa, <a href=\"https://pl.wikipedia.org/wiki/Lapacho\" target=\"_blank\" rel=\"noopener noreferrer\">lapacho</a>, drewna cytrynowego), z <a href=\"https://pl.wikipedia.org/wiki/Owoc\" target=\"_blank\" rel=\"noopener noreferrer\">owoców</a> <a href=\"https://pl.wikipedia.org/wiki/Dzbaniwo_kalebasowe\" target=\"_blank\" rel=\"noopener noreferrer\">dzbaniwa kalebasowego</a> (zwanych kalebasami lub tykwami), z metali (<a href=\"https://pl.wikipedia.org/wiki/Stal\" target=\"_blank\" rel=\"noopener noreferrer\">stal</a>, <a href=\"https://pl.wikipedia.org/wiki/Srebro\" target=\"_blank\" rel=\"noopener noreferrer\">srebro</a>) i ceramiki. Naczynia z drewna i <a href=\"https://pl.wikipedia.org/wiki/Kalabasa\" target=\"_blank\" rel=\"noopener noreferrer\">kalebasy</a> zmieniają smak <a href=\"https://pl.wikipedia.org/wiki/Napar\" target=\"_blank\" rel=\"noopener noreferrer\">naparu</a>. Nowe naczynia z kalebasy wymagają przejścia przez proces zwany <i>curado</i> (przygotowania porcji naparu w naczyniu i odstawienia na 24 godziny) w celu usunięcia resztek miąższu.", "Mihaly": "<p>Mihály to węgierska męska nazwa. Jest krewnym angielskiego Michaela i może odnosić się do: Mihály András (1917-1993), węgierskiego wiolonczelnika, kompozytora i nauczyciela akademickiego Mihály Apafi (1632-1690), węgierski książę Transylwanii Mihály Babák (ur. 1947), węgarskiego polityka i członka Węgierskiego Zgromadzenia Narodowego Mihály Babits (1883-1941), węgarski poeta, pisarz i tłumacz Mihály Bakos (około 1590).</p>", "Mohanad": "<p>Mohannad (zwrócony również jako Mohanad, Mohanned, Mohaned, Muhannad lub Muhanned; arabski: مهند) to męskie arabskie imię. Mohannad lub jego odmiany mogą odnosić się do:</p>", "Mehmood": "<p>Mahmud jest transliteracją męskiego arabskiego nazwiska Mahmoud (Maḥmūd), powszechnego w większości części świata islamskiego. Pochodzi od arabskiego korzenia trójkononantalnego Ḥ-M-D, co oznacza chwałę, wraz z Mahometem.</p>", "Montgomery": "<p>Montgomery - powszechne angielskie imię, pochodzące od nazwy miejscowości w Normandii.</p>", "Maurício": "<p>Maurício to portugalski wariant Mauricio. Sportyści z nazwiskiem to: Maurício (piłkarz, urodzony w 2001 roku), paragwajski piłkarz Maurício Assoline, brazylijczy piłkarze Maurício Cardoso da Silva, brazylijski piłkerz Maurísio Copertino, brazyliiśki piłkarzek Maurício Fernandes, brazylianki piłker Maurício José da Silveira Júnior, brazyliana piłkarza Maurício Lima, brazylicki piłka siatkówka Maurício de Oliveira Anastácio,...</p>", "Md Masud": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mustapa": "<p>Mustapa jest zarówno malezyjską męską nazwą, jak i nazwą. Do wybitnych osób z tym nazwiskiem należą:</p>", "Mạnh Cường": "<p>Trần Mạnh Cường (ur. 4 września 1960 r.) w Hanoi, znany jako Mạnh Cương, jest znanym artystą w dzielnicy teatralnej, a także w wietnamskim kino, obecnie jest wice dyrektorem Centrum Pomocy Twórczości Literatury Artystycznej w Ministerstwie Kultury, Sportu i Turystyki. Został uhonorowany przez państwo Wietnamskie mianem Artysta Ludowego.</p>", "Mściwój": "<b>Mściwoj</b>, <b>Mszczujwoj</b> – <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów „mścić (się)” i „woj”, oznaczające prawdopodobnie tego, który \"mści swoich współtowarzyszy\". Jego pomorskim odpowiednikiem może być <a href=\"https://pl.wikipedia.org/wiki/Miestwin\" target=\"_blank\" rel=\"noopener noreferrer\">Miestwin</a>. Na temat <a href=\"https://pl.wikipedia.org/wiki/Etymologia\" target=\"_blank\" rel=\"noopener noreferrer\">etymologii</a> patrz również wyjaśnienia pod hasłem <a href=\"https://pl.wikipedia.org/wiki/M%C5%9Bciwoj_I_gda%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">Mściwoj I</a>.", "Marion": "<p>Marion, Marion - to imię własnego pochodzenia francuskiego. Rozprzestrzenione w USA, Kanadzie, Wielkiej Brytanii, Francji, Niemczech.</p>", "Maroš": "<p>Maroš jest męskie imię, które jest nowoczesnym słowackim nadniskom pochodzącym od Mareka i Mariana. Wymawia się mah-row:sh.</p>", "Md Saiful": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Marco Antonio": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marco</b>.</p><b>Marek</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, należące do wąskiej grupy najstarszych <a href=\"https://pl.wikipedia.org/wiki/Imiona_%C5%82aci%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imion rzymskich</a> (imion właściwych, <i>praenomen</i>, por. <a href=\"https://pl.wikipedia.org/wiki/Tyberiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Tyberiusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Aulus\" target=\"_blank\" rel=\"noopener noreferrer\">Aulus</a>, <a href=\"https://pl.wikipedia.org/wiki/Maniusz\" target=\"_blank\" rel=\"noopener noreferrer\">Maniusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Gajusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Gajusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Lucjusz\" target=\"_blank\" rel=\"noopener noreferrer\">Lucjusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Publiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Publiusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Tytus\" target=\"_blank\" rel=\"noopener noreferrer\">Tytus</a>, <a href=\"https://pl.wikipedia.org/wiki/Serwiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Serwiusz</a>), utworzone z <i>*Mart-ico-s</i> od imienia boga <i><a href=\"https://pl.wikipedia.org/wiki/Mars_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Mars</a></i>, <i>Martis</i> i oznaczające „należący do Marsa, związany z Marsem”. W Polsce imię to jest notowane od <a href=\"https://pl.wikipedia.org/wiki/XIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIII wieku</a>, choć poza współczesnością nie było często spotykane, w formach <i><b>Marek</b></i>, <i><b>Marko</b></i>, <i><b>Margusz</b></i>, <i><b>Markusz</b></i>, <i><b>Merkusz</b></i>. Zapisana została także żeńska <b>Marka</b> (<a href=\"https://pl.wikipedia.org/wiki/1263\" target=\"_blank\" rel=\"noopener noreferrer\">1263</a>) – żeński odpowiednik imienia Marek lub zdrobnienie od imion żeńskich rozpoczynających się na Mar-, takich jak <i>Margorzata</i> (= <a href=\"https://pl.wikipedia.org/wiki/Ma%C5%82gorzata_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Małgorzata</a>) lub <a href=\"https://pl.wikipedia.org/wiki/Maria\" target=\"_blank\" rel=\"noopener noreferrer\">Maria</a> – oraz <a href=\"https://pl.wikipedia.org/wiki/Markus%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Markusław</a>, staropolskie imię utworzone od imienia Marek poprzez dodanie typowej dla imion słowiańskich cząstki -sław. Imię to według danych 2022 r. jest na 10 miejscu najpopularniejszych imion męskich.", "Meyer": "<p>Friedrich Albrecht Anton Meyer (niem. Friedrich Albrext Anton Meyer) - niemiecki naturalista.</p>", "Mael": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maëla</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maël</b>.</p><p>Mael (V wiek, Bretany lub Bretany, metropolia Francji - V wiek, Bardsi, Guinet) - święty odchodnik z Walii. Dzień Pamięci - 13 maja.</p>", "Matyáš": "<p>Matvej (Mattias; nim. Matthias, węg.</p>", "Morteza": "<p>Murtaza (afgańska perskia: مُرتَضٰ Murtazâ) lub Morteza (iranska: مُرْتِضیٰ Mortezâ) to perskie imię męskie, ostatecznie pochodzące z arabskiej Murtada (مُرْطَضَى Murtaḍā). Wymowa różni się w zależności od akcentu, od rodzimych arabskich do języków europejskich i azjatyckich.</p>", "Mujtaba": "<p>Mojtaba lub Mujtaba (perskiego: مجتبی; arabski: اَلْـمُـجْـتَـبَى, romanized: al-Mujtabā) to irańskie imię męskie. Pochodzi z języka arabskiego, co oznacza wybranych.</p>", "Md Omar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mushegh": "<p>Mushegh, Moushegh lub Mušeł (w języku armenijskim Մուշեղ) jest armenijską męską nazwą. Do wybitnych osób z nazwą należą: Moushegh Ishkhan (1914-1990), armenijski Diasporan poet, pisarz i edukacja Mushegh Mamikonian (zmówianie), kilka szlachetnych Mamikonian rodziny Mushegh Sarvarian, znany również jako Mushegh Soruri (1910-1981), irański reżyser filmowy</p>", "Mithun": "<p>Błoka hodowlana (w języku francuskim: Bos frontalis), znana również jako Mithun i zwana po angielsku Gayal, jest gatunkiem z Błoka Błoka, wprowadzonym do handlu, rozmieszczonym w północno-wschodniej Indie, Bangladeszie, północnej Birmie i południowochińskim regionie Chin. To krowy, ale wolno się poruszają, obecnie tylko w północno-wschodniej Indie.</p>", "Moataz": "<p>Mutaz lub Mu'taz lub Motaz lub Moataz (arabski: معتز) to męskie imię i nazwisko pochodzenia arabskiego. Do wybitnych osób z tym nazwiskiem należą:</p>", "Mohamed Amine": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohamed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Muhamet": "<p>Muhamet (albanie: [muhˈmet]) jest albańską formą arabskiego imienia Muhammad oznacza \"praisewothy\".</p>", "Mylo": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Milo</b>.</p><p>Milo - marka handlowa, pod którą firma Nestlé od 1934 roku produkuje firma napoju z słodkiem MILO - amerykański czasopism o sportach</p>", "Mahi̇r": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mahira</b>.</p><p>Mahira jest miastem censusem Barddhaman w stanie Bengal Zachód, India.</p>", "Matyas": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Matias</b>.</p><p>Matías to portugalska wersja Matthias. Matías jest bardzo popularny w Ameryce Łacińskiej, zwłaszcza w Argentynie.</p>", "Manolo": "<p>Manuel Martinez Hugué (w katalonskim wymowie - Uge), bardziej znany jako Manolo (hisz. Manuel MartinezHugué; 29 kwietnia 1872 r. - 17 listopada 1945 r.) - katalonski rzeźbiarz, przedstawiciel ruchu nowencentu.</p>", "Md Al": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Abdur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Minh Anh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Mickey": "<p>Mickey (ang. Mickey) - angielskie imię męskie.</p>", "Mehul": "<p>Mehul (hindi: मेहुल) to indyjska męska nazwisko pochodzenia sanskrytu, co oznacza deszcz lub chmurę. Wśród znanych osób z tym nazwiskiem są: Mehul Choksi (ur. 1964/65), indyjski biznesmen Mehul Kumar (ur.</p>", "Mohammadreza": "<p>Mohammad-Reza (persk. محمدرضا, również pisane jako Mohammad Reza lub Mohammadreza) to popularne imię w Iranie. Mohammad i Reza to arabskie nazwiska, które są popularne na całym świecie muzułmańskim.</p>", "Mayer": "<p>Mayer może być: Maria Goeppert-Mayer Nathan Mayer Rothschild John Mayer Mayer Amschel Rothschild Metro-Goldwyn-Mayer</p>", "Michell": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Michelle</b>.</p><p>⁇ Michelle ⁇ (z angielskiego - ⁇ Mishel ⁇) - miłosna balada angielskiego zespołu rockowego The Beatles, napisana przez Paula McCartney'ego (pisanego przez J.</p>", "Maricel": "<p>Maricel to męskie lub kobiece imię. Według \"Miano znaczenia\" jego biblijna definicja oznacza \"Ten, który podnosi\" w języku hebrajskim.</p>", "Møller": "<p>Hans Peter Christian Møller (danowski, 10 listopada 1810 - 18 października 1845 r., Rzym) - duński badacz łupek i królewski inspektor w północnej Grenlandii w latach 1943 - 1945.</p>", "Malick": "<p>Malik, Maleek, Malek lub Malyk (arabski: مَالِك or مَلِك) (urdu &amp; (perskiego): مالک) () jest nazwą pochodzenia semityckiego Azji Zachodniej. Jest używany zarówno jako imię i nazwisko pierwotnie głównie w Azji Zachodniej przez chrześcijan, muzułmanów i Żydów z różnych etnicznych grup, takich jak Asyryjczycy, Żydzi, Aramejczycy , Mandejczycy i Arabowie, zanim rozprzestrzenił się do nie-semityckiej mówiących krajów na Kaukazie, Azji Południowej, Azji Środkowej, Afryki Północnej i ...</p>", "Masood": "<p>Masoud (arabski: مسعود, lit. 'szczęście, szczęśliwy, dobrodziejny, szczęśliwy') jest męskie imię i nazwisko pochodzące z arabskiego.</p>", "Miki": "<b>Miki</b>, <b>łyszczyki</b> – grupa <a href=\"https://pl.wikipedia.org/wiki/Minera%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">minerałów</a> zaliczana do gromady <a href=\"https://pl.wikipedia.org/wiki/Krzemiany\" target=\"_blank\" rel=\"noopener noreferrer\">krzemianów</a>. Nazwa „mika” pochodzi od <a href=\"https://pl.wikipedia.org/wiki/%C5%81ac.\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <i>mica</i> (ziarno) lub <i>micare</i> (błyszczeć).", "Md Sohel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Minh Quan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Md Habibur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mahbubur": "<p>Mahbubur to arabskie imię, które oznacza umiłowany. Nazwa ta jest bardzo powszechna w krajach muzułmańskich w Azji Południowej (np.</p>", "Manolis": "<p>Manolis (grecki: Μανώλης, Μανόλης) to greckie imię męskie, które czasami jest skróceniem Emmanouil. Może odnosić się do: Manolis Anagnostakis (1925-2005), greckiego poeta i krytyka Manolis Andronikos (1919-1992), greckiego archeologa Manolis Angelopoulos (1939-1989), greckiego piosenkarza Manolis Chiotis (1920-1970), greckego kompozytora, piosenkarka i muzyka Manolis Glezos (1922-2020), greckiej polityk i pisarza Manolis Kalomiris (1883-1962), greck...</p>", "Mohand": "<p>Mohannad (zwrócony również jako Mohanad, Mohanned, Mohaned, Muhannad lub Muhanned; arabski: مهند) to męskie arabskie imię. Mohannad lub jego odmiany mogą odnosić się do:</p>", "Martiros": "<p>Martiros to armenijska nazwa, oznaczająca męczennik. Martiros i jego wariant Mardiros w języku zachodnim Armenii mogą odnosić się do:</p>", "Md Imran": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mingyu": "<p>Kim Min-gyu (Korea: 김민규; ur. 6 kwietnia 1997), znany pod pseudonimem Mingyu (민규), jest koreańskim piosenkarzem i raperem z Pledis Entertainment, członkiem grupy Seventeen oraz Hip-hop Team.</p>", "Millan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Milan</b>.</p><b>Milan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię słowiańskie</a>. Jedno z licznych <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">zdrobnień od imion słowiańskich</a> zaczynających się na <i>Miło-</i>, takich jak <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82obor\" target=\"_blank\" rel=\"noopener noreferrer\">Miłobor</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82obrat\" target=\"_blank\" rel=\"noopener noreferrer\">Miłobrat</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82ogost_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miłogost</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82ogost_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miłgost</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82orad\" target=\"_blank\" rel=\"noopener noreferrer\">Miłorad</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82os%C5%82aw_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miłosław</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82os%C5%82aw_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miełosław</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82ostryj\" target=\"_blank\" rel=\"noopener noreferrer\">Miłostryj</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82owit\" target=\"_blank\" rel=\"noopener noreferrer\">Miłowit</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82owit\" target=\"_blank\" rel=\"noopener noreferrer\">Miłwit</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82osz\" target=\"_blank\" rel=\"noopener noreferrer\">Miłosz</a>. Obecnie imię Milan używane jest także samodzielnie.", "Manswet": "<b>Manswet</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzące od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> przymiotnika <i>mansuetus</i> (łagodny, miły).", "Md Mehedi": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mikaël": "<p>Michael jest męskim imieniem, wariantem hebrajskiej nazwy Michał (מִיכָאֵל), co oznacza \"Kto jest jak Bóg\". Jest stosowany głównie w Skandynawii i Finlandii.</p>", "Mai": "<b>Mai</b> – imię dwupłciowe używane w wielu państwach świata.", "Magno": "<p>Magn (italicki Magno; 530) - święty, archbiskup miłanów od 518 do 530 roku (około).</p>", "Mikey": "<p>Mikey to męskie imię, często diminutiwna forma Michaela. Może również odnosić się do:</p>", "Moustapha": "<p>Mustafa (arabski: مصطفى, romanized: Muṣṭafā) jest jednym z imion islamskiego proroka Mahometa. W arabskim oznacza \"wybrany, wybrany, wyznaczony, preferujący\".</p>", "Md Nazmul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Miguel Antonio": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Miguel</b>.</p><p>Miguel (hisz. Miguel) - hiszpański odpowiednik imienia Michaila.</p>", "Mathews": "<p>Gregory Macalister Mathews (ang. Gregory Macalisters Mathews; 10 września 1876, Merrigoen, Nowy Południowy Wales - 27 marca 1949, Wincester) - australijski ornitholog-amator.</p>", "Mateush": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mateusz</b>.</p><b>Mateusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>, wywodzące się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מַתִּתְיָהוּ&#8206;, imienia <i>Matanjah</i>, <i>Matisyahu</i> oznaczającego „dar Boga”, „dar <a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a>”. W dawnych źródłach polskich występowało jako: <i>Mathaeus</i>, <i>Matyjasz</i>, <i>Matitiasz</i>, <i>Matyja</i>, <i>Matys(z)</i>, <i>Matoz</i>, <i>Matusz</i>. Do XVI wieku imiona <a href=\"https://pl.wikipedia.org/wiki/Maciej\" target=\"_blank\" rel=\"noopener noreferrer\">Maciej</a> i Mateusz nie były w języku polskim rozróżniane.", "Munna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Muna</b>.</p><p>Muna jest miastem w stanie Yucatán w Meksyku. W 2005 roku liczba mieszkańców miasta wynosiła 11763.</p>", "Md Rakib": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Shahadat": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Martinez": "<p>Martinez lub Martínez może odnosić się do: Omar Martinez San Juan y Martínez Conchita Martínez Melanie Martinez</p>", "Mohamed Ahmed": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohamed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Maarif": "<p>Maarif jest miastem w prowincji Msila w Algierii. W 2002 roku liczba ludności wynosiła 10,99.</p>", "Masato": "<b>Masato</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;まさと, マサト) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Manish Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Manish</b>.</p><p>Manish (także Maneesh) (Devanagari: मनिष lub मनीष) jest powszechną indyjską nazwą męską, która dosłownie oznacza \"Bóg umysłu\" lub ten, który kontrolował i opanował swój umysł (reprezentuje intelektualistę, geniusz itp.), pochodząca z sanskrytów \"man\" (mann), co oznacza umysł i \"ish\", co odnosi się do Boga lub mistrza. Wielu hinduskich chłopców ma takie imię.</p>", "Márkó": "<p>Márkó jest miastem w hrabstwie Veszprém w Węgrzech. Miasto ma powierzchnię 34,41 km2, liczba ludności w 2010 roku wynosi 1152 mieszkańców, a jego gęstość wynosi 33 mieszkańców/km2.</p>", "Manjula": "<p>Manjula (sanskrit: मंजुला) to hinduska i sanskrycka nazwisko dla kobiet, co oznacza \"melodyjne\".</p>", "Mervan": "<p>Marwan, Merwan lub Marwen lub Mervan (arabski: مروان, romanized: Marwān) jest arabskim męskim imieniem pochodzącym od słowa maruww (مرو) z znaczeniem minerałów, 'flint (-kamień) ', 'kwartz' lub 'twardy kamień prawie czystej krzemiony'. Jednak arabska nazwa kwarcu jest ṣawwān (صَوَّان).</p>", "Martinov": "<p>Ivan Iwanovich Martynov (1771[...], Przewołowoczna, Poltawski polk - 20 października [1 listopada] 1833 lub 1 listopada 1833, Sankt-Petersburg) - rosyjski filolog i botanik, tłumacz, pedagog. Członek Rosyjskiej Akademii (1807).</p>", "Md Rasel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Muneer": "<p>Muneer (zwany również Moneer, Monir, Mounir lub Muneyr, w arabski: منير, oznaczające oświetlające, jasne, jasne i jasne) jest męskie arabskie imię, może odnosić się do:</p>", "Mścibor": "<b>Mścibor</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z dwóch członów: <i>Mści-</i> („mścić”) i <i>-bor</i> („walczyć, zmagać się”). Mogło oznaczać „tego, który mści się bojem”.", "Marcellus": "<p>Marcellus (lat. Marcellus) - łacińska nazwa, niektórzy znani działacze religijni: Marcel I (? - 309) - biskup rzymski od 27 maja 308 do 16 stycznia 309 r.</p>", "Matey": "<p>Matey może odnosić się do: Matey Kaziyski (ur. 1984), bułgarski gracz siatkówki Matey Mateev (1940-2010), bułgarski fizyk teoretyczny Matey Preobrazhenski (1828-1875), nazwisko księża Mono Petrov Seizmonov, bułgarskiego kapłana prawosławnego i rewolucjonisty Yumsem Matey, indyjski polityk wybrany w 2009 roku Malcolm \"Matey\" McDuck, postać Disneya, który jest przodkiem Scrooge'a McDuck'a i Donald Duck'a</p>", "Md Ismail": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Jahidul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Rubel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mischa": "<p>Mischa to drobna forma imienia Michaił.</p>", "Md Alamgir": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mena": "<p>Menes (? - ~ 3100 r. p.n.e.; starożytny egipski mnj, prawdopodobnie wymawiający się */maˈnij/; starożytna grecka: Μήνης) był faraonem z okresu Szaura starożytnego Egiptu i według starożytnej legendy był uważany za zjednoczycie Egiptu Górnego i Dolnego oraz założyciela I Królestwa.</p>", "Michelle": "<p>⁇ Michelle ⁇ (z angielskiego - ⁇ Mishel ⁇) - miłosna balada angielskiego zespołu rockowego The Beatles, napisana przez Paula McCartney'ego (pisanego przez J.</p>", "Momčilo": "<p>Momcilo lub Momčilo (cyrylicki: Момчило) to męskie imię pochodzenia sławskiego południa. Często występuje w Serbii i Czarnogórii.</p>", "Mehrdad": "<p>Mehrdad (persk: مهرداد) jest powszechną perską nazwą męską w Iranie (Percja) i innych krajach języków perskiego. Mehrdad to perskie imię dla chłopców, które oznacza \"oddawane przez słońce\" lub \"oddaane przez miłość\".</p>", "Marc-Antoine": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marc</b>.</p><p>Marc: MARC (ang. Machine-Readable Cataloging) - grupa formatów (MARC21, UNIMARC, RUSMAC itp.</p>", "Manuele": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Manuel</b>.</p><b>Emanuel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od słowa עִמָּנוּאֵל oznaczającego „Bóg z nami”. Imię mesjasza oraz kilku świętych katolickich. Żeński odpowiednik to <a href=\"https://pl.wikipedia.org/wiki/Emanuela\" target=\"_blank\" rel=\"noopener noreferrer\">Emanuela</a>.", "Maksimus": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maximus</b>.</p><p>Maximus: Maximus (BBS) - program komputerowy BBS Maximus (Maximus) - główny bohater filmu ⁇ Gladiator ⁇</p>", "Milon": "<p>Milon (lat. Milon, fr.</p>", "Mogens": "<p>Mogens to duńskie męskie imię (szczególnie duńskie zamieszczenie Magnus), i może odnosić się do: Mogens Ballin, duński artysta, jednego z grupy malarzy, którzy zebrali się w bretonskiej wiosce Pont-Aven Mogens Berg (ur. 1944), duński był piłkarz Jens Mogens Boyesen (1920-1996), norweski dyplomat i polityk dla Partii Pracy Mogens Brandt (1909-1970), duński aktor filmowy Mogens Camre (1936-2016), duński polityk i...</p>", "Murthy": "<p>Murthy, Murthi, Murty, Murti lub Moorthy, lub podobne warianty, to nazwa z południowoindyjskich stanów Andhra Pradesh, Karnataka, Tamil Nadu i Telangana. Jest to powszechne wśród brahmów jako imię lub nazwisko.</p>", "Minh Hieu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Mesrop": "<p>Mesrob lub Mesrop (armejski: Մեսրոպ) to armenijska nazwa. Mesrob / Mesrop może odnosić się do: Mesrop Mashtots, również Święty Mesrop, armenijski mnich, teolog i lingwist.</p>", "Maryn": "<b>Maryn</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzące od przymiotnika <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>marinus</em> („morski”). Wersją oboczną jest <a href=\"https://pl.wikipedia.org/wiki/Maryniusz\" target=\"_blank\" rel=\"noopener noreferrer\">Maryniusz</a>. Wśród patronów tego imienia św.&#160;<a href=\"https://pl.wikipedia.org/wiki/Maryn_z_San_Marino\" target=\"_blank\" rel=\"noopener noreferrer\">Maryn</a>, od imienia którego pochodzi nazwa państwa <a href=\"https://pl.wikipedia.org/wiki/San_Marino\" target=\"_blank\" rel=\"noopener noreferrer\">San Marino</a>.", "Man Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Man</b>.</p><p>man (od angielskiego manual - wytyczne) - polecenie Unix przeznaczone do formatowania i wyciągania stron odniesienia.</p>", "Madox": "<p>Madox to imię i nazwisko. Do wybitnych osób z tym nazwiskiem należą:</p>", "Manuel Alejandro": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Manuel</b>.</p><b>Emanuel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od słowa עִמָּנוּאֵל oznaczającego „Bóg z nami”. Imię mesjasza oraz kilku świętych katolickich. Żeński odpowiednik to <a href=\"https://pl.wikipedia.org/wiki/Emanuela\" target=\"_blank\" rel=\"noopener noreferrer\">Emanuela</a>.", "Md Nasir": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Myhaylo": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mihailo</b>.</p><p>Mihailo (Serbski cyrylski: Михаило) (\"\\mi-hail\\o\") jest sławskim nazwa męska. Jest to wariant hebrajskiej nazwy Michał, a jego krewni włączają Mihajlo i Mijailo.</p>", "Md Kamrul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Movses": "<p>Movses (armejski: Մովսես) jest ormińskie imię, równoważne Mojżeszowi. To dało początek nazwie Movsesian.</p>", "Mackenzie": "<p>Mackenzie, rzadko Mackenzie (ang. Mackenzie, MacKenzie, McKenzie) - szkocka nazwisko, od niej pochodzące osobiste imię (częściej kobiece) i toponim: Klan Mackenzie</p>", "Milutin": "<p>Milutin (serski: Милутин) to serbskie męskie imię pochodzenia słowiańskiego. Nazwa może odnosić się do: Stephen Uroš II Milutin z Serbii (1253-1321), król Serbii Milutin Bojić (1892-1917), poeta Milutin Ivković (1906-1943), piłkarz Milutin Milanković (1879-1958), serbski naukowiec Milutin Mrkonjić (1942-2021), polityk Milutin Šoškić (ur. 1937-2022), były serbski bramkarz</p>", "Misak": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Misaki</b>.</p><b>Misaki</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;みさき, ミサキ) – popularne żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>, jest także używane jako nazwisko, bardzo rzadko używane jako imię męskie.", "Md Abul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Maksymin": "<b>Maksymin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81ac.\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wśród patronów – św. Maksymin (†<a href=\"https://pl.wikipedia.org/wiki/IV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">IV wiek</a>).", "Md Ariful": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Miracle": "<p>Miracle (ruck. Cudo) - album studiowy kanadyjskiej piosenkarki Celine Dion z udziałem światowej sławy fotografa Anny Geddes.</p>", "Monty": "<p>Monty to męskie imię, często skrótowa forma Montgomery, Montague i innych podobnych nazw. To też nazwisko.</p>", "Metodi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Metody</b>.</p><b>Metody</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa <i>methodos</i> – „kroczący właściwą drogą”.", "Maria Józef": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mitra": "<p>Mitra (lat. Mitra) - rodzaj morskich brzuchowoogich łupek z rodziny mitrydów (Mitridae). Średnie i duże drapieżne żołądkowo-żołądkie.</p>", "Mario Alberto": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mario</b>.</p><p>Mario (jap. Mario Mario, angielski.</p>", "Muhammad Ali": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammad</b>.</p><b>Muhammad</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;مُحَمَّد&#8206;) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wariantami tego imienia są: Mohammed, Mehmed, Mamadu i Mahomet.", "Miltiadis": "<p>Miltiades lub Miltiadis (grecki: Μιλτιάδης, krótki: Miltos) to greckie imię męskie. Nazwa pochodzi od greckiego słowa oznaczającego \"czerwony ziemie\".</p>", "Mazin": "<p>Mazin - rosyjska nazwisko; kobieca forma Mazin.</p>", "Mordekhay": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mordechay</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mordechai</b>.</p><p>Mordechai to trzeci album studiowego amerykańskiego trójki Khruangbin z Houston (stan Texas), wydany 26 czerwca 2020 roku na wytwórniach Dead Oceans i Night Time Stories.</p>", "Mikoła": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mykola</b>.</p><p>Mykola jest ukraińską wariantą męskiego nazwiska \"Nicholas\", co oznacza \"wygrę narodu\". Może odnosić się do:</p>", "Minh Tuấn": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Murphy": "<p>Murphy, lub Murphy (ang. Murphy; ['mɜ:fɪ]), - nazwisko pochodzenia irlandzkiego, angielowana wersja irlandzkiego nazwiska Ó Murchadha (⁇ przodek Murchadh ⁇ , potomek żołnierza morskiego) i Mac Murchaidh (⁇ syn Murchadh ⁇ , syn żołnierz marynarza).</p>", "Minh Khoi": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Muneeb": "<p>Munib (zwany również Moneeb, Muneeb lub Münip, arabski: منيب) jest arabskim męskim imieniem. Do wybitnych osób z tym nazwiskiem należą:</p>", "Mardan": "<p>Mardan to miasto w Khyber Pakhtunkhwa w Pakistanie. Miasto miało ludności szacunkową w 2010 roku.</p>", "Michaylo": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mikhaylo</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mykhaylo</b>.</p><p>Mykhailo lub Mykhaylo to ukraińskie męskie imię, równoważne angielskim Michałowi. Wśród znanych osób z nazwiskiem są: Mykhaylo Berkos (1861-1919), rosyjski i ukraiński artysta pochodzenia greckiego Mykhayilo Bolotskykh (ur. 1960), ukraiński polityk i wojskowy, pułkownik generalny (Służba Obrony Cywilnej) Mykhayło Brodskyy (ur. 1959), ukraiński polityk, przywódca Partii Wolnych Demokratów i biznesmen Mykhayla Chemberzhi,...</p>", "Md Rabiul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mail": "<p>Mail (⁇ poczta ⁇): Electronic mail (poczta elektroniczna) - technologia i świadczone przez nią usługi wysyłania i otrzymywania wiadomości elektronicznych (⁇ pisma ⁇) w rozproszonym (w tym globalnym) sieci komputerowej. mail (programowanie) - klient pocztowy dla systemów operacyjnych podobnych do Unix, który działa w trybie konsolnym.</p>", "Melwin": "<p>Melwin to męskie imię. Znanymi osobami z nazwiska są: Melwin Beckman (ur. 2000), polski piłkarz handbalowy Melwin Cedeño (ur. 1964), portorykański aktor, tancerz i komik Melwin Lycke Holm (ur. 2004), szwedzki wysoki skakacz</p>", "Mwangi": "<p>Mwangi - własna nazwa; rozpowszechniona w postaci nazwisk.</p>", "Markku": "<p>Markku to imię. Wśród znanych osób z tej nazwy są: Markku Alén (ur. 1951), Finlandii, Markku Aro (ur. 1950), Finlanda, piosenkarz, który wystąpił na konkursie Eurovision w 1971 roku, Markku Huhtamo (ur. 1946), Finlandi, aktor Markku Into (1945-2018), legenda poezji finskiej, członek finskiego 1960 roku underground ruchu Turku Markku Kanerva (ur. 1964), finski menedżer piłki nożnej i były gracz Markku Kivinen...</p>", "Mahamad": "<p>Maamad (lat. Mahamad; מעמד) - termin pochodzenia żydowskiego.</p>", "Md Nur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Miranda": "<b>Miranda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa <i>miranda</i> oznaczającego \"godna podziwu\". Imię zostało pierwszy raz użyte przez <a href=\"https://pl.wikipedia.org/wiki/William_Szekspir\" target=\"_blank\" rel=\"noopener noreferrer\">Williama Shakespeare'a</a> w dramacie <i><a href=\"https://pl.wikipedia.org/wiki/Burza_(sztuka)\" target=\"_blank\" rel=\"noopener noreferrer\">Burza</a></i>.", "Mariian": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Marian</b>.</p><b>Marian</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> od imienia <i>Marius</i> lub nazwy rodu <i>Marii</i>. Oznacza „należący do Mariusza, rodu Mariuszów”. Występuje w Polsce od 1332 roku, jako <b>Marzyjan</b>. Forma Marian pojawiła się w Polsce w XVI wieku. W języku angielskim używane jest jako imię żeńskie. W Polsce w żeńskim użyciu w 2025 roku wystąpiło 35 razy.", "Marad": "<p>Marad (Sumer: Marda, obecnie Tell Wannat es-Sadum lub Tell as-Sadoum, Irak) było starożytnym Sumerskim miastem. Marad znajduje się na zachodnim brzegu, zachodnim odcinkiem nadwyżej Eufrat w zachodnim Nippurze w dzisiejszym Iraku i około 50 km na południowo-wschodni od Kiša, na Arahtu.</p>", "Mumtaz": "<p>Mumtaz (arabski: ممتاز) oznacza \"wystarczający\" w języku arabskim. Może być używana do sygnału pochwały za osiągnięcie, podobnego w znaczeniu do bravo i kudos.</p>", "Murtaza": "<p>Murtaza (afgańska perskia: مُرتَضٰ Murtazâ) lub Morteza (iranska: مُرْتِضیٰ Mortezâ) to perskie imię męskie, ostatecznie pochodzące z arabskiej Murtada (مُرْطَضَى Murtaḍā). Wymowa różni się w zależności od akcentu, od rodzimych arabskich do języków europejskich i azjatyckich.</p>", "Menderes": "<p>Menderes jest dzielnicą w Turcji. Ogromnie obszarzyła 775 km2 i liczba ludności w 2007 roku wynosiła 64065 osób, zwiększając gęstość 83 osób/km2.</p>", "Mojmir": "<b>Mojmir</b> – starosłowiańskie (w tym staropolskie) <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Moj-</i> (\"mój\") i <i>-mir</i> (\"pokój, spokój, dobro\"). Prawdopodobnie oznaczało \"moje dobro\", \"mój skarb\".", "Minh Ðức": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Mierosław": "<b>Mirosław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie imię</a> męskie. Imię <i>Mirosław</i> jest przykładem <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staropolski\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskiego</a>, złożonego, osobowego imienia dwuczłonowego, które jest <a href=\"https://pl.wikipedia.org/wiki/Relikt\" target=\"_blank\" rel=\"noopener noreferrer\">reliktem</a> <a href=\"https://pl.wikipedia.org/wiki/Poganie\" target=\"_blank\" rel=\"noopener noreferrer\">pogańskich</a> imion używanych we wczesnym średniowieczu przez <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie\" target=\"_blank\" rel=\"noopener noreferrer\">Słowian</a>. Składa się z członów <i>Miro-</i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pras%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">ps.</a> <i>*mirъ</i> „pokój”, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staropolski\" target=\"_blank\" rel=\"noopener noreferrer\">stpol.</a> <i>mir</i>, <i>mier</i> - „pokój, bezpieczeństwo, przyjaźń”) oraz <i>-sław</i> („sława”). Mogło oznaczać „ten, który sławi pokój” albo „ten, który zdobywa sławę poprzez zaprowadzenie porządku, pokoju”. <a href=\"https://pl.wikipedia.org/wiki/Witold_Taszycki\" target=\"_blank\" rel=\"noopener noreferrer\">Witold Taszycki</a> zaliczył je do grupy najstarszych polskich imion osobowych&#8201;.", "Md Golam": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Masashi": "<b>Masashi</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;まさし, マサシ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię japońskie</a>.", "Mychaylo": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mykhaylo</b>.</p><p>Mykhailo lub Mykhaylo to ukraińskie męskie imię, równoważne angielskim Michałowi. Wśród znanych osób z nazwiskiem są: Mykhaylo Berkos (1861-1919), rosyjski i ukraiński artysta pochodzenia greckiego Mykhayilo Bolotskykh (ur. 1960), ukraiński polityk i wojskowy, pułkownik generalny (Służba Obrony Cywilnej) Mykhayło Brodskyy (ur. 1959), ukraiński polityk, przywódca Partii Wolnych Demokratów i biznesmen Mykhayla Chemberzhi,...</p>", "Mon": "<p>Mon może oznaczać: Miasto miasta Mon w stanie Nagaland, Indie Nowoczesna Indie Nagaland, India Wyspa Mon w Danie Mianmarskie Narody i języki Naród Mon (lub Mon) w południowo-wschodniej Azji Mońskie (narodu Mon) w grupie języków Mon-Khmer Odmienne MON jest kodem IATA Monarch Airlines Powieść Mon (門) Soseki Natsume Japoński mon (文) jest popularny w Japonii</p>", "Maurycjusz": "<b>Maurycjusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>", "Monaco": "<p>O państwie patrz artykuł Monako.</p>", "Md Shamim": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Malay": "<p>Małajskie (ang. 马来) używane jest do oznaczenia: Malezji przed zjednoczeniem państw na północnej wyspie Borneo, czyli części półwyspu Malezji (ang. Peninsular Malaysia). Tak więc Malajskie lub Malajskie (przysłowie: 馬來亞, przenoszone: 马來亚) to poprzednie nazwisko Malezji.</p>", "Mohammad Abu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Milenov": "<p>Milenov jest wioską w hrabstwie Přerov w Olomoucký Obszarze, Czech Republic.</p>", "Mujahid": "<p>Mujahideen lub mujahidin (arabski: مجاهدين, mujāhidīn jest liczbową formą mujahidów arabski: مجاهد, 'władze islamskie'), ogólnie po arabsku termin o islamskich bojownikach uczestniczących w dżihadzie (boju), wojnie w imię islamu / Allah lub społeczności islamskiej (ummah). Angielski termin \"żihadista\" jest gramatycznie odpowiedni.</p>", "Michael Steven": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Michael</b>.</p><p>Michael: Botanika Michael - skrócie botaniczne, oznaczające, że autorem taksy jest Edmund Michael. Muzyka ⁇ Michael ⁇ - piosenka grupy Franz Ferdinand, wydana w 2004 roku.</p>", "María": "<p>⁇ María ⁇ to piosenka zapisana przez Puerto Rikanego piosenkarza Ricca Martina na trzecim albumie A Medio Vivir. Został wydany jako singel 21 listopada 1995 roku.</p>", "Mykolaj": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mikołaj</b>.</p><b>Mikołaj</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Νικόλαος, <i>Nikólaos</i>, od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;νίκη + λαός/<i>lassos</i>, tj. „zwycięstwo” + „lud”; to samo znaczenie ma imię <a href=\"https://pl.wikipedia.org/wiki/Nikodem\" target=\"_blank\" rel=\"noopener noreferrer\">Nikodem</a> od νίκη + δήμος) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia greckiego.", "Mojtaba": "<p>Mojtaba lub Mujtaba (perskiego: مجتبی; arabski: اَلْـمُـجْـتَـبَى, romanized: al-Mujtabā) to irańskie imię męskie. Pochodzi z języka arabskiego, co oznacza wybranych.</p>", "Mehboob": "<p>Mahbūb (wspelany również Mahboob lub Mehboob itp., z arabskiego: مَحبُوب, przenoszony do innych języków, takich jak urdu: محبوب jest męskie nazwisko i nazwisko. Do wybitnych osób z tym nazwiskiem należą:</p>", "Md Ali": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Anwar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Muamer": "<p>Muammer (wspisuje się również w podobny sposób, jak Ma'mar, arabski: معمر) jest męskie imię pochodzenia arabskiego oznaczające \"długożyłe\". Do osób z tym nazwiskiem należą:</p>", "Mubashir": "<p>Mubashir to nazwa arabskiego pochodzenia, zakorzeniona w Koranie. Oznacza to \"niewiści dobrą nowinę\".</p>", "Md Mizanur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Maamar": "<p>Maamar to męskie imię i nazwisko pochodzące z arabskiego. Do wybitnych osób z tym nazwiskiem należą:</p>", "Masaya": "<p>Masaya jest samorządem w prowincji Masaya w Nikaragui. Masako Autonomii zajmuje powierzchnię 147 km2.</p>", "Mari": "<p>Mari to miasto w brazylijskim stanie Paraíba. Miasto ma powierzchnię 154,726 km2, liczba ludności w 2007 roku wynosi 20634 osób, a jego gęstość 133,4 osób/km2.</p>", "Marouen": "<p>Marouane, Merouane lub ich odmiany to męskie imię i nazwisko pochodzenia arabskiego. Do wybitnych osób z tym nazwiskiem należą:</p>", "Maduranga": "<p>Maduranga to zarówno imię, jak i nazwisko. Znani ludzie z nazwiska to: Maduranga Zoysa (ur. 1984), Sri Lankaniec Kusal Maduranga (ur. 1993), Sri Lankański aktor Malindu Maduranga (ura. 1997), Sri Lankowy kryker Tharindu Maduranga, ur. 1985), Sri Lanki kryker</p>", "Md Kamal": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mao": "<p>Mao Zedun (kiet. Wręcz przeciwnie.</p>", "Molina": "<p>Molina (hisp. Molina) - hiszpańska nazwisko pochodzące od słowa molino ⁇ meelnica, młyńca ⁇: Molina, Alfred (ur.</p>", "Malachiasz": "<b>Malachiasz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, oznaczające „mój posłaniec” albo „mój anioł”. Patronem tego imienia jest prorok z <a href=\"https://pl.wikipedia.org/wiki/V_wiek_p.n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">V wieku p.n.e.</a>, autor biblijnej <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_Malachiasza\" target=\"_blank\" rel=\"noopener noreferrer\">Księgi Malachiasza</a>, oraz pierwszy irlandzki święty bp <a href=\"https://pl.wikipedia.org/wiki/Malachiasz_(biskup)\" target=\"_blank\" rel=\"noopener noreferrer\">Malachiasz</a>.", "Mel": "<p>Mel jest miastem w prowincji Belluno w regionie Veneto, znajdującym się około 170 km na północ od Wenecji i około 14 km na południowo-zachodni od Belluno i około 16 km na północy od Feltre. Na dzień 31 grudnia 2004 roku mieście miało ludności 6,311 i powierzchnię 85,7 km2.</p>", "Md Ashraful": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Morandi": "<p>To artykuł o ruumyńskim zespole muzycznym. O znanych osobnościach z takimi nazwiskami patrz.</p>", "Mac": "<p>Macintosh [ˈmækɪntɒʃ] lub Mac [mæk] - linia komputerów osobistych produkowanych przez Apple. Pracują pod zarządzaniem systemami operacyjnymi rodziny Mac OS, możliwe jest również praca na OS Windows NT, A/UX, NeXTSTEP, BeOS/Haiku, GNU/Linux i Rhapsody.</p>", "Marcellinus": "<p>Marcellinus (lat. Marcellinus) - rzymski polityk i wojskowy działacz drugiej połowy III wieku.</p>", "Mihaylo": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Myhaylo</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mihailo</b>.</p><p>Mihailo (Serbski cyrylski: Михаило) (\"\\mi-hail\\o\") jest sławskim nazwa męska. Jest to wariant hebrajskiej nazwy Michał, a jego krewni włączają Mihajlo i Mijailo.</p>", "Mio": "<p>Mio Technology - tajwański producent elektroniki konsumpcyjnej należący do MiTAC International Corporation. Pod międzynarodową marką handlową Mio produkowana jest technika dla samochodów: rejestratory wideo, radar-detektory, urządzenia nawigacyjne GPS.</p>", "Mukesh Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mukesh</b>.</p><p>Mukesh jest epitetem hinduskiego boga Shiwy i dosłownie oznacza \"podbiór demona Muka\". Jest powszechnie stosowany jako imię męskie w Indiach.</p>", "Marouan": "<p>Marouane, Merouane lub ich odmiany to męskie imię i nazwisko pochodzenia arabskiego. Do wybitnych osób z tym nazwiskiem należą:</p>", "Mohammed A": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammed</b>.</p><p>Muhammad - muzułmańskie imię i nazwisko. Mahomet jest islamskim prorokiem.</p>", "Md Nurul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Munawar": "<p>Munawar to imię i nazwisko. Do osób z tym nazwiskiem należą:</p>", "Mateen": "<p>Mateen to nazwisko i nazwisko pochodzące z arabskiego. Do wybitnych osób z tym nazwiskiem należą:</p>", "Md Monir": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Sumon": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mordechaj": "<b>Mordechaj</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> מרדכי) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%BBydzi\" target=\"_blank\" rel=\"noopener noreferrer\">żydowskiego</a>.", "Md Shafiqul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Iqbal": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Markas": "<p>Markas to męskie litewskie imię pochodzące od Marcus. Jego pochodne są Markauskas i Markevičius (nazwa rodziny).</p>", "Mohamed El Amine": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohamed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Md Rakibul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Shariful": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mariush": "W latach 2001–2014 był członkiem <a href=\"https://pl.wikipedia.org/wiki/Kabaret_Limo\" target=\"_blank\" rel=\"noopener noreferrer\">Kabaretu Limo</a>. Po zakończeniu działalności tej formacji zajmuje się głównie pisaniem sztuk oraz improwizacją komediową.", "Mitchel": "<p>Mitchell, Mitchell (ang. Mitchell, Mitchel) - angielskie nazwisko.</p>", "Md Maruf": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Malachy": "<p>Malachy to imię irlandzkiego pochodzenia. Wśród znanych nosicieli nazwy są:</p>", "Md Hasan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mario Jr.": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mario</b>.</p><p>Mario (jap. Mario Mario, angielski.</p>", "Mykolay": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mikolai</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mikola</b>.</p><p>Mikola to nazwisko: Ananda Mikola (ur. 1980), indonezyjski kierowca samochodu wyścigowego István Mikola (r. 1947), węgierski lekarz i polityk, minister zdrowia od 2001 do 2002 roku Nándor Mikola (1911-2006), fiński-węgierski malarz Nazwa: Święty Mikołaj Mozhaiński lub Mikola Mozhaiski, rosyjska wariantka tradycji św. Mikola Abramchyk (1903-1970), białoruski dziennikarz i polityka Mikola Statkevich (ur. 1956),...</p>", "Mozammel": "<p>Muzzammil (arabski: مزّمّل; transliteracje różnią się) jest arabską nazwą z Al-Muzzammil, nazwiska Mahometa wspomniane w Koranie. Do wybitnych osób z tym nazwiskiem należą:</p>", "Miłogost": "<b>Miłogost</b>, <b>Miłgost</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z członów <i>Miło-</i> („miły”, „miłujący”) i <i>-gost</i> („goście”, „gościć”). Mogło oznaczać „przyjaznego gościom”.", "Michaiło": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mychaylo</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mykhaylo</b>.</p><p>Mykhailo lub Mykhaylo to ukraińskie męskie imię, równoważne angielskim Michałowi. Wśród znanych osób z nazwiskiem są: Mykhaylo Berkos (1861-1919), rosyjski i ukraiński artysta pochodzenia greckiego Mykhayilo Bolotskykh (ur. 1960), ukraiński polityk i wojskowy, pułkownik generalny (Służba Obrony Cywilnej) Mykhayło Brodskyy (ur. 1959), ukraiński polityk, przywódca Partii Wolnych Demokratów i biznesmen Mykhayla Chemberzhi,...</p>", "Maryna": "Imię Maryna jest żeńskim odpowiednikiem imienia <a href=\"https://pl.wikipedia.org/wiki/Maryn\" target=\"_blank\" rel=\"noopener noreferrer\">Maryn</a>, w Polsce niezwykle rzadkim (w 1994 roku nosiła je jedna osoba, w roku 2001 – 203 osoby, zaś w wariancie <i>Marina</i> – 362). Imię to wywodzi się od imienia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Marinus</em>, a to z kolei powstało z przymiotnika <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>marinus</em> („morski”). Imię Maryna – rozumiane jako żeński odpowiednik imienia Maryn – poświadczone jest w Polsce już w XV wieku (najwcześniej w 1443 roku). Zdrobnienie od niego brzmi Marynia. Marina to cudzoziemski wariant imienia Maryna; trudno powiedzieć, skąd przybyło do Polski, z uwagi na podobną formę w prawie wszystkich językach europejskich.", "Manmohan": "<p>Manmohan oznacza \"wygrywający serce\". Jest to kolejna nazwa Kryszny, hinduistycznego bóstwa, jednego z \"avatarów\" (lub \"wcielenia\") Pana Wisnu.</p>", "Md Shahin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Tajul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mthokozisi": "<p>Mthokozisi to męskie imię. Znani ludzie z nazwiska obejmują: Mthokozisi Dube (ur. 1992), południowoafrykański piłkarz Mthokozizi Selby Khumalo (ur. 1971), połudnoafrykański polityk, urzędnik urzędników i kaznodziei Malachi Tyrese Mthokoziti Napa (ur. 1999), angielski piłkarzek Mthokozimi Nxumalo (1989-2021), południeafrykańskiego polityka Mthokozizi Shezi (ur. 1987), południaafrykańczy kryketa i sędziarz Mthokosizi Yende (ur. 1984), połud...</p>", "Minh Tri": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Ma": "<p>MA lub Ma może oznaczać: Ma (myfologia) - bogini. Kod kraju i domeny krajowej najwyższego poziomu Maroka (.ma) ISO 3166.</p>", "Mikal": "<b>Mikal</b> (hebr. מיכל; skrócona forma imienia <i>Michael</i> − <i>kto jest jak Bóg</i>) − córka <a href=\"https://pl.wikipedia.org/wiki/Saul_(kr%C3%B3l_Izraela)\" target=\"_blank\" rel=\"noopener noreferrer\">Saula</a>, króla Izraela, pierwsza żona króla <a href=\"https://pl.wikipedia.org/wiki/Dawid_(kr%C3%B3l_Izraela)\" target=\"_blank\" rel=\"noopener noreferrer\">Dawida</a>. Zapis historii Mikal przekazują <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijne</a> Księgi Samuela.", "May": "<p>May to imię. May to skrócie botaniczne, które oznacza, że May jest autorem taksy.</p>", "Md Jahirul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Minh Hiếu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Muslum": "<p>Muslim (arabski: مُسْلِم muslim), również przetransliterowany jako Muslim lub Müslüm (tyrk), jest arabskim męskim nazwiskiem, które oznacza 'czysty, czysty, nieskazitelny, czysty , bez skazy, prosty, absolutny', 'oddania, bogobojny, pobożny, zadowolony, posłuszny, poddany', 'cudowny, czysty i skromny, bezwzględny, niewinny'. Nazwa Muslim jest diminutiwem nazwy Aslam (أَسْلَم aslam), które oba nazwy pochodzą z męskiego rzeczoznacznika Salaam.</p>", "Minh Trí": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Md Mamun": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Maulik": "<p>Maulik to popularne indyjskie i bangladeszkie imię. Znane również jako Moulik, Maulick i Moulick.</p>", "Mevlut": "<p>Mevlüt (z arabskiego: مولود, romanized: mawlūd) to tureckie imię dla mężczyzn. Mevlüt Chavuşoğlu (ur. 1968), turecki dyplomat i polityk; minister spraw zagranicznych Turcji (2015-2023) Mevlút Erdinç (ur. 1987), francusko-turecki piłkarz, który grał dla Paris Saint-Germain jako obrońca Mevlût Mert Altıntaş (1994-2016), zabójca rosyjskiego ambasadora w Turcji Andre Karlova</p>", "Mosze": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Moshe</b>.</p><p>Moshe jest hebrajską wersją męskiego imienia Mojżesza, w tym biblijnej postaci Mojżeszowej. Miano nosi: Moshe Arens (1925-2019), izraelski polityk Moshe Bar (zrównanie) Moshe Bejski (1921-2007), izraelski sędzia Moshe Brener (ur. 1971), izraelski piłkarz koszykówki Moshe Czerniak (1910-1984), izraelscy mistrz szachowców Moshe Dayan (1915-1981), izraelska wojskowa przywódca i polityk Moshe Erem (1896-1978), izraelsko...</p>", "Miromir": "<b>Mirogod</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Miro-</i> (\"pokój, spokój, dobro\") oraz <i>-god</i> (\"robić coś w stosownym czasie, dopasowywać, czynić odpowiednim\"). Mogło oznaczać \"ten, który czyni pokój\". Por. <a href=\"https://pl.wikipedia.org/wiki/Godzimir\" target=\"_blank\" rel=\"noopener noreferrer\">Godzimir</a>, imię złożone z tych samych członów w odwrotnej kolejności.", "Moein": "<p>Moeen lub Moein lub Moien to imię i nazwisko. Jest to imię koraniczne, które oznacza: pomocnik, wspierający lub dający schronienie.</p>", "Md Ibrahim": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mattheo": "<p>Matteo to włoska forma nazwiska Matthew. Inną formą jest Mattia.</p>", "Minh Tien": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Md Al Amin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mana": "<p>Mana: Maná - meksykański pop-rock zespół utworzony w 1978 roku. Mana to seria japońskich gier komputerowych.</p>", "Md Sabbir": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Maja": "<b>Maja</b> – imię żeńskie pochodzenia greckiego, wywodzące się od słowa <i>μαῖα (maia)</i> oznaczającego „dobrą matkę”, „damę” lub „przybraną matkę”. W mitologiach greckiej i rzymskiej <a href=\"https://pl.wikipedia.org/wiki/Maja_(mitologia_grecka)\" target=\"_blank\" rel=\"noopener noreferrer\">Maja</a> była najstarszą z <a href=\"https://pl.wikipedia.org/wiki/Nimfy\" target=\"_blank\" rel=\"noopener noreferrer\">nimf</a> – <a href=\"https://pl.wikipedia.org/wiki/Plejady_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Plejad</a>, córek <a href=\"https://pl.wikipedia.org/wiki/Zeus\" target=\"_blank\" rel=\"noopener noreferrer\">Zeusa</a> i <a href=\"https://pl.wikipedia.org/wiki/Plejone_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Plejone</a>, oraz matką <a href=\"https://pl.wikipedia.org/wiki/Hermes\" target=\"_blank\" rel=\"noopener noreferrer\">Hermesa</a>.", "Md Abdullah Al": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Myhajlo": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mihajlo</b>.</p><p>Mihajlo (sirbski cyrylski: Михајло) jest południowsłowiańskim wariantem imienia Michał, często występującym wśród Serbów. Mijailo i Mijailo to między innymi imiona.</p>", "Md Rafiqul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Arif": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mahdy": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mahdi</b>.</p>Według niektórych koncepcji (bliższych <a href=\"https://pl.wikipedia.org/wiki/Sunnizm\" target=\"_blank\" rel=\"noopener noreferrer\">sunnizmowi</a>) jedynym mahdim był <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Jezus</a> – <a href=\"https://pl.wikipedia.org/wiki/Isa_(Jezus)\" target=\"_blank\" rel=\"noopener noreferrer\">Isa</a>. Częściej jednak sunnici uważają, że mahdi i Isa połączą swoje siły w ostatecznej walce z <a href=\"https://pl.wikipedia.org/wiki/Antychryst\" target=\"_blank\" rel=\"noopener noreferrer\">antychrystem</a> (fałszywym <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorokiem</a>) Dadżdżalem. Przyjście mahdiego ma poprzedzać atak wojsk niewiernych na miejscowość <a href=\"https://pl.wikipedia.org/wiki/Lod\" target=\"_blank\" rel=\"noopener noreferrer\">Lod</a> w <a href=\"https://pl.wikipedia.org/wiki/Izrael\" target=\"_blank\" rel=\"noopener noreferrer\">Izraelu</a>. Większość <a href=\"https://pl.wikipedia.org/wiki/Szyizm\" target=\"_blank\" rel=\"noopener noreferrer\">szyitów</a> uważa mahdiego za inną osobę, która ma przyjść na ziemię tuż przed <a href=\"https://pl.wikipedia.org/wiki/S%C4%85d_Ostateczny\" target=\"_blank\" rel=\"noopener noreferrer\">Sądem Ostatecznym</a>, by zbawić/uratować ludzkość przed <a href=\"https://pl.wikipedia.org/wiki/Szatan\" target=\"_blank\" rel=\"noopener noreferrer\">Szatanem</a>. Część wyznawców <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">islamu</a> łączy obie koncepcje, twierdząc, że Jezus urodzi się ponownie w <a href=\"https://pl.wikipedia.org/wiki/Damaszek\" target=\"_blank\" rel=\"noopener noreferrer\">Damaszku</a>, by pokonać <a href=\"https://pl.wikipedia.org/wiki/Z%C5%82o\" target=\"_blank\" rel=\"noopener noreferrer\">zło</a>. Według zapowiedzi Proroka <a href=\"https://pl.wikipedia.org/wiki/Mahomet\" target=\"_blank\" rel=\"noopener noreferrer\">Mahometa</a>, mahdi pochodzić będzie z jego rodu. Dla <a href=\"https://pl.wikipedia.org/wiki/Szyizm\" target=\"_blank\" rel=\"noopener noreferrer\">szyitów</a> jest to bardzo ważna postać, łączona czasem z osobą ostatniego ukrytego <a href=\"https://pl.wikipedia.org/wiki/Imam_(szyizm)\" target=\"_blank\" rel=\"noopener noreferrer\">imama</a>, który ma poprzedzać Mahdiego, bądź nim być.", "Mayan": "<p>MaYaN - holenderska symfonika-det-metal-grupa, utworzona w 2011 roku przez wokalistę Marka Jansena, klawiastę Jacka Driessen'a (w dół Jack Driessen) i gitarzystę Franka Shiphorsta (w dóło).</p>", "Md Jahid": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Manolito": "<p>Manolito jest diminutiwą formą hiszpańskiego nazwiska Manolo, a z kolei diminutiwą Manuel. Może odnosić się do:</p>", "Mohan Singh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohan</b>.</p><p>Mohan to gmin i nagar panchayat z okręgu Unnao w stanie Uttar Pradesh, India.</p>", "Md Yousuf": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Minh Quân": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Mutaz": "<p>Mutaz lub Mu'taz lub Motaz lub Moataz (arabski: معتز) to męskie imię i nazwisko pochodzenia arabskiego. Do wybitnych osób z tym nazwiskiem należą:</p>", "Mbongeni": "<p>Mbongeni to imię pochodzące od słowa Nguni ukubonga, co oznacza \"chwalenie\". Wśród znanych osób z imieniem: Mbongeni Buthelezi (ur. 1966), artysta z Południowej Afryki Mbongeni Khumalo, poety z Połedniowej Afrii Mbongeni Mzimela, piłkarz z Połodniowej Afriki Mbongeni Ngema, pisarz z Połowo Afryki Phesheya Mbongeni Dlamini, polityk</p>", "Md Emran": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Munish": "<p>Munish może odnosić się do: Munish Arora (ur. 1971), indyjski-ur. singapurski kryker Munish Jolly (ur. 1974), indyjskiego byłego krykera Munish Makhija (ur. 1968), indyskiego video jockey Munish Chander Puri (1939-2005), byłego profesora emerytum matematyki w IIT Delhi</p>", "Mauryliusz": "<b>Mauryliusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, którego patronem jest m.in. św. Mauryliusz, biskup <a href=\"https://pl.wikipedia.org/wiki/Angers\" target=\"_blank\" rel=\"noopener noreferrer\">Angers</a> we <a href=\"https://pl.wikipedia.org/wiki/Francja\" target=\"_blank\" rel=\"noopener noreferrer\">Francji</a>. <a href=\"https://pl.wikipedia.org/wiki/Imieniny\" target=\"_blank\" rel=\"noopener noreferrer\">Imieniny</a> obchodzi <a href=\"https://pl.wikipedia.org/wiki/13_wrze%C5%9Bnia\" target=\"_blank\" rel=\"noopener noreferrer\">13 września</a>.", "Manuel Jr.": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Manuel</b>.</p><b>Emanuel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od słowa עִמָּנוּאֵל oznaczającego „Bóg z nami”. Imię mesjasza oraz kilku świętych katolickich. Żeński odpowiednik to <a href=\"https://pl.wikipedia.org/wiki/Emanuela\" target=\"_blank\" rel=\"noopener noreferrer\">Emanuela</a>.", "Md Nahid": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Maksym-Ivan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maksym</b>.</p><b>Maksym</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, utworzone od przymiotnika <i>maximus</i> oznaczający \"największy\", przydomka <a href=\"https://pl.wikipedia.org/wiki/Jowisz_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Jowisza</a>. Istnieją liczni święci prawosławni i katoliccy o tym imieniu: <a href=\"https://pl.wikipedia.org/wiki/Maksym_Wyznawca\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym Wyznawca</a>, <a href=\"https://pl.wikipedia.org/wiki/Maksym_Grek\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym Grek</a>, <a href=\"https://pl.wikipedia.org/wiki/Maksym_Brankowicz\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym Wołoski</a>, <a href=\"https://pl.wikipedia.org/wiki/Maksym_Gorlicki\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym Gorlicki</a>, <a href=\"https://pl.wikipedia.org/wiki/Maksym_z_Riez\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym z Riez</a> i wielu innych.", "Maruti": "Indyjskie przedsiębiorstwo od 1983 roku produkuje samochody na licencji Suzuki. Pierwszym pojazdem produkowanym w Indiach na tej zasadzie było <a href=\"https://pl.wikipedia.org/wiki/Maruti_800\" target=\"_blank\" rel=\"noopener noreferrer\">Maruti 800</a>, odpowiednik modelu <a href=\"https://pl.wikipedia.org/wiki/Suzuki_Alto\" target=\"_blank\" rel=\"noopener noreferrer\">Suzuki Alto</a>. Był to najlepiej sprzedający się samochód w Indiach.", "Marius-Adrian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marius</b>.</p>Pochodził z niższych warstw społecznych, miał być z zawodu rzemieślnikiem (kowalem), później przypuszczalnie służył w wojsku, lecz nie wiadomo w jakiej funkcji. Po stłumionej w początkach 269 roku rewolcie <a href=\"https://pl.wikipedia.org/wiki/Lelian_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Leliana</a> wzniecił kolejny bunt w <a href=\"https://pl.wikipedia.org/wiki/Moguncja\" target=\"_blank\" rel=\"noopener noreferrer\">Mogontiacum</a> przeciwko władzy <a href=\"https://pl.wikipedia.org/wiki/Wiktoryn_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Wiktoryna</a>, następcy <a href=\"https://pl.wikipedia.org/wiki/Postumus\" target=\"_blank\" rel=\"noopener noreferrer\">Postuma</a>. Według <i><a href=\"https://pl.wikipedia.org/wiki/Historia_Augusta\" target=\"_blank\" rel=\"noopener noreferrer\">Historia Augusta</a></i> jego rządy trwały zaledwie 2-3 dni, czemu jednak przeczy zachowana liczba jego monet. Najpewniej w mennicy w <a href=\"https://pl.wikipedia.org/wiki/Kolonia_(Niemcy)\" target=\"_blank\" rel=\"noopener noreferrer\">Kolonii</a> (<i>Colonia Agrippina</i>) <a href=\"https://pl.wikipedia.org/wiki/Emisja_pieni%C4%85dza\" target=\"_blank\" rel=\"noopener noreferrer\">emitował</a> w swym imieniu niskowartościowe <a href=\"https://pl.wikipedia.org/wiki/Antoninian\" target=\"_blank\" rel=\"noopener noreferrer\">antoniniany</a> typów: AEQUITAS, CONCORDIA MILIT(um), SAEC(uli) FELICITAS, VICTORIA AUG(usti), VIRTUS AUG(usti).", "Miklos": "<p>Miklós jest nazwiskiem lub nazwiskiem, węgierską formą greckiego Νικόλαος (ang. Nicholas), i może odnosić się do:</p>", "Maxx": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Max</b>.</p><p>Max (wymawia się: max) - niejednoznaczny termin. Max - w matematyce i językach programowania oznacza funkcję wyboru maksymalnego ze swoich argumentów, (Max (3, 6, 1) = 6).</p>", "Md Arman": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Melan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Melani</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Melany</b>.</p><p>Melanie to kobiece imię pochodzące od greckiego μελανία (melania), \"czarność\", a od μέλας (melas), oznaczające \"ciemny\". Urodzony w łacinie przez dwóch świętych, Melanię Starszą i jej wnuczkę Melanię Młodszą, nazwę wprowadzili do Anglii Normanie w francuskiej formie Melanie.</p>", "Minh Khôi": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Moinuddin": "<p>Mu'in al-Din lub Moinuddin (arabski: معین الدین) to męskie muzułmańskie imię składające się z elementów Muin, co oznacza pomocnika i ad-Din, co oznacza wiarę. Moinuddin Ahmed (zjednoznaczenie), wielokrotne osoby Mu'in ad-Din Unur (m.</p>", "Magid": "<b>Magid</b> lub <b>maggid</b> (z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מַגִּיד&#8206; „przemawiający”) – w <a href=\"https://pl.wikipedia.org/wiki/Judaizm\" target=\"_blank\" rel=\"noopener noreferrer\">judaizmie</a> wschodnioeuropejskim tytuł przyznawany wędrownym kaznodziejom, którzy często zarabiali na życie opłatami zbieranymi w różnych gminach. Z racji tego, że dawni rabini byli bardziej uczonymi i znawcami pisma niż kaznodziejami, długie, barwne i przystępne kazania (często w <a href=\"https://pl.wikipedia.org/wiki/Jidysz\" target=\"_blank\" rel=\"noopener noreferrer\">jidysz</a>) znajdowały wielu chętnych słuchaczy. Termin ten oznacza także pozaziemskiego mentora, który nawiązuje kontakt z ludźmi za pomocą nawiedzeń, snów, wizji, a także słów wypowiedzianych ich własnymi ustami. Wielu mistyków posiadało własnego magida, który wprowadzał ich w tajniki kabały. Posiadanie magida było znakiem duchowej wyższości takiej osoby. O <a href=\"https://pl.wikipedia.org/wiki/Eliasz_ben_Salomon_Zalman\" target=\"_blank\" rel=\"noopener noreferrer\">Eliaszu Gaonie z Wilna</a> mówiono, że odmówił przyjęcia magida, gdyż nie chciał poznać Tory bez wysiłku ze swej strony. Najsłynniejszym magidem był magid <a href=\"https://pl.wikipedia.org/wiki/J%C3%B3zef_Karo\" target=\"_blank\" rel=\"noopener noreferrer\">Józef Karo</a>, a niektóre prawdy, które objawił, Karo zapisał w dzienniku <i>Magid Meiszarim</i>.", "Mergim": "<p>Mërgim to albaniańskie imię i nazwisko męskie i może odnosić się do: Mërgim Bajraktari (ur. 1993), szwajcarsko-albaniański piłkarz Mërgim Berisha (ur. 1998), kosowskiego-niemieckiego piłkarza Mërgim Brahimi (ur. 1992), kosowskiego piłka nożnego Mërgim Fejzullahu (ur. 1994), albanianskiego piłkarze Mërgim Mavraj (ur. 1986), niemiecko-albanieckiego Piłkarza Płka noże Mërgim Neziri (ur. 1993)</p>", "Moïse": "<p>Moise jest nazwiskiem i nazwiskiem, z różnymi pisowniami w jego francuskim i rumuńskim pochodzeniu, które oba pochodzą z imienia Mojżesz: Moïse jest francuskim pisownią Mojżesza, podczas gdy Moise jest rumuńskie pisownią. Jako nazwisko, Moisè i Mosè to włoskie pisownię Mojżesza.</p>", "Matus": "<p>Matus może być zarówno nazwiskiem, jak i nazwiskiem. Do powszechnych wariantów należą Matúš, Matuš i Matůš.</p>", "Mario Andres": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mario</b>.</p><p>Mario (jap. Mario Mario, angielski.</p>", "Mostapha": "<p>Mustafa (arabski: مصطفى, romanized: Muṣṭafā) jest jednym z imion islamskiego proroka Mahometa. W arabskim oznacza \"wybrany, wybrany, wyznaczony, preferujący\".</p>", "Marik": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Marika</b>.</p><b>Marika</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzące od imienia „<a href=\"https://pl.wikipedia.org/wiki/Maria\" target=\"_blank\" rel=\"noopener noreferrer\">Maria</a>”. Jest <a href=\"https://pl.wikipedia.org/wiki/W%C4%99gry\" target=\"_blank\" rel=\"noopener noreferrer\">węgierską</a> formą tego imienia, chociaż znane jest także w Bułgarii i na terenie byłej Jugosławii. Imię jest również zniemczoną formą zdrobnienia „Maryjka” występującego w <a href=\"https://pl.wikipedia.org/wiki/Etnolekt_%C5%9Bl%C4%85ski\" target=\"_blank\" rel=\"noopener noreferrer\">etnolekcie śląskim</a>.", "Minoru": "<b>Minoru</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;みのる, ミノル) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Merouane": "<p>Marouane, Merouane lub ich odmiany to męskie imię i nazwisko pochodzenia arabskiego. Do wybitnych osób z tym nazwiskiem należą:</p>", "Mikalay": "<p>Mikalai to męskie białoruskie imię. Znani ludzie z imieniem to: Mikalai Barkouski, białoruska judoka Mikalai Kamianchuk (ur. 1987), białoruskie pary skater Mikalai Novikau (ur. 1986), białorski ciężarosta Mikalai Sharlap (ur. 1994), białoruśski remarka Mikalai Shubianok (ur. 1985), białorowski dekathlete Mikalai Zhukavets (ur. 1986), białoruski windsurfer</p>", "Moazzam": "<p>Moazzam, Muazzam, Muzzem i Moazzem (od arabskiego المعظم, muʿaẓẓam, \"wywyższony\") jest męskie imię i nazwisko pochodzenia arabskiego. Do wybitnych osób z tym nazwiskiem należą:</p>", "Md Atikur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mohammad Ali": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Mohan Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohan</b>.</p><p>Mohan to gmin i nagar panchayat z okręgu Unnao w stanie Uttar Pradesh, India.</p>", "Michael Stiven": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Michael</b>.</p><p>Michael: Botanika Michael - skrócie botaniczne, oznaczające, że autorem taksy jest Edmund Michael. Muzyka ⁇ Michael ⁇ - piosenka grupy Franz Ferdinand, wydana w 2004 roku.</p>", "Mubin": "<p>Mobeen (arabski: مبين; perskiego: مبین) (zwany również Mubeen, Mobin, Mubin) to imię pochodzące od arabskiego słowa (مبين), które jest używane jako poetycki przymiot w literaturze, mowie i kontekście religijnym. Nazwa może być przetłumaczana jako \"wyraźne\", \"jasne\", \"wymowne\", \"wybitne\" lub \"jasne\".</p>", "Md Sujan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Manuel De Jesus": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Manuel</b>.</p><b>Emanuel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od słowa עִמָּנוּאֵל oznaczającego „Bóg z nami”. Imię mesjasza oraz kilku świętych katolickich. Żeński odpowiednik to <a href=\"https://pl.wikipedia.org/wiki/Emanuela\" target=\"_blank\" rel=\"noopener noreferrer\">Emanuela</a>.", "Minh Hung": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Md Jakir": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Arafat": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Marius-Constantin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marius</b>.</p>Pochodził z niższych warstw społecznych, miał być z zawodu rzemieślnikiem (kowalem), później przypuszczalnie służył w wojsku, lecz nie wiadomo w jakiej funkcji. Po stłumionej w początkach 269 roku rewolcie <a href=\"https://pl.wikipedia.org/wiki/Lelian_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Leliana</a> wzniecił kolejny bunt w <a href=\"https://pl.wikipedia.org/wiki/Moguncja\" target=\"_blank\" rel=\"noopener noreferrer\">Mogontiacum</a> przeciwko władzy <a href=\"https://pl.wikipedia.org/wiki/Wiktoryn_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Wiktoryna</a>, następcy <a href=\"https://pl.wikipedia.org/wiki/Postumus\" target=\"_blank\" rel=\"noopener noreferrer\">Postuma</a>. Według <i><a href=\"https://pl.wikipedia.org/wiki/Historia_Augusta\" target=\"_blank\" rel=\"noopener noreferrer\">Historia Augusta</a></i> jego rządy trwały zaledwie 2-3 dni, czemu jednak przeczy zachowana liczba jego monet. Najpewniej w mennicy w <a href=\"https://pl.wikipedia.org/wiki/Kolonia_(Niemcy)\" target=\"_blank\" rel=\"noopener noreferrer\">Kolonii</a> (<i>Colonia Agrippina</i>) <a href=\"https://pl.wikipedia.org/wiki/Emisja_pieni%C4%85dza\" target=\"_blank\" rel=\"noopener noreferrer\">emitował</a> w swym imieniu niskowartościowe <a href=\"https://pl.wikipedia.org/wiki/Antoninian\" target=\"_blank\" rel=\"noopener noreferrer\">antoniniany</a> typów: AEQUITAS, CONCORDIA MILIT(um), SAEC(uli) FELICITAS, VICTORIA AUG(usti), VIRTUS AUG(usti).", "Maria Aleksander": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Minh Phuc": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Marc-André": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marc</b>.</p><p>Marc: MARC (ang. Machine-Readable Cataloging) - grupa formatów (MARC21, UNIMARC, RUSMAC itp.</p>", "Md Nazrul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Murtazo": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Murtaz</b>.</p><p>Murtaz (georgijski: მურთაზ; rosyjski: Муртаз) to męskie imię. Wśród znanych osób z nazwiskiem są: Murtaz Daushvili (ur. 1989), gruziński piłkarz Murtaz Khurtsilava (ur. 1943), gruzijski obrońca piłki nożnej Murtaz Shelia (ur. 1969), gruzianski obrońca.</p>", "Mugurel": "<p>Mugur (\"bud\") i jego diminutiwny Mugurel są rumuńskimi nazwami. Do osób znanych z tych nazw należą: Mugur Bolohan (ur. 1976), rumuński piłkarz Mugur Gușatu (ur. 1969), rumuński piłkarze Mugur Isărescu (ur. 1949), rumuinski ekonomista i polityk Mugurel Buga (ur. 1977), rumuńczyk Mugurel Dedu (ur. 1985), rumuinik Mugurel Dumitru (ur. 1972), rumuinianin piłkarza</p>", "Md Saiful Islam": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Meysam": "<p>Meysam, Maitham lub Maytham (arabski: ميثم, azerbaijski: Meysəm, turecki: Meysem, perskiego: میثم) to międzynarodowo stosowane imię męskie pochodzące z języków semitycznych. Nazwa pochodzi od arabskiego korzenia w-th-m i oznacza \"płaszczenie\" jak dźwięk, jaki powstaje z kopyt konia lub wielbłąda.</p>", "Medina": "<p>Madina (المدينة, al-Madīnah (arabski: [almaˈdiːna]), \"mieść\"), pełna nazwa al-Madînah al-Munawwarah (arabsko: المدينة المنورة, \"mieść jasną\"), znana również jako Medina w zachodnich tekstach, jest miastem i siedzibą administracyjną regionu Al-Madinah w Arabii Saudyjskiej. al-Masjid an-Nabawi (\"świątynia proroka\") znajduje się w centrum miasta, jest to miejsce pochodu islamskiego proroka Mahometa,</p>", "Mohamed Mohamed": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohamed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Mubeen": "<p>Mobeen (arabski: مبين; perskiego: مبین) (zwany również Mubeen, Mobin, Mubin) to imię pochodzące od arabskiego słowa (مبين), które jest używane jako poetycki przymiot w literaturze, mowie i kontekście religijnym. Nazwa może być przetłumaczana jako \"wyraźne\", \"jasne\", \"wymowne\", \"wybitne\" lub \"jasne\".</p>", "Md Mamunur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Manuel Antonio": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Manuel</b>.</p><b>Emanuel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od słowa עִמָּנוּאֵל oznaczającego „Bóg z nami”. Imię mesjasza oraz kilku świętych katolickich. Żeński odpowiednik to <a href=\"https://pl.wikipedia.org/wiki/Emanuela\" target=\"_blank\" rel=\"noopener noreferrer\">Emanuela</a>.", "Miladin": "<p>Miladin to męskie imię. Może odnosić się do: Miladina Bečanović (ur. 1973), piłkarz Miladin Kozlina (ur. 1983), piłkacha w rękę Miladin Peković (r. 1983), koszykarz Miladina Pešterac (1960-2007), piłkarza Miladin Popović (1910-1945), polityk Miladin \"Dado\" Pršo (ur. 1974), emeryturę Miladin Stevanović (or. 1996), piłkęcha Miladin Šobić (ur., 1956), piosenkarz Miladyn Zarić (1889-1976), nauczyciel i żołnierz</p>", "Md Aminul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mobolaji": "<p>Mobolaji to męskie imię pochodzenia joruba, co oznacza (Obudziłem się z bogactwem).</p>", "Melvyn": "<p>Melvyn to męskie imię, które może odnosić się do: Melvyn Betts (ur. 1975), angielski kryketer Melvyn Bragg (ur. 1939), brytyjski nadawca i autor Melvyn Caplan, brytyjski polityk konserwatywny Mel Collins (ur. 1947), brytyjskiego saksofonisty, byłego członka króla Crimson Melvyn Douglas (1901-1981), amerykańskiego aktora Melvyn Dubofsky (ur. 1934), amerykański profesor historii i socjologii Melvyn Gale (ur. 1952), angielskiego wiolonczelnika, byłego...</p>", "Maksimiliyan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maksimilian</b>.</p><p>Maksymilian lub Maximillian (Maximiliaan w języku holenderskim i Maximilien w językach francuskich) to męskie imię. Nazwa \"Max\" jest skróceniem \"Maximilian\" oraz kilku innych nazw, w tym, ale nie ograniczając się do Maxwell.</p>", "Md Robiul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Rifat": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Yeasin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Musthafa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mustafa</b>.</p><b>Mustafa</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia arabskiego, oznacza „wybrany”.", "Máni": "<b>Mani</b> – w <a href=\"https://pl.wikipedia.org/wiki/Mitologia_nordycka\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii nordyckiej</a> bóg Księżyca, syn Glaur i <a href=\"https://pl.wikipedia.org/wiki/Olbrzym_(istota)\" target=\"_blank\" rel=\"noopener noreferrer\">olbrzyma</a> Mundilfariego. Każdej nocy podgryzany przez <a href=\"https://pl.wikipedia.org/wiki/Hati\" target=\"_blank\" rel=\"noopener noreferrer\">Hatiego</a>, wiedzie przez niebo księżyc. Gdy nadejdzie <a href=\"https://pl.wikipedia.org/wiki/Ragnar%C3%B6k\" target=\"_blank\" rel=\"noopener noreferrer\">Ragnarök</a>, Hati schwyta Mániego. W <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staronordyjski\" target=\"_blank\" rel=\"noopener noreferrer\">języku staronordyjskim</a> słowo <i>máni</i> było pospolitym słowem oznaczającym księżyc.", "Monika": "<b>Monika</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o znaczeniu i pochodzeniu trudnym do objaśnienia. Według niektórych badaczy imię pochodzi od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> słowa „monos” oznaczającego <i>jeden</i>, <i>sam</i>, <i>pojedynczy</i>, <i>jedynak</i> i <i>jedynaczka</i>. Z tego samego rdzenia pochodzą takie słowa jak: <a href=\"https://pl.wikipedia.org/wiki/Monogamia\" target=\"_blank\" rel=\"noopener noreferrer\">monogamia</a>, <a href=\"https://pl.wikipedia.org/wiki/Monoteizm\" target=\"_blank\" rel=\"noopener noreferrer\">monoteizm</a>, monaster (klasztor). Inne źródło podaje, że imię to wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> „monaché”, co znaczy <i>samotna</i>, <i>odosobniona</i>; we <a href=\"https://pl.wikipedia.org/wiki/W%C5%82ochy\" target=\"_blank\" rel=\"noopener noreferrer\">Włoszech</a> zakonnica zwana jest <i>monaca</i>, a w niektórych dialektach wręcz <i>monica</i>.", "Majit": "<p>Majid, Majed (także: Maajed, Maged, Magid lub Mjid) to męskie arabskie imię, które może również pojawić się jako nazwisko Majid lub Magid. Nazwa Majid w języku arabskim oznacza \"szlachetny\", \"sławny\" lub \"wspanialny\" i może również oznaczać \"honor\" lub \"oddzielność\".</p>", "Mirwais": "<b>Mirwais Ahmadzaï</b> (ur. <a href=\"https://pl.wikipedia.org/wiki/23_pa%C5%BAdziernika\" target=\"_blank\" rel=\"noopener noreferrer\">23 października</a> <a href=\"https://pl.wikipedia.org/wiki/1960\" target=\"_blank\" rel=\"noopener noreferrer\">1960</a> w <a href=\"https://pl.wikipedia.org/wiki/Lozanna\" target=\"_blank\" rel=\"noopener noreferrer\">Lozannie</a> w <a href=\"https://pl.wikipedia.org/wiki/Szwajcaria\" target=\"_blank\" rel=\"noopener noreferrer\">Szwajcarii</a>) – <a href=\"https://pl.wikipedia.org/wiki/Francja\" target=\"_blank\" rel=\"noopener noreferrer\">francuski</a> <a href=\"https://pl.wikipedia.org/wiki/Muzyk\" target=\"_blank\" rel=\"noopener noreferrer\">muzyk</a>, <a href=\"https://pl.wikipedia.org/wiki/Kompozytor\" target=\"_blank\" rel=\"noopener noreferrer\">kompozytor</a>, producent <a href=\"https://pl.wikipedia.org/wiki/Muzyka\" target=\"_blank\" rel=\"noopener noreferrer\">muzyczny</a> i <a href=\"https://pl.wikipedia.org/wiki/DJ\" target=\"_blank\" rel=\"noopener noreferrer\">DJ</a>, podpisujący się też często jedynie jako <b>Mirwais</b>. Swoje nazwisko odziedziczył po <a href=\"https://pl.wikipedia.org/wiki/Afganistan\" target=\"_blank\" rel=\"noopener noreferrer\">afgańskim</a> ojcu, matka była z pochodzenia <a href=\"https://pl.wikipedia.org/wiki/W%C5%82ochy\" target=\"_blank\" rel=\"noopener noreferrer\">Włoszką</a>.", "Minh An": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Manol": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Manole</b>.</p><p>Manole to rumuńska nazwa, używana zarówno jako imię i nazwisko. Osoby z nazwiskiem: Manole Aldescu Manole Marcus Osoby z przyrzeczeniem: Laurențiu Manole Leonard Manole Mădălina Manole Viorel Manole</p>", "Mirel": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mirela</b>.</p><b>Mirela</b>, <b>Mirella</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, pochodzące z <a href=\"https://pl.wikipedia.org/wiki/Dialekt_prowansalski\" target=\"_blank\" rel=\"noopener noreferrer\">dialektu prowansalskiego</a> <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_oksyta%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">języka oksytańskiego</a>, od imienia <i>Mirèio</i>. Zostało ono użyte po raz pierwszy w <a href=\"https://pl.wikipedia.org/wiki/Mirejo\" target=\"_blank\" rel=\"noopener noreferrer\">jednym z poematów</a> przez poetę <a href=\"https://pl.wikipedia.org/wiki/Fr%C3%A9d%C3%A9ric_Mistral\" target=\"_blank\" rel=\"noopener noreferrer\">Frédérica Mistrala</a>, który wywiódł <i>Mirèio</i> prawdopodobnie od słowa <i>mirar</i>, w dialekcie <a href=\"https://pl.wikipedia.org/wiki/Prowansja\" target=\"_blank\" rel=\"noopener noreferrer\">prowansalskim</a> oznaczającego „podziwiana” (z <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <i>mirare</i> „podziwiać”). Mirela może także stanowić skrócenie włoskiego imienia <i>Mirabella</i>.", "Md Asif": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Tanvir": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Maro": "<b>Maro</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> oznaczające urzędnika municypalnego. Przekształciło się ono z czasem w cognomen, które nosił na przykład <a href=\"https://pl.wikipedia.org/wiki/Wergiliusz\" target=\"_blank\" rel=\"noopener noreferrer\">Publiusz Wergilusz Maro</a>.", "Md Farhad": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Maycon": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maicon</b>.</p><p>Maicon to brazylijskie odmianie nazwiska Michaela. Może odnosić się do:</p>", "Mohana Rao": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohana</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mohan</b>.</p><p>Mohan to gmin i nagar panchayat z okręgu Unnao w stanie Uttar Pradesh, India.</p>", "Md Mahadi": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Khairul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Anowar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Miloje": "<p>Miloje to serbskie imię męskie pochodzenia słowiańskiego. Może odnosić się do: Miloje Miletić (ur. 1953), generał Miloje Milojević (1884-1946), muzykiem Miloje Petković (ur., 1967), emerytem piłkarzem Miloje Preković (urat. 1991), bramkarzem piłki nożnej</p>", "Meliton": "<b>Meliton</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, utworzone od wyrazu pospolitego méli, -itos 'miód' za pomocą <a href=\"https://pl.wikipedia.org/wiki/Przyrostek\" target=\"_blank\" rel=\"noopener noreferrer\">przyrostka</a> -n, oznaczające 'człowieka jak miód'. Patronem imienia jest <a href=\"https://pl.wikipedia.org/wiki/Meliton_z_Sardes\" target=\"_blank\" rel=\"noopener noreferrer\">Meliton z Sardes</a>, święty z II wieku.", "Md Mosharaf": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Jahangir": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Matko": "<p>Matko to chorwackie imię i nazwisko, które mogą odnosić się do: Matko Babić (ur. 1998), chorwacki piłkarz Matko Djarmati (ur. 1982), chorwackiego piłkarza Matko Jelavić (ur., 1958), chorwackich piosenkarza, pisarza piosenek, kompozytora i perkusistki Matko Laginja (1852-1930), chorwańskiego prawnika i polityka Matko Obradović (ur.).</p>", "Michael John": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Michael</b>.</p><p>Michael: Botanika Michael - skrócie botaniczne, oznaczające, że autorem taksy jest Edmund Michael. Muzyka ⁇ Michael ⁇ - piosenka grupy Franz Ferdinand, wydana w 2004 roku.</p>", "Maric": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Marik</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Marika</b>.</p><b>Marika</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzące od imienia „<a href=\"https://pl.wikipedia.org/wiki/Maria\" target=\"_blank\" rel=\"noopener noreferrer\">Maria</a>”. Jest <a href=\"https://pl.wikipedia.org/wiki/W%C4%99gry\" target=\"_blank\" rel=\"noopener noreferrer\">węgierską</a> formą tego imienia, chociaż znane jest także w Bułgarii i na terenie byłej Jugosławii. Imię jest również zniemczoną formą zdrobnienia „Maryjka” występującego w <a href=\"https://pl.wikipedia.org/wiki/Etnolekt_%C5%9Bl%C4%85ski\" target=\"_blank\" rel=\"noopener noreferrer\">etnolekcie śląskim</a>.", "Marcellin": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Marcelin</b>.</p><b>Marcelin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, utworzone od imienia <a href=\"https://pl.wikipedia.org/wiki/Marceli\" target=\"_blank\" rel=\"noopener noreferrer\">Marceli</a> za pomocą sufiksu oznaczającego przynależność lub pochodzenie. Istniało wielu świętych o tym imieniu.", "Muhannad": "<p>Mohannad (zwrócony również jako Mohanad, Mohanned, Mohaned, Muhannad lub Muhanned; arabski: مهند) to męskie arabskie imię. Mohannad lub jego odmiany mogą odnosić się do:</p>", "Montana": "Nazwa prawdopodobnie pochodzi od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hiszpa%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">hiszpańskiego</a> słowa <em>montaña</em>, które znaczy „góra”. Chociaż Montana kojarzona jest przede wszystkim z położonymi na jej obszarze górami, około 60% terytorium stanu pokrywa <a href=\"https://pl.wikipedia.org/wiki/Preria\" target=\"_blank\" rel=\"noopener noreferrer\">preria</a>, wchodząca w skład <a href=\"https://pl.wikipedia.org/wiki/Wielkie_R%C3%B3wniny\" target=\"_blank\" rel=\"noopener noreferrer\">Wielkich Równin</a>. Region nazywany jest „Stanem Skarbów” (<em>Treasure State</em>) ze względu na jego ogromne bogactwo mineralne, a także „Krainą lśniących gór” (<em>Land of the Shining Mountains</em>) i „Krainą wielkiego nieba” (<em>Big Sky Country</em>). Zróżnicowana gospodarka Montany historycznie bazuje na rolnictwie, górnictwie i przemyśle drzewnym. W XXI wieku na znaczeniu zyskały usługi, finanse, nieruchomości, czy turystyka. W Montanie znajduje się <a href=\"https://pl.wikipedia.org/wiki/Park_Narodowy_Glacier_(USA)\" target=\"_blank\" rel=\"noopener noreferrer\">Park Narodowy Glacier</a> oraz północny, niewielki fragment <a href=\"https://pl.wikipedia.org/wiki/Park_Narodowy_Yellowstone\" target=\"_blank\" rel=\"noopener noreferrer\">Parku Narodowego Yellowstone</a>. Przez stan przechodzi <a href=\"https://pl.wikipedia.org/wiki/Wododzia%C5%82_kontynentalny_Ameryki\" target=\"_blank\" rel=\"noopener noreferrer\">wododział kontynentalny Ameryki</a>.", "Minh Tiến": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Md Mahbubur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mario Alejandro": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mario</b>.</p><p>Mario (jap. Mario Mario, angielski.</p>", "Minh Thanh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Md Rashedul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Merey": "<p>Merey jest gminą w prowincji Eure w północnej Francji.</p>", "Marian Andrzej": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marian</b>.</p><b>Marian</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> od imienia <i>Marius</i> lub nazwy rodu <i>Marii</i>. Oznacza „należący do Mariusza, rodu Mariuszów”. Występuje w Polsce od 1332 roku, jako <b>Marzyjan</b>. Forma Marian pojawiła się w Polsce w XVI wieku. W języku angielskim używane jest jako imię żeńskie. W Polsce w żeńskim użyciu w 2025 roku wystąpiło 35 razy.", "Md Anisur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Munish Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Munish</b>.</p><p>Munish może odnosić się do: Munish Arora (ur. 1971), indyjski-ur. singapurski kryker Munish Jolly (ur. 1974), indyjskiego byłego krykera Munish Makhija (ur. 1968), indyskiego video jockey Munish Chander Puri (1939-2005), byłego profesora emerytum matematyki w IIT Delhi</p>", "Marius-Mihai": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marius</b>.</p>Pochodził z niższych warstw społecznych, miał być z zawodu rzemieślnikiem (kowalem), później przypuszczalnie służył w wojsku, lecz nie wiadomo w jakiej funkcji. Po stłumionej w początkach 269 roku rewolcie <a href=\"https://pl.wikipedia.org/wiki/Lelian_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Leliana</a> wzniecił kolejny bunt w <a href=\"https://pl.wikipedia.org/wiki/Moguncja\" target=\"_blank\" rel=\"noopener noreferrer\">Mogontiacum</a> przeciwko władzy <a href=\"https://pl.wikipedia.org/wiki/Wiktoryn_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Wiktoryna</a>, następcy <a href=\"https://pl.wikipedia.org/wiki/Postumus\" target=\"_blank\" rel=\"noopener noreferrer\">Postuma</a>. Według <i><a href=\"https://pl.wikipedia.org/wiki/Historia_Augusta\" target=\"_blank\" rel=\"noopener noreferrer\">Historia Augusta</a></i> jego rządy trwały zaledwie 2-3 dni, czemu jednak przeczy zachowana liczba jego monet. Najpewniej w mennicy w <a href=\"https://pl.wikipedia.org/wiki/Kolonia_(Niemcy)\" target=\"_blank\" rel=\"noopener noreferrer\">Kolonii</a> (<i>Colonia Agrippina</i>) <a href=\"https://pl.wikipedia.org/wiki/Emisja_pieni%C4%85dza\" target=\"_blank\" rel=\"noopener noreferrer\">emitował</a> w swym imieniu niskowartościowe <a href=\"https://pl.wikipedia.org/wiki/Antoninian\" target=\"_blank\" rel=\"noopener noreferrer\">antoniniany</a> typów: AEQUITAS, CONCORDIA MILIT(um), SAEC(uli) FELICITAS, VICTORIA AUG(usti), VIRTUS AUG(usti).", "Mścibór": "<b>Mścibor</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z dwóch członów: <i>Mści-</i> („mścić”) i <i>-bor</i> („walczyć, zmagać się”). Mogło oznaczać „tego, który mści się bojem”.", "Mislav": "<p>Mislav jest sławskim imieniem męskim w Chorwacji. Do wybitnych osób z tym nazwiskiem należą: Mislav, książę Chorwacji (fl.</p>", "Mohamed Lamine": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohamed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Milosav": "<p>Milosav (Serbski: Милосав) to serbskie męskie imię. Do wybitnych osób z nazwą należą: Milosav Jelić (1883-1947), serbski chetnik i poeta Milosav Jovanović (1935-2014), serbski artysta Milosav Lapovac (1770-1844), serbski rewolucjonarz Milosav Miličković (ur. 1959), serbski polityk Milosav Milojević (ur., 1954), serbski politik Milosav Sićović (ur. 1999), serbski piłkarz Milosaw Zdravković (1787-1854), serbski...</p>", "Mitrofan": "<b>Metrofan</b> — <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia greckiego, <a href=\"https://pl.wikipedia.org/wiki/Gr.\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> <i>Μητροφανης</i>, złożone z członów <i>μητηρ (meter)</i> — \"matki\" i <i>φανης (phanes)</i> — \"pojawienie się, objawienie się\", co oznacza \"objawienie matki\". Patronem tego imienia jest św. Metrofan, biskup <a href=\"https://pl.wikipedia.org/wiki/Cesarstwo_Bizanty%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">Bizancjum</a> (III–IV wiek). U Słowian wschodnich imię to rozpowszechniło się w formie <i><b>Mitrofan</b></i>.", "Md Helal": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Marco Tulio": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marco</b>.</p><b>Marek</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, należące do wąskiej grupy najstarszych <a href=\"https://pl.wikipedia.org/wiki/Imiona_%C5%82aci%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imion rzymskich</a> (imion właściwych, <i>praenomen</i>, por. <a href=\"https://pl.wikipedia.org/wiki/Tyberiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Tyberiusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Aulus\" target=\"_blank\" rel=\"noopener noreferrer\">Aulus</a>, <a href=\"https://pl.wikipedia.org/wiki/Maniusz\" target=\"_blank\" rel=\"noopener noreferrer\">Maniusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Gajusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Gajusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Lucjusz\" target=\"_blank\" rel=\"noopener noreferrer\">Lucjusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Publiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Publiusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Tytus\" target=\"_blank\" rel=\"noopener noreferrer\">Tytus</a>, <a href=\"https://pl.wikipedia.org/wiki/Serwiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Serwiusz</a>), utworzone z <i>*Mart-ico-s</i> od imienia boga <i><a href=\"https://pl.wikipedia.org/wiki/Mars_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Mars</a></i>, <i>Martis</i> i oznaczające „należący do Marsa, związany z Marsem”. W Polsce imię to jest notowane od <a href=\"https://pl.wikipedia.org/wiki/XIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIII wieku</a>, choć poza współczesnością nie było często spotykane, w formach <i><b>Marek</b></i>, <i><b>Marko</b></i>, <i><b>Margusz</b></i>, <i><b>Markusz</b></i>, <i><b>Merkusz</b></i>. Zapisana została także żeńska <b>Marka</b> (<a href=\"https://pl.wikipedia.org/wiki/1263\" target=\"_blank\" rel=\"noopener noreferrer\">1263</a>) – żeński odpowiednik imienia Marek lub zdrobnienie od imion żeńskich rozpoczynających się na Mar-, takich jak <i>Margorzata</i> (= <a href=\"https://pl.wikipedia.org/wiki/Ma%C5%82gorzata_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Małgorzata</a>) lub <a href=\"https://pl.wikipedia.org/wiki/Maria\" target=\"_blank\" rel=\"noopener noreferrer\">Maria</a> – oraz <a href=\"https://pl.wikipedia.org/wiki/Markus%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Markusław</a>, staropolskie imię utworzone od imienia Marek poprzez dodanie typowej dla imion słowiańskich cząstki -sław. Imię to według danych 2022 r. jest na 10 miejscu najpopularniejszych imion męskich.", "Miika": "<p>Miika to fińskie imię męskie. Do wybitnych osób z nazwiskiem należą: Miika Elomo (1977-2025), fiński hokejista na lodzie Miika Koivisto (urodzony 1990), fiński tenisista na lodze Miika Koppinen (urodzona 1978), fiński obrońca piłki nożnej Miika Tenkula (1974-2009), fiński muzyka heavy metalowy Miika Wiikman (urodzono 1984), fiński goliard w hokeju na lodzie</p>", "Matyás": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Matias</b>.</p><p>Matías to portugalska wersja Matthias. Matías jest bardzo popularny w Ameryce Łacińskiej, zwłaszcza w Argentynie.</p>", "Mohamed Elsayed": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohamed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Mairbek": "<p>Mairbek to czeskie imię męskie. Wśród znanych osób z nazwiskiem są: Mairbek Sheripov (1905-1942), czechenski przywódca Mairbek Taisumov (ur. 1988), czechenijski artysta walki mieszanej Mairbek Vatchagaev (ur. 1965), czeczenijski historyk i analityk polityczny</p>", "Maria Michał": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Marian Józef": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marian</b>.</p><b>Marian</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> od imienia <i>Marius</i> lub nazwy rodu <i>Marii</i>. Oznacza „należący do Mariusza, rodu Mariuszów”. Występuje w Polsce od 1332 roku, jako <b>Marzyjan</b>. Forma Marian pojawiła się w Polsce w XVI wieku. W języku angielskim używane jest jako imię żeńskie. W Polsce w żeńskim użyciu w 2025 roku wystąpiło 35 razy.", "Md Zahirul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Minh Quang": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Md Sajib": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Minh Thang": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Marius-Ionut": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marius</b>.</p>Pochodził z niższych warstw społecznych, miał być z zawodu rzemieślnikiem (kowalem), później przypuszczalnie służył w wojsku, lecz nie wiadomo w jakiej funkcji. Po stłumionej w początkach 269 roku rewolcie <a href=\"https://pl.wikipedia.org/wiki/Lelian_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Leliana</a> wzniecił kolejny bunt w <a href=\"https://pl.wikipedia.org/wiki/Moguncja\" target=\"_blank\" rel=\"noopener noreferrer\">Mogontiacum</a> przeciwko władzy <a href=\"https://pl.wikipedia.org/wiki/Wiktoryn_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Wiktoryna</a>, następcy <a href=\"https://pl.wikipedia.org/wiki/Postumus\" target=\"_blank\" rel=\"noopener noreferrer\">Postuma</a>. Według <i><a href=\"https://pl.wikipedia.org/wiki/Historia_Augusta\" target=\"_blank\" rel=\"noopener noreferrer\">Historia Augusta</a></i> jego rządy trwały zaledwie 2-3 dni, czemu jednak przeczy zachowana liczba jego monet. Najpewniej w mennicy w <a href=\"https://pl.wikipedia.org/wiki/Kolonia_(Niemcy)\" target=\"_blank\" rel=\"noopener noreferrer\">Kolonii</a> (<i>Colonia Agrippina</i>) <a href=\"https://pl.wikipedia.org/wiki/Emisja_pieni%C4%85dza\" target=\"_blank\" rel=\"noopener noreferrer\">emitował</a> w swym imieniu niskowartościowe <a href=\"https://pl.wikipedia.org/wiki/Antoninian\" target=\"_blank\" rel=\"noopener noreferrer\">antoniniany</a> typów: AEQUITAS, CONCORDIA MILIT(um), SAEC(uli) FELICITAS, VICTORIA AUG(usti), VIRTUS AUG(usti).", "Marius-Alexandru": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marius</b>.</p>Pochodził z niższych warstw społecznych, miał być z zawodu rzemieślnikiem (kowalem), później przypuszczalnie służył w wojsku, lecz nie wiadomo w jakiej funkcji. Po stłumionej w początkach 269 roku rewolcie <a href=\"https://pl.wikipedia.org/wiki/Lelian_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Leliana</a> wzniecił kolejny bunt w <a href=\"https://pl.wikipedia.org/wiki/Moguncja\" target=\"_blank\" rel=\"noopener noreferrer\">Mogontiacum</a> przeciwko władzy <a href=\"https://pl.wikipedia.org/wiki/Wiktoryn_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Wiktoryna</a>, następcy <a href=\"https://pl.wikipedia.org/wiki/Postumus\" target=\"_blank\" rel=\"noopener noreferrer\">Postuma</a>. Według <i><a href=\"https://pl.wikipedia.org/wiki/Historia_Augusta\" target=\"_blank\" rel=\"noopener noreferrer\">Historia Augusta</a></i> jego rządy trwały zaledwie 2-3 dni, czemu jednak przeczy zachowana liczba jego monet. Najpewniej w mennicy w <a href=\"https://pl.wikipedia.org/wiki/Kolonia_(Niemcy)\" target=\"_blank\" rel=\"noopener noreferrer\">Kolonii</a> (<i>Colonia Agrippina</i>) <a href=\"https://pl.wikipedia.org/wiki/Emisja_pieni%C4%85dza\" target=\"_blank\" rel=\"noopener noreferrer\">emitował</a> w swym imieniu niskowartościowe <a href=\"https://pl.wikipedia.org/wiki/Antoninian\" target=\"_blank\" rel=\"noopener noreferrer\">antoniniany</a> typów: AEQUITAS, CONCORDIA MILIT(um), SAEC(uli) FELICITAS, VICTORIA AUG(usti), VIRTUS AUG(usti).", "Minh Hải": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Mara": "<b>Mara</b> – włoskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> (hebr. מָרָא), występujące w <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starym Testamencie</a>.", "Mailo": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mail</b>.</p><p>Mail (⁇ poczta ⁇): Electronic mail (poczta elektroniczna) - technologia i świadczone przez nią usługi wysyłania i otrzymywania wiadomości elektronicznych (⁇ pisma ⁇) w rozproszonym (w tym globalnym) sieci komputerowej. mail (programowanie) - klient pocztowy dla systemów operacyjnych podobnych do Unix, który działa w trybie konsolnym.</p>", "Michael Alexander": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Michael</b>.</p><p>Michael: Botanika Michael - skrócie botaniczne, oznaczające, że autorem taksy jest Edmund Michael. Muzyka ⁇ Michael ⁇ - piosenka grupy Franz Ferdinand, wydana w 2004 roku.</p>", "Mohammed Ali": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammed</b>.</p><p>Muhammad - muzułmańskie imię i nazwisko. Mahomet jest islamskim prorokiem.</p>", "Mihai-Bogdan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mihai</b>.</p><p>Mihai (rumuńska wymowa: [miˈhaj]) jest rumuńskim nazwiskiem męskim lub nazwiskiem. To równoważne angielskiej imienia Michael.</p>", "Mihnea": "<p>Mihnea jest rumuńskim językiem męskim, które może odnosić się do: Mihnea cel Rău Mihnea Turcitul Mihnea III Mihnea Chioveanu Mihnea Motoc Mihnea-Ion Năstase Mihnea Popa</p>", "Md Masum": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mikha": "<p>Micha (; hebrajskie: מִיכָה, nowoczesne: Mikha, tyberyjskie: Mî ⁇ ā) jest nazwiskiem. Micha jest nazwiskiem kilku ludzi w Tanakh, co oznacza \"Kto jest jak Bóg? \"Przecież to prawda\".</p>", "Miłorad": "<b>Miłorad</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie złożone z członów <i>Miło-</i> (\"miły\") i <i>-rad</i> (\"być zadowolonym, chętnym, cieszyć się\").", "Milomir": "<p>Milomir (bułgarski: Миломир, rosyjski: Миломір, czeski: Milomír, serbski cyrylski: Миламир) jest słowiańskie męskie imię, słowiańska nazwa pochodząca od milo \"miłość, lubić\" i mir \"świat, pokój, prestiż\". Może odnosić się do: Milomira Kovaca, serbsko-niemieckiego lekarza weterynaryjnego Milomira Marić, serbskiego dziennikarza Milomira Miljanić, murzynskiego muzyka Milomira Minić, serbskiego polityka Milomira Odović, bosniackiego menedżera piłki nożnej i byłego gracza Milomira...</p>", "Manabu": "<b>Manabu</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;まなぶ, マナブ) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Madan Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Madan</b>.</p><p>Madan jest miastem w prowincji Smolyan, Bungaria. W 2011 roku liczba ludności wynosiła 5791.</p>", "Md Billal": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Mahmudul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mico": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Miko</b>.</p><p>Węwice (巫女, Miko) to imię oznaczające \"trzymujący świątynię; święta pani\" służąca w templu Sześcian (świątyni Świątyni) w Japonii. Wcześniej Vu-Wem oznaczała \"wiastywa, męża, prorok\" i \"wiastwo proroków\".</p>", "Md Kawsar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Matwey": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Matvey</b>.</p><p>Matvei lub Matvey (Матвей) jest rosyjską wersją Mateusza. Wśród znanych osób z nazwy są: Matvey Blanter (1903-1990), rosyjski kompozytor muzyki popularnej i filmowej Matvei Bronstein (1906-1938), radziecki fizyk teoretyczny Matvey Frantskevich (ur. 1995), białoruski piłkarz Matvei Gedenshtrom (r.</p>", "Marius-Nicolae": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marius</b>.</p>Pochodził z niższych warstw społecznych, miał być z zawodu rzemieślnikiem (kowalem), później przypuszczalnie służył w wojsku, lecz nie wiadomo w jakiej funkcji. Po stłumionej w początkach 269 roku rewolcie <a href=\"https://pl.wikipedia.org/wiki/Lelian_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Leliana</a> wzniecił kolejny bunt w <a href=\"https://pl.wikipedia.org/wiki/Moguncja\" target=\"_blank\" rel=\"noopener noreferrer\">Mogontiacum</a> przeciwko władzy <a href=\"https://pl.wikipedia.org/wiki/Wiktoryn_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Wiktoryna</a>, następcy <a href=\"https://pl.wikipedia.org/wiki/Postumus\" target=\"_blank\" rel=\"noopener noreferrer\">Postuma</a>. Według <i><a href=\"https://pl.wikipedia.org/wiki/Historia_Augusta\" target=\"_blank\" rel=\"noopener noreferrer\">Historia Augusta</a></i> jego rządy trwały zaledwie 2-3 dni, czemu jednak przeczy zachowana liczba jego monet. Najpewniej w mennicy w <a href=\"https://pl.wikipedia.org/wiki/Kolonia_(Niemcy)\" target=\"_blank\" rel=\"noopener noreferrer\">Kolonii</a> (<i>Colonia Agrippina</i>) <a href=\"https://pl.wikipedia.org/wiki/Emisja_pieni%C4%85dza\" target=\"_blank\" rel=\"noopener noreferrer\">emitował</a> w swym imieniu niskowartościowe <a href=\"https://pl.wikipedia.org/wiki/Antoninian\" target=\"_blank\" rel=\"noopener noreferrer\">antoniniany</a> typów: AEQUITAS, CONCORDIA MILIT(um), SAEC(uli) FELICITAS, VICTORIA AUG(usti), VIRTUS AUG(usti).", "Md Rayhan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Madhava": "<b>Madhava</b> (ur. <a href=\"https://pl.wikipedia.org/wiki/1340\" target=\"_blank\" rel=\"noopener noreferrer\">1340</a>, zm. <a href=\"https://pl.wikipedia.org/wiki/1425\" target=\"_blank\" rel=\"noopener noreferrer\">1425</a>) – <a href=\"https://pl.wikipedia.org/wiki/Indie\" target=\"_blank\" rel=\"noopener noreferrer\">indyjski</a> <a href=\"https://pl.wikipedia.org/wiki/Matematyk\" target=\"_blank\" rel=\"noopener noreferrer\">matematyk</a> i <a href=\"https://pl.wikipedia.org/wiki/Astronom\" target=\"_blank\" rel=\"noopener noreferrer\">astronom</a> pochodzący z miejscowości Sangamagramma położonej w północno-zachodnich Indiach (dzisiejsza <a href=\"https://pl.wikipedia.org/wiki/Kerala\" target=\"_blank\" rel=\"noopener noreferrer\">Kerala</a>); wniósł pionierski wkład w badania nad <a href=\"https://pl.wikipedia.org/wiki/Szereg_(matematyka)\" target=\"_blank\" rel=\"noopener noreferrer\">szeregami nieskończonymi</a>, <a href=\"https://pl.wikipedia.org/wiki/Analiza_matematyczna\" target=\"_blank\" rel=\"noopener noreferrer\">analizą matematyczną</a>, <a href=\"https://pl.wikipedia.org/wiki/Trygonometria\" target=\"_blank\" rel=\"noopener noreferrer\">trygonometrią</a>, <a href=\"https://pl.wikipedia.org/wiki/Geometria\" target=\"_blank\" rel=\"noopener noreferrer\">geometrią</a> i <a href=\"https://pl.wikipedia.org/wiki/Algebra\" target=\"_blank\" rel=\"noopener noreferrer\">algebrą</a>.", "Md Akram": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Minh Sang": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Md Mahedi": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mohnish": "<p>Mohnish to męskie imię pochodzące z Indii. Nazwa oznacza \"Pan Krishna\".</p>", "Melori": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Melor</b>.</p><b>Melsor</b> (ros. Мэлсор) – imię, będące akronimem powstałe od pierwszych liter: <a href=\"https://pl.wikipedia.org/wiki/Karl_Marx\" target=\"_blank\" rel=\"noopener noreferrer\"><b>M</b>arks</a>-<a href=\"https://pl.wikipedia.org/wiki/Friedrich_Engels\" target=\"_blank\" rel=\"noopener noreferrer\"><b>E</b>ngels</a>-<a href=\"https://pl.wikipedia.org/wiki/W%C5%82odzimierz_Lenin\" target=\"_blank\" rel=\"noopener noreferrer\"><b>L</b>enin</a>-<a href=\"https://pl.wikipedia.org/wiki/J%C3%B3zef_Stalin\" target=\"_blank\" rel=\"noopener noreferrer\"><b>S</b>talin</a>-<a href=\"https://pl.wikipedia.org/wiki/Rewolucja_pa%C5%BAdziernikowa\" target=\"_blank\" rel=\"noopener noreferrer\"><b>O</b>ktiabr'skaja <b>R</b>iewolucyja</a>. Po śmierci Stalina, tezach wygłoszonych na <a href=\"https://pl.wikipedia.org/wiki/XX_Zjazd_KPZR\" target=\"_blank\" rel=\"noopener noreferrer\">XX Zjeździe KPZR</a> z imienia Melsor usunięto literę „s”, zmieniając je na Melor: <b>M</b>arks-<b>E</b>ngels-<b>L</b>enin-<b>O</b>ktiabr'skaja <b>R</b>iewolucyja.", "Md Jashim": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Muhammed Suhail": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Marthin": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Martin</b>.</p><p>William Charles Lynne Martin (1798 - 1864) - angielski naturalista. Martin był kuratorem muzeum London Zoological Society od 1830 do 1838 roku, aż do czasu, gdy stracił pracę w wyniku zmniejszenia finansowania.</p>", "Myhail": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mihail</b>.</p><p>Mihai (rumuńska wymowa: [miˈhaj]) jest rumuńskim nazwiskiem męskim lub nazwiskiem. To równoważne angielskiej imienia Michael.</p>", "Md Razib": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mohammad Arif": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Md Shakil": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Miikka": "<p>Miikka to fińska nazwa następujących osób: Miikka Anttila (ur. 1972), fiński ko-kierowca rally Miikka Ilo (ur. 1982), fiński piłkarz Miikka Kiprusoff (ur. 1976), fiński hokejista Miikka Männikkö (ur. 1979), fiński gracz hokeja na lodzie Miikka Mujunen (ur. 1996), fiński futbolista Miikka Multaharju (ur. 1977), fiński Piłkarz miikka Muurinen (ur. 2007), fiński koszykarz Miikk Oinonen (ur. 1983), fiński...</p>", "Mia": "<b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maziar": "<p>Maziar (persk: مازیار) to perskie imię męskie. Wśród znanych osób z imieniem Maziar są: Mazyar, irański książę z dynastii Qarinvand Maziar (1952-1997), irański piosenkarz Mazyar Asadi (ur. 1979), irański fotograf Maziar Bahari (ur. 1967), irański kanadyjski dziennikarz, filmowiec i działacz w dziedzinie praw człowieka Maziar Behrooz (ur. 1959), irański historyk Maziar Ashrafian Bonab (ur. 1966), irański...</p>", "Md Delowar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mohammad Reza": "<p>Mohammad-Reza (persk. محمدرضا, również pisane jako Mohammad Reza lub Mohammadreza) to popularne imię w Iranie. Mohammad i Reza to arabskie nazwiska, które są popularne na całym świecie muzułmańskim.</p>", "Michio": "<b>Michio</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;道雄 lub 通夫) – męskie imię japońskie.", "Mihai-Răzvan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mihai</b>.</p><p>Mihai (rumuńska wymowa: [miˈhaj]) jest rumuńskim nazwiskiem męskim lub nazwiskiem. To równoważne angielskiej imienia Michael.</p>", "Marian-Daniel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marian</b>.</p><b>Marian</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> od imienia <i>Marius</i> lub nazwy rodu <i>Marii</i>. Oznacza „należący do Mariusza, rodu Mariuszów”. Występuje w Polsce od 1332 roku, jako <b>Marzyjan</b>. Forma Marian pojawiła się w Polsce w XVI wieku. W języku angielskim używane jest jako imię żeńskie. W Polsce w żeńskim użyciu w 2025 roku wystąpiło 35 razy.", "Muhammad Usman": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammad</b>.</p><b>Muhammad</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;مُحَمَّد&#8206;) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wariantami tego imienia są: Mohammed, Mehmed, Mamadu i Mahomet.", "Mohammed S": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammed</b>.</p><p>Muhammad - muzułmańskie imię i nazwisko. Mahomet jest islamskim prorokiem.</p>", "Michael David": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Michael</b>.</p><p>Michael: Botanika Michael - skrócie botaniczne, oznaczające, że autorem taksy jest Edmund Michael. Muzyka ⁇ Michael ⁇ - piosenka grupy Franz Ferdinand, wydana w 2004 roku.</p>", "Md Mojibur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Marcos Antonio": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marcos</b>.</p><p>Marcos - brytyjski producent samochodów, który wyprodukował samochody sportowe w latach 1959-2007. Nazwa firmy powstała z pierwszych liter nazwisk współzałożycieli.</p>", "Maria Antoni": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mukti": "<b>Mukti</b> (<a href=\"https://pl.wikipedia.org/wiki/Pismo_dewanagari\" target=\"_blank\" rel=\"noopener noreferrer\">dewanagari</a> मुक्ति) – termin <a href=\"https://pl.wikipedia.org/wiki/Filozofia_indyjska\" target=\"_blank\" rel=\"noopener noreferrer\">filozofii indyjskiej</a> oznaczający <a href=\"https://pl.wikipedia.org/wiki/Wyzwolenie_w_hinduizmie\" target=\"_blank\" rel=\"noopener noreferrer\">wyzwolenie</a> w doktrynach <a href=\"https://pl.wikipedia.org/wiki/Upaniszady\" target=\"_blank\" rel=\"noopener noreferrer\">Upaniszad</a> oraz <a href=\"https://pl.wikipedia.org/wiki/Wedanta\" target=\"_blank\" rel=\"noopener noreferrer\">wedanty</a>.", "Melor": "<b>Melsor</b> (ros. Мэлсор) – imię, będące akronimem powstałe od pierwszych liter: <a href=\"https://pl.wikipedia.org/wiki/Karl_Marx\" target=\"_blank\" rel=\"noopener noreferrer\"><b>M</b>arks</a>-<a href=\"https://pl.wikipedia.org/wiki/Friedrich_Engels\" target=\"_blank\" rel=\"noopener noreferrer\"><b>E</b>ngels</a>-<a href=\"https://pl.wikipedia.org/wiki/W%C5%82odzimierz_Lenin\" target=\"_blank\" rel=\"noopener noreferrer\"><b>L</b>enin</a>-<a href=\"https://pl.wikipedia.org/wiki/J%C3%B3zef_Stalin\" target=\"_blank\" rel=\"noopener noreferrer\"><b>S</b>talin</a>-<a href=\"https://pl.wikipedia.org/wiki/Rewolucja_pa%C5%BAdziernikowa\" target=\"_blank\" rel=\"noopener noreferrer\"><b>O</b>ktiabr'skaja <b>R</b>iewolucyja</a>. Po śmierci Stalina, tezach wygłoszonych na <a href=\"https://pl.wikipedia.org/wiki/XX_Zjazd_KPZR\" target=\"_blank\" rel=\"noopener noreferrer\">XX Zjeździe KPZR</a> z imienia Melsor usunięto literę „s”, zmieniając je na Melor: <b>M</b>arks-<b>E</b>ngels-<b>L</b>enin-<b>O</b>ktiabr'skaja <b>R</b>iewolucyja.", "Md Saidul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Zahid": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Ruhul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Rajib": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Selim": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Marinko": "<p>Marinko (czyli: Маринко) to męskie imię i nazwisko. Może odnosić się do: Marinko Čavara (ur. 1967), polityka Marinko Galič (ur. 1970), piłkarz Marinko Jurendic (ur. 1977), piłka nożna i trener Marinko Kekezović (ur. 1985), piłkownik ręczny Marinko Koljanin (ur. 1957), piłkapocieł Marinko Mačkić (ur., 1983), piłkę nożna Marinko Madžgalj (1978-2016), aktor Marinko Magda (ur. 1963), zabójca Marinko Matosevic (ur. 1985)...</p>", "Moustafa Mohamed": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Moustafa</b>.</p><p>Mustafa (arabski: مصطفى, romanized: Muṣṭafā) jest jednym z imion islamskiego proroka Mahometa. W arabskim oznacza \"wybrany, wybrany, wyznaczony, preferujący\".</p>", "Min Ho": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Min</b>.</p><p>Min to niejednoznaczny termin. min - w matematyce i językach programowania oznacza funkcję wyboru najmniejszego ze swoich argumentów, (Min (3, 6, 2) = 2).</p>", "Mohammad Sohag": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Md Azizur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mohammad Sohel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Mohammed Abu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammed</b>.</p><p>Muhammad - muzułmańskie imię i nazwisko. Mahomet jest islamskim prorokiem.</p>", "Miao": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mia</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Md Robel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Maria Stanisław": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mohammad Hossein": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Momodou": "<p>Momodou to gambijska nazwisko, które może odnosić się do: Momodou Alieu Bah, gambijski starszy oficer wojskowy Momodou Baboucar Njie (1929-2009), gambijski polityk Momodou Ceesay (urodzony 1988), gambijski piłkarz Momodou Cesay (artysta) (urodzona 1945), gambijska artysta i pisarka Momodou L. K.</p>", "Mykhailo-Oleksandr": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mykhailo</b>.</p><p>Mykhailo lub Mykhaylo to ukraińskie męskie imię, równoważne angielskim Michałowi. Wśród znanych osób z nazwiskiem są: Mykhaylo Berkos (1861-1919), rosyjski i ukraiński artysta pochodzenia greckiego Mykhayilo Bolotskykh (ur. 1960), ukraiński polityk i wojskowy, pułkownik generalny (Służba Obrony Cywilnej) Mykhayło Brodskyy (ur. 1959), ukraiński polityk, przywódca Partii Wolnych Demokratów i biznesmen Mykhayla Chemberzhi,...</p>", "Md Jamal": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mohammad Saidul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Minh Quý": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Micheál": "<p>Micheal to męskie imię. Czasami jest to anglicizowana forma irlandzkiego imienia Micheál, Mícheál i Michéal; lub szkockiego gaelickiego imienia Mìcheal.</p>", "Muhsen": "<p>Muhsin (zwanego również Mohsen, Mohsin, Mehsin lub Muhsen, arabski: محسن) jest męskim arabskim nazwiskiem. Pierwszą osobą, o której wiadomo, że nosi nazwę \"Muhsin\", był Muhsin ibn Ali, syn Ali ibn Abi Talib i Fatimah bint Muhammad.</p>", "Mitsuru": "<b>Mitsuru</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;みつる, ミツル) – głównie męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>, bardzo rzadko noszone przez kobiety.", "Md Amir": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mohammad Jahangir": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Md Arifur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mohamed Anis": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohamed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Miroljub": "<p>Miroljub (cyrylicki: Мирољуб) jest słowiańskim męskim imieniem używanym w językach sławskich południowych, zwłaszcza w języku serbskim. Nazwa składa się z słowiańskich elementów mir (\"pokój\") i ljub (\"miłość\"), co oznacza \"miłujące pokojowo\" lub \"koś, kto kocha pokój\".</p>", "Manuel Enrique": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Manuel</b>.</p><b>Emanuel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od słowa עִמָּנוּאֵל oznaczającego „Bóg z nami”. Imię mesjasza oraz kilku świętych katolickich. Żeński odpowiednik to <a href=\"https://pl.wikipedia.org/wiki/Emanuela\" target=\"_blank\" rel=\"noopener noreferrer\">Emanuela</a>.", "Mei": "<p>- Nie, nie, nie. Mei - Mei (dinosaur) MEI - Matsushita Electric Industrial Co.</p>", "Moacir": "<p>Moacir, również pisany jako Moacyr (portugalskie wymowa: [moa'siɾ] lub [moa'ssiʁ]), to brazylijskie męskie imię pochodzenia rdzennego (z języków Tupi-Guarani) i postać brazylijskiej powieści Iracema. Wśród znanych osób z nazwiskiem są: Moacir Santos (1926-2006), brazylijski muzyk i kompozytor, znany z albumu jazzowego Coisas Moacir Barbosa Nascimento (1921-2000), zwany Barbosa, brazylijczyk piłkarz Moacyr Claudino...</p>", "Md Jasim": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Manuel Eduardo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Manuel</b>.</p><b>Emanuel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od słowa עִמָּנוּאֵל oznaczającego „Bóg z nami”. Imię mesjasza oraz kilku świętych katolickich. Żeński odpowiednik to <a href=\"https://pl.wikipedia.org/wiki/Emanuela\" target=\"_blank\" rel=\"noopener noreferrer\">Emanuela</a>.", "Milan Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Milan</b>.</p><b>Milan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię słowiańskie</a>. Jedno z licznych <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">zdrobnień od imion słowiańskich</a> zaczynających się na <i>Miło-</i>, takich jak <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82obor\" target=\"_blank\" rel=\"noopener noreferrer\">Miłobor</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82obrat\" target=\"_blank\" rel=\"noopener noreferrer\">Miłobrat</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82ogost_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miłogost</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82ogost_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miłgost</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82orad\" target=\"_blank\" rel=\"noopener noreferrer\">Miłorad</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82os%C5%82aw_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miłosław</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82os%C5%82aw_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miełosław</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82ostryj\" target=\"_blank\" rel=\"noopener noreferrer\">Miłostryj</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82owit\" target=\"_blank\" rel=\"noopener noreferrer\">Miłowit</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82owit\" target=\"_blank\" rel=\"noopener noreferrer\">Miłwit</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82osz\" target=\"_blank\" rel=\"noopener noreferrer\">Miłosz</a>. Obecnie imię Milan używane jest także samodzielnie.", "Md Zakir": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Main": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Matthaios": "<p>Matthaios to greckie imię. Do wybitnych osób z tym nazwiskiem należą: Matthaios Kamariotis (zmarł w 1490 roku), grecki uczony z ery renesansu Matthaios Kofidis (1855-1921), grecki biznesmen i członek parlamentu osmańskiego Matthaios Paranikas (1832-1914), grecki naukowiec Matthaios Tsahouridis (ur. 1978), grecki kompozytor i muzyk narzędzi strunkowych</p>", "Murtadha": "<p>Murtaza (afgańska perskia: مُرتَضٰ Murtazâ) lub Morteza (iranska: مُرْتِضیٰ Mortezâ) to perskie imię męskie, ostatecznie pochodzące z arabskiej Murtada (مُرْطَضَى Murtaḍā). Wymowa różni się w zależności od akcentu, od rodzimych arabskich do języków europejskich i azjatyckich.</p>", "Miguel Andres": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Miguel</b>.</p><p>Miguel (hisz. Miguel) - hiszpański odpowiednik imienia Michaila.</p>", "Marius-Cătălin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marius</b>.</p>Pochodził z niższych warstw społecznych, miał być z zawodu rzemieślnikiem (kowalem), później przypuszczalnie służył w wojsku, lecz nie wiadomo w jakiej funkcji. Po stłumionej w początkach 269 roku rewolcie <a href=\"https://pl.wikipedia.org/wiki/Lelian_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Leliana</a> wzniecił kolejny bunt w <a href=\"https://pl.wikipedia.org/wiki/Moguncja\" target=\"_blank\" rel=\"noopener noreferrer\">Mogontiacum</a> przeciwko władzy <a href=\"https://pl.wikipedia.org/wiki/Wiktoryn_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Wiktoryna</a>, następcy <a href=\"https://pl.wikipedia.org/wiki/Postumus\" target=\"_blank\" rel=\"noopener noreferrer\">Postuma</a>. Według <i><a href=\"https://pl.wikipedia.org/wiki/Historia_Augusta\" target=\"_blank\" rel=\"noopener noreferrer\">Historia Augusta</a></i> jego rządy trwały zaledwie 2-3 dni, czemu jednak przeczy zachowana liczba jego monet. Najpewniej w mennicy w <a href=\"https://pl.wikipedia.org/wiki/Kolonia_(Niemcy)\" target=\"_blank\" rel=\"noopener noreferrer\">Kolonii</a> (<i>Colonia Agrippina</i>) <a href=\"https://pl.wikipedia.org/wiki/Emisja_pieni%C4%85dza\" target=\"_blank\" rel=\"noopener noreferrer\">emitował</a> w swym imieniu niskowartościowe <a href=\"https://pl.wikipedia.org/wiki/Antoninian\" target=\"_blank\" rel=\"noopener noreferrer\">antoniniany</a> typów: AEQUITAS, CONCORDIA MILIT(um), SAEC(uli) FELICITAS, VICTORIA AUG(usti), VIRTUS AUG(usti).", "Minh Trung": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Md Hasibul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Marthinus": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Martinus</b>.</p><b>Marcin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od wyrażenia <i>Martinus</i> oznaczającego „należący do boga <a href=\"https://pl.wikipedia.org/wiki/Mars_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Marsa</a>”.", "Minh Nghia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Myślibor": "<b>Myślibor</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Myśli-</i> (\"myśleć\") i <i>-bor</i> (\"walczyć, zmagać się\"). Być może oznaczało \"tego, który myśli o walce\" albo \"tego, który obmyśla walkę\".", "Md Rashed": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Merwan": "<p>Marwan, Merwan lub Marwen lub Mervan (arabski: مروان, romanized: Marwān) jest arabskim męskim imieniem pochodzącym od słowa maruww (مرو) z znaczeniem minerałów, 'flint (-kamień) ', 'kwartz' lub 'twardy kamień prawie czystej krzemiony'. Jednak arabska nazwa kwarcu jest ṣawwān (صَوَّان).</p>", "Mohammed El Amine": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammed</b>.</p><p>Muhammad - muzułmańskie imię i nazwisko. Mahomet jest islamskim prorokiem.</p>", "Minh Long": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Md Kamruzzaman": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Miguel Alejandro": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Miguel</b>.</p><p>Miguel (hisz. Miguel) - hiszpański odpowiednik imienia Michaila.</p>", "Md Azizul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Raju": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Minh Tan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Md Sharif": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Musashi": "<p>Musashi (武蔵) to japońska nazwa, która może odnosić się do:</p>", "Md Sojib": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Rezaul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Minh Hai": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Maria Andrzej": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Makis": "<b>Makia</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_francuski\" target=\"_blank\" rel=\"noopener noreferrer\">fr.</a> <i>maquis</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">wł.</a> <i>macchia</i>) – zaroślowa <a href=\"https://pl.wikipedia.org/wiki/Formacja_ro%C5%9Blinna\" target=\"_blank\" rel=\"noopener noreferrer\">formacja roślinna</a> charakterystyczna dla <a href=\"https://pl.wikipedia.org/wiki/Strefa_%C5%9Br%C3%B3dziemnomorska\" target=\"_blank\" rel=\"noopener noreferrer\">obszaru śródziemnomorskiego</a>, kształtująca się zwykle wtórnie w miejscach po usuniętych <a href=\"https://pl.wikipedia.org/wiki/Ro%C5%9Blinno%C5%9B%C4%87_twardolistna\" target=\"_blank\" rel=\"noopener noreferrer\">lasach twardolistnych</a>, głównie dębowych, rzadziej sosnowych i cyprysowych. Makia w zależności od warunków siedliskowych bywa luźna lub gęsta, niska – wyłącznie zaroślowa (do 2,5 m wysokości), lub wysoka – z udziałem okazałych krzewów i niskich drzew osiągających do 5 m wysokości. Dominują zawsze <a href=\"https://pl.wikipedia.org/wiki/Krzew\" target=\"_blank\" rel=\"noopener noreferrer\">krzewy</a>, zwykle zimozielone o liściach skórzastych, miejscami z większym lub mniejszym udziałem gatunków zrzucających liście zimą. Pod względem fizjonomii i zajmowanych <a href=\"https://pl.wikipedia.org/wiki/Siedlisko_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">siedlisk</a> makia w całym obszarze jej występowania jest podobna, występują jednak znaczne różnice w kompozycji gatunkowej. W płatach bardzo zróżnicowanych warstwę krzewów może tworzyć nawet ok. 30 gatunków. Charakterystyczny dla makii jest silny aromat ze względu na to, że wiele występujących w niej roślin wydziela duże ilości <a href=\"https://pl.wikipedia.org/wiki/Olejek_eteryczny\" target=\"_blank\" rel=\"noopener noreferrer\">olejków eterycznych</a>. Ze względu na gęstość zarośli, duży udział gatunków ciernistych, kolczastych i pnączy makia często bywa bardzo trudna do przebycia.", "Milann": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Milan</b>.</p><b>Milan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię słowiańskie</a>. Jedno z licznych <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">zdrobnień od imion słowiańskich</a> zaczynających się na <i>Miło-</i>, takich jak <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82obor\" target=\"_blank\" rel=\"noopener noreferrer\">Miłobor</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82obrat\" target=\"_blank\" rel=\"noopener noreferrer\">Miłobrat</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82ogost_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miłogost</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82ogost_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miłgost</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82orad\" target=\"_blank\" rel=\"noopener noreferrer\">Miłorad</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82os%C5%82aw_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miłosław</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82os%C5%82aw_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miełosław</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82ostryj\" target=\"_blank\" rel=\"noopener noreferrer\">Miłostryj</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82owit\" target=\"_blank\" rel=\"noopener noreferrer\">Miłowit</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82owit\" target=\"_blank\" rel=\"noopener noreferrer\">Miłwit</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82osz\" target=\"_blank\" rel=\"noopener noreferrer\">Miłosz</a>. Obecnie imię Milan używane jest także samodzielnie.", "Muhammed Enes": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Muhammed Ali̇": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Manuel Fernando": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Manuel</b>.</p><b>Emanuel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od słowa עִמָּנוּאֵל oznaczającego „Bóg z nami”. Imię mesjasza oraz kilku świętych katolickich. Żeński odpowiednik to <a href=\"https://pl.wikipedia.org/wiki/Emanuela\" target=\"_blank\" rel=\"noopener noreferrer\">Emanuela</a>.", "Muhieddine": "<p>Mohyeddin to arabskie imię, które oznacza \"Ożywiciel Dīn\". Jest używana zarówno jako imię osobiste dla mężczyzn, jak i jako tytuł honorowy w tradycji islamskiej.</p>", "Minhaj": "<p>Minhaj (\" droga \" lub \" droga \" w języku arabskim) może odnosić się do:</p>", "Majcher": "<p>Majcher to nazwisko i nazwisko, rodzinną formę \"Melchior\". Warianty: Maycher, Maicher.</p>", "Mohammed Ismail": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammed</b>.</p><p>Muhammad - muzułmańskie imię i nazwisko. Mahomet jest islamskim prorokiem.</p>", "Miguel Enrique": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Miguel</b>.</p><p>Miguel (hisz. Miguel) - hiszpański odpowiednik imienia Michaila.</p>", "Mohammad Nazmul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Mădălin-Alex": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mădălin</b>.</p><p>Mădălin to rumuńskie imię i nazwisko mężczyzny, które może odnosić się do: Mădăline Ciucă (ur. 1982), rumuński piłkarz Mădă Lin Lemnaru (ur. 1989), rumuński piłkarze rugby Mădă lin Marius Popa (ur. 1982) rumuński futbolista i menedżer Mădăilin Martin (ur. 1992), rumuńskiego piłkarza Mădălina Mihăescu (ur. 1988), rumuńczyka piłkarka Mădăl Murgan (ur. 1983), rumuńca piłkarzem Mădă l Popa (UR. 1983), rumunskiego piłkarta Mădălini Răileanu (ur....</p>", "Md Mohiuddin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Mostafa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Monik": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Monika</b>.</p><b>Monika</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o znaczeniu i pochodzeniu trudnym do objaśnienia. Według niektórych badaczy imię pochodzi od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> słowa „monos” oznaczającego <i>jeden</i>, <i>sam</i>, <i>pojedynczy</i>, <i>jedynak</i> i <i>jedynaczka</i>. Z tego samego rdzenia pochodzą takie słowa jak: <a href=\"https://pl.wikipedia.org/wiki/Monogamia\" target=\"_blank\" rel=\"noopener noreferrer\">monogamia</a>, <a href=\"https://pl.wikipedia.org/wiki/Monoteizm\" target=\"_blank\" rel=\"noopener noreferrer\">monoteizm</a>, monaster (klasztor). Inne źródło podaje, że imię to wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> „monaché”, co znaczy <i>samotna</i>, <i>odosobniona</i>; we <a href=\"https://pl.wikipedia.org/wiki/W%C5%82ochy\" target=\"_blank\" rel=\"noopener noreferrer\">Włoszech</a> zakonnica zwana jest <i>monaca</i>, a w niektórych dialektach wręcz <i>monica</i>.", "Miguel Jr.": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Miguel</b>.</p><p>Miguel (hisz. Miguel) - hiszpański odpowiednik imienia Michaila.</p>", "Md Faysal": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Marie Jean": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Md Forhad": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Maria Stefan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Michael Andres": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Michael</b>.</p><p>Michael: Botanika Michael - skrócie botaniczne, oznaczające, że autorem taksy jest Edmund Michael. Muzyka ⁇ Michael ⁇ - piosenka grupy Franz Ferdinand, wydana w 2004 roku.</p>", "Muhammed Mustafa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Masław": "Według hipotezy <a href=\"https://pl.wikipedia.org/wiki/Stanis%C5%82aw_Rospond_(j%C4%99zykoznawca)\" target=\"_blank\" rel=\"noopener noreferrer\">Stanisława Rosponda</a>, <b>Masław</b> jest skróconą formą niezachowanego w pierwotnym brzmieniu imienia <i>Jimasław</i>, który wtórnie utrzymał się jako <a href=\"https://pl.wikipedia.org/wiki/Imis%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Jimisław</a>, natomiast w oryginale kroniki Nestora występowała forma Masław, <a href=\"https://pl.wikipedia.org/wiki/Adideacja\" target=\"_blank\" rel=\"noopener noreferrer\">zadideowana</a> następnie z bardziej znaną kopistom formą Mojsław. Inną hipotezą jest założenie <a href=\"https://pl.wikipedia.org/wiki/Maria_Malec_(j%C4%99zykoznawczyni)\" target=\"_blank\" rel=\"noopener noreferrer\">Marii Malec</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C3%B3zef_Bubak\" target=\"_blank\" rel=\"noopener noreferrer\">Józef Bubaka</a>, że imię to mogło być skrótem od niepoświadczonego imienia <i>*Małosław</i>.", "Muhammad Faisal": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammad</b>.</p><b>Muhammad</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;مُحَمَّد&#8206;) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wariantami tego imienia są: Mohammed, Mehmed, Mamadu i Mahomet.", "Md Akbar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mohamed Moustafa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohamed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Muhammadi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Muhammad</b>.</p><b>Muhammad</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;مُحَمَّد&#8206;) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wariantami tego imienia są: Mohammed, Mehmed, Mamadu i Mahomet.", "Markiz": "Wyraz pochodzi z francuskiego <i>marquis</i>, które wywodzi się najwyraźniej z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a> słowa oznaczającego granicę (<i>mark</i>). W języku niemieckim odpowiadający tytuł to <i>Markgraf</i>, co można analizować jako <i>Mark + graf</i> = granica + <a href=\"https://pl.wikipedia.org/wiki/Hrabia\" target=\"_blank\" rel=\"noopener noreferrer\">hrabia</a>, tj. hrabia opiekujący się granicami. Dawniej hrabia, który chronił granice, był bardziej uprzywilejowany od innych hrabiów, co tłumaczy stosunkowo wysoką pozycję w hierarchii, tym bardziej, że mógł zdobyte na sąsiadach (przeważnie barbarzyńcach) ziemie dodawać do swojej domeny.", "Md Liton": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Milana": "<b>Milena</b> lub <b>Milana</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, używane w językach <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_bu%C5%82garski\" target=\"_blank\" rel=\"noopener noreferrer\">bułgarskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_czeski\" target=\"_blank\" rel=\"noopener noreferrer\">czeskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_s%C5%82owacki\" target=\"_blank\" rel=\"noopener noreferrer\">słowackim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbsko-chorwacki\" target=\"_blank\" rel=\"noopener noreferrer\">chorwackim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">polskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbski\" target=\"_blank\" rel=\"noopener noreferrer\">serbskim</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_s%C5%82owe%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">słoweńskim</a>. Zawiera pierwiastek <i>mil</i> oznaczający „miły”. Męskim odpowiednikiem imienia jest <a href=\"https://pl.wikipedia.org/wiki/Milan_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Milan</a>.", "Mohammed M": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammed</b>.</p><p>Muhammad - muzułmańskie imię i nazwisko. Mahomet jest islamskim prorokiem.</p>", "Minh Duong": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Mateos": "<p>Mateos to hiszpańskie nazwisko i albanskie i etyopskie nazwisko. Do wybitnych osób z tym nazwiskiem należą:</p>", "Matthew James": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Matthew</b>.</p><p>William Diller Matthew (ang. William Diller; 19 lutego 1871 - 24 września 1930 w Berkeley) - kanadyjski i amerykański naukowiec-geolog, paleontolog, biogeograf, kurator Muzeum Historii Naturalnej Ameryki, profesor Uniwersytetu Kalifornijskiego w Berkeley, znany popularyzator nauki.</p>", "Mohamed Ibrahim": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohamed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Mohan Bahadur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohan</b>.</p><p>Mohan to gmin i nagar panchayat z okręgu Unnao w stanie Uttar Pradesh, India.</p>", "Md Nizam": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mohammed H": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammed</b>.</p><p>Muhammad - muzułmańskie imię i nazwisko. Mahomet jest islamskim prorokiem.</p>", "Michali": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Michał</b>.</p><b>Michał</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִיכָאֵל&#8206; – Mîchā’ēl) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, wywodzące się od <a href=\"https://pl.wikipedia.org/wiki/Archanio%C5%82_Micha%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">jednego z archaniołów</a>. Po hebrajsku znaczy „któż [jest taki] jak Bóg”. Forma żeńska to <a href=\"https://pl.wikipedia.org/wiki/Michalina\" target=\"_blank\" rel=\"noopener noreferrer\">Michalina</a>.", "Md Jabed": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Abid": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Michał Jan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Michał</b>.</p><b>Michał</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִיכָאֵל&#8206; – Mîchā’ēl) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, wywodzące się od <a href=\"https://pl.wikipedia.org/wiki/Archanio%C5%82_Micha%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">jednego z archaniołów</a>. Po hebrajsku znaczy „któż [jest taki] jak Bóg”. Forma żeńska to <a href=\"https://pl.wikipedia.org/wiki/Michalina\" target=\"_blank\" rel=\"noopener noreferrer\">Michalina</a>.", "Marian Jan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marian</b>.</p><b>Marian</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> od imienia <i>Marius</i> lub nazwy rodu <i>Marii</i>. Oznacza „należący do Mariusza, rodu Mariuszów”. Występuje w Polsce od 1332 roku, jako <b>Marzyjan</b>. Forma Marian pojawiła się w Polsce w XVI wieku. W języku angielskim używane jest jako imię żeńskie. W Polsce w żeńskim użyciu w 2025 roku wystąpiło 35 razy.", "Maicon": "<p>Maicon to brazylijskie odmianie nazwiska Michaela. Może odnosić się do:</p>", "Milisav": "<p>Milisav (Serbski cyrylski: Милисав), jest słowiańskim męskim imieniem. Wśród znanych osób z imieniem: Milisav Čamdžija (1770-1815), serbski rewolucyjny Milisav Đorđević (m.</p>", "Md Faisal": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Marie J": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Maria Jan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Muhanad": "<p>Muhanad to męskie imię.</p>", "Mario Enrique": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mario</b>.</p><p>Mario (jap. Mario Mario, angielski.</p>", "Maati": "<p>Maati to imię i nazwisko. Do wybitnych osób z nazwą należą: Maati Bouabid (1927-1996), premier Maroka w latach 1979-1983 Maati Kabbal (ur. 1954), marokański pisarz i esejista Maati Monjib (ur. 1962), marokański profesor uniwersyteckie, dziennikarz, historyk, pisarz oraz polityczny aktywista Nasreddine Ben Maati (ur. 1990), tunyjski filmowiec i aktor</p>", "Muhammad Talha": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammad</b>.</p><b>Muhammad</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;مُحَمَّد&#8206;) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wariantami tego imienia są: Mohammed, Mehmed, Mamadu i Mahomet.", "Md Anamul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mohammad Ibrahim": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Mejdi": "<p>Majdy i Majdi lub Mejdi lub egipskie warianty Magdi lub Magdy (w arabskim مجدي) to arabskie męskie imię i nazwisko pochodzenia arabskiego. Do wybitnych osób z tym nazwiskiem należą:</p>", "Minh Nam": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Mihai-Cristian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mihai</b>.</p><p>Mihai (rumuńska wymowa: [miˈhaj]) jest rumuńskim nazwiskiem męskim lub nazwiskiem. To równoważne angielskiej imienia Michael.</p>", "Muhammad Yasir": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammad</b>.</p><b>Muhammad</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;مُحَمَّد&#8206;) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wariantami tego imienia są: Mohammed, Mehmed, Mamadu i Mahomet.", "Mikele": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mikel</b>.</p><p>Mikel jest baskijską adaptacją nazwiska Michaela. Nazwa Mikel pochodzi od hebrajskiego słowa Micha'el, co oznacza \"Kto jest jak Bóg\".</p>", "Mohammed Mohammed": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammed</b>.</p><p>Muhammad - muzułmańskie imię i nazwisko. Mahomet jest islamskim prorokiem.</p>", "Marius-Ilie": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marius</b>.</p>Pochodził z niższych warstw społecznych, miał być z zawodu rzemieślnikiem (kowalem), później przypuszczalnie służył w wojsku, lecz nie wiadomo w jakiej funkcji. Po stłumionej w początkach 269 roku rewolcie <a href=\"https://pl.wikipedia.org/wiki/Lelian_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Leliana</a> wzniecił kolejny bunt w <a href=\"https://pl.wikipedia.org/wiki/Moguncja\" target=\"_blank\" rel=\"noopener noreferrer\">Mogontiacum</a> przeciwko władzy <a href=\"https://pl.wikipedia.org/wiki/Wiktoryn_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Wiktoryna</a>, następcy <a href=\"https://pl.wikipedia.org/wiki/Postumus\" target=\"_blank\" rel=\"noopener noreferrer\">Postuma</a>. Według <i><a href=\"https://pl.wikipedia.org/wiki/Historia_Augusta\" target=\"_blank\" rel=\"noopener noreferrer\">Historia Augusta</a></i> jego rządy trwały zaledwie 2-3 dni, czemu jednak przeczy zachowana liczba jego monet. Najpewniej w mennicy w <a href=\"https://pl.wikipedia.org/wiki/Kolonia_(Niemcy)\" target=\"_blank\" rel=\"noopener noreferrer\">Kolonii</a> (<i>Colonia Agrippina</i>) <a href=\"https://pl.wikipedia.org/wiki/Emisja_pieni%C4%85dza\" target=\"_blank\" rel=\"noopener noreferrer\">emitował</a> w swym imieniu niskowartościowe <a href=\"https://pl.wikipedia.org/wiki/Antoninian\" target=\"_blank\" rel=\"noopener noreferrer\">antoniniany</a> typów: AEQUITAS, CONCORDIA MILIT(um), SAEC(uli) FELICITAS, VICTORIA AUG(usti), VIRTUS AUG(usti).", "Marian-Alexandru": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marian</b>.</p><b>Marian</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> od imienia <i>Marius</i> lub nazwy rodu <i>Marii</i>. Oznacza „należący do Mariusza, rodu Mariuszów”. Występuje w Polsce od 1332 roku, jako <b>Marzyjan</b>. Forma Marian pojawiła się w Polsce w XVI wieku. W języku angielskim używane jest jako imię żeńskie. W Polsce w żeńskim użyciu w 2025 roku wystąpiło 35 razy.", "Mitar": "<p>Mitar (cyrylicki: Митар) to męskie imię. Jest to serbska warianta greckiego imienia Demetrius.</p>", "Md Samiul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Mahabub": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Minh Phúc": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Matyii": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Matyi</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Matii</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mati</b>.</p><p>Mati jest miastem w prowincji Davao Oriental, w Filipinach. To jest stolica prowincji.</p>", "Muhibullah": "<p>Muhibullah, również pisane Mohebullah/Mohibullah/Mohibullah i w innych znaczeniach, to muzułmańskie imię, które oznacza miłośnika Boga. Może odnosić się do Mohib Ullah (1971-2021), aktywisty pokojowego Rohingya, który został zamordowany w 2021 roku Muhebullah (więziony w Guantanamo 974) (urodzony około 20 lat).</p>", "Md Gias": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Shahjahan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Shahriar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mohana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mohan</b>.</p><p>Mohan to gmin i nagar panchayat z okręgu Unnao w stanie Uttar Pradesh, India.</p>", "Md Shahidul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Minh Nhat": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Minh Tu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Mohamed Abdu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohamed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Mohamed El Hadi": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohamed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Md Tarek": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Maryush": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mariush</b>.</p>W latach 2001–2014 był członkiem <a href=\"https://pl.wikipedia.org/wiki/Kabaret_Limo\" target=\"_blank\" rel=\"noopener noreferrer\">Kabaretu Limo</a>. Po zakończeniu działalności tej formacji zajmuje się głównie pisaniem sztuk oraz improwizacją komediową.", "Maria Krzysztof": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mohammad Nur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Murtada": "<p>Murtaza (afgańska perskia: مُرتَضٰ Murtazâ) lub Morteza (iranska: مُرْتِضیٰ Mortezâ) to perskie imię męskie, ostatecznie pochodzące z arabskiej Murtada (مُرْطَضَى Murtaḍā). Wymowa różni się w zależności od akcentu, od rodzimych arabskich do języków europejskich i azjatyckich.</p>", "Md Shohel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Marian-Cristian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marian</b>.</p><b>Marian</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> od imienia <i>Marius</i> lub nazwy rodu <i>Marii</i>. Oznacza „należący do Mariusza, rodu Mariuszów”. Występuje w Polsce od 1332 roku, jako <b>Marzyjan</b>. Forma Marian pojawiła się w Polsce w XVI wieku. W języku angielskim używane jest jako imię żeńskie. W Polsce w żeńskim użyciu w 2025 roku wystąpiło 35 razy.", "Mohammad Monir": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Mohammed Ahmed": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammed</b>.</p><p>Muhammad - muzułmańskie imię i nazwisko. Mahomet jest islamskim prorokiem.</p>", "Mohamed El Sayed": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohamed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Minh Đức": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Mikho": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Micho</b>.</p><p>Micha (; hebrajskie: מִיכָה, nowoczesne: Mikha, tyberyjskie: Mî ⁇ ā) jest nazwiskiem. Micha jest nazwiskiem kilku ludzi w Tanakh, co oznacza \"Kto jest jak Bóg? \"Przecież to prawda\".</p>", "Md Alamin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Matijas": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Matias</b>.</p><p>Matías to portugalska wersja Matthias. Matías jest bardzo popularny w Ameryce Łacińskiej, zwłaszcza w Argentynie.</p>", "Md Kabir": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Muhammad Adnan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammad</b>.</p><b>Muhammad</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;مُحَمَّد&#8206;) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wariantami tego imienia są: Mohammed, Mehmed, Mamadu i Mahomet.", "Minh Dang": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Minh Truong": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Mi̇rza": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Myrza</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mirza</b>.</p><p>Mirza (lat. Mirza) - rodzaj zwierząt mleczarzy z infraodrodu oddziału lemurowych prymatów.</p>", "Mimir": "<b>Mimir</b> – w <a href=\"https://pl.wikipedia.org/wiki/Mitologia_nordycka\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii nordyckiej</a> tajemniczy mędrzec o nieznanym pochodzeniu.", "Mohan Prasad": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohan</b>.</p><p>Mohan to gmin i nagar panchayat z okręgu Unnao w stanie Uttar Pradesh, India.</p>", "Mudassir": "<p>Mudassar, Mudassir, Modasser lub Mudasiru to męskie nazwiska i nazwiska pochodzące z arabskiego. Do wybitnych osób z tym nazwiskiem należą:</p>", "Minh Son": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Mahal": "Najwięecej ochotników pochodziło ze <a href=\"https://pl.wikipedia.org/wiki/Stany_Zjednoczone\" target=\"_blank\" rel=\"noopener noreferrer\">Stanów Zjednoczonych</a> i <a href=\"https://pl.wikipedia.org/wiki/Wielka_Brytania\" target=\"_blank\" rel=\"noopener noreferrer\">Wielkiej Brytanii</a>. Byli to najczęściej weterani wojskowi z <a href=\"https://pl.wikipedia.org/wiki/II_wojna_%C5%9Bwiatowa\" target=\"_blank\" rel=\"noopener noreferrer\">II wojny światowej</a>. Posiadali oni duże doświadczenie bojowe, często byli to piloci wojskowi.", "Minh Nghĩa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Meinolf": "<p>Meinolf (także Meinulf) to niemieckie męskie imię. Pochodzi od starożytnego niemieckiego magan oznaczającego \"silny\" (starozsakski mugan) i starożytny wolf oznaczający \"wolf\" (stary saksoński wulf).</p>", "Maksym-Mykola": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maksym</b>.</p><b>Maksym</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, utworzone od przymiotnika <i>maximus</i> oznaczający \"największy\", przydomka <a href=\"https://pl.wikipedia.org/wiki/Jowisz_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Jowisza</a>. Istnieją liczni święci prawosławni i katoliccy o tym imieniu: <a href=\"https://pl.wikipedia.org/wiki/Maksym_Wyznawca\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym Wyznawca</a>, <a href=\"https://pl.wikipedia.org/wiki/Maksym_Grek\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym Grek</a>, <a href=\"https://pl.wikipedia.org/wiki/Maksym_Brankowicz\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym Wołoski</a>, <a href=\"https://pl.wikipedia.org/wiki/Maksym_Gorlicki\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym Gorlicki</a>, <a href=\"https://pl.wikipedia.org/wiki/Maksym_z_Riez\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym z Riez</a> i wielu innych.", "Minh Vu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Maksymus": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maksimus</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maximus</b>.</p><p>Maximus: Maximus (BBS) - program komputerowy BBS Maximus (Maximus) - główny bohater filmu ⁇ Gladiator ⁇</p>", "Marian Stanisław": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marian</b>.</p><b>Marian</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> od imienia <i>Marius</i> lub nazwy rodu <i>Marii</i>. Oznacza „należący do Mariusza, rodu Mariuszów”. Występuje w Polsce od 1332 roku, jako <b>Marzyjan</b>. Forma Marian pojawiła się w Polsce w XVI wieku. W języku angielskim używane jest jako imię żeńskie. W Polsce w żeńskim użyciu w 2025 roku wystąpiło 35 razy.", "Minh Duy": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Maksym-Andrii": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maksym</b>.</p><b>Maksym</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, utworzone od przymiotnika <i>maximus</i> oznaczający \"największy\", przydomka <a href=\"https://pl.wikipedia.org/wiki/Jowisz_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Jowisza</a>. Istnieją liczni święci prawosławni i katoliccy o tym imieniu: <a href=\"https://pl.wikipedia.org/wiki/Maksym_Wyznawca\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym Wyznawca</a>, <a href=\"https://pl.wikipedia.org/wiki/Maksym_Grek\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym Grek</a>, <a href=\"https://pl.wikipedia.org/wiki/Maksym_Brankowicz\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym Wołoski</a>, <a href=\"https://pl.wikipedia.org/wiki/Maksym_Gorlicki\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym Gorlicki</a>, <a href=\"https://pl.wikipedia.org/wiki/Maksym_z_Riez\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym z Riez</a> i wielu innych.", "Mytrofan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mitrofan</b>.</p><b>Metrofan</b> — <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia greckiego, <a href=\"https://pl.wikipedia.org/wiki/Gr.\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> <i>Μητροφανης</i>, złożone z członów <i>μητηρ (meter)</i> — \"matki\" i <i>φανης (phanes)</i> — \"pojawienie się, objawienie się\", co oznacza \"objawienie matki\". Patronem tego imienia jest św. Metrofan, biskup <a href=\"https://pl.wikipedia.org/wiki/Cesarstwo_Bizanty%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">Bizancjum</a> (III–IV wiek). U Słowian wschodnich imię to rozpowszechniło się w formie <i><b>Mitrofan</b></i>.", "Marius-Daniel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marius</b>.</p>Pochodził z niższych warstw społecznych, miał być z zawodu rzemieślnikiem (kowalem), później przypuszczalnie służył w wojsku, lecz nie wiadomo w jakiej funkcji. Po stłumionej w początkach 269 roku rewolcie <a href=\"https://pl.wikipedia.org/wiki/Lelian_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Leliana</a> wzniecił kolejny bunt w <a href=\"https://pl.wikipedia.org/wiki/Moguncja\" target=\"_blank\" rel=\"noopener noreferrer\">Mogontiacum</a> przeciwko władzy <a href=\"https://pl.wikipedia.org/wiki/Wiktoryn_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Wiktoryna</a>, następcy <a href=\"https://pl.wikipedia.org/wiki/Postumus\" target=\"_blank\" rel=\"noopener noreferrer\">Postuma</a>. Według <i><a href=\"https://pl.wikipedia.org/wiki/Historia_Augusta\" target=\"_blank\" rel=\"noopener noreferrer\">Historia Augusta</a></i> jego rządy trwały zaledwie 2-3 dni, czemu jednak przeczy zachowana liczba jego monet. Najpewniej w mennicy w <a href=\"https://pl.wikipedia.org/wiki/Kolonia_(Niemcy)\" target=\"_blank\" rel=\"noopener noreferrer\">Kolonii</a> (<i>Colonia Agrippina</i>) <a href=\"https://pl.wikipedia.org/wiki/Emisja_pieni%C4%85dza\" target=\"_blank\" rel=\"noopener noreferrer\">emitował</a> w swym imieniu niskowartościowe <a href=\"https://pl.wikipedia.org/wiki/Antoninian\" target=\"_blank\" rel=\"noopener noreferrer\">antoniniany</a> typów: AEQUITAS, CONCORDIA MILIT(um), SAEC(uli) FELICITAS, VICTORIA AUG(usti), VIRTUS AUG(usti).", "Md Al Mamun": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Minh Tú": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Muhammed Ali": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Mohan Babu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohan</b>.</p><p>Mohan to gmin i nagar panchayat z okręgu Unnao w stanie Uttar Pradesh, India.</p>", "Min Prasad": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Min</b>.</p><p>Min to niejednoznaczny termin. min - w matematyce i językach programowania oznacza funkcję wyboru najmniejszego ze swoich argumentów, (Min (3, 6, 2) = 2).</p>", "Masaru": "<b>Masaru</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;まさる, マサル) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię japońskie</a>.", "Moysés": "<p>Moysés (zwany również Moyses, Moyse, Moisés lub Mojżesz) jest nazwiskiem hebrajskim i nazwiskiem pochodzącym od מֹשֶׁה Moshe, imienia biblijnego proroka Mojżesza. Wariant \"Moisés\" jest standardową formą w portugalsku i hiszpańskim i popularną nazwą, podczas gdy \"Moyse\", \"Moyses\" i \"Moysés\" były używane w różnych kontekstach historycznych i regionalnych, zwłaszcza wśród żydów sefardyjskich częściej jako nazwisko. Nazwa funkcjonuje zarówno jako dane...</p>", "Md Masudur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mohammad Ariful": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Manuel Francisco": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Manuel</b>.</p><b>Emanuel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od słowa עִמָּנוּאֵל oznaczającego „Bóg z nami”. Imię mesjasza oraz kilku świętych katolickich. Żeński odpowiednik to <a href=\"https://pl.wikipedia.org/wiki/Emanuela\" target=\"_blank\" rel=\"noopener noreferrer\">Emanuela</a>.", "Md Abdullah": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Muhammad-Ali": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammad</b>.</p><b>Muhammad</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;مُحَمَّد&#8206;) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wariantami tego imienia są: Mohammed, Mehmed, Mamadu i Mahomet.", "Minh Hoang": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Mobin": "<p>Mobeen (arabski: مبين; perskiego: مبین) (zwany również Mubeen, Mobin, Mubin) to imię pochodzące od arabskiego słowa (مبين), które jest używane jako poetycki przymiot w literaturze, mowie i kontekście religijnym. Nazwa może być przetłumaczana jako \"wyraźne\", \"jasne\", \"wymowne\", \"wybitne\" lub \"jasne\".</p>", "Md Abdus": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Miłowan": "<b>Miłowan</b> – słowiańskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie jednoczłonowe, utworzone z członu <i>Miło-</i> (\"miłować\"). Wzmiankowane w dokumentach z 1136 roku. Może oznaczać: miłowany. Popularne zwłaszcza w <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie_po%C5%82udniowi\" target=\"_blank\" rel=\"noopener noreferrer\">krajach południowosłowiańskich</a>", "Md Nazrul Islam": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Maria Kazimierz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Miłan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Milana</b>.</p><b>Milena</b> lub <b>Milana</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, używane w językach <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_bu%C5%82garski\" target=\"_blank\" rel=\"noopener noreferrer\">bułgarskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_czeski\" target=\"_blank\" rel=\"noopener noreferrer\">czeskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_s%C5%82owacki\" target=\"_blank\" rel=\"noopener noreferrer\">słowackim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbsko-chorwacki\" target=\"_blank\" rel=\"noopener noreferrer\">chorwackim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">polskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbski\" target=\"_blank\" rel=\"noopener noreferrer\">serbskim</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_s%C5%82owe%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">słoweńskim</a>. Zawiera pierwiastek <i>mil</i> oznaczający „miły”. Męskim odpowiednikiem imienia jest <a href=\"https://pl.wikipedia.org/wiki/Milan_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Milan</a>.", "Md Humayun": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Momcilo": "<p>Momcilo lub Momčilo (cyrylicki: Момчило) to męskie imię pochodzenia sławskiego południa. Często występuje w Serbii i Czarnogórii.</p>", "Md Ahsan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mohamed Said": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohamed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Md Tuhin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Maria Tadeusz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mykhailo-Yaroslav": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mykhailo</b>.</p><p>Mykhailo lub Mykhaylo to ukraińskie męskie imię, równoważne angielskim Michałowi. Wśród znanych osób z nazwiskiem są: Mykhaylo Berkos (1861-1919), rosyjski i ukraiński artysta pochodzenia greckiego Mykhayilo Bolotskykh (ur. 1960), ukraiński polityk i wojskowy, pułkownik generalny (Służba Obrony Cywilnej) Mykhayło Brodskyy (ur. 1959), ukraiński polityk, przywódca Partii Wolnych Demokratów i biznesmen Mykhayla Chemberzhi,...</p>", "Muhammed Fati̇h": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Maruthi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maruti</b>.</p>Indyjskie przedsiębiorstwo od 1983 roku produkuje samochody na licencji Suzuki. Pierwszym pojazdem produkowanym w Indiach na tej zasadzie było <a href=\"https://pl.wikipedia.org/wiki/Maruti_800\" target=\"_blank\" rel=\"noopener noreferrer\">Maruti 800</a>, odpowiednik modelu <a href=\"https://pl.wikipedia.org/wiki/Suzuki_Alto\" target=\"_blank\" rel=\"noopener noreferrer\">Suzuki Alto</a>. Był to najlepiej sprzedający się samochód w Indiach.", "Mirand": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Miranda</b>.</p><b>Miranda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa <i>miranda</i> oznaczającego \"godna podziwu\". Imię zostało pierwszy raz użyte przez <a href=\"https://pl.wikipedia.org/wiki/William_Szekspir\" target=\"_blank\" rel=\"noopener noreferrer\">Williama Shakespeare'a</a> w dramacie <i><a href=\"https://pl.wikipedia.org/wiki/Burza_(sztuka)\" target=\"_blank\" rel=\"noopener noreferrer\">Burza</a></i>.", "Marie Joseph": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Matii": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mati</b>.</p><p>Mati jest miastem w prowincji Davao Oriental, w Filipinach. To jest stolica prowincji.</p>", "Md Sahadat": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Maryian": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mariian</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Marian</b>.</p><b>Marian</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> od imienia <i>Marius</i> lub nazwy rodu <i>Marii</i>. Oznacza „należący do Mariusza, rodu Mariuszów”. Występuje w Polsce od 1332 roku, jako <b>Marzyjan</b>. Forma Marian pojawiła się w Polsce w XVI wieku. W języku angielskim używane jest jako imię żeńskie. W Polsce w żeńskim użyciu w 2025 roku wystąpiło 35 razy.", "Maria Wojciech": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Md Delwar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mohammed Abdul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammed</b>.</p><p>Muhammad - muzułmańskie imię i nazwisko. Mahomet jest islamskim prorokiem.</p>", "Md Shamsul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Maksimilyan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maksimilian</b>.</p><p>Maksymilian lub Maximillian (Maximiliaan w języku holenderskim i Maximilien w językach francuskich) to męskie imię. Nazwa \"Max\" jest skróceniem \"Maximilian\" oraz kilku innych nazw, w tym, ale nie ograniczając się do Maxwell.</p>", "Matuš": "<p>Matus może być zarówno nazwiskiem, jak i nazwiskiem. Do powszechnych wariantów należą Matúš, Matuš i Matůš.</p>", "Manole": "<p>Manole to rumuńska nazwa, używana zarówno jako imię i nazwisko. Osoby z nazwiskiem: Manole Aldescu Manole Marcus Osoby z przyrzeczeniem: Laurențiu Manole Leonard Manole Mădălina Manole Viorel Manole</p>", "Minh Tùng": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Marek Wojciech": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marek</b>.</p><b>Marek</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, należące do wąskiej grupy najstarszych <a href=\"https://pl.wikipedia.org/wiki/Imiona_%C5%82aci%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imion rzymskich</a> (imion właściwych, <i>praenomen</i>, por. <a href=\"https://pl.wikipedia.org/wiki/Tyberiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Tyberiusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Aulus\" target=\"_blank\" rel=\"noopener noreferrer\">Aulus</a>, <a href=\"https://pl.wikipedia.org/wiki/Maniusz\" target=\"_blank\" rel=\"noopener noreferrer\">Maniusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Gajusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Gajusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Lucjusz\" target=\"_blank\" rel=\"noopener noreferrer\">Lucjusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Publiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Publiusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Tytus\" target=\"_blank\" rel=\"noopener noreferrer\">Tytus</a>, <a href=\"https://pl.wikipedia.org/wiki/Serwiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Serwiusz</a>), utworzone z <i>*Mart-ico-s</i> od imienia boga <i><a href=\"https://pl.wikipedia.org/wiki/Mars_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Mars</a></i>, <i>Martis</i> i oznaczające „należący do Marsa, związany z Marsem”. W Polsce imię to jest notowane od <a href=\"https://pl.wikipedia.org/wiki/XIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIII wieku</a>, choć poza współczesnością nie było często spotykane, w formach <i><b>Marek</b></i>, <i><b>Marko</b></i>, <i><b>Margusz</b></i>, <i><b>Markusz</b></i>, <i><b>Merkusz</b></i>. Zapisana została także żeńska <b>Marka</b> (<a href=\"https://pl.wikipedia.org/wiki/1263\" target=\"_blank\" rel=\"noopener noreferrer\">1263</a>) – żeński odpowiednik imienia Marek lub zdrobnienie od imion żeńskich rozpoczynających się na Mar-, takich jak <i>Margorzata</i> (= <a href=\"https://pl.wikipedia.org/wiki/Ma%C5%82gorzata_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Małgorzata</a>) lub <a href=\"https://pl.wikipedia.org/wiki/Maria\" target=\"_blank\" rel=\"noopener noreferrer\">Maria</a> – oraz <a href=\"https://pl.wikipedia.org/wiki/Markus%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Markusław</a>, staropolskie imię utworzone od imienia Marek poprzez dodanie typowej dla imion słowiańskich cząstki -sław. Imię to według danych 2022 r. jest na 10 miejscu najpopularniejszych imion męskich.", "Mohammad Sadek": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Marc André": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marc</b>.</p><p>Marc: MARC (ang. Machine-Readable Cataloging) - grupa formatów (MARC21, UNIMARC, RUSMAC itp.</p>", "Md Saif": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Muhammad Rashid": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammad</b>.</p><b>Muhammad</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;مُحَمَّد&#8206;) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wariantami tego imienia są: Mohammed, Mehmed, Mamadu i Mahomet.", "Mihai-Petru": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mihai</b>.</p><p>Mihai (rumuńska wymowa: [miˈhaj]) jest rumuńskim nazwiskiem męskim lub nazwiskiem. To równoważne angielskiej imienia Michael.</p>", "Muhammed Sinan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Major": "<b>Major</b> (mjr) – stopień <a href=\"https://pl.wikipedia.org/wiki/Oficer_(wojsko)\" target=\"_blank\" rel=\"noopener noreferrer\">oficerski</a> używany w armiach wielu krajów. Major jest najniższym stopniem w <a href=\"https://pl.wikipedia.org/wiki/Korpus_(wojsko)\" target=\"_blank\" rel=\"noopener noreferrer\">korpusie</a> oficerów starszych, natomiast w <a href=\"https://pl.wikipedia.org/wiki/Historia_Polski_(1918%E2%80%931939)\" target=\"_blank\" rel=\"noopener noreferrer\">okresie międzywojennym</a> wchodził w skład korpusu oficerów sztabowych. W wojsku polskim jest to stopień niższy od <a href=\"https://pl.wikipedia.org/wiki/Podpu%C5%82kownik\" target=\"_blank\" rel=\"noopener noreferrer\">podpułkownika</a>, wyższy od <a href=\"https://pl.wikipedia.org/wiki/Kapitan_(ranga)\" target=\"_blank\" rel=\"noopener noreferrer\">kapitana</a>. Odpowiednikiem majora w <a href=\"https://pl.wikipedia.org/wiki/Marynarka_wojenna\" target=\"_blank\" rel=\"noopener noreferrer\">marynarce wojennej</a> jest <a href=\"https://pl.wikipedia.org/wiki/Komandor_podporucznik\" target=\"_blank\" rel=\"noopener noreferrer\">komandor podporucznik</a>, a w <a href=\"https://pl.wikipedia.org/wiki/Policja\" target=\"_blank\" rel=\"noopener noreferrer\">policji</a> <a href=\"https://pl.wikipedia.org/wiki/Stopnie_s%C5%82u%C5%BCbowe_w_Policji\" target=\"_blank\" rel=\"noopener noreferrer\">podinspektor Policji</a>. Stopień majora występuje również w <a href=\"https://pl.wikipedia.org/wiki/Stra%C5%BC_Graniczna_(Polska)\" target=\"_blank\" rel=\"noopener noreferrer\">Straży Granicznej</a>, <a href=\"https://pl.wikipedia.org/wiki/S%C5%82u%C5%BCba_Wi%C4%99zienna\" target=\"_blank\" rel=\"noopener noreferrer\">Służbie Więziennej</a>, <a href=\"https://pl.wikipedia.org/wiki/Biuro_Ochrony_Rz%C4%85du\" target=\"_blank\" rel=\"noopener noreferrer\">Biurze Ochrony Rządu</a> oraz Służbie Kontrwywiadu i Wywiadu Wojskowego.", "Mohamed-Lamine": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohamed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Md Belal": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Yusuf": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Marek Tadeusz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marek</b>.</p><b>Marek</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, należące do wąskiej grupy najstarszych <a href=\"https://pl.wikipedia.org/wiki/Imiona_%C5%82aci%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imion rzymskich</a> (imion właściwych, <i>praenomen</i>, por. <a href=\"https://pl.wikipedia.org/wiki/Tyberiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Tyberiusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Aulus\" target=\"_blank\" rel=\"noopener noreferrer\">Aulus</a>, <a href=\"https://pl.wikipedia.org/wiki/Maniusz\" target=\"_blank\" rel=\"noopener noreferrer\">Maniusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Gajusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Gajusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Lucjusz\" target=\"_blank\" rel=\"noopener noreferrer\">Lucjusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Publiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Publiusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Tytus\" target=\"_blank\" rel=\"noopener noreferrer\">Tytus</a>, <a href=\"https://pl.wikipedia.org/wiki/Serwiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Serwiusz</a>), utworzone z <i>*Mart-ico-s</i> od imienia boga <i><a href=\"https://pl.wikipedia.org/wiki/Mars_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Mars</a></i>, <i>Martis</i> i oznaczające „należący do Marsa, związany z Marsem”. W Polsce imię to jest notowane od <a href=\"https://pl.wikipedia.org/wiki/XIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIII wieku</a>, choć poza współczesnością nie było często spotykane, w formach <i><b>Marek</b></i>, <i><b>Marko</b></i>, <i><b>Margusz</b></i>, <i><b>Markusz</b></i>, <i><b>Merkusz</b></i>. Zapisana została także żeńska <b>Marka</b> (<a href=\"https://pl.wikipedia.org/wiki/1263\" target=\"_blank\" rel=\"noopener noreferrer\">1263</a>) – żeński odpowiednik imienia Marek lub zdrobnienie od imion żeńskich rozpoczynających się na Mar-, takich jak <i>Margorzata</i> (= <a href=\"https://pl.wikipedia.org/wiki/Ma%C5%82gorzata_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Małgorzata</a>) lub <a href=\"https://pl.wikipedia.org/wiki/Maria\" target=\"_blank\" rel=\"noopener noreferrer\">Maria</a> – oraz <a href=\"https://pl.wikipedia.org/wiki/Markus%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Markusław</a>, staropolskie imię utworzone od imienia Marek poprzez dodanie typowej dla imion słowiańskich cząstki -sław. Imię to według danych 2022 r. jest na 10 miejscu najpopularniejszych imion męskich.", "Marco Aurelio": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marco</b>.</p><b>Marek</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, należące do wąskiej grupy najstarszych <a href=\"https://pl.wikipedia.org/wiki/Imiona_%C5%82aci%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imion rzymskich</a> (imion właściwych, <i>praenomen</i>, por. <a href=\"https://pl.wikipedia.org/wiki/Tyberiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Tyberiusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Aulus\" target=\"_blank\" rel=\"noopener noreferrer\">Aulus</a>, <a href=\"https://pl.wikipedia.org/wiki/Maniusz\" target=\"_blank\" rel=\"noopener noreferrer\">Maniusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Gajusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Gajusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Lucjusz\" target=\"_blank\" rel=\"noopener noreferrer\">Lucjusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Publiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Publiusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Tytus\" target=\"_blank\" rel=\"noopener noreferrer\">Tytus</a>, <a href=\"https://pl.wikipedia.org/wiki/Serwiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Serwiusz</a>), utworzone z <i>*Mart-ico-s</i> od imienia boga <i><a href=\"https://pl.wikipedia.org/wiki/Mars_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Mars</a></i>, <i>Martis</i> i oznaczające „należący do Marsa, związany z Marsem”. W Polsce imię to jest notowane od <a href=\"https://pl.wikipedia.org/wiki/XIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIII wieku</a>, choć poza współczesnością nie było często spotykane, w formach <i><b>Marek</b></i>, <i><b>Marko</b></i>, <i><b>Margusz</b></i>, <i><b>Markusz</b></i>, <i><b>Merkusz</b></i>. Zapisana została także żeńska <b>Marka</b> (<a href=\"https://pl.wikipedia.org/wiki/1263\" target=\"_blank\" rel=\"noopener noreferrer\">1263</a>) – żeński odpowiednik imienia Marek lub zdrobnienie od imion żeńskich rozpoczynających się na Mar-, takich jak <i>Margorzata</i> (= <a href=\"https://pl.wikipedia.org/wiki/Ma%C5%82gorzata_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Małgorzata</a>) lub <a href=\"https://pl.wikipedia.org/wiki/Maria\" target=\"_blank\" rel=\"noopener noreferrer\">Maria</a> – oraz <a href=\"https://pl.wikipedia.org/wiki/Markus%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Markusław</a>, staropolskie imię utworzone od imienia Marek poprzez dodanie typowej dla imion słowiańskich cząstki -sław. Imię to według danych 2022 r. jest na 10 miejscu najpopularniejszych imion męskich.", "Matyjas": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Matijas</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Matias</b>.</p><p>Matías to portugalska wersja Matthias. Matías jest bardzo popularny w Ameryce Łacińskiej, zwłaszcza w Argentynie.</p>", "Manuel David": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Manuel</b>.</p><b>Emanuel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od słowa עִמָּנוּאֵל oznaczającego „Bóg z nami”. Imię mesjasza oraz kilku świętych katolickich. Żeński odpowiednik to <a href=\"https://pl.wikipedia.org/wiki/Emanuela\" target=\"_blank\" rel=\"noopener noreferrer\">Emanuela</a>.", "Moise-Elisei": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Moise</b>.</p><p>Moise jest nazwiskiem i nazwiskiem, z różnymi pisowniami w jego francuskim i rumuńskim pochodzeniu, które oba pochodzą z imienia Mojżesz: Moïse jest francuskim pisownią Mojżesza, podczas gdy Moise jest rumuńskie pisownią. Jako nazwisko, Moisè i Mosè to włoskie pisownię Mojżesza.</p>", "Mahyar": "<p>Mahyar (perską مهیار) to perskie słowo i może odnosić się do:</p>", "Maheswaran": "<p>Maheswaran (tamilsky மகேஸ்வரன், romanized: Makēsvaraṉ) to tamilska męska nazwisko. Ze względu na tamilską tradycję używania nazwisk patronymicznych może być również nazwiskiem dla mężczyzn i kobiet.</p>", "Md Aminul Islam": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mohammad Ala": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Mikito": "<p>Mikito (pisanie: 右人 lub 幹人) to męskie japońskie imię. Wśród znanych osób z nazwiskiem są: Mikito Tachizaki (立崎 幹人; ur. 1988), japoński biatleta Mikito Takayasu (高安 右人; 1860-1938), japoński oftalmolog</p>", "Miguel Alexander": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Miguel</b>.</p><p>Miguel (hisz. Miguel) - hiszpański odpowiednik imienia Michaila.</p>", "Minh Vương": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Mohammed Fazil": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammed</b>.</p><p>Muhammad - muzułmańskie imię i nazwisko. Mahomet jest islamskim prorokiem.</p>", "Michael Javier": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Michael</b>.</p><p>Michael: Botanika Michael - skrócie botaniczne, oznaczające, że autorem taksy jest Edmund Michael. Muzyka ⁇ Michael ⁇ - piosenka grupy Franz Ferdinand, wydana w 2004 roku.</p>", "Mebarek": "<p>Mebarek jest nazwiskiem i nazwiskiem pochodzenia północnoafrykańskiego.</p>", "Md Fahim": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mohamed Aslam": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohamed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Mohammad Iqbal": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Michael Angelo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Michael</b>.</p><p>Michael: Botanika Michael - skrócie botaniczne, oznaczające, że autorem taksy jest Edmund Michael. Muzyka ⁇ Michael ⁇ - piosenka grupy Franz Ferdinand, wydana w 2004 roku.</p>", "Miguel David": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Miguel</b>.</p><p>Miguel (hisz. Miguel) - hiszpański odpowiednik imienia Michaila.</p>", "Mohammad Danish": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Md Amdadul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mustafa Can": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mustafa</b>.</p><b>Mustafa</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia arabskiego, oznacza „wybrany”.", "Md Ikbal": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Hossain": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mohammed-El-Amin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammed</b>.</p><p>Muhammad - muzułmańskie imię i nazwisko. Mahomet jest islamskim prorokiem.</p>", "Machabeusz": "<b>Machabeusz</b> – biblijne imię męskie pochodzenia hebrajskiego. Wywodzi się od słowa <em>&#8207;mqqabhak&#8206;</em>, oznaczającego \"<a href=\"https://pl.wikipedia.org/wiki/M%C5%82otek\" target=\"_blank\" rel=\"noopener noreferrer\">młot</a>\". Pojawia się wielokrotnie w <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">Biblii</a>, szczególnie w <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99gi_Machabejskie\" target=\"_blank\" rel=\"noopener noreferrer\">Księgach Machabejskich</a>.", "Marian-Alin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marian</b>.</p><b>Marian</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> od imienia <i>Marius</i> lub nazwy rodu <i>Marii</i>. Oznacza „należący do Mariusza, rodu Mariuszów”. Występuje w Polsce od 1332 roku, jako <b>Marzyjan</b>. Forma Marian pojawiła się w Polsce w XVI wieku. W języku angielskim używane jest jako imię żeńskie. W Polsce w żeńskim użyciu w 2025 roku wystąpiło 35 razy.", "Monti": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Monty</b>.</p><p>Monty to męskie imię, często skrótowa forma Montgomery, Montague i innych podobnych nazw. To też nazwisko.</p>", "Md Ziaul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mironi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Miron</b>.</p><b>Miron</b> (<i>Myron</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa <i>myron</i> oznaczającego „wonny olejek, pachnidło”.", "Md Riazul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Muamar": "<p>Muammer (wspisuje się również w podobny sposób, jak Ma'mar, arabski: معمر) jest męskie imię pochodzenia arabskiego oznaczające \"długożyłe\". Do osób z tym nazwiskiem należą:</p>", "Maria Paweł": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Md Joynal": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Min Su": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Min</b>.</p><p>Min to niejednoznaczny termin. min - w matematyce i językach programowania oznacza funkcję wyboru najmniejszego ze swoich argumentów, (Min (3, 6, 2) = 2).</p>", "Md Raihan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Miguel Ângelo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Miguel</b>.</p><p>Miguel (hisz. Miguel) - hiszpański odpowiednik imienia Michaila.</p>", "Minh Viet": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Muhammad Nadeem": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammad</b>.</p><b>Muhammad</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;مُحَمَّد&#8206;) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wariantami tego imienia są: Mohammed, Mehmed, Mamadu i Mahomet.", "Manuel Andres": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Manuel</b>.</p><b>Emanuel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od słowa עִמָּנוּאֵל oznaczającego „Bóg z nami”. Imię mesjasza oraz kilku świętych katolickich. Żeński odpowiednik to <a href=\"https://pl.wikipedia.org/wiki/Emanuela\" target=\"_blank\" rel=\"noopener noreferrer\">Emanuela</a>.", "Mukesh Singh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mukesh</b>.</p><p>Mukesh jest epitetem hinduskiego boga Shiwy i dosłownie oznacza \"podbiór demona Muka\". Jest powszechnie stosowany jako imię męskie w Indiach.</p>", "Madan Bahadur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Madan</b>.</p><p>Madan jest miastem w prowincji Smolyan, Bungaria. W 2011 roku liczba ludności wynosiła 5791.</p>", "Mohamed Aly": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohamed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Minh Hưng": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Madhava Rao": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Madhava</b>.</p><b>Madhava</b> (ur. <a href=\"https://pl.wikipedia.org/wiki/1340\" target=\"_blank\" rel=\"noopener noreferrer\">1340</a>, zm. <a href=\"https://pl.wikipedia.org/wiki/1425\" target=\"_blank\" rel=\"noopener noreferrer\">1425</a>) – <a href=\"https://pl.wikipedia.org/wiki/Indie\" target=\"_blank\" rel=\"noopener noreferrer\">indyjski</a> <a href=\"https://pl.wikipedia.org/wiki/Matematyk\" target=\"_blank\" rel=\"noopener noreferrer\">matematyk</a> i <a href=\"https://pl.wikipedia.org/wiki/Astronom\" target=\"_blank\" rel=\"noopener noreferrer\">astronom</a> pochodzący z miejscowości Sangamagramma położonej w północno-zachodnich Indiach (dzisiejsza <a href=\"https://pl.wikipedia.org/wiki/Kerala\" target=\"_blank\" rel=\"noopener noreferrer\">Kerala</a>); wniósł pionierski wkład w badania nad <a href=\"https://pl.wikipedia.org/wiki/Szereg_(matematyka)\" target=\"_blank\" rel=\"noopener noreferrer\">szeregami nieskończonymi</a>, <a href=\"https://pl.wikipedia.org/wiki/Analiza_matematyczna\" target=\"_blank\" rel=\"noopener noreferrer\">analizą matematyczną</a>, <a href=\"https://pl.wikipedia.org/wiki/Trygonometria\" target=\"_blank\" rel=\"noopener noreferrer\">trygonometrią</a>, <a href=\"https://pl.wikipedia.org/wiki/Geometria\" target=\"_blank\" rel=\"noopener noreferrer\">geometrią</a> i <a href=\"https://pl.wikipedia.org/wiki/Algebra\" target=\"_blank\" rel=\"noopener noreferrer\">algebrą</a>.", "Md Shakhawat": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Marie-Joseph": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Mohamed Aziz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohamed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Mikka": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mika</b>.</p><b>Mika</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;みか, ミカ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a> i fińskie zdrobnienie od <a href=\"https://pl.wikipedia.org/wiki/Micha%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Michała</a>.", "Md Mahabubur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mora": "<p>Mora to rodzaj roślin kwiatowych z rodziny Białego.</p>", "Md Naimul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Marius-Andrei": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marius</b>.</p>Pochodził z niższych warstw społecznych, miał być z zawodu rzemieślnikiem (kowalem), później przypuszczalnie służył w wojsku, lecz nie wiadomo w jakiej funkcji. Po stłumionej w początkach 269 roku rewolcie <a href=\"https://pl.wikipedia.org/wiki/Lelian_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Leliana</a> wzniecił kolejny bunt w <a href=\"https://pl.wikipedia.org/wiki/Moguncja\" target=\"_blank\" rel=\"noopener noreferrer\">Mogontiacum</a> przeciwko władzy <a href=\"https://pl.wikipedia.org/wiki/Wiktoryn_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Wiktoryna</a>, następcy <a href=\"https://pl.wikipedia.org/wiki/Postumus\" target=\"_blank\" rel=\"noopener noreferrer\">Postuma</a>. Według <i><a href=\"https://pl.wikipedia.org/wiki/Historia_Augusta\" target=\"_blank\" rel=\"noopener noreferrer\">Historia Augusta</a></i> jego rządy trwały zaledwie 2-3 dni, czemu jednak przeczy zachowana liczba jego monet. Najpewniej w mennicy w <a href=\"https://pl.wikipedia.org/wiki/Kolonia_(Niemcy)\" target=\"_blank\" rel=\"noopener noreferrer\">Kolonii</a> (<i>Colonia Agrippina</i>) <a href=\"https://pl.wikipedia.org/wiki/Emisja_pieni%C4%85dza\" target=\"_blank\" rel=\"noopener noreferrer\">emitował</a> w swym imieniu niskowartościowe <a href=\"https://pl.wikipedia.org/wiki/Antoninian\" target=\"_blank\" rel=\"noopener noreferrer\">antoniniany</a> typów: AEQUITAS, CONCORDIA MILIT(um), SAEC(uli) FELICITAS, VICTORIA AUG(usti), VIRTUS AUG(usti).", "Muhammad Waqas": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammad</b>.</p><b>Muhammad</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;مُحَمَّد&#8206;) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wariantami tego imienia są: Mohammed, Mehmed, Mamadu i Mahomet.", "Md Salman": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Atiqur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Marius-Cristian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marius</b>.</p>Pochodził z niższych warstw społecznych, miał być z zawodu rzemieślnikiem (kowalem), później przypuszczalnie służył w wojsku, lecz nie wiadomo w jakiej funkcji. Po stłumionej w początkach 269 roku rewolcie <a href=\"https://pl.wikipedia.org/wiki/Lelian_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Leliana</a> wzniecił kolejny bunt w <a href=\"https://pl.wikipedia.org/wiki/Moguncja\" target=\"_blank\" rel=\"noopener noreferrer\">Mogontiacum</a> przeciwko władzy <a href=\"https://pl.wikipedia.org/wiki/Wiktoryn_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Wiktoryna</a>, następcy <a href=\"https://pl.wikipedia.org/wiki/Postumus\" target=\"_blank\" rel=\"noopener noreferrer\">Postuma</a>. Według <i><a href=\"https://pl.wikipedia.org/wiki/Historia_Augusta\" target=\"_blank\" rel=\"noopener noreferrer\">Historia Augusta</a></i> jego rządy trwały zaledwie 2-3 dni, czemu jednak przeczy zachowana liczba jego monet. Najpewniej w mennicy w <a href=\"https://pl.wikipedia.org/wiki/Kolonia_(Niemcy)\" target=\"_blank\" rel=\"noopener noreferrer\">Kolonii</a> (<i>Colonia Agrippina</i>) <a href=\"https://pl.wikipedia.org/wiki/Emisja_pieni%C4%85dza\" target=\"_blank\" rel=\"noopener noreferrer\">emitował</a> w swym imieniu niskowartościowe <a href=\"https://pl.wikipedia.org/wiki/Antoninian\" target=\"_blank\" rel=\"noopener noreferrer\">antoniniany</a> typów: AEQUITAS, CONCORDIA MILIT(um), SAEC(uli) FELICITAS, VICTORIA AUG(usti), VIRTUS AUG(usti).", "Md Ebrahim": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Michał Antoni": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Michał</b>.</p><b>Michał</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִיכָאֵל&#8206; – Mîchā’ēl) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, wywodzące się od <a href=\"https://pl.wikipedia.org/wiki/Archanio%C5%82_Micha%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">jednego z archaniołów</a>. Po hebrajsku znaczy „któż [jest taki] jak Bóg”. Forma żeńska to <a href=\"https://pl.wikipedia.org/wiki/Michalina\" target=\"_blank\" rel=\"noopener noreferrer\">Michalina</a>.", "Michael Vincent": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Michael</b>.</p><p>Michael: Botanika Michael - skrócie botaniczne, oznaczające, że autorem taksy jest Edmund Michael. Muzyka ⁇ Michael ⁇ - piosenka grupy Franz Ferdinand, wydana w 2004 roku.</p>", "Matheos": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mateos</b>.</p><p>Mateos to hiszpańskie nazwisko i albanskie i etyopskie nazwisko. Do wybitnych osób z tym nazwiskiem należą:</p>", "Mohammad Ahmad": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Md Saidur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Muhammad Naveed": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammad</b>.</p><b>Muhammad</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;مُحَمَّد&#8206;) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wariantami tego imienia są: Mohammed, Mehmed, Mamadu i Mahomet.", "Md Ashik": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mohammed Omar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammed</b>.</p><p>Muhammad - muzułmańskie imię i nazwisko. Mahomet jest islamskim prorokiem.</p>", "Md Samir": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Babul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Shakawat": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mariana": "<p>Mariana jest miastem w stanie Minas Gerais w Brazylii. Miasto to ma powierzchnię 1193,293 km2, liczba ludności w 2007 roku wynosi 53989 osób, a jego gęstość 44,4 osoby/km2.</p>", "Md Zihad": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Marc François": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marc</b>.</p><p>Marc: MARC (ang. Machine-Readable Cataloging) - grupa formatów (MARC21, UNIMARC, RUSMAC itp.</p>", "Marek Krzysztof": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marek</b>.</p><b>Marek</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, należące do wąskiej grupy najstarszych <a href=\"https://pl.wikipedia.org/wiki/Imiona_%C5%82aci%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imion rzymskich</a> (imion właściwych, <i>praenomen</i>, por. <a href=\"https://pl.wikipedia.org/wiki/Tyberiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Tyberiusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Aulus\" target=\"_blank\" rel=\"noopener noreferrer\">Aulus</a>, <a href=\"https://pl.wikipedia.org/wiki/Maniusz\" target=\"_blank\" rel=\"noopener noreferrer\">Maniusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Gajusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Gajusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Lucjusz\" target=\"_blank\" rel=\"noopener noreferrer\">Lucjusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Publiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Publiusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Tytus\" target=\"_blank\" rel=\"noopener noreferrer\">Tytus</a>, <a href=\"https://pl.wikipedia.org/wiki/Serwiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Serwiusz</a>), utworzone z <i>*Mart-ico-s</i> od imienia boga <i><a href=\"https://pl.wikipedia.org/wiki/Mars_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Mars</a></i>, <i>Martis</i> i oznaczające „należący do Marsa, związany z Marsem”. W Polsce imię to jest notowane od <a href=\"https://pl.wikipedia.org/wiki/XIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIII wieku</a>, choć poza współczesnością nie było często spotykane, w formach <i><b>Marek</b></i>, <i><b>Marko</b></i>, <i><b>Margusz</b></i>, <i><b>Markusz</b></i>, <i><b>Merkusz</b></i>. Zapisana została także żeńska <b>Marka</b> (<a href=\"https://pl.wikipedia.org/wiki/1263\" target=\"_blank\" rel=\"noopener noreferrer\">1263</a>) – żeński odpowiednik imienia Marek lub zdrobnienie od imion żeńskich rozpoczynających się na Mar-, takich jak <i>Margorzata</i> (= <a href=\"https://pl.wikipedia.org/wiki/Ma%C5%82gorzata_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Małgorzata</a>) lub <a href=\"https://pl.wikipedia.org/wiki/Maria\" target=\"_blank\" rel=\"noopener noreferrer\">Maria</a> – oraz <a href=\"https://pl.wikipedia.org/wiki/Markus%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Markusław</a>, staropolskie imię utworzone od imienia Marek poprzez dodanie typowej dla imion słowiańskich cząstki -sław. Imię to według danych 2022 r. jest na 10 miejscu najpopularniejszych imion męskich.", "Md Ripon": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Michał Ludwik": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Michał</b>.</p><b>Michał</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִיכָאֵל&#8206; – Mîchā’ēl) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, wywodzące się od <a href=\"https://pl.wikipedia.org/wiki/Archanio%C5%82_Micha%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">jednego z archaniołów</a>. Po hebrajsku znaczy „któż [jest taki] jak Bóg”. Forma żeńska to <a href=\"https://pl.wikipedia.org/wiki/Michalina\" target=\"_blank\" rel=\"noopener noreferrer\">Michalina</a>.", "Min Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Min</b>.</p><p>Min to niejednoznaczny termin. min - w matematyce i językach programowania oznacza funkcję wyboru najmniejszego ze swoich argumentów, (Min (3, 6, 2) = 2).</p>", "Mohammed Ashiq": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammed</b>.</p><p>Muhammad - muzułmańskie imię i nazwisko. Mahomet jest islamskim prorokiem.</p>", "Minigniew": "<b>Minigniew</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z członów <i>Mini-</i> (\"minąć\") oraz <i>-gniew</i>. Mogło oznaczać \"tego, którego gniew szybko mija\".", "Minkai": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Minka</b>.</p><p>Minka (ur. 7 września 1970 -) jest koreańsko-amerykańską gwiazdą filmową i tenisistą.</p>", "Muhammad Asad": "<b>Muhammad Asad</b>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_urdu\" target=\"_blank\" rel=\"noopener noreferrer\">urdu</a>&#160;&#8207;محمد اسد&#8206; urodzony jako <b>Leopold Weiss</b> (ur. <a href=\"https://pl.wikipedia.org/wiki/2_lipca\" target=\"_blank\" rel=\"noopener noreferrer\">2 lipca</a> <a href=\"https://pl.wikipedia.org/wiki/1900\" target=\"_blank\" rel=\"noopener noreferrer\">1900</a> we <a href=\"https://pl.wikipedia.org/wiki/Lw%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Lwowie</a>, zm. <a href=\"https://pl.wikipedia.org/wiki/20_lutego\" target=\"_blank\" rel=\"noopener noreferrer\">20 lutego</a> <a href=\"https://pl.wikipedia.org/wiki/1992\" target=\"_blank\" rel=\"noopener noreferrer\">1992</a> w <a href=\"https://pl.wikipedia.org/wiki/Mijas\" target=\"_blank\" rel=\"noopener noreferrer\">Mijas</a>) – Austriak żydowskiego pochodzenia, dziennikarz, podróżnik, pisarz, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zykoznawstwo\" target=\"_blank\" rel=\"noopener noreferrer\">językoznawca</a>, myśliciel, reformator, <a href=\"https://pl.wikipedia.org/wiki/Dyplomata\" target=\"_blank\" rel=\"noopener noreferrer\">dyplomata</a> i politolog.", "Muhammad Khurram": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammad</b>.</p><b>Muhammad</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;مُحَمَّد&#8206;) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wariantami tego imienia są: Mohammed, Mehmed, Mamadu i Mahomet.", "Motti": "<p>Motti to męskie imię, czasami skrócona forma Mordechai lub Mordechai, a nazwisko, które może odnosić się do: Ludzi: Motti Aroesti (ur. 1954), izraelski były piłkarz koszykówki Motti Daniel (ur. 1963), izraelska piłkarza koszykówka Motti Ivanir (ur. 1964), izraelsko trener piłkarski i były gracz Motti Kakoun (ur. 1972), izraelscy emerytowany piłkarzek Motti Lerner (ur. 1949), izraelskich dramatyk i scenarzysta Motti Malka, izraelski...</p>", "Mykhayl": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mikhail</b>.</p><p>Michał (Hebrajskie: מִיכָאֵל; Aramejski: ⁇ , romanized: Mīkhāʼēl) jest powszechnym męskim imieniem, które zazwyczaj uważa się za pochodzące z hebrajskiego pytania retorycznego מי כאל (mī kāʼēl), \"Kto [jest] podobny do [Hebrajskiego boga] El?\", a więc jest nazwiskiem teoforycznym, którego odpowiedź brzmi \"nie ma nikogo podobnego do El\", lub \"nie słynny i potężny jak Bóg\".[is] Paradoksalnie, nazwisko jest czasami interpretowane jako \"Jeden...</p>", "Mkrticz": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mkrtich</b>.</p><p>Mkrtich to armenijska męska nazwa, oznaczająca na języku armenijskim Baptystę. Nazwa ta odnosi się pierwotnie do Jana Chrzciciela, znany jako Surb Hovhannes Mkrtich (Święty Jan Chrzciciel) w języku armenijskim.</p>", "Miguel Alfredo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Miguel</b>.</p><p>Miguel (hisz. Miguel) - hiszpański odpowiednik imienia Michaila.</p>", "Md Shohag": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Mohibul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mohammad Umar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Masami": "<b>Masami</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;まさみ,マサミ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a> noszone zarówno przez kobiety, jak i przez mężczyzn.", "Muhammad Imran": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammad</b>.</p><b>Muhammad</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;مُحَمَّد&#8206;) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wariantami tego imienia są: Mohammed, Mehmed, Mamadu i Mahomet.", "Muayad": "<p>Muayad, Muayyad lub Muayyed, to arabskie imię. Mieszkańcy tej nazwy to: Al-Mu'ayyad fi'l-Din al-Shirazi, 11-wieczny arabski/perskiej uczony Mu'ayyad Al-Haddad (ur. 1960), były kubajtyński piłkarz Mu'ayad Al Khouli (ur. 1993), syryjski piłkarze Mu'ayad Alayan, palestyński filmowiec, reżyser filmu The Reports on Sarah and Saleem (2018) Mu'ayad Khalid, były iracki piłkarzem Mu'ayyada al-Din al - Urdi, 11-wieczne syryjskie arabskie astronom...</p>", "Min Young": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Min</b>.</p><p>Min to niejednoznaczny termin. min - w matematyce i językach programowania oznacza funkcję wyboru najmniejszego ze swoich argumentów, (Min (3, 6, 2) = 2).</p>", "Minh Ðạt": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Matei-Daniel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Matei</b>.</p><p>Matei (rumuńska: [maˈtej]) jest rumuńskim męskim nazwiskiem i nazwiskiem. Jest odwzajemniony od nazwiska Matthias, a jest spokrewniony z angielską nazwą Matthew.</p>", "Miguel Ernesto": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Miguel</b>.</p><p>Miguel (hisz. Miguel) - hiszpański odpowiednik imienia Michaila.</p>", "Muhammed Shamil": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Md Azim": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Manuel Jr": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Manuel</b>.</p><b>Emanuel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od słowa עִמָּנוּאֵל oznaczającego „Bóg z nami”. Imię mesjasza oraz kilku świętych katolickich. Żeński odpowiednik to <a href=\"https://pl.wikipedia.org/wiki/Emanuela\" target=\"_blank\" rel=\"noopener noreferrer\">Emanuela</a>.", "Mohammad Rasel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Marie Charles": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Minh Nhut": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Mohammad Salim": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Minh Tuyên": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Muhammed Furkan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Md Roman": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Belayet": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Melaniusz": "<b>Melaniusz</b> – imię męskie pochodzenia greckiego.", "Md Sarif": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mohammed-Amine": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammed</b>.</p><p>Muhammad - muzułmańskie imię i nazwisko. Mahomet jest islamskim prorokiem.</p>", "Mykhailo-Ivan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mykhailo</b>.</p><p>Mykhailo lub Mykhaylo to ukraińskie męskie imię, równoważne angielskim Michałowi. Wśród znanych osób z nazwiskiem są: Mykhaylo Berkos (1861-1919), rosyjski i ukraiński artysta pochodzenia greckiego Mykhayilo Bolotskykh (ur. 1960), ukraiński polityk i wojskowy, pułkownik generalny (Służba Obrony Cywilnej) Mykhayło Brodskyy (ur. 1959), ukraiński polityk, przywódca Partii Wolnych Demokratów i biznesmen Mykhayla Chemberzhi,...</p>", "Md Amzad": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Manuel Alfonso": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Manuel</b>.</p><b>Emanuel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od słowa עִמָּנוּאֵל oznaczającego „Bóg z nami”. Imię mesjasza oraz kilku świętych katolickich. Żeński odpowiednik to <a href=\"https://pl.wikipedia.org/wiki/Emanuela\" target=\"_blank\" rel=\"noopener noreferrer\">Emanuela</a>.", "Mohinder": "<p>Mohinder to indyjskie imię męskie, prawdopodobnie wariant Mahendry. Wśród ludzi o imieniu Mohinder są: Mohinder Amarnath, indyjski kryketer Mohinder Lal, indyjski hokejista Mohinder Pratap Chand, indyjskie poeta Mohinder Purba (znany również jako \"Mohinder Purba\").</p>", "Marius-Costel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marius</b>.</p>Pochodził z niższych warstw społecznych, miał być z zawodu rzemieślnikiem (kowalem), później przypuszczalnie służył w wojsku, lecz nie wiadomo w jakiej funkcji. Po stłumionej w początkach 269 roku rewolcie <a href=\"https://pl.wikipedia.org/wiki/Lelian_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Leliana</a> wzniecił kolejny bunt w <a href=\"https://pl.wikipedia.org/wiki/Moguncja\" target=\"_blank\" rel=\"noopener noreferrer\">Mogontiacum</a> przeciwko władzy <a href=\"https://pl.wikipedia.org/wiki/Wiktoryn_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Wiktoryna</a>, następcy <a href=\"https://pl.wikipedia.org/wiki/Postumus\" target=\"_blank\" rel=\"noopener noreferrer\">Postuma</a>. Według <i><a href=\"https://pl.wikipedia.org/wiki/Historia_Augusta\" target=\"_blank\" rel=\"noopener noreferrer\">Historia Augusta</a></i> jego rządy trwały zaledwie 2-3 dni, czemu jednak przeczy zachowana liczba jego monet. Najpewniej w mennicy w <a href=\"https://pl.wikipedia.org/wiki/Kolonia_(Niemcy)\" target=\"_blank\" rel=\"noopener noreferrer\">Kolonii</a> (<i>Colonia Agrippina</i>) <a href=\"https://pl.wikipedia.org/wiki/Emisja_pieni%C4%85dza\" target=\"_blank\" rel=\"noopener noreferrer\">emitował</a> w swym imieniu niskowartościowe <a href=\"https://pl.wikipedia.org/wiki/Antoninian\" target=\"_blank\" rel=\"noopener noreferrer\">antoniniany</a> typów: AEQUITAS, CONCORDIA MILIT(um), SAEC(uli) FELICITAS, VICTORIA AUG(usti), VIRTUS AUG(usti).", "Masson": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mason</b>.</p><p>Mason Mason to skrócie botaniczne, oznaczające, że autorem taksy jest Mason, Francis.</p>", "Marcel-Florin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marcel</b>.</p><b>Marceli</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od nazwy jednej z gałęzi rzymskiego <a href=\"https://pl.wikipedia.org/wiki/Klaudiusze\" target=\"_blank\" rel=\"noopener noreferrer\">rodu Klaudiuszów</a>, <i>Marcelli</i>. Imię to bywa nadawane także w formie <b>Marcel</b>, jakkolwiek pojawia się ona w wydawnictwach poprawnościowych jako nieakceptowana. Żeńskim odpowiednikiem jest <a href=\"https://pl.wikipedia.org/wiki/Marcela\" target=\"_blank\" rel=\"noopener noreferrer\">Marcela</a>.", "Md Shah": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Muhammad Sajid": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammad</b>.</p><b>Muhammad</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;مُحَمَّد&#8206;) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wariantami tego imienia są: Mohammed, Mehmed, Mamadu i Mahomet.", "Mady": "<p>Mady to imię i nazwisko (rzadko można go używać jako nick). Jest to nazwisko unisex.</p>", "Maryk": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Marik</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Marika</b>.</p><b>Marika</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzące od imienia „<a href=\"https://pl.wikipedia.org/wiki/Maria\" target=\"_blank\" rel=\"noopener noreferrer\">Maria</a>”. Jest <a href=\"https://pl.wikipedia.org/wiki/W%C4%99gry\" target=\"_blank\" rel=\"noopener noreferrer\">węgierską</a> formą tego imienia, chociaż znane jest także w Bułgarii i na terenie byłej Jugosławii. Imię jest również zniemczoną formą zdrobnienia „Maryjka” występującego w <a href=\"https://pl.wikipedia.org/wiki/Etnolekt_%C5%9Bl%C4%85ski\" target=\"_blank\" rel=\"noopener noreferrer\">etnolekcie śląskim</a>.", "Md Sohag": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Miomir": "<p>Miomir (Serbski cyrylski: Миомир) to serbsko-chorwackie męskie imię pochodzenia słowiańskiego. Do wybitnych osób z nazwiskiem należą: Miomir Mugoša (ur. 1955), czarnogorski polityk Miomir Vukobratović (1931-2012), serbski wynalazca Miomir Žužul (ur. 1955), chorwacki polityk Mior Kecmanović (ur. 1999), serbski tenista Miomir Petrović, członek grupy rockowej Siluete</p>", "Mon Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mon</b>.</p><p>Mon może oznaczać: Miasto miasta Mon w stanie Nagaland, Indie Nowoczesna Indie Nagaland, India Wyspa Mon w Danie Mianmarskie Narody i języki Naród Mon (lub Mon) w południowo-wschodniej Azji Mońskie (narodu Mon) w grupie języków Mon-Khmer Odmienne MON jest kodem IATA Monarch Airlines Powieść Mon (門) Soseki Natsume Japoński mon (文) jest popularny w Japonii</p>", "Md Bayezid": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Muhammad Hassan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammad</b>.</p><b>Muhammad</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;مُحَمَّد&#8206;) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wariantami tego imienia są: Mohammed, Mehmed, Mamadu i Mahomet.", "Mahmoud Ahmed": "<b>Mahmoud Ahmed</b> (<i><a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_amharski\" target=\"_blank\" rel=\"noopener noreferrer\">amh.</a></i> ማሀሙድ አህመድ; ur. <a href=\"https://pl.wikipedia.org/wiki/8_maja\" target=\"_blank\" rel=\"noopener noreferrer\">8</a> lub <a href=\"https://pl.wikipedia.org/wiki/18_maja\" target=\"_blank\" rel=\"noopener noreferrer\">18 maja</a> <a href=\"https://pl.wikipedia.org/wiki/1941\" target=\"_blank\" rel=\"noopener noreferrer\">1941</a>) – <a href=\"https://pl.wikipedia.org/wiki/Etiopia\" target=\"_blank\" rel=\"noopener noreferrer\">etiopski</a> muzyk pochodzący z ludu <a href=\"https://pl.wikipedia.org/wiki/Gurage\" target=\"_blank\" rel=\"noopener noreferrer\">Gurage</a>.", "Muhammed Ashique": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Melquiades": "<p>Melquíades to hiszpańskie imię. Jest to hiszpańska forma greckiego imienia Melchiades, jak w papieżu Miltiades.</p>", "Mohammad Shamsul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Mario Luis": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mario</b>.</p><p>Mario (jap. Mario Mario, angielski.</p>", "Marius-Ioan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marius</b>.</p>Pochodził z niższych warstw społecznych, miał być z zawodu rzemieślnikiem (kowalem), później przypuszczalnie służył w wojsku, lecz nie wiadomo w jakiej funkcji. Po stłumionej w początkach 269 roku rewolcie <a href=\"https://pl.wikipedia.org/wiki/Lelian_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Leliana</a> wzniecił kolejny bunt w <a href=\"https://pl.wikipedia.org/wiki/Moguncja\" target=\"_blank\" rel=\"noopener noreferrer\">Mogontiacum</a> przeciwko władzy <a href=\"https://pl.wikipedia.org/wiki/Wiktoryn_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Wiktoryna</a>, następcy <a href=\"https://pl.wikipedia.org/wiki/Postumus\" target=\"_blank\" rel=\"noopener noreferrer\">Postuma</a>. Według <i><a href=\"https://pl.wikipedia.org/wiki/Historia_Augusta\" target=\"_blank\" rel=\"noopener noreferrer\">Historia Augusta</a></i> jego rządy trwały zaledwie 2-3 dni, czemu jednak przeczy zachowana liczba jego monet. Najpewniej w mennicy w <a href=\"https://pl.wikipedia.org/wiki/Kolonia_(Niemcy)\" target=\"_blank\" rel=\"noopener noreferrer\">Kolonii</a> (<i>Colonia Agrippina</i>) <a href=\"https://pl.wikipedia.org/wiki/Emisja_pieni%C4%85dza\" target=\"_blank\" rel=\"noopener noreferrer\">emitował</a> w swym imieniu niskowartościowe <a href=\"https://pl.wikipedia.org/wiki/Antoninian\" target=\"_blank\" rel=\"noopener noreferrer\">antoniniany</a> typów: AEQUITAS, CONCORDIA MILIT(um), SAEC(uli) FELICITAS, VICTORIA AUG(usti), VIRTUS AUG(usti).", "Mohammad Akbar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Marian Antoni": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marian</b>.</p><b>Marian</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> od imienia <i>Marius</i> lub nazwy rodu <i>Marii</i>. Oznacza „należący do Mariusza, rodu Mariuszów”. Występuje w Polsce od 1332 roku, jako <b>Marzyjan</b>. Forma Marian pojawiła się w Polsce w XVI wieku. W języku angielskim używane jest jako imię żeńskie. W Polsce w żeńskim użyciu w 2025 roku wystąpiło 35 razy.", "Mihai-Alexandru": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mihai</b>.</p><p>Mihai (rumuńska wymowa: [miˈhaj]) jest rumuńskim nazwiskiem męskim lub nazwiskiem. To równoważne angielskiej imienia Michael.</p>", "Muammar": "<p>Muammer (wspisuje się również w podobny sposób, jak Ma'mar, arabski: معمر) jest męskie imię pochodzenia arabskiego oznaczające \"długożyłe\". Do osób z tym nazwiskiem należą:</p>", "Musbah": "<p>Misbah (arabski: مصباح, romanized: Miṣbāḥ) lub Musbah to muzułmańska nazwa arabska oznaczająca \"lampa\" lub \"światło\". Nazwa ta pochodzi z Koranu z Ayatu-n-Nur, znanej również jako Ajaty światła, z następującego wersetu: \"Bóg jest światłem niebios i ziemi.</p>", "Mohammad Suleiman": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Minh Thi": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Mihai-Adrian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mihai</b>.</p><p>Mihai (rumuńska wymowa: [miˈhaj]) jest rumuńskim nazwiskiem męskim lub nazwiskiem. To równoważne angielskiej imienia Michael.</p>", "Md Rajon": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Magdalena": "<b>Magdalena</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od przydomka <a href=\"https://pl.wikipedia.org/wiki/Maria_Magdalena\" target=\"_blank\" rel=\"noopener noreferrer\">Marii Magdaleny</a>, czyli Marii z <a href=\"https://pl.wikipedia.org/wiki/Magdala_(Izrael)\" target=\"_blank\" rel=\"noopener noreferrer\">Magdali</a>, wioski leżącej w pobliżu <a href=\"https://pl.wikipedia.org/wiki/Jezioro_Tyberiadzkie\" target=\"_blank\" rel=\"noopener noreferrer\">Jeziora Tyberiadzkiego (Galilejskiego)</a>.", "Marta": "<b>Marta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. Wywodzi się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_aramejski\" target=\"_blank\" rel=\"noopener noreferrer\">aramejskiego</a> rzeczownika <i>mar</i>, <i>mar(a)tha, marta</i>, oznaczającego „pani domu, gospodyni, pani”. W Polsce po raz pierwszy zanotowano je w 1265 roku. Do dawnych zdrobnień zaliczała się np. Marusza (wsł., od wsł. <i>Marchwa</i>), oraz m.in. <i>Marocha, Marsza, Marszka, Marucha, Maruchna, Maruszka</i> (też od innych imion na Ma-, np. od <a href=\"https://pl.wikipedia.org/wiki/Ma%C5%82gorzata_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Małgorzaty</a>). Istnieje ponad 10 świętych katolickich o tym imieniu.", "Md Rana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mohamed-Ali": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohamed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Michael-Alexander": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Michael</b>.</p><p>Michael: Botanika Michael - skrócie botaniczne, oznaczające, że autorem taksy jest Edmund Michael. Muzyka ⁇ Michael ⁇ - piosenka grupy Franz Ferdinand, wydana w 2004 roku.</p>", "Manase": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Manas</b>.</p><p>Manas (stylownik: 玛纳斯县; substylownik; ślonski: 玛納斯县; ślony: Mǎnàsī Xiàn, vietnamski: Mǎnásī Xiàn; uygurski: Manas ناھىيىسى , ULY: Manas Nahiyisi, UPNY: Manas Nah ⁇ iyisi?) jest okręgem samorządu Azji narodowego muzułmańskiego, regionu samorządowego Tangiu, China. Obecnie mieści się w stanie Manas (玛纳斯), na brzegu rzeki Manas, wschodniej od Czarnogórza.</p>", "Marzouk": "<p>Marzouk lub Marzouq to męskie imię i nazwisko pochodzenia arabskiego. Do wybitnych osób z tym nazwiskiem należą:</p>", "Mame": "<b>MAME</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">ang.</a>&#160;<em>Multiple Arcade Machine Emulator</em>) – <a href=\"https://pl.wikipedia.org/wiki/Emulator\" target=\"_blank\" rel=\"noopener noreferrer\">emulator</a> pozwalający na uruchomienie gier ze starych <a href=\"https://pl.wikipedia.org/wiki/Automat_do_gry\" target=\"_blank\" rel=\"noopener noreferrer\">automatów do gry</a> na współczesnych platformach sprzętowych. Twórcą emulatora jest Nicola Salmoria, a pierwszą wersję programu (0.1) stworzył w 1997 roku. Serwis <a href=\"https://pl.wikipedia.org/wiki/Joystiq\" target=\"_blank\" rel=\"noopener noreferrer\">Joystiq</a> umieścił MAME na liście programów, które każdy gracz powinien posiadać.", "Md Zahangir": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Manuel Esteban": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Manuel</b>.</p><b>Emanuel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od słowa עִמָּנוּאֵל oznaczającego „Bóg z nami”. Imię mesjasza oraz kilku świętych katolickich. Żeński odpowiednik to <a href=\"https://pl.wikipedia.org/wiki/Emanuela\" target=\"_blank\" rel=\"noopener noreferrer\">Emanuela</a>.", "Maksymiliano": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maksymilian</b>.</p><b>Maksymilian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa <i>maximus</i> oznaczającego „największy” oraz nazwiska <a href=\"https://pl.wikipedia.org/wiki/Staro%C5%BCytny_Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">rzymskiego</a> rodu <a href=\"https://pl.wikipedia.org/wiki/Emiliusze\" target=\"_blank\" rel=\"noopener noreferrer\">Emiliuszów</a>. Żeńskie odpowiedniki tego imienia to <a href=\"https://pl.wikipedia.org/wiki/Maksymiliana\" target=\"_blank\" rel=\"noopener noreferrer\">Maksymiliana</a> i <a href=\"https://pl.wikipedia.org/wiki/Maksymiliana\" target=\"_blank\" rel=\"noopener noreferrer\">Maksymilianna</a>.", "Mohammad Arshad": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Md Didarul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Muhammad Tahir": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammad</b>.</p><b>Muhammad</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;مُحَمَّد&#8206;) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wariantami tego imienia są: Mohammed, Mehmed, Mamadu i Mahomet.", "Malith": "<p>Malith to imię. Znani ludzie z nazwiska to: Malith Cooray (ur. 1990), kryketer Sri Lanki Malith Gunathilake (ur. 1987), kryker Sri Lanki Malith Jayathilake, polityk Sri Lanki Malith Kumara (ur. 1989), krykera Sri Lanki Malik Premathilake (urd. 1997), kryketa Sri Lanki Maleth de Silva (ur. 1992), kryketera Sri Lanka Malith de Silva</p>", "Mohammed Abul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammed</b>.</p><p>Muhammad - muzułmańskie imię i nazwisko. Mahomet jest islamskim prorokiem.</p>", "Mario Fernando": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mario</b>.</p><p>Mario (jap. Mario Mario, angielski.</p>", "Marco Alexandre": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marco</b>.</p><b>Marek</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, należące do wąskiej grupy najstarszych <a href=\"https://pl.wikipedia.org/wiki/Imiona_%C5%82aci%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imion rzymskich</a> (imion właściwych, <i>praenomen</i>, por. <a href=\"https://pl.wikipedia.org/wiki/Tyberiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Tyberiusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Aulus\" target=\"_blank\" rel=\"noopener noreferrer\">Aulus</a>, <a href=\"https://pl.wikipedia.org/wiki/Maniusz\" target=\"_blank\" rel=\"noopener noreferrer\">Maniusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Gajusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Gajusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Lucjusz\" target=\"_blank\" rel=\"noopener noreferrer\">Lucjusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Publiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Publiusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Tytus\" target=\"_blank\" rel=\"noopener noreferrer\">Tytus</a>, <a href=\"https://pl.wikipedia.org/wiki/Serwiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Serwiusz</a>), utworzone z <i>*Mart-ico-s</i> od imienia boga <i><a href=\"https://pl.wikipedia.org/wiki/Mars_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Mars</a></i>, <i>Martis</i> i oznaczające „należący do Marsa, związany z Marsem”. W Polsce imię to jest notowane od <a href=\"https://pl.wikipedia.org/wiki/XIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIII wieku</a>, choć poza współczesnością nie było często spotykane, w formach <i><b>Marek</b></i>, <i><b>Marko</b></i>, <i><b>Margusz</b></i>, <i><b>Markusz</b></i>, <i><b>Merkusz</b></i>. Zapisana została także żeńska <b>Marka</b> (<a href=\"https://pl.wikipedia.org/wiki/1263\" target=\"_blank\" rel=\"noopener noreferrer\">1263</a>) – żeński odpowiednik imienia Marek lub zdrobnienie od imion żeńskich rozpoczynających się na Mar-, takich jak <i>Margorzata</i> (= <a href=\"https://pl.wikipedia.org/wiki/Ma%C5%82gorzata_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Małgorzata</a>) lub <a href=\"https://pl.wikipedia.org/wiki/Maria\" target=\"_blank\" rel=\"noopener noreferrer\">Maria</a> – oraz <a href=\"https://pl.wikipedia.org/wiki/Markus%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Markusław</a>, staropolskie imię utworzone od imienia Marek poprzez dodanie typowej dla imion słowiańskich cząstki -sław. Imię to według danych 2022 r. jest na 10 miejscu najpopularniejszych imion męskich.", "Motoi": "<p>Motoi to japońska nazwa, która może odnosić się do: Motoi -motoi, ósmej piosenki na albumie muzycznym Amachan przez Matsuko Mawatari.</p>", "Muhammad Saad": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammad</b>.</p><b>Muhammad</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;مُحَمَّد&#8206;) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wariantami tego imienia są: Mohammed, Mehmed, Mamadu i Mahomet.", "Md Enamul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mohammad Anis": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Manuel Felipe": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Manuel</b>.</p><b>Emanuel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od słowa עִמָּנוּאֵל oznaczającego „Bóg z nami”. Imię mesjasza oraz kilku świętych katolickich. Żeński odpowiednik to <a href=\"https://pl.wikipedia.org/wiki/Emanuela\" target=\"_blank\" rel=\"noopener noreferrer\">Emanuela</a>.", "Mohammad Shahadat": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Mohammad Arman": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Md Sajid": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Michael Jr.": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Michael</b>.</p><p>Michael: Botanika Michael - skrócie botaniczne, oznaczające, że autorem taksy jest Edmund Michael. Muzyka ⁇ Michael ⁇ - piosenka grupy Franz Ferdinand, wydana w 2004 roku.</p>", "Md Shaiful": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Morshed": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Min Jae": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Min</b>.</p><p>Min to niejednoznaczny termin. min - w matematyce i językach programowania oznacza funkcję wyboru najmniejszego ze swoich argumentów, (Min (3, 6, 2) = 2).</p>", "Md Saleh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Ujjal": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Måns": "<p>Måns to szwedzka męska nazwa, która może odnosić się do Måns, fikcyjnego kota w Pelle Svanslös dziecka historii Gösta Knutsson 8536 Måns, niewielkiej planety nazwanej po kota Måns Andersson, 17-wieczny szwedzki odkrywca Måns Ekvall (ur. 1995), szwedzkiej piłkarz Måns Forsfjäll (ur. 2002), szwedyckiego obrońca hokeja na lodzie Måns Gahrton (ur. 1961), szwedeski autor Måns Grenhagen (ur. 1993), szwedski kierowca wyścigów Måns Groundstroem (ur....</p>", "Mihai-Claudiu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mihai</b>.</p><p>Mihai (rumuńska wymowa: [miˈhaj]) jest rumuńskim nazwiskiem męskim lub nazwiskiem. To równoważne angielskiej imienia Michael.</p>", "Marius-Ionuţ": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marius</b>.</p>Pochodził z niższych warstw społecznych, miał być z zawodu rzemieślnikiem (kowalem), później przypuszczalnie służył w wojsku, lecz nie wiadomo w jakiej funkcji. Po stłumionej w początkach 269 roku rewolcie <a href=\"https://pl.wikipedia.org/wiki/Lelian_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Leliana</a> wzniecił kolejny bunt w <a href=\"https://pl.wikipedia.org/wiki/Moguncja\" target=\"_blank\" rel=\"noopener noreferrer\">Mogontiacum</a> przeciwko władzy <a href=\"https://pl.wikipedia.org/wiki/Wiktoryn_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Wiktoryna</a>, następcy <a href=\"https://pl.wikipedia.org/wiki/Postumus\" target=\"_blank\" rel=\"noopener noreferrer\">Postuma</a>. Według <i><a href=\"https://pl.wikipedia.org/wiki/Historia_Augusta\" target=\"_blank\" rel=\"noopener noreferrer\">Historia Augusta</a></i> jego rządy trwały zaledwie 2-3 dni, czemu jednak przeczy zachowana liczba jego monet. Najpewniej w mennicy w <a href=\"https://pl.wikipedia.org/wiki/Kolonia_(Niemcy)\" target=\"_blank\" rel=\"noopener noreferrer\">Kolonii</a> (<i>Colonia Agrippina</i>) <a href=\"https://pl.wikipedia.org/wiki/Emisja_pieni%C4%85dza\" target=\"_blank\" rel=\"noopener noreferrer\">emitował</a> w swym imieniu niskowartościowe <a href=\"https://pl.wikipedia.org/wiki/Antoninian\" target=\"_blank\" rel=\"noopener noreferrer\">antoniniany</a> typów: AEQUITAS, CONCORDIA MILIT(um), SAEC(uli) FELICITAS, VICTORIA AUG(usti), VIRTUS AUG(usti).", "Md Sazzad Hossain": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Tariqul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Dulal": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Muhammed Faris": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Meseret": "<p>Meseret (amharski: መሰረት) to imię kobiety lub mężczyzny pochodzenia etyopskiego, które może odnosić się do: Meseret Defar (ur. 1983), etyopski biegacz długodystansowy i dwukrotny mistrz olimpijski Meseret Hailu (ur. 1990), etyopijski biegacz długości i mistrz świata półmaratonów Meseret Mebrate, etyopska aktorka Meseret Mengistu (ur. 1990, etyopskie biegacz na długodystans i medaliarz drużyny w 2010 IAAF World Half Marathon Championships</p>", "Madison": "<p>Madison: Madison to angielskojęzyczne nazwisko i toponim. Madison to skrócie botaniczne, które oznacza, że autorem taksy jest Michael Madison.</p>", "Muhammed Sefa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Mira": "<b>Mira</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie. Jest skróconą (zdrobniałą) formą <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskiego imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Miros%C5%82awa\" target=\"_blank\" rel=\"noopener noreferrer\">Mirosława</a>. Imię pochodzenia słowiańskiego o niejasnej etymologii. Najprawdopodobniej wywodzi się od rdzenia mir (\"pokój, świat\") i oznacza: \"zgodna, spokojna\". Inna hipoteza zakłada, iż funkcjonuje samodzielnie jako skrót imion Mirosława, Miranda, Sławomira itp. Kolejna teoria głosi, że jest to po prostu żeński odpowiednik imienia Miron. Istnieje także hinduskie imię żeńskie o tym samym brzmieniu, wywodzące się ze słowa oznaczającego \"morze, ocean\" w języku <a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sanskryt</a>. Nosiła je XVI-wieczna <a href=\"https://pl.wikipedia.org/wiki/Indie\" target=\"_blank\" rel=\"noopener noreferrer\">indyjska</a> księżniczka, znana wyznawczyni boga <a href=\"https://pl.wikipedia.org/wiki/Kryszna\" target=\"_blank\" rel=\"noopener noreferrer\">Kriszny</a>. Może stanowić także formę skróconą niesłowiańskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Miranda_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miranda</a>.", "Mohammad A": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Md Sohan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Amirul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Minh Nhật": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Md Rabbi": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Marian-Ionuţ": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marian</b>.</p><b>Marian</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> od imienia <i>Marius</i> lub nazwy rodu <i>Marii</i>. Oznacza „należący do Mariusza, rodu Mariuszów”. Występuje w Polsce od 1332 roku, jako <b>Marzyjan</b>. Forma Marian pojawiła się w Polsce w XVI wieku. W języku angielskim używane jest jako imię żeńskie. W Polsce w żeńskim użyciu w 2025 roku wystąpiło 35 razy.", "Morrie": "<p>Morrie to męskie imię, często diminutiwna forma (hipokoryzm) Morris lub Maurice. Może odnosić się do:</p>", "Md Mazharul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Salim": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mohammad Salman": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Md Shoriful": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Man Singh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Man</b>.</p><p>man (od angielskiego manual - wytyczne) - polecenie Unix przeznaczone do formatowania i wyciągania stron odniesienia.</p>", "Md Hafizur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Minh Châu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Marius-Vasile": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marius</b>.</p>Pochodził z niższych warstw społecznych, miał być z zawodu rzemieślnikiem (kowalem), później przypuszczalnie służył w wojsku, lecz nie wiadomo w jakiej funkcji. Po stłumionej w początkach 269 roku rewolcie <a href=\"https://pl.wikipedia.org/wiki/Lelian_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Leliana</a> wzniecił kolejny bunt w <a href=\"https://pl.wikipedia.org/wiki/Moguncja\" target=\"_blank\" rel=\"noopener noreferrer\">Mogontiacum</a> przeciwko władzy <a href=\"https://pl.wikipedia.org/wiki/Wiktoryn_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Wiktoryna</a>, następcy <a href=\"https://pl.wikipedia.org/wiki/Postumus\" target=\"_blank\" rel=\"noopener noreferrer\">Postuma</a>. Według <i><a href=\"https://pl.wikipedia.org/wiki/Historia_Augusta\" target=\"_blank\" rel=\"noopener noreferrer\">Historia Augusta</a></i> jego rządy trwały zaledwie 2-3 dni, czemu jednak przeczy zachowana liczba jego monet. Najpewniej w mennicy w <a href=\"https://pl.wikipedia.org/wiki/Kolonia_(Niemcy)\" target=\"_blank\" rel=\"noopener noreferrer\">Kolonii</a> (<i>Colonia Agrippina</i>) <a href=\"https://pl.wikipedia.org/wiki/Emisja_pieni%C4%85dza\" target=\"_blank\" rel=\"noopener noreferrer\">emitował</a> w swym imieniu niskowartościowe <a href=\"https://pl.wikipedia.org/wiki/Antoninian\" target=\"_blank\" rel=\"noopener noreferrer\">antoniniany</a> typów: AEQUITAS, CONCORDIA MILIT(um), SAEC(uli) FELICITAS, VICTORIA AUG(usti), VIRTUS AUG(usti).", "Marc-Olivier": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marc</b>.</p><p>Marc: MARC (ang. Machine-Readable Cataloging) - grupa formatów (MARC21, UNIMARC, RUSMAC itp.</p>", "Mykola-Roman": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mykola</b>.</p><p>Mykola jest ukraińską wariantą męskiego nazwiska \"Nicholas\", co oznacza \"wygrę narodu\". Może odnosić się do:</p>", "Marian Bogdan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marian</b>.</p><b>Marian</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> od imienia <i>Marius</i> lub nazwy rodu <i>Marii</i>. Oznacza „należący do Mariusza, rodu Mariuszów”. Występuje w Polsce od 1332 roku, jako <b>Marzyjan</b>. Forma Marian pojawiła się w Polsce w XVI wieku. W języku angielskim używane jest jako imię żeńskie. W Polsce w żeńskim użyciu w 2025 roku wystąpiło 35 razy.", "Md Nayem": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Marius-Iulian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marius</b>.</p>Pochodził z niższych warstw społecznych, miał być z zawodu rzemieślnikiem (kowalem), później przypuszczalnie służył w wojsku, lecz nie wiadomo w jakiej funkcji. Po stłumionej w początkach 269 roku rewolcie <a href=\"https://pl.wikipedia.org/wiki/Lelian_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Leliana</a> wzniecił kolejny bunt w <a href=\"https://pl.wikipedia.org/wiki/Moguncja\" target=\"_blank\" rel=\"noopener noreferrer\">Mogontiacum</a> przeciwko władzy <a href=\"https://pl.wikipedia.org/wiki/Wiktoryn_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Wiktoryna</a>, następcy <a href=\"https://pl.wikipedia.org/wiki/Postumus\" target=\"_blank\" rel=\"noopener noreferrer\">Postuma</a>. Według <i><a href=\"https://pl.wikipedia.org/wiki/Historia_Augusta\" target=\"_blank\" rel=\"noopener noreferrer\">Historia Augusta</a></i> jego rządy trwały zaledwie 2-3 dni, czemu jednak przeczy zachowana liczba jego monet. Najpewniej w mennicy w <a href=\"https://pl.wikipedia.org/wiki/Kolonia_(Niemcy)\" target=\"_blank\" rel=\"noopener noreferrer\">Kolonii</a> (<i>Colonia Agrippina</i>) <a href=\"https://pl.wikipedia.org/wiki/Emisja_pieni%C4%85dza\" target=\"_blank\" rel=\"noopener noreferrer\">emitował</a> w swym imieniu niskowartościowe <a href=\"https://pl.wikipedia.org/wiki/Antoninian\" target=\"_blank\" rel=\"noopener noreferrer\">antoniniany</a> typów: AEQUITAS, CONCORDIA MILIT(um), SAEC(uli) FELICITAS, VICTORIA AUG(usti), VIRTUS AUG(usti).", "Marius-Aurel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marius</b>.</p>Pochodził z niższych warstw społecznych, miał być z zawodu rzemieślnikiem (kowalem), później przypuszczalnie służył w wojsku, lecz nie wiadomo w jakiej funkcji. Po stłumionej w początkach 269 roku rewolcie <a href=\"https://pl.wikipedia.org/wiki/Lelian_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Leliana</a> wzniecił kolejny bunt w <a href=\"https://pl.wikipedia.org/wiki/Moguncja\" target=\"_blank\" rel=\"noopener noreferrer\">Mogontiacum</a> przeciwko władzy <a href=\"https://pl.wikipedia.org/wiki/Wiktoryn_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Wiktoryna</a>, następcy <a href=\"https://pl.wikipedia.org/wiki/Postumus\" target=\"_blank\" rel=\"noopener noreferrer\">Postuma</a>. Według <i><a href=\"https://pl.wikipedia.org/wiki/Historia_Augusta\" target=\"_blank\" rel=\"noopener noreferrer\">Historia Augusta</a></i> jego rządy trwały zaledwie 2-3 dni, czemu jednak przeczy zachowana liczba jego monet. Najpewniej w mennicy w <a href=\"https://pl.wikipedia.org/wiki/Kolonia_(Niemcy)\" target=\"_blank\" rel=\"noopener noreferrer\">Kolonii</a> (<i>Colonia Agrippina</i>) <a href=\"https://pl.wikipedia.org/wiki/Emisja_pieni%C4%85dza\" target=\"_blank\" rel=\"noopener noreferrer\">emitował</a> w swym imieniu niskowartościowe <a href=\"https://pl.wikipedia.org/wiki/Antoninian\" target=\"_blank\" rel=\"noopener noreferrer\">antoniniany</a> typów: AEQUITAS, CONCORDIA MILIT(um), SAEC(uli) FELICITAS, VICTORIA AUG(usti), VIRTUS AUG(usti).", "Muhammed Burak": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Manga Raju": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Manga</b>.</p><b>Manga</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;漫画&#59; wymowa (<a href=\"https://pl.wikipedia.org/wiki/IPA\" target=\"_blank\" rel=\"noopener noreferrer\">IPA</a>): <a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_nosowa_dwuwargowa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">m</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_otwarta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">a</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_nosowa_tylnoj%C4%99zykowo-mi%C4%99kkopodniebienna_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">ŋ</a><a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">g</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_otwarta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">a</a>) – komiks, obraz, rysunek, szkic, <a href=\"https://pl.wikipedia.org/wiki/Karykatura\" target=\"_blank\" rel=\"noopener noreferrer\">karykatura</a>. Japońskie słowo wywodzące się ze sposobu ozdabiania <a href=\"https://pl.wikipedia.org/wiki/Rycina\" target=\"_blank\" rel=\"noopener noreferrer\">rycin</a> i innych form <a href=\"https://pl.wikipedia.org/wiki/Sztuka_u%C5%BCytkowa\" target=\"_blank\" rel=\"noopener noreferrer\">sztuki użytkowej</a>. Współcześnie używane poza <a href=\"https://pl.wikipedia.org/wiki/Japonia\" target=\"_blank\" rel=\"noopener noreferrer\">Japonią</a> oznacza japoński <a href=\"https://pl.wikipedia.org/wiki/Komiks\" target=\"_blank\" rel=\"noopener noreferrer\">komiks</a>.", "Md Moshiur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Myślibór": "<b>Myślibor</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Myśli-</i> (\"myśleć\") i <i>-bor</i> (\"walczyć, zmagać się\"). Być może oznaczało \"tego, który myśli o walce\" albo \"tego, który obmyśla walkę\".", "Mohan Raj": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohan</b>.</p><p>Mohan to gmin i nagar panchayat z okręgu Unnao w stanie Uttar Pradesh, India.</p>", "Md Imam": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Amin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Mainul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mary": "<p>Mary: Mary (Mary, rzadko Marie) - angielskie nazwisko kobiece, odpowiadające rosyjskiej nazwie Maria. Jest to jedno z najstarszych nazw zachowanych do naszych czasów.</p>", "Mohammad Al": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Minh Phương": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Minh Triet": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Minh Thành": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Mohammad Ismail": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Martyna": "<b>Martyna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> od męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Marcin\" target=\"_blank\" rel=\"noopener noreferrer\">Marcin</a> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Martinus</em>, „należący do <a href=\"https://pl.wikipedia.org/wiki/Mars_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Marsa”</a>). Błędnym skojarzeniem jest, że Martyna powstała od imienia <a href=\"https://pl.wikipedia.org/wiki/Marta_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Marta</a>. Spotykana jest również forma <b>Marcina</b>. W wielu językach imię to występuje w formie <i>Martina</i>.", "Md Emdadul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Monirul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Motiur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Miralem": "<p>Miralem to bosniackie imię męskie. Nazwa pochodzi z arabskiego أَمِير (ʾamīr) oznaczającego \"księcia, dowódca\" w połączeniu z عالم (ʿālam) oznaczającym \"świat, królestwo\".</p>", "Md Saddam": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mario Roberto": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mario</b>.</p><p>Mario (jap. Mario Mario, angielski.</p>", "Mohammad Abdur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Maksym-Oleksandr": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maksym</b>.</p><b>Maksym</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, utworzone od przymiotnika <i>maximus</i> oznaczający \"największy\", przydomka <a href=\"https://pl.wikipedia.org/wiki/Jowisz_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Jowisza</a>. Istnieją liczni święci prawosławni i katoliccy o tym imieniu: <a href=\"https://pl.wikipedia.org/wiki/Maksym_Wyznawca\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym Wyznawca</a>, <a href=\"https://pl.wikipedia.org/wiki/Maksym_Grek\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym Grek</a>, <a href=\"https://pl.wikipedia.org/wiki/Maksym_Brankowicz\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym Wołoski</a>, <a href=\"https://pl.wikipedia.org/wiki/Maksym_Gorlicki\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym Gorlicki</a>, <a href=\"https://pl.wikipedia.org/wiki/Maksym_z_Riez\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym z Riez</a> i wielu innych.", "Marie Pierre": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Marian-Mădălin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marian</b>.</p><b>Marian</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> od imienia <i>Marius</i> lub nazwy rodu <i>Marii</i>. Oznacza „należący do Mariusza, rodu Mariuszów”. Występuje w Polsce od 1332 roku, jako <b>Marzyjan</b>. Forma Marian pojawiła się w Polsce w XVI wieku. W języku angielskim używane jest jako imię żeńskie. W Polsce w żeńskim użyciu w 2025 roku wystąpiło 35 razy.", "Md Akter": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Martins Krasowski": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Martins</b>.</p><p>Martins to miasto w Brazylii. Miasto ma powierzchnię 169,466 km2, liczba ludności w 2007 roku wynosi 7551 mieszkańców, a jego gęstość 44,6 mieszkańców/km2.</p>", "Md Tarikul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Minh Hùng": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Mostafa Ibrahim": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mostafa</b>.</p><p>Mustafa sultan (tat. Mostafa, Mostafa; umysł.</p>", "Mohamed Yassine": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohamed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Mitya": "<p>Dmitry (rosyjski: Дми́трий; forma słowiańska Kościoła: Dimitry lub Dimitri (Дими́трий); starożytne rosyjskie formy: D'mitriy lub Dmitr (Дьмитр (ии) lub Дъмитръ)) to męskie imię w kulturze prawosławnej chrześcijańskiej, rosyjska wersja Demetrios (grek. Δημήτριος, romanized: Dēm ⁇ trios, greckie wymowa: [ðiˈmitrios]). Znaczenie nazwy jest \"oddana, poświęcona lub wyznawczy Demetera\" (Δημήτηρ, Dēmētēr), \"matka-Ziemia\", greckiej bogini...</p>", "Mohammed Amir": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammed</b>.</p><p>Muhammad - muzułmańskie imię i nazwisko. Mahomet jest islamskim prorokiem.</p>", "Md Tufajjal": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Tawhid": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Al-Amin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Jobayer": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mohammad Minhaj": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Majewski": "<b>Majewski</b> (forma żeńska: <b>Majewska</b>; liczba mnoga: <b>Majewscy</b>) – <a href=\"https://pl.wikipedia.org/wiki/Polskie_nazwiska\" target=\"_blank\" rel=\"noopener noreferrer\">polskie</a> <a href=\"https://pl.wikipedia.org/wiki/Nazwisko\" target=\"_blank\" rel=\"noopener noreferrer\">nazwisko</a>. Na początku <a href=\"https://pl.wikipedia.org/wiki/Lata_90._XX_wieku\" target=\"_blank\" rel=\"noopener noreferrer\">lat 90.</a> <a href=\"https://pl.wikipedia.org/wiki/XX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XX wieku</a> w <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">Polsce</a> nosiło je 46 379 osób.", "Minh Toàn": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Md Parvez": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mustafa Ali̇": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mustafa</b>.</p><b>Mustafa</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia arabskiego, oznacza „wybrany”.", "Maria Zbigniew": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mohammad Imran": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Mikali": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mikal</b>.</p><b>Mikal</b> (hebr. מיכל; skrócona forma imienia <i>Michael</i> − <i>kto jest jak Bóg</i>) − córka <a href=\"https://pl.wikipedia.org/wiki/Saul_(kr%C3%B3l_Izraela)\" target=\"_blank\" rel=\"noopener noreferrer\">Saula</a>, króla Izraela, pierwsza żona króla <a href=\"https://pl.wikipedia.org/wiki/Dawid_(kr%C3%B3l_Izraela)\" target=\"_blank\" rel=\"noopener noreferrer\">Dawida</a>. Zapis historii Mikal przekazują <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijne</a> Księgi Samuela.", "Mohammed Irfan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammed</b>.</p><p>Muhammad - muzułmańskie imię i nazwisko. Mahomet jest islamskim prorokiem.</p>", "Md Rafiul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mon Bahadur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mon</b>.</p><p>Mon może oznaczać: Miasto miasta Mon w stanie Nagaland, Indie Nowoczesna Indie Nagaland, India Wyspa Mon w Danie Mianmarskie Narody i języki Naród Mon (lub Mon) w południowo-wschodniej Azji Mońskie (narodu Mon) w grupie języków Mon-Khmer Odmienne MON jest kodem IATA Monarch Airlines Powieść Mon (門) Soseki Natsume Japoński mon (文) jest popularny w Japonii</p>", "Muhammad Zaheer": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammad</b>.</p><b>Muhammad</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;مُحَمَّد&#8206;) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wariantami tego imienia są: Mohammed, Mehmed, Mamadu i Mahomet.", "Melquiades Jr.": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Melquiades</b>.</p><p>Melquíades to hiszpańskie imię. Jest to hiszpańska forma greckiego imienia Melchiades, jak w papieżu Miltiades.</p>", "Md Imdadul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Fazlur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Muhammad Hamza": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammad</b>.</p><b>Muhammad</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;مُحَمَّد&#8206;) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wariantami tego imienia są: Mohammed, Mehmed, Mamadu i Mahomet.", "Manuel Jose": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Manuel</b>.</p><b>Emanuel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od słowa עִמָּנוּאֵל oznaczającego „Bóg z nami”. Imię mesjasza oraz kilku świętych katolickich. Żeński odpowiednik to <a href=\"https://pl.wikipedia.org/wiki/Emanuela\" target=\"_blank\" rel=\"noopener noreferrer\">Emanuela</a>.", "Michael Eduardo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Michael</b>.</p><p>Michael: Botanika Michael - skrócie botaniczne, oznaczające, że autorem taksy jest Edmund Michael. Muzyka ⁇ Michael ⁇ - piosenka grupy Franz Ferdinand, wydana w 2004 roku.</p>", "Md Mijanur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Mostofa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mohammed A.a.": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammed</b>.</p><p>Muhammad - muzułmańskie imię i nazwisko. Mahomet jest islamskim prorokiem.</p>", "Muhammad Qasim": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammad</b>.</p><b>Muhammad</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;مُحَمَّد&#8206;) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wariantami tego imienia są: Mohammed, Mehmed, Mamadu i Mahomet.", "Md Mofizul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mansoor Ahmed": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mansoor</b>.</p><p>Mansour (arabickie: منصور, Manṣūr); również pisane Mounsor, Monsur (Bengali), Mansoor, Manser, Mansur, Mansyur (indonezyjski) lub Mensur (tyrki), to męskie arabskie imię oznaczające \"Ten, który zwycięża\", z arabskiego korzenia naṣr (نصر), oznaczające \"wygrę\". Pierwszym znanym nosicielem nazwy był Mansur ibn Sarjun, bizantyjski gubernator Damaszku pod koniec lat 500 i na początku lat 600, który poddał miasto muzułmanom w 635 r. Inni ludzie nazywają się Mansur...</p>", "Mohan Rao": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohan</b>.</p><p>Mohan to gmin i nagar panchayat z okręgu Unnao w stanie Uttar Pradesh, India.</p>", "Mohammed Aslam": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammed</b>.</p><p>Muhammad - muzułmańskie imię i nazwisko. Mahomet jest islamskim prorokiem.</p>", "Mohiuddin": "<p>Mohyeddin to arabskie imię, które oznacza \"Ożywiciel Dīn\". Jest używana zarówno jako imię osobiste dla mężczyzn, jak i jako tytuł honorowy w tradycji islamskiej.</p>", "Md Younus": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mileta": "<p>Mileta (Serbski: Милета) to serbskie, chorwackie i murzynskie imię męskie, a także nazwisko. Znanymi osobami z nazwiskiem są: Mężczyzna Mileta Andrejević (1925-1989), amerykański malarz Mileta Jakšić (1863-1935), serbska poeta Mileta Lisica (urodzona 1966), serbsko-słowenijska piłkarz koszykówki Mileta Poskurica (ur. 1954), serbska polityk Mileta Radojković (1778-1852), serbska urzędnik Mileta Radulović (ur. 1981),...</p>", "Md Parvej": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Minh Thao": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Meinrad": "<b>Meinrad</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, złożone z członów <i>magin</i> – \"siła, moc\" i <i>rad</i> – \"rada\". Patronem tego imienia jest św. Meinrad, mnich benedyktyński z <a href=\"https://pl.wikipedia.org/wiki/IX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">IX wieku</a>.", "Md Mohsin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Maria Hubert": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Muhammed Shafeek": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Muhammad Arslan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammad</b>.</p><b>Muhammad</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;مُحَمَّد&#8206;) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wariantami tego imienia są: Mohammed, Mehmed, Mamadu i Mahomet.", "Mohammad Mehdi": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Md Faruk": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Marko-Illia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marko</b>.</p><b>Marek</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, należące do wąskiej grupy najstarszych <a href=\"https://pl.wikipedia.org/wiki/Imiona_%C5%82aci%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imion rzymskich</a> (imion właściwych, <i>praenomen</i>, por. <a href=\"https://pl.wikipedia.org/wiki/Tyberiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Tyberiusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Aulus\" target=\"_blank\" rel=\"noopener noreferrer\">Aulus</a>, <a href=\"https://pl.wikipedia.org/wiki/Maniusz\" target=\"_blank\" rel=\"noopener noreferrer\">Maniusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Gajusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Gajusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Lucjusz\" target=\"_blank\" rel=\"noopener noreferrer\">Lucjusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Publiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Publiusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Tytus\" target=\"_blank\" rel=\"noopener noreferrer\">Tytus</a>, <a href=\"https://pl.wikipedia.org/wiki/Serwiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Serwiusz</a>), utworzone z <i>*Mart-ico-s</i> od imienia boga <i><a href=\"https://pl.wikipedia.org/wiki/Mars_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Mars</a></i>, <i>Martis</i> i oznaczające „należący do Marsa, związany z Marsem”. W Polsce imię to jest notowane od <a href=\"https://pl.wikipedia.org/wiki/XIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIII wieku</a>, choć poza współczesnością nie było często spotykane, w formach <i><b>Marek</b></i>, <i><b>Marko</b></i>, <i><b>Margusz</b></i>, <i><b>Markusz</b></i>, <i><b>Merkusz</b></i>. Zapisana została także żeńska <b>Marka</b> (<a href=\"https://pl.wikipedia.org/wiki/1263\" target=\"_blank\" rel=\"noopener noreferrer\">1263</a>) – żeński odpowiednik imienia Marek lub zdrobnienie od imion żeńskich rozpoczynających się na Mar-, takich jak <i>Margorzata</i> (= <a href=\"https://pl.wikipedia.org/wiki/Ma%C5%82gorzata_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Małgorzata</a>) lub <a href=\"https://pl.wikipedia.org/wiki/Maria\" target=\"_blank\" rel=\"noopener noreferrer\">Maria</a> – oraz <a href=\"https://pl.wikipedia.org/wiki/Markus%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Markusław</a>, staropolskie imię utworzone od imienia Marek poprzez dodanie typowej dla imion słowiańskich cząstki -sław. Imię to według danych 2022 r. jest na 10 miejscu najpopularniejszych imion męskich.", "Muhammad Haseeb": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammad</b>.</p><b>Muhammad</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;مُحَمَّد&#8206;) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wariantami tego imienia są: Mohammed, Mehmed, Mamadu i Mahomet.", "Mirosław Antoni": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mirosław</b>.</p><b>Mirosław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie imię</a> męskie. Imię <i>Mirosław</i> jest przykładem <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staropolski\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskiego</a>, złożonego, osobowego imienia dwuczłonowego, które jest <a href=\"https://pl.wikipedia.org/wiki/Relikt\" target=\"_blank\" rel=\"noopener noreferrer\">reliktem</a> <a href=\"https://pl.wikipedia.org/wiki/Poganie\" target=\"_blank\" rel=\"noopener noreferrer\">pogańskich</a> imion używanych we wczesnym średniowieczu przez <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie\" target=\"_blank\" rel=\"noopener noreferrer\">Słowian</a>. Składa się z członów <i>Miro-</i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pras%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">ps.</a> <i>*mirъ</i> „pokój”, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staropolski\" target=\"_blank\" rel=\"noopener noreferrer\">stpol.</a> <i>mir</i>, <i>mier</i> - „pokój, bezpieczeństwo, przyjaźń”) oraz <i>-sław</i> („sława”). Mogło oznaczać „ten, który sławi pokój” albo „ten, który zdobywa sławę poprzez zaprowadzenie porządku, pokoju”. <a href=\"https://pl.wikipedia.org/wiki/Witold_Taszycki\" target=\"_blank\" rel=\"noopener noreferrer\">Witold Taszycki</a> zaliczył je do grupy najstarszych polskich imion osobowych&#8201;.", "Mohammad Masud": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Md Aminur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Minh Loi": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Muhammed Yuşa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Magdy Mohamed": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Magdy</b>.</p><p>Majdy i Majdi lub Mejdi lub egipskie warianty Magdi lub Magdy (w arabskim مجدي) to arabskie męskie imię i nazwisko pochodzenia arabskiego. Do wybitnych osób z tym nazwiskiem należą:</p>", "Matei-Andrei": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Matei</b>.</p><p>Matei (rumuńska: [maˈtej]) jest rumuńskim męskim nazwiskiem i nazwiskiem. Jest odwzajemniony od nazwiska Matthias, a jest spokrewniony z angielską nazwą Matthew.</p>", "Md Fazlul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Manuel Ricardo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Manuel</b>.</p><b>Emanuel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od słowa עִמָּנוּאֵל oznaczającego „Bóg z nami”. Imię mesjasza oraz kilku świętych katolickich. Żeński odpowiednik to <a href=\"https://pl.wikipedia.org/wiki/Emanuela\" target=\"_blank\" rel=\"noopener noreferrer\">Emanuela</a>.", "Md Adnan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mihai-Daniel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mihai</b>.</p><p>Mihai (rumuńska wymowa: [miˈhaj]) jest rumuńskim nazwiskiem męskim lub nazwiskiem. To równoważne angielskiej imienia Michael.</p>", "Meisam": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Meysam</b>.</p><p>Meysam, Maitham lub Maytham (arabski: ميثم, azerbaijski: Meysəm, turecki: Meysem, perskiego: میثم) to międzynarodowo stosowane imię męskie pochodzące z języków semitycznych. Nazwa pochodzi od arabskiego korzenia w-th-m i oznacza \"płaszczenie\" jak dźwięk, jaki powstaje z kopyt konia lub wielbłąda.</p>", "Mustaf": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mustafa</b>.</p><b>Mustafa</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia arabskiego, oznacza „wybrany”.", "Md Alan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Marian-Laurențiu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marian</b>.</p><b>Marian</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> od imienia <i>Marius</i> lub nazwy rodu <i>Marii</i>. Oznacza „należący do Mariusza, rodu Mariuszów”. Występuje w Polsce od 1332 roku, jako <b>Marzyjan</b>. Forma Marian pojawiła się w Polsce w XVI wieku. W języku angielskim używane jest jako imię żeńskie. W Polsce w żeńskim użyciu w 2025 roku wystąpiło 35 razy.", "Mehtab Singh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mehtab</b>.</p><p>Mehtab jest unisex nazwisko i nazwisko pochodzenia perskiego. Do wybitnych osób z tym nazwiskiem należą:</p>", "Mchitar": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mkhitar</b>.</p><p>Mkhitar lub Mekhitar lub Mechitar lub Latinized Mechitarius (armeńska: Մխիթար) to armenijska męska nazwisko. Zobacz Mխիթար dla więcej informacji na temat pochodzenia nazwy.</p>", "Mostafa Kamal": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mostafa</b>.</p><p>Mustafa sultan (tat. Mostafa, Mostafa; umysł.</p>", "Md Shekh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mehtab": "<p>Mehtab jest unisex nazwisko i nazwisko pochodzenia perskiego. Do wybitnych osób z tym nazwiskiem należą:</p>", "Muhammad Zeeshan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammad</b>.</p><b>Muhammad</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;مُحَمَّد&#8206;) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wariantami tego imienia są: Mohammed, Mehmed, Mamadu i Mahomet.", "Maryl": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maryla</b>.</p><b>Maryla</b> – forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Maria\" target=\"_blank\" rel=\"noopener noreferrer\">Maria</a> pochodząca od romańskiego zdrobnienia pierwowzoru.", "Marcos Felipe": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marcos</b>.</p><p>Marcos - brytyjski producent samochodów, który wyprodukował samochody sportowe w latach 1959-2007. Nazwa firmy powstała z pierwszych liter nazwisk współzałożycieli.</p>", "Md Asraful": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mahmut Can": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mahmut</b>.</p><p>Aidin Mahmutović (ur. 6 kwietnia 1986 r., Doba, SFRY) - bosnijski piłkarz, zawodnik.</p>", "Md Arham": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mohamed Amin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohamed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Mohammad Hussain": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Mohamed Taha": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohamed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Muhammed Bilal": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Mălin": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Malini</b>.</p><p>Mălini jest gmina w prowincji Suceava, Rumunii. W 2002 roku liczba ludności wynosiła 7206.</p>", "Muhammad Abdul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammad</b>.</p><b>Muhammad</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;مُحَمَّد&#8206;) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wariantami tego imienia są: Mohammed, Mehmed, Mamadu i Mahomet.", "Marian-Aurel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marian</b>.</p><b>Marian</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> od imienia <i>Marius</i> lub nazwy rodu <i>Marii</i>. Oznacza „należący do Mariusza, rodu Mariuszów”. Występuje w Polsce od 1332 roku, jako <b>Marzyjan</b>. Forma Marian pojawiła się w Polsce w XVI wieku. W języku angielskim używane jest jako imię żeńskie. W Polsce w żeńskim użyciu w 2025 roku wystąpiło 35 razy.", "Md Shajib": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Marian-Marius": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marian</b>.</p><b>Marian</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> od imienia <i>Marius</i> lub nazwy rodu <i>Marii</i>. Oznacza „należący do Mariusza, rodu Mariuszów”. Występuje w Polsce od 1332 roku, jako <b>Marzyjan</b>. Forma Marian pojawiła się w Polsce w XVI wieku. W języku angielskim używane jest jako imię żeńskie. W Polsce w żeńskim użyciu w 2025 roku wystąpiło 35 razy.", "Marijo": "<p>Marijo to sławskie imię męskie, krewny Mario. Wśród osób znanych z tego nazwiska są: Marijo Baković (ur. 1982), emerytowany chorwacki long jumper Marijo Dodik (ur. 1974), bosniak-chorwacki piłkarz Marijo Marić (ur., 1977), chorwacki piłki nożnej Marijo Moćić (ur.).</p>", "Md Mozammel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Marius-Sorin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marius</b>.</p>Pochodził z niższych warstw społecznych, miał być z zawodu rzemieślnikiem (kowalem), później przypuszczalnie służył w wojsku, lecz nie wiadomo w jakiej funkcji. Po stłumionej w początkach 269 roku rewolcie <a href=\"https://pl.wikipedia.org/wiki/Lelian_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Leliana</a> wzniecił kolejny bunt w <a href=\"https://pl.wikipedia.org/wiki/Moguncja\" target=\"_blank\" rel=\"noopener noreferrer\">Mogontiacum</a> przeciwko władzy <a href=\"https://pl.wikipedia.org/wiki/Wiktoryn_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Wiktoryna</a>, następcy <a href=\"https://pl.wikipedia.org/wiki/Postumus\" target=\"_blank\" rel=\"noopener noreferrer\">Postuma</a>. Według <i><a href=\"https://pl.wikipedia.org/wiki/Historia_Augusta\" target=\"_blank\" rel=\"noopener noreferrer\">Historia Augusta</a></i> jego rządy trwały zaledwie 2-3 dni, czemu jednak przeczy zachowana liczba jego monet. Najpewniej w mennicy w <a href=\"https://pl.wikipedia.org/wiki/Kolonia_(Niemcy)\" target=\"_blank\" rel=\"noopener noreferrer\">Kolonii</a> (<i>Colonia Agrippina</i>) <a href=\"https://pl.wikipedia.org/wiki/Emisja_pieni%C4%85dza\" target=\"_blank\" rel=\"noopener noreferrer\">emitował</a> w swym imieniu niskowartościowe <a href=\"https://pl.wikipedia.org/wiki/Antoninian\" target=\"_blank\" rel=\"noopener noreferrer\">antoniniany</a> typów: AEQUITAS, CONCORDIA MILIT(um), SAEC(uli) FELICITAS, VICTORIA AUG(usti), VIRTUS AUG(usti).", "Micho": "<p>Micha (; hebrajskie: מִיכָה, nowoczesne: Mikha, tyberyjskie: Mî ⁇ ā) jest nazwiskiem. Micha jest nazwiskiem kilku ludzi w Tanakh, co oznacza \"Kto jest jak Bóg? \"Przecież to prawda\".</p>", "Md Alamgir Hossain": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Min Kyu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Min</b>.</p><p>Min to niejednoznaczny termin. min - w matematyce i językach programowania oznacza funkcję wyboru najmniejszego ze swoich argumentów, (Min (3, 6, 2) = 2).</p>", "Mohammed Yassine": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammed</b>.</p><p>Muhammad - muzułmańskie imię i nazwisko. Mahomet jest islamskim prorokiem.</p>", "Marian-Ciprian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marian</b>.</p><b>Marian</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> od imienia <i>Marius</i> lub nazwy rodu <i>Marii</i>. Oznacza „należący do Mariusza, rodu Mariuszów”. Występuje w Polsce od 1332 roku, jako <b>Marzyjan</b>. Forma Marian pojawiła się w Polsce w XVI wieku. W języku angielskim używane jest jako imię żeńskie. W Polsce w żeńskim użyciu w 2025 roku wystąpiło 35 razy.", "Marian Wojciech": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marian</b>.</p><b>Marian</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> od imienia <i>Marius</i> lub nazwy rodu <i>Marii</i>. Oznacza „należący do Mariusza, rodu Mariuszów”. Występuje w Polsce od 1332 roku, jako <b>Marzyjan</b>. Forma Marian pojawiła się w Polsce w XVI wieku. W języku angielskim używane jest jako imię żeńskie. W Polsce w żeńskim użyciu w 2025 roku wystąpiło 35 razy.", "Marian Adam": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marian</b>.</p><b>Marian</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> od imienia <i>Marius</i> lub nazwy rodu <i>Marii</i>. Oznacza „należący do Mariusza, rodu Mariuszów”. Występuje w Polsce od 1332 roku, jako <b>Marzyjan</b>. Forma Marian pojawiła się w Polsce w XVI wieku. W języku angielskim używane jest jako imię żeńskie. W Polsce w żeńskim użyciu w 2025 roku wystąpiło 35 razy.", "Maciej Ryszard": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maciej</b>.</p><b>Maciej</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, pochodzenia hebrajskiego: <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מַתִּתְיָהוּ&#8206; <i>Mattitjahu</i>, oznaczające „dar <a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a>”.", "Md Jewel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mohammad Saif": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Md Riaz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Malindu": "<p>Malindu to imię. Znani ludzie z nazwiskiem to: Malindu Maduranga (ur. 1997), Sri Lankanki kryker Malindu Shehan (ur. 1994), Sri Lanka kryker</p>", "Mortaza": "<p>Murtaza (afgańska perskia: مُرتَضٰ Murtazâ) lub Morteza (iranska: مُرْتِضیٰ Mortezâ) to perskie imię męskie, ostatecznie pochodzące z arabskiej Murtada (مُرْطَضَى Murtaḍā). Wymowa różni się w zależności od akcentu, od rodzimych arabskich do języków europejskich i azjatyckich.</p>", "Mohammad Alamgir": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Micheel": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Michel</b>.</p><p>⁇ Michel ⁇ (niemieckie MICHEL-Briefmarken-Katalog) - największy i najbardziej znany katalog znaków pocztowych w niemieckojęzycznym świecie i Europie.</p>", "Md Murad": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mohammad Omar Faruk": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Mohammed J": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammed</b>.</p><p>Muhammad - muzułmańskie imię i nazwisko. Mahomet jest islamskim prorokiem.</p>", "Md Ataur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Shumon": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mykola-Ostap": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mykola</b>.</p><p>Mykola jest ukraińską wariantą męskiego nazwiska \"Nicholas\", co oznacza \"wygrę narodu\". Może odnosić się do:</p>", "Mohamed Abdelsattar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohamed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Md Harun": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Nadim": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mohammad Mehedi": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Man Prasad": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Man</b>.</p><p>man (od angielskiego manual - wytyczne) - polecenie Unix przeznaczone do formatowania i wyciągania stron odniesienia.</p>", "Marc-Andre": "<p>Marc-André to francuskie imię męskie, powszechne w Kanadzie. To złożone imię, składające się z Marka i André'a.</p>", "Matiaș": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mátyás</b>.</p><p>Matvej (Mattias; nim. Matthias, węg.</p>", "Ming-Yuan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ming</b>.</p><p>Ming - biblioteka C do tworzenia plików Adobe Flash (.swf). Może być stosowany jako moduł PHP, pozwalając tworzyć dynamicznie (⁇ na lot ⁇) animację Flash.</p>", "Mohammed Shan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammed</b>.</p><p>Muhammad - muzułmańskie imię i nazwisko. Mahomet jest islamskim prorokiem.</p>", "Mohammed Rasel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammed</b>.</p><p>Muhammad - muzułmańskie imię i nazwisko. Mahomet jest islamskim prorokiem.</p>", "Md Moinul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Michał Bogumił": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Michał</b>.</p><b>Michał</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִיכָאֵל&#8206; – Mîchā’ēl) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, wywodzące się od <a href=\"https://pl.wikipedia.org/wiki/Archanio%C5%82_Micha%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">jednego z archaniołów</a>. Po hebrajsku znaczy „któż [jest taki] jak Bóg”. Forma żeńska to <a href=\"https://pl.wikipedia.org/wiki/Michalina\" target=\"_blank\" rel=\"noopener noreferrer\">Michalina</a>.", "Muhammed Salim": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Mac Arthur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mac</b>.</p><p>Macintosh [ˈmækɪntɒʃ] lub Mac [mæk] - linia komputerów osobistych produkowanych przez Apple. Pracują pod zarządzaniem systemami operacyjnymi rodziny Mac OS, możliwe jest również praca na OS Windows NT, A/UX, NeXTSTEP, BeOS/Haiku, GNU/Linux i Rhapsody.</p>", "Mykhailo-Andrii": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mykhailo</b>.</p><p>Mykhailo lub Mykhaylo to ukraińskie męskie imię, równoważne angielskim Michałowi. Wśród znanych osób z nazwiskiem są: Mykhaylo Berkos (1861-1919), rosyjski i ukraiński artysta pochodzenia greckiego Mykhayilo Bolotskykh (ur. 1960), ukraiński polityk i wojskowy, pułkownik generalny (Służba Obrony Cywilnej) Mykhayło Brodskyy (ur. 1959), ukraiński polityk, przywódca Partii Wolnych Demokratów i biznesmen Mykhayla Chemberzhi,...</p>", "Moroni": "<b>Moroni</b> (<a href=\"https://pl.wikipedia.org/wiki/Alfabet_deseret\" target=\"_blank\" rel=\"noopener noreferrer\">deseret</a> rozmaicie, chociażby jako 𐐣𐐄𐐡𐐄𐐤𐐌, 𐐣𐐃𐐡𐐃𐐤𐐌, 𐐣𐐄𐐡𐐃𐐤𐐌, 𐐣𐐃𐐡𐐄𐐤𐐌 czy 𐐤𐐄𐐡𐐄𐐤𐐌) – imię męskie występujące w wyznaniach należących do <a href=\"https://pl.wikipedia.org/wiki/Ruch_%C5%9Bwi%C4%99tych_w_dniach_ostatnich\" target=\"_blank\" rel=\"noopener noreferrer\">ruchu świętych w dniach ostatnich</a> (mormonów). Pochodzi z Księgi Mormona, w której nosiły je dwie postacie. Pojawiło się w źródłach już w początkach mormonizmu. Popularne w zdominowanym przez świętych w dniach ostatnich stanie Utah. Występuje wśród wyznających mormonizm Maorysów oraz w Brazylii i Ekwadorze, jak również w praktykującym małżeństwa pluralistyczne Fundamentalistycznym Kościele Jezusa Chrystusa Świętych w Dniach Ostatnich. Znalazło odzwierciedlenie w szerszej mormońskiej kulturze. Jako imię wywiedzione z pism świętych uznawane jest za powód do dumy. Ma także wywierać pozytywny wpływ na życie duchowe noszącego je człowieka.", "Mohammed Haris": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammed</b>.</p><p>Muhammad - muzułmańskie imię i nazwisko. Mahomet jest islamskim prorokiem.</p>", "Md Sakil": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Minh Thuy": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Maanas": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Manas</b>.</p><p>Manas (stylownik: 玛纳斯县; substylownik; ślonski: 玛納斯县; ślony: Mǎnàsī Xiàn, vietnamski: Mǎnásī Xiàn; uygurski: Manas ناھىيىسى , ULY: Manas Nahiyisi, UPNY: Manas Nah ⁇ iyisi?) jest okręgem samorządu Azji narodowego muzułmańskiego, regionu samorządowego Tangiu, China. Obecnie mieści się w stanie Manas (玛纳斯), na brzegu rzeki Manas, wschodniej od Czarnogórza.</p>", "Miguel Jose": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Miguel</b>.</p><p>Miguel (hisz. Miguel) - hiszpański odpowiednik imienia Michaila.</p>", "Muhammad Hasan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammad</b>.</p><b>Muhammad</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;مُحَمَّد&#8206;) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wariantami tego imienia są: Mohammed, Mehmed, Mamadu i Mahomet.", "Muhammed Afsal": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Mohammed Nasir": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammed</b>.</p><p>Muhammad - muzułmańskie imię i nazwisko. Mahomet jest islamskim prorokiem.</p>", "Muhammad Faheem": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammad</b>.</p><b>Muhammad</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;مُحَمَّد&#8206;) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wariantami tego imienia są: Mohammed, Mehmed, Mamadu i Mahomet.", "Md Safayet": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Muazzam": "<p>Moazzam, Muazzam, Muzzem i Moazzem (od arabskiego المعظم, muʿaẓẓam, \"wywyższony\") jest męskie imię i nazwisko pochodzenia arabskiego. Do wybitnych osób z tym nazwiskiem należą:</p>", "Mohammad Rubel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Md Foysol": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Marian-Darius": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marian</b>.</p><b>Marian</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> od imienia <i>Marius</i> lub nazwy rodu <i>Marii</i>. Oznacza „należący do Mariusza, rodu Mariuszów”. Występuje w Polsce od 1332 roku, jako <b>Marzyjan</b>. Forma Marian pojawiła się w Polsce w XVI wieku. W języku angielskim używane jest jako imię żeńskie. W Polsce w żeńskim użyciu w 2025 roku wystąpiło 35 razy.", "Marian-Bogdan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marian</b>.</p><b>Marian</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> od imienia <i>Marius</i> lub nazwy rodu <i>Marii</i>. Oznacza „należący do Mariusza, rodu Mariuszów”. Występuje w Polsce od 1332 roku, jako <b>Marzyjan</b>. Forma Marian pojawiła się w Polsce w XVI wieku. W języku angielskim używane jest jako imię żeńskie. W Polsce w żeńskim użyciu w 2025 roku wystąpiło 35 razy.", "Md Milon": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Sani": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mihai-Marian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mihai</b>.</p><p>Mihai (rumuńska wymowa: [miˈhaj]) jest rumuńskim nazwiskiem męskim lub nazwiskiem. To równoważne angielskiej imienia Michael.</p>", "Md Mustafizur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mufaddal": "<p>Mufaddal lub Mofazzal to arabskie imię. Mieszkańcy tej nazwy to:</p>", "Matei-Mihai": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Matei</b>.</p><p>Matei (rumuńska: [maˈtej]) jest rumuńskim męskim nazwiskiem i nazwiskiem. Jest odwzajemniony od nazwiska Matthias, a jest spokrewniony z angielską nazwą Matthew.</p>", "Minh Tứ": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Minh Tuyen": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Maksym-Matvii": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maksym</b>.</p><b>Maksym</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, utworzone od przymiotnika <i>maximus</i> oznaczający \"największy\", przydomka <a href=\"https://pl.wikipedia.org/wiki/Jowisz_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Jowisza</a>. Istnieją liczni święci prawosławni i katoliccy o tym imieniu: <a href=\"https://pl.wikipedia.org/wiki/Maksym_Wyznawca\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym Wyznawca</a>, <a href=\"https://pl.wikipedia.org/wiki/Maksym_Grek\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym Grek</a>, <a href=\"https://pl.wikipedia.org/wiki/Maksym_Brankowicz\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym Wołoski</a>, <a href=\"https://pl.wikipedia.org/wiki/Maksym_Gorlicki\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym Gorlicki</a>, <a href=\"https://pl.wikipedia.org/wiki/Maksym_z_Riez\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym z Riez</a> i wielu innych.", "Md Sadman": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Marian-Cătălin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marian</b>.</p><b>Marian</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> od imienia <i>Marius</i> lub nazwy rodu <i>Marii</i>. Oznacza „należący do Mariusza, rodu Mariuszów”. Występuje w Polsce od 1332 roku, jako <b>Marzyjan</b>. Forma Marian pojawiła się w Polsce w XVI wieku. W języku angielskim używane jest jako imię żeńskie. W Polsce w żeńskim użyciu w 2025 roku wystąpiło 35 razy.", "Marian Stefan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marian</b>.</p><b>Marian</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> od imienia <i>Marius</i> lub nazwy rodu <i>Marii</i>. Oznacza „należący do Mariusza, rodu Mariuszów”. Występuje w Polsce od 1332 roku, jako <b>Marzyjan</b>. Forma Marian pojawiła się w Polsce w XVI wieku. W języku angielskim używane jest jako imię żeńskie. W Polsce w żeńskim użyciu w 2025 roku wystąpiło 35 razy.", "Muhammed Irshad": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Min Raj": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Min</b>.</p><p>Min to niejednoznaczny termin. min - w matematyce i językach programowania oznacza funkcję wyboru najmniejszego ze swoich argumentów, (Min (3, 6, 2) = 2).</p>", "Mohammad Amin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Mariami": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mariam</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Marius-Petre": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marius</b>.</p>Pochodził z niższych warstw społecznych, miał być z zawodu rzemieślnikiem (kowalem), później przypuszczalnie służył w wojsku, lecz nie wiadomo w jakiej funkcji. Po stłumionej w początkach 269 roku rewolcie <a href=\"https://pl.wikipedia.org/wiki/Lelian_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Leliana</a> wzniecił kolejny bunt w <a href=\"https://pl.wikipedia.org/wiki/Moguncja\" target=\"_blank\" rel=\"noopener noreferrer\">Mogontiacum</a> przeciwko władzy <a href=\"https://pl.wikipedia.org/wiki/Wiktoryn_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Wiktoryna</a>, następcy <a href=\"https://pl.wikipedia.org/wiki/Postumus\" target=\"_blank\" rel=\"noopener noreferrer\">Postuma</a>. Według <i><a href=\"https://pl.wikipedia.org/wiki/Historia_Augusta\" target=\"_blank\" rel=\"noopener noreferrer\">Historia Augusta</a></i> jego rządy trwały zaledwie 2-3 dni, czemu jednak przeczy zachowana liczba jego monet. Najpewniej w mennicy w <a href=\"https://pl.wikipedia.org/wiki/Kolonia_(Niemcy)\" target=\"_blank\" rel=\"noopener noreferrer\">Kolonii</a> (<i>Colonia Agrippina</i>) <a href=\"https://pl.wikipedia.org/wiki/Emisja_pieni%C4%85dza\" target=\"_blank\" rel=\"noopener noreferrer\">emitował</a> w swym imieniu niskowartościowe <a href=\"https://pl.wikipedia.org/wiki/Antoninian\" target=\"_blank\" rel=\"noopener noreferrer\">antoniniany</a> typów: AEQUITAS, CONCORDIA MILIT(um), SAEC(uli) FELICITAS, VICTORIA AUG(usti), VIRTUS AUG(usti).", "Miljko": "<p>Miljko (serski: Миљко) to serbskie imię męskie, pochodzące od słowiańskiego mil- (\"miłość, lubić\") i hipokorystycznego sufiksu -ko, oba bardzo powszechne w słowiańskich nazwiskach. Może odnosić się do: Miljko Radonjić (1770-1836), serbskiego pisarza, profesora i ministra Miljko Radisavljević, specjalnego prokuratora ds. przestępczości zorganizowanej MiljkoRadonjić, perkusista, klasztor Riblja Čorba Miljko, Serbii Miljko Živojinović, producenta filmowego, Cienie wspomnień...</p>", "Minh Phu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Miller Antonio": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Miller</b>.</p><p>Gerrit Smith Miller (ang. Gerrit Smith; 1869 - 1956) - amerykański zoolog i botanik.</p>", "Maiko": "<b>Maiko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;舞妓) – uczennica szkoląca się na <a href=\"https://pl.wikipedia.org/wiki/Gejsza\" target=\"_blank\" rel=\"noopener noreferrer\">gejszę</a>. Termin <i>maiko</i> występuje tylko w <a href=\"https://pl.wikipedia.org/wiki/Kioto\" target=\"_blank\" rel=\"noopener noreferrer\">Kioto</a>. Odpowiednik maiko w <a href=\"https://pl.wikipedia.org/wiki/Tokio\" target=\"_blank\" rel=\"noopener noreferrer\">Tokio</a> to <i>hangyoku</i>.", "Md Rashidul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Muhammad Faraz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammad</b>.</p><b>Muhammad</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;مُحَمَّد&#8206;) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wariantami tego imienia są: Mohammed, Mehmed, Mamadu i Mahomet.", "Mohammad Zahidul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Maya": "<p>Maya: Autodesk Maya to redaktor grafiki trójwymiarowej. Maya - album Banco de Gaia z 1994 roku.</p>", "Mohammad Shahid": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Morani": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Moran</b>.</p><p>Moran to japoński zespół rockowy, który oficjalnie istniał w latach 2008-2015. Wykonywała muzykę w gatunku wizual-kay.</p>", "Maciej Michał": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maciej</b>.</p><b>Maciej</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, pochodzenia hebrajskiego: <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מַתִּתְיָהוּ&#8206; <i>Mattitjahu</i>, oznaczające „dar <a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a>”.", "Mohammed O": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammed</b>.</p><p>Muhammad - muzułmańskie imię i nazwisko. Mahomet jest islamskim prorokiem.</p>", "Modesta": "<b>Modesta</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Modest\" target=\"_blank\" rel=\"noopener noreferrer\">Modest</a>. Patronką tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Modesta_z_Trewiru\" target=\"_blank\" rel=\"noopener noreferrer\">św. Modesta z Trewiru</a>, benedyktynka, zm. ok. <a href=\"https://pl.wikipedia.org/wiki/680\" target=\"_blank\" rel=\"noopener noreferrer\">680</a> r.", "Marc Marie": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marc</b>.</p><p>Marc: MARC (ang. Machine-Readable Cataloging) - grupa formatów (MARC21, UNIMARC, RUSMAC itp.</p>", "Md Lutfur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Maria Wacław": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Muhammed Shafeeque": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Mihai-Nicolae": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mihai</b>.</p><p>Mihai (rumuńska wymowa: [miˈhaj]) jest rumuńskim nazwiskiem męskim lub nazwiskiem. To równoważne angielskiej imienia Michael.</p>", "Melchiades": "<b>Melchiades</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Gr.\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, pochodzące od greckiego słowa <i>μιλτος (miltos)</i> – \"czerwona ziemia\". Patronem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Milcjades\" target=\"_blank\" rel=\"noopener noreferrer\">św. Melchiades (Milcjades), papież</a>.", "Minh Phuong": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Muhammad Ilham": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammad</b>.</p><b>Muhammad</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;مُحَمَّد&#8206;) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wariantami tego imienia są: Mohammed, Mehmed, Mamadu i Mahomet.", "Md Nuruzzaman": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Marius-Ştefan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marius</b>.</p>Pochodził z niższych warstw społecznych, miał być z zawodu rzemieślnikiem (kowalem), później przypuszczalnie służył w wojsku, lecz nie wiadomo w jakiej funkcji. Po stłumionej w początkach 269 roku rewolcie <a href=\"https://pl.wikipedia.org/wiki/Lelian_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Leliana</a> wzniecił kolejny bunt w <a href=\"https://pl.wikipedia.org/wiki/Moguncja\" target=\"_blank\" rel=\"noopener noreferrer\">Mogontiacum</a> przeciwko władzy <a href=\"https://pl.wikipedia.org/wiki/Wiktoryn_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Wiktoryna</a>, następcy <a href=\"https://pl.wikipedia.org/wiki/Postumus\" target=\"_blank\" rel=\"noopener noreferrer\">Postuma</a>. Według <i><a href=\"https://pl.wikipedia.org/wiki/Historia_Augusta\" target=\"_blank\" rel=\"noopener noreferrer\">Historia Augusta</a></i> jego rządy trwały zaledwie 2-3 dni, czemu jednak przeczy zachowana liczba jego monet. Najpewniej w mennicy w <a href=\"https://pl.wikipedia.org/wiki/Kolonia_(Niemcy)\" target=\"_blank\" rel=\"noopener noreferrer\">Kolonii</a> (<i>Colonia Agrippina</i>) <a href=\"https://pl.wikipedia.org/wiki/Emisja_pieni%C4%85dza\" target=\"_blank\" rel=\"noopener noreferrer\">emitował</a> w swym imieniu niskowartościowe <a href=\"https://pl.wikipedia.org/wiki/Antoninian\" target=\"_blank\" rel=\"noopener noreferrer\">antoniniany</a> typów: AEQUITAS, CONCORDIA MILIT(um), SAEC(uli) FELICITAS, VICTORIA AUG(usti), VIRTUS AUG(usti).", "Mohammad Jashim": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Md Emon": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Muhammad Irfan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammad</b>.</p><b>Muhammad</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;مُحَمَّد&#8206;) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wariantami tego imienia są: Mohammed, Mehmed, Mamadu i Mahomet.", "Mohammed Tarek": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammed</b>.</p><p>Muhammad - muzułmańskie imię i nazwisko. Mahomet jest islamskim prorokiem.</p>", "Mosad": "<b>Mosad</b>, właśc. <b>Instytut do spraw Wywiadu i Zadań Specjalnych</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> המוסד למודיעין ולתפקידים מיוחדים, <i>Ha-Mosad le-Modi’in u-le-Tafkidim Mejuchadim</i>) – <a href=\"https://pl.wikipedia.org/wiki/Izrael\" target=\"_blank\" rel=\"noopener noreferrer\">izraelska</a> agencja wywiadowcza odpowiedzialna m.in. za gromadzenie politycznych, technicznych, gospodarczych danych wywiadowczych poza granicami kraju, formalnie utworzona 1 kwietnia 1951 jako Instytut Koordynacji. Obecną nazwę nadano w 1963.", "Mychaiło": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mykhailo</b>.</p><p>Mykhailo lub Mykhaylo to ukraińskie męskie imię, równoważne angielskim Michałowi. Wśród znanych osób z nazwiskiem są: Mykhaylo Berkos (1861-1919), rosyjski i ukraiński artysta pochodzenia greckiego Mykhayilo Bolotskykh (ur. 1960), ukraiński polityk i wojskowy, pułkownik generalny (Służba Obrony Cywilnej) Mykhayło Brodskyy (ur. 1959), ukraiński polityk, przywódca Partii Wolnych Demokratów i biznesmen Mykhayla Chemberzhi,...</p>", "Mohammed Arif": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammed</b>.</p><p>Muhammad - muzułmańskie imię i nazwisko. Mahomet jest islamskim prorokiem.</p>", "Mansoor Ali": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mansoor</b>.</p><p>Mansour (arabickie: منصور, Manṣūr); również pisane Mounsor, Monsur (Bengali), Mansoor, Manser, Mansur, Mansyur (indonezyjski) lub Mensur (tyrki), to męskie arabskie imię oznaczające \"Ten, który zwycięża\", z arabskiego korzenia naṣr (نصر), oznaczające \"wygrę\". Pierwszym znanym nosicielem nazwy był Mansur ibn Sarjun, bizantyjski gubernator Damaszku pod koniec lat 500 i na początku lat 600, który poddał miasto muzułmanom w 635 r. Inni ludzie nazywają się Mansur...</p>", "Md Din": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Muayad Youssof A": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muayad</b>.</p><p>Muayad, Muayyad lub Muayyed, to arabskie imię. Mieszkańcy tej nazwy to: Al-Mu'ayyad fi'l-Din al-Shirazi, 11-wieczny arabski/perskiej uczony Mu'ayyad Al-Haddad (ur. 1960), były kubajtyński piłkarz Mu'ayad Al Khouli (ur. 1993), syryjski piłkarze Mu'ayad Alayan, palestyński filmowiec, reżyser filmu The Reports on Sarah and Saleem (2018) Mu'ayad Khalid, były iracki piłkarzem Mu'ayyada al-Din al - Urdi, 11-wieczne syryjskie arabskie astronom...</p>", "Mohammad Shamim": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Minh Quyết": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Matias Ezequiel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Matias</b>.</p><p>Matías to portugalska wersja Matthias. Matías jest bardzo popularny w Ameryce Łacińskiej, zwłaszcza w Argentynie.</p>", "Mohammed Zahir": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammed</b>.</p><p>Muhammad - muzułmańskie imię i nazwisko. Mahomet jest islamskim prorokiem.</p>", "Marja": "<p>Marja: Marja at-taklid - szyickie tytuł religijny Marja - miasto w Afganistanie</p>", "Marius-Marin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marius</b>.</p>Pochodził z niższych warstw społecznych, miał być z zawodu rzemieślnikiem (kowalem), później przypuszczalnie służył w wojsku, lecz nie wiadomo w jakiej funkcji. Po stłumionej w początkach 269 roku rewolcie <a href=\"https://pl.wikipedia.org/wiki/Lelian_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Leliana</a> wzniecił kolejny bunt w <a href=\"https://pl.wikipedia.org/wiki/Moguncja\" target=\"_blank\" rel=\"noopener noreferrer\">Mogontiacum</a> przeciwko władzy <a href=\"https://pl.wikipedia.org/wiki/Wiktoryn_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Wiktoryna</a>, następcy <a href=\"https://pl.wikipedia.org/wiki/Postumus\" target=\"_blank\" rel=\"noopener noreferrer\">Postuma</a>. Według <i><a href=\"https://pl.wikipedia.org/wiki/Historia_Augusta\" target=\"_blank\" rel=\"noopener noreferrer\">Historia Augusta</a></i> jego rządy trwały zaledwie 2-3 dni, czemu jednak przeczy zachowana liczba jego monet. Najpewniej w mennicy w <a href=\"https://pl.wikipedia.org/wiki/Kolonia_(Niemcy)\" target=\"_blank\" rel=\"noopener noreferrer\">Kolonii</a> (<i>Colonia Agrippina</i>) <a href=\"https://pl.wikipedia.org/wiki/Emisja_pieni%C4%85dza\" target=\"_blank\" rel=\"noopener noreferrer\">emitował</a> w swym imieniu niskowartościowe <a href=\"https://pl.wikipedia.org/wiki/Antoninian\" target=\"_blank\" rel=\"noopener noreferrer\">antoniniany</a> typów: AEQUITAS, CONCORDIA MILIT(um), SAEC(uli) FELICITAS, VICTORIA AUG(usti), VIRTUS AUG(usti).", "Mustafë": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mustaf</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mustafa</b>.</p><b>Mustafa</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia arabskiego, oznacza „wybrany”.", "Mihai-Vlad": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mihai</b>.</p><p>Mihai (rumuńska wymowa: [miˈhaj]) jest rumuńskim nazwiskiem męskim lub nazwiskiem. To równoważne angielskiej imienia Michael.</p>", "Mohammed Nazrul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammed</b>.</p><p>Muhammad - muzułmańskie imię i nazwisko. Mahomet jest islamskim prorokiem.</p>", "Mykhailo-Arsenii": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mykhailo</b>.</p><p>Mykhailo lub Mykhaylo to ukraińskie męskie imię, równoważne angielskim Michałowi. Wśród znanych osób z nazwiskiem są: Mykhaylo Berkos (1861-1919), rosyjski i ukraiński artysta pochodzenia greckiego Mykhayilo Bolotskykh (ur. 1960), ukraiński polityk i wojskowy, pułkownik generalny (Służba Obrony Cywilnej) Mykhayło Brodskyy (ur. 1959), ukraiński polityk, przywódca Partii Wolnych Demokratów i biznesmen Mykhayla Chemberzhi,...</p>", "Macjej": "<p>Mathias to imię pochodzące z greckiego Ματθαίος, pochodzące podobnie jak Mateusz.</p>", "Manon": "<p>Manon to opera pięciu występów francuskiego kompozytora Jules Masseneta. Wśród scenarzystów tej opery byli Henri Meilhac i Philippe Gille.</p>", "Mohamed-Amine": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohamed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Mieczysław Adam": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mieczysław</b>.</p><b>Mieczysław</b> – dwuczłonowe <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, które powstało najprawdopodobniej w wyniku błędnego odczytania słowiańskiego imienia złożonego <a href=\"https://pl.wikipedia.org/wiki/Miecis%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Miecisław</a> (którego najstarszy zapis pochodzi z 1257).", "Minh Phát": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Md Ahsanul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mykhailo-Liubomyr": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mykhailo</b>.</p><p>Mykhailo lub Mykhaylo to ukraińskie męskie imię, równoważne angielskim Michałowi. Wśród znanych osób z nazwiskiem są: Mykhaylo Berkos (1861-1919), rosyjski i ukraiński artysta pochodzenia greckiego Mykhayilo Bolotskykh (ur. 1960), ukraiński polityk i wojskowy, pułkownik generalny (Służba Obrony Cywilnej) Mykhayło Brodskyy (ur. 1959), ukraiński polityk, przywódca Partii Wolnych Demokratów i biznesmen Mykhayla Chemberzhi,...</p>", "Marcel-Tiberiu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marcel</b>.</p><b>Marceli</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od nazwy jednej z gałęzi rzymskiego <a href=\"https://pl.wikipedia.org/wiki/Klaudiusze\" target=\"_blank\" rel=\"noopener noreferrer\">rodu Klaudiuszów</a>, <i>Marcelli</i>. Imię to bywa nadawane także w formie <b>Marcel</b>, jakkolwiek pojawia się ona w wydawnictwach poprawnościowych jako nieakceptowana. Żeńskim odpowiednikiem jest <a href=\"https://pl.wikipedia.org/wiki/Marcela\" target=\"_blank\" rel=\"noopener noreferrer\">Marcela</a>.", "Margo": "<p>Margo (Margo; 10 maja 1917, Mexico - 17 lipca 1985, Pacifik-Paliseides, Kalifornia) - meksykańsko-amerykańska aktorka teatru, kina i telewizji, tancerka.</p>", "Myhaiło": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Myhaylo</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mihailo</b>.</p><p>Mihailo (Serbski cyrylski: Михаило) (\"\\mi-hail\\o\") jest sławskim nazwa męska. Jest to wariant hebrajskiej nazwy Michał, a jego krewni włączają Mihajlo i Mijailo.</p>", "Muriel": "<b>Muriel</b> to żeńskie imię używane w Anglii, Francji oraz Irlandii. Jest to uproszczona wersja imienia Muirghea, które po <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_irlandzki\" target=\"_blank\" rel=\"noopener noreferrer\">irlandzku</a> znaczy \"jasne (lśniące) morze\"; wywodzące się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_celtyckie\" target=\"_blank\" rel=\"noopener noreferrer\">celtyckiego</a> muir – \"morze\", i geal – \"jasny\".", "Mi̇chal": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Michala</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Michał</b>.</p><b>Michał</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִיכָאֵל&#8206; – Mîchā’ēl) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, wywodzące się od <a href=\"https://pl.wikipedia.org/wiki/Archanio%C5%82_Micha%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">jednego z archaniołów</a>. Po hebrajsku znaczy „któż [jest taki] jak Bóg”. Forma żeńska to <a href=\"https://pl.wikipedia.org/wiki/Michalina\" target=\"_blank\" rel=\"noopener noreferrer\">Michalina</a>.", "Marian Ryszard": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marian</b>.</p><b>Marian</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> od imienia <i>Marius</i> lub nazwy rodu <i>Marii</i>. Oznacza „należący do Mariusza, rodu Mariuszów”. Występuje w Polsce od 1332 roku, jako <b>Marzyjan</b>. Forma Marian pojawiła się w Polsce w XVI wieku. W języku angielskim używane jest jako imię żeńskie. W Polsce w żeńskim użyciu w 2025 roku wystąpiło 35 razy.", "Minh Khôi̇": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Muhammed Shabeer": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Michayl": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Michail</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mikhail</b>.</p><p>Michał (Hebrajskie: מִיכָאֵל; Aramejski: ⁇ , romanized: Mīkhāʼēl) jest powszechnym męskim imieniem, które zazwyczaj uważa się za pochodzące z hebrajskiego pytania retorycznego מי כאל (mī kāʼēl), \"Kto [jest] podobny do [Hebrajskiego boga] El?\", a więc jest nazwiskiem teoforycznym, którego odpowiedź brzmi \"nie ma nikogo podobnego do El\", lub \"nie słynny i potężny jak Bóg\".[is] Paradoksalnie, nazwisko jest czasami interpretowane jako \"Jeden...</p>", "Md Mubarak": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Matias Ignacio": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Matias</b>.</p><p>Matías to portugalska wersja Matthias. Matías jest bardzo popularny w Ameryce Łacińskiej, zwłaszcza w Argentynie.</p>", "Md Harun Ur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mohammad Shoaib": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Md Akramul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Munavvar": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Munavar</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Munawar</b>.</p><p>Munawar to imię i nazwisko. Do osób z tym nazwiskiem należą:</p>", "Md Safiqul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mohinder Singh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohinder</b>.</p><p>Mohinder to indyjskie imię męskie, prawdopodobnie wariant Mahendry. Wśród ludzi o imieniu Mohinder są: Mohinder Amarnath, indyjski kryketer Mohinder Lal, indyjski hokejista Mohinder Pratap Chand, indyjskie poeta Mohinder Purba (znany również jako \"Mohinder Purba\").</p>", "Marcin Jan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marcin</b>.</p><b>Marcin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od wyrażenia <i>Martinus</i> oznaczającego „należący do boga <a href=\"https://pl.wikipedia.org/wiki/Mars_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Marsa</a>”.", "Manuel Santiago": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Manuel</b>.</p><b>Emanuel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od słowa עִמָּנוּאֵל oznaczającego „Bóg z nami”. Imię mesjasza oraz kilku świętych katolickich. Żeński odpowiednik to <a href=\"https://pl.wikipedia.org/wiki/Emanuela\" target=\"_blank\" rel=\"noopener noreferrer\">Emanuela</a>.", "Mysław": "<b>Mysław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, które powstało prawdopodobnie poprzez zlanie się dwóch członów końcowych staropolskich imion: członu <i>-mysł</i> (\"myśleć\") i <i>-sław</i> (\"sława, sławić\"), kiedy świadomość ich pochodzenia zatarła się.", "Marian Michał": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marian</b>.</p><b>Marian</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> od imienia <i>Marius</i> lub nazwy rodu <i>Marii</i>. Oznacza „należący do Mariusza, rodu Mariuszów”. Występuje w Polsce od 1332 roku, jako <b>Marzyjan</b>. Forma Marian pojawiła się w Polsce w XVI wieku. W języku angielskim używane jest jako imię żeńskie. W Polsce w żeńskim użyciu w 2025 roku wystąpiło 35 razy.", "Major Singh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Major</b>.</p><b>Major</b> (mjr) – stopień <a href=\"https://pl.wikipedia.org/wiki/Oficer_(wojsko)\" target=\"_blank\" rel=\"noopener noreferrer\">oficerski</a> używany w armiach wielu krajów. Major jest najniższym stopniem w <a href=\"https://pl.wikipedia.org/wiki/Korpus_(wojsko)\" target=\"_blank\" rel=\"noopener noreferrer\">korpusie</a> oficerów starszych, natomiast w <a href=\"https://pl.wikipedia.org/wiki/Historia_Polski_(1918%E2%80%931939)\" target=\"_blank\" rel=\"noopener noreferrer\">okresie międzywojennym</a> wchodził w skład korpusu oficerów sztabowych. W wojsku polskim jest to stopień niższy od <a href=\"https://pl.wikipedia.org/wiki/Podpu%C5%82kownik\" target=\"_blank\" rel=\"noopener noreferrer\">podpułkownika</a>, wyższy od <a href=\"https://pl.wikipedia.org/wiki/Kapitan_(ranga)\" target=\"_blank\" rel=\"noopener noreferrer\">kapitana</a>. Odpowiednikiem majora w <a href=\"https://pl.wikipedia.org/wiki/Marynarka_wojenna\" target=\"_blank\" rel=\"noopener noreferrer\">marynarce wojennej</a> jest <a href=\"https://pl.wikipedia.org/wiki/Komandor_podporucznik\" target=\"_blank\" rel=\"noopener noreferrer\">komandor podporucznik</a>, a w <a href=\"https://pl.wikipedia.org/wiki/Policja\" target=\"_blank\" rel=\"noopener noreferrer\">policji</a> <a href=\"https://pl.wikipedia.org/wiki/Stopnie_s%C5%82u%C5%BCbowe_w_Policji\" target=\"_blank\" rel=\"noopener noreferrer\">podinspektor Policji</a>. Stopień majora występuje również w <a href=\"https://pl.wikipedia.org/wiki/Stra%C5%BC_Graniczna_(Polska)\" target=\"_blank\" rel=\"noopener noreferrer\">Straży Granicznej</a>, <a href=\"https://pl.wikipedia.org/wiki/S%C5%82u%C5%BCba_Wi%C4%99zienna\" target=\"_blank\" rel=\"noopener noreferrer\">Służbie Więziennej</a>, <a href=\"https://pl.wikipedia.org/wiki/Biuro_Ochrony_Rz%C4%85du\" target=\"_blank\" rel=\"noopener noreferrer\">Biurze Ochrony Rządu</a> oraz Służbie Kontrwywiadu i Wywiadu Wojskowego.", "Mariam": "<b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mi": "<p>Mi może być: Mi (powieść), znakiem E Mi (ty), a to jest powieść wietnamska.</p>", "Md Habib": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Muhammed Emin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Melchizedek": "W <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starym Testamencie</a> wspominany jest także w <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_Psalm%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Ps</a> <a href=\"https://pl.wikipedia.org/wiki/Psalm_110\" target=\"_blank\" rel=\"noopener noreferrer\">110</a>,4. W <a href=\"https://pl.wikipedia.org/wiki/Judaizm\" target=\"_blank\" rel=\"noopener noreferrer\">judaistycznej</a> literaturze mądrościowej (hebr. <i>hazal</i>) okresu od <a href=\"https://pl.wikipedia.org/wiki/Druga_%C5%9Awi%C4%85tynia\" target=\"_blank\" rel=\"noopener noreferrer\">Drugiej Świątyni</a> aż do VI w. n.e., imię <i>Melchi-sedek</i> (hebr. מלכי־צדק) rozumiane było jako przydomek syna <a href=\"https://pl.wikipedia.org/wiki/Noe\" target=\"_blank\" rel=\"noopener noreferrer\">Noego</a>, <a href=\"https://pl.wikipedia.org/wiki/Sem_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Sema</a>.", "Mandy": "<p>⁇ Mandy ⁇ (⁇ Mandy ⁇; oryginalna nazwa: ⁇ Brandy ⁇) - piosenka napisana przez Scotta Inglisha i Richarda Kerra. Piosenka ⁇ Brandy ⁇ stała się hitem w 1971 roku w wykonaniu Scotta English'a i w 1972 roku w Nowej Zelandii w wykonwaniu Bunny Walters'a, ale najbardziej popularna była wersja 1974 roku angielskiego piosenkarza Barry'ego Manilowa, nazwana ⁇ Mandy ⁇ , aby uniknąć zamieszania z piosenką ⁇ Brady (You're a Fine Girl) ⁇ amerykańskiego popu Looking Glass.</p>", "Mihai-Gabriel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mihai</b>.</p><p>Mihai (rumuńska wymowa: [miˈhaj]) jest rumuńskim nazwiskiem męskim lub nazwiskiem. To równoważne angielskiej imienia Michael.</p>", "Mohammed Riyaz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammed</b>.</p><p>Muhammad - muzułmańskie imię i nazwisko. Mahomet jest islamskim prorokiem.</p>", "Minos": "Według podań był potężnym i zdolnym władcą, który sprawił, że Kreta niepodzielnie panowała w tej części <a href=\"https://pl.wikipedia.org/wiki/Morze_%C5%9Ar%C3%B3dziemne\" target=\"_blank\" rel=\"noopener noreferrer\">Morza Śródziemnego</a>. Miał ukrócić <a href=\"https://pl.wikipedia.org/wiki/Pirat\" target=\"_blank\" rel=\"noopener noreferrer\">piractwo</a> i doprowadzić do rozkwitu handlu między państwami greckimi. Był znany ze sprawiedliwości, wobec czego po śmierci został jednym z trzech sędziów w <a href=\"https://pl.wikipedia.org/wiki/Hades\" target=\"_blank\" rel=\"noopener noreferrer\">Hadesie</a> – obok <a href=\"https://pl.wikipedia.org/wiki/Ajakos\" target=\"_blank\" rel=\"noopener noreferrer\">Ajakosa</a> i swojego brata <a href=\"https://pl.wikipedia.org/wiki/Radamantys\" target=\"_blank\" rel=\"noopener noreferrer\">Radamantysa</a>. Nie jest do końca zbadane, czy Minos to imię, czy też wyraz ten oznaczał na Krecie słowo <i>król</i>. Od Minosa pochodzi pojęcie <a href=\"https://pl.wikipedia.org/wiki/Kultura_minojska\" target=\"_blank\" rel=\"noopener noreferrer\">kultury minojskiej</a>.", "Miri": "<p>Miri to miasto w stanie Sarawak w Malezji. Miasto Miri ma powierzchnię kilometrów kwadratowych, populacja w 2010 roku wynosi 280,518 osób.</p>", "Md Emtiaz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Fardin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Milla": "<p>Milla (lat. Milla) - rodzaj trawnic roślin rodziny Sparaże (Asparagaceae), rozmieszczony w Gwatemali, Meksyku i USA (stanów Arizona i Nowego Meksyku).</p>", "Maria M": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mohaned": "<p>Mohannad (zwrócony również jako Mohanad, Mohanned, Mohaned, Muhannad lub Muhanned; arabski: مهند) to męskie arabskie imię. Mohannad lub jego odmiany mogą odnosić się do:</p>", "Md Ratan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Michael Santiago": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Michael</b>.</p><p>Michael: Botanika Michael - skrócie botaniczne, oznaczające, że autorem taksy jest Edmund Michael. Muzyka ⁇ Michael ⁇ - piosenka grupy Franz Ferdinand, wydana w 2004 roku.</p>", "Md Monjurul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mustafa Ozan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mustafa</b>.</p><b>Mustafa</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia arabskiego, oznacza „wybrany”.", "Md Ikram": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mykhailo-Bohdan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mykhailo</b>.</p><p>Mykhailo lub Mykhaylo to ukraińskie męskie imię, równoważne angielskim Michałowi. Wśród znanych osób z nazwiskiem są: Mykhaylo Berkos (1861-1919), rosyjski i ukraiński artysta pochodzenia greckiego Mykhayilo Bolotskykh (ur. 1960), ukraiński polityk i wojskowy, pułkownik generalny (Służba Obrony Cywilnej) Mykhayło Brodskyy (ur. 1959), ukraiński polityk, przywódca Partii Wolnych Demokratów i biznesmen Mykhayla Chemberzhi,...</p>", "Md Rasal": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Emam": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Minh Ha": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Marian-Sorin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marian</b>.</p><b>Marian</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> od imienia <i>Marius</i> lub nazwy rodu <i>Marii</i>. Oznacza „należący do Mariusza, rodu Mariuszów”. Występuje w Polsce od 1332 roku, jako <b>Marzyjan</b>. Forma Marian pojawiła się w Polsce w XVI wieku. W języku angielskim używane jest jako imię żeńskie. W Polsce w żeńskim użyciu w 2025 roku wystąpiło 35 razy.", "Mingi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ming</b>.</p><p>Ming - biblioteka C do tworzenia plików Adobe Flash (.swf). Może być stosowany jako moduł PHP, pozwalając tworzyć dynamicznie (⁇ na lot ⁇) animację Flash.</p>", "Max Karl": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Max</b>.</p><p>Max (wymawia się: max) - niejednoznaczny termin. Max - w matematyce i językach programowania oznacza funkcję wyboru maksymalnego ze swoich argumentów, (Max (3, 6, 1) = 6).</p>", "Md Atikul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Nazmus": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Mozahidul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mohammed Abdulrahman": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammed</b>.</p><p>Muhammad - muzułmańskie imię i nazwisko. Mahomet jest islamskim prorokiem.</p>", "Md Limon": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Minh Thắng": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Mycola": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mykola</b>.</p><p>Mykola jest ukraińską wariantą męskiego nazwiska \"Nicholas\", co oznacza \"wygrę narodu\". Może odnosić się do:</p>", "Mario Antonio": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mario</b>.</p><p>Mario (jap. Mario Mario, angielski.</p>", "Maria Jerzy": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Masamune": "<b>Masamune Okazaki</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;岡崎 正宗&#32;<i>Okazaki Masamune</i>) – <a href=\"https://pl.wikipedia.org/wiki/Japonia\" target=\"_blank\" rel=\"noopener noreferrer\">japoński</a> wytwórca mieczy <a href=\"https://pl.wikipedia.org/wiki/Tachi\" target=\"_blank\" rel=\"noopener noreferrer\">tachi</a>. Znany również jako Gorō Nyūdō Masamune (五郎 入道 正宗), ur. ok. 1264, zm. 1343. Pochodził z prowincji Sagami.", "Md Zafor": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Minh Quoc": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Maur": "<b>Maur</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa oznaczającego \"pochodzący z Mauretanii\" (inaczej \"Arab\") lub posiadający ciemną skórę. Istnieli liczni święci o tym imieniu m.in. <a href=\"https://pl.wikipedia.org/wiki/Maur_(ucze%C5%84_%C5%9Bw._Benedykta)\" target=\"_blank\" rel=\"noopener noreferrer\">Maur (uczeń św. Benedykta)</a>.", "Mihai-Ioan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mihai</b>.</p><p>Mihai (rumuńska wymowa: [miˈhaj]) jest rumuńskim nazwiskiem męskim lub nazwiskiem. To równoważne angielskiej imienia Michael.</p>", "Maksym-Mykhailo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maksym</b>.</p><b>Maksym</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, utworzone od przymiotnika <i>maximus</i> oznaczający \"największy\", przydomka <a href=\"https://pl.wikipedia.org/wiki/Jowisz_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Jowisza</a>. Istnieją liczni święci prawosławni i katoliccy o tym imieniu: <a href=\"https://pl.wikipedia.org/wiki/Maksym_Wyznawca\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym Wyznawca</a>, <a href=\"https://pl.wikipedia.org/wiki/Maksym_Grek\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym Grek</a>, <a href=\"https://pl.wikipedia.org/wiki/Maksym_Brankowicz\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym Wołoski</a>, <a href=\"https://pl.wikipedia.org/wiki/Maksym_Gorlicki\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym Gorlicki</a>, <a href=\"https://pl.wikipedia.org/wiki/Maksym_z_Riez\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym z Riez</a> i wielu innych.", "Muhhamad": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Muhamad</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Mohammad Taghi": "<p>Mohammad-Taqi (محمد تقی), również pisany jako Muhammad Taqi lub Mohammad Taghi jest powszechną nazwą wśród muzułmanów, zwłaszcza muzułmańskich szyitów. Może odnosić się do następujących: Muhammad al-Taqi (811 AD - 835), 9. Ismaili Imam Mohammad-Taqi Bahar (1884 - 1951), irański poeta, uczony i polityk Muhammad Taqi-ud-Din al-Hilali (1893?</p>", "Mohammed Arham": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammed</b>.</p><p>Muhammad - muzułmańskie imię i nazwisko. Mahomet jest islamskim prorokiem.</p>", "Milanko": "<p>Milanko to zarówno imię, jak i nazwisko. Do wybitnych osób z tym nazwiskiem należą:</p>", "Mohammad Omar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Martinas": "<p>Martinas to imię. Znanymi osobami z nazwiska są: Martinas Geben (ur. 1994), litewski piłkarz koszykówki Martinas Rankin (ur. 1994), amerykański piłkarzek</p>", "Marc Anthony": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marc</b>.</p><p>Marc: MARC (ang. Machine-Readable Cataloging) - grupa formatów (MARC21, UNIMARC, RUSMAC itp.</p>", "Matei-Alexandru": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Matei</b>.</p><p>Matei (rumuńska: [maˈtej]) jest rumuńskim męskim nazwiskiem i nazwiskiem. Jest odwzajemniony od nazwiska Matthias, a jest spokrewniony z angielską nazwą Matthew.</p>", "Mustafa Alper": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mustafa</b>.</p><b>Mustafa</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia arabskiego, oznacza „wybrany”.", "Marian Tomasz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marian</b>.</p><b>Marian</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> od imienia <i>Marius</i> lub nazwy rodu <i>Marii</i>. Oznacza „należący do Mariusza, rodu Mariuszów”. Występuje w Polsce od 1332 roku, jako <b>Marzyjan</b>. Forma Marian pojawiła się w Polsce w XVI wieku. W języku angielskim używane jest jako imię żeńskie. W Polsce w żeńskim użyciu w 2025 roku wystąpiło 35 razy.", "Mohammad Ruhul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Michael Paul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Michael</b>.</p><p>Michael: Botanika Michael - skrócie botaniczne, oznaczające, że autorem taksy jest Edmund Michael. Muzyka ⁇ Michael ⁇ - piosenka grupy Franz Ferdinand, wydana w 2004 roku.</p>", "Martin Emilio": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Martin</b>.</p><p>William Charles Lynne Martin (1798 - 1864) - angielski naturalista. Martin był kuratorem muzeum London Zoological Society od 1830 do 1838 roku, aż do czasu, gdy stracił pracę w wyniku zmniejszenia finansowania.</p>", "Mohammad Ilyas": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Md Tareq": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Mehedi Hasan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Najir": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Minh Quyen": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Mohammad Kamrul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Mihovil": "<p>Mihovil to chorwackie imię. To wariant Michaela.</p>", "Minh Ngọc": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Md Anik": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mohamed Attia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohamed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Marcelina": "<b>Marcelina</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Marcelin_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Marcelin</a>. <b>Pochodzenie i znaczenie:</b> z łaciny: Marcellus, liczba mnoga Marcelli – plebejski, później patrycjuszowski ród rzymski, jedna z gałęzi rodu Klaudiuszów.", "Minh Chung": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Moneeb": "<p>Munib (zwany również Moneeb, Muneeb lub Münip, arabski: منيب) jest arabskim męskim imieniem. Do wybitnych osób z tym nazwiskiem należą:</p>", "M M": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>M</b>.</p><b>M</b> (<i>em</i>, <a href=\"https://pl.wikipedia.org/wiki/Minusku%C5%82a\" target=\"_blank\" rel=\"noopener noreferrer\">minuskuła</a>: <b>m</b>) – trzynasta <a href=\"https://pl.wikipedia.org/wiki/Litera\" target=\"_blank\" rel=\"noopener noreferrer\">litera</a> <a href=\"https://pl.wikipedia.org/wiki/Alfabet_%C5%82aci%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu łacińskiego</a> i siedemnasta <a href=\"https://pl.wikipedia.org/wiki/Alfabet_polski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu polskiego</a>. Oznacza zwykle w danym języku <a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_nosowa_dwuwargowa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">spółgłoskę wargową nosową</a>, np. [<a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_nosowa_dwuwargowa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">m</a>].", "Mohammad Nurul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Marian Robert": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marian</b>.</p><b>Marian</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> od imienia <i>Marius</i> lub nazwy rodu <i>Marii</i>. Oznacza „należący do Mariusza, rodu Mariuszów”. Występuje w Polsce od 1332 roku, jako <b>Marzyjan</b>. Forma Marian pojawiła się w Polsce w XVI wieku. W języku angielskim używane jest jako imię żeńskie. W Polsce w żeńskim użyciu w 2025 roku wystąpiło 35 razy.", "Mohamed Mahmoud": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohamed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Md Hamidur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Marpat": "<b>MARPAT</b> (skrót od <b>MAR</b>ine <b>PAT</b>tern) – pikselowany <a href=\"https://pl.wikipedia.org/wiki/Maskowanie_(wojsko)\" target=\"_blank\" rel=\"noopener noreferrer\">kamuflaż</a> używany przez <a href=\"https://pl.wikipedia.org/wiki/Korpus_Piechoty_Morskiej_Stan%C3%B3w_Zjednoczonych\" target=\"_blank\" rel=\"noopener noreferrer\">Korpus Piechoty Morskiej Stanów Zjednoczonych</a>, zastosowany w <a href=\"https://pl.wikipedia.org/wiki/Marine_Corps_Combat_Utility_Uniform\" target=\"_blank\" rel=\"noopener noreferrer\">Marine Corps Combat Utility Uniform</a> (MCCUU), który zastąpił Camouflage Utility Uniform. Opracowany na wzór kanadyjskiego <a href=\"https://pl.wikipedia.org/wiki/CADPAT\" target=\"_blank\" rel=\"noopener noreferrer\">CADPAT</a>'a (CAnadian Disruptive PATtern). Wzór jest tworzony przez wiele małych, prostokątnych pikseli. W teorii oznacza to, że MARPAT jest bardziej efektywny w kamuflowaniu od innych „normalnych” kamuflaży, ponieważ naśladuje cętkowane powierzchnie i zatarte granice jakie można znaleźć w naturalnym środowisku. Spowodowane jest to tym, jak ludzkie oko odbiera spikselowane obrazy. Kamuflaż MARPAT pozwala opóźnić wykrycie żołnierza około 2,5-krotnie (w porównaniu do munduru w jednolitym kolorze) lub 1,5-krotnie (w porównaniu do Eurocam). Taki kamuflaż dobrze maskuje gdy patrzy się na niego z niewielkiej odległości ale, za to gdy patrzy się na niego z większej odległości, zlewa się, tworząc dobrze rozpoznawalną plamę o kształcie człowieka. Graniczną odległością, na jakiej wzór nie zlewa się w jednolitą plamę, jest około 100 <a href=\"https://pl.wikipedia.org/wiki/Metr\" target=\"_blank\" rel=\"noopener noreferrer\">metrów</a>.", "Mansour A": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mansour</b>.</p><p>Mansour (arabickie: منصور, Manṣūr); również pisane Mounsor, Monsur (Bengali), Mansoor, Manser, Mansur, Mansyur (indonezyjski) lub Mensur (tyrki), to męskie arabskie imię oznaczające \"Ten, który zwycięża\", z arabskiego korzenia naṣr (نصر), oznaczające \"wygrę\". Pierwszym znanym nosicielem nazwy był Mansur ibn Sarjun, bizantyjski gubernator Damaszku pod koniec lat 500 i na początku lat 600, który poddał miasto muzułmanom w 635 r. Inni ludzie nazywają się Mansur...</p>", "Marian-Emil": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marian</b>.</p><b>Marian</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> od imienia <i>Marius</i> lub nazwy rodu <i>Marii</i>. Oznacza „należący do Mariusza, rodu Mariuszów”. Występuje w Polsce od 1332 roku, jako <b>Marzyjan</b>. Forma Marian pojawiła się w Polsce w XVI wieku. W języku angielskim używane jest jako imię żeńskie. W Polsce w żeńskim użyciu w 2025 roku wystąpiło 35 razy.", "Micius": "<b>Mo Di</b> (chiń. 墨翟) albo <b>Mozi</b> (chiń. 墨子, dosł. <b>Mistrz Mo</b>), przestarzale latynizowany także jako <b>Micjusz</b> (łac. Micius) (ur. ok. <a href=\"https://pl.wikipedia.org/wiki/480_p.n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">480 p.n.e.</a>, zm. ok. <a href=\"https://pl.wikipedia.org/wiki/390_p.n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">390 p.n.e.</a>) – <a href=\"https://pl.wikipedia.org/wiki/Chiny\" target=\"_blank\" rel=\"noopener noreferrer\">chiński</a> <a href=\"https://pl.wikipedia.org/wiki/Filozof\" target=\"_blank\" rel=\"noopener noreferrer\">filozof</a>, twórca <a href=\"https://pl.wikipedia.org/wiki/Motizm\" target=\"_blank\" rel=\"noopener noreferrer\">motizmu</a>. Swoje poglądy zawarł w księdze nazywanej od jego imienia – <i>Mozi</i>. Po nastaniu <a href=\"https://pl.wikipedia.org/wiki/Cesarstwo_chi%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">Cesarstwa Chińskiego</a> jego szkoła przestała istnieć, ale myśl nie została zapomniana, była jedynie przedmiotem nieustannej krytyki ze strony konfucjanistów. W XVI wieku misjonarze europejscy (jezuici) uważali Mo Di za naturalnego chrześcijanina (<i>anima naturaliter christiana</i>). Odkryto go na nowo pod koniec <a href=\"https://pl.wikipedia.org/wiki/XIX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIX wieku</a>, jego nauka stała się przedmiotem zainteresowania ideologów nacjonalizmu chińskiego (<a href=\"https://pl.wikipedia.org/wiki/Liang_Qichao\" target=\"_blank\" rel=\"noopener noreferrer\">Liang Qichao</a>), <a href=\"https://pl.wikipedia.org/wiki/Republika_Chi%C5%84ska\" target=\"_blank\" rel=\"noopener noreferrer\">Republiki Chińskiej</a> (<a href=\"https://pl.wikipedia.org/wiki/Sun_Jat-sen\" target=\"_blank\" rel=\"noopener noreferrer\">Sun Jat-sen</a>) oraz <a href=\"https://pl.wikipedia.org/wiki/Komunizm\" target=\"_blank\" rel=\"noopener noreferrer\">komunistów</a> (proto-komunista).", "Muhammad Noman": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammad</b>.</p><b>Muhammad</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;مُحَمَّد&#8206;) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wariantami tego imienia są: Mohammed, Mehmed, Mamadu i Mahomet.", "Mohammad Nayem": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Mártin": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Martyn</b>.</p><b>Marcin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od wyrażenia <i>Martinus</i> oznaczającego „należący do boga <a href=\"https://pl.wikipedia.org/wiki/Mars_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Marsa</a>”.", "Melitoni": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Meliton</b>.</p><b>Meliton</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, utworzone od wyrazu pospolitego méli, -itos 'miód' za pomocą <a href=\"https://pl.wikipedia.org/wiki/Przyrostek\" target=\"_blank\" rel=\"noopener noreferrer\">przyrostka</a> -n, oznaczające 'człowieka jak miód'. Patronem imienia jest <a href=\"https://pl.wikipedia.org/wiki/Meliton_z_Sardes\" target=\"_blank\" rel=\"noopener noreferrer\">Meliton z Sardes</a>, święty z II wieku.", "Md Manir": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mohamed Salah": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohamed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Md Rokibul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Martin Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Martin</b>.</p><p>William Charles Lynne Martin (1798 - 1864) - angielski naturalista. Martin był kuratorem muzeum London Zoological Society od 1830 do 1838 roku, aż do czasu, gdy stracił pracę w wyniku zmniejszenia finansowania.</p>", "Mohammed Asif": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammed</b>.</p><p>Muhammad - muzułmańskie imię i nazwisko. Mahomet jest islamskim prorokiem.</p>", "Muhammad Asghar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammad</b>.</p><b>Muhammad</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;مُحَمَّد&#8206;) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wariantami tego imienia są: Mohammed, Mehmed, Mamadu i Mahomet.", "Maria Roman": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Minh Công": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Md Badsha": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Rezaul Karim": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Zahidul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Massoud": "<p>Massoud (arabski: مسعود اِقرا:مَس عَود , romanized: fortunate, prosperous, lucky, happy, perskiego: مسعود خوانده شود:مسود) to nazwisko i nazwisko, powszechnie występujące na Bliskim Wschodzie i Azji. Jest on różnorodnie napisany, w tym Masoud, Masud, Massoude, Massudeh, Masood, Masʽud, Masud.</p>", "Mohammed Abdur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammed</b>.</p><p>Muhammad - muzułmańskie imię i nazwisko. Mahomet jest islamskim prorokiem.</p>", "Mirosław Kazimierz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mirosław</b>.</p><b>Mirosław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie imię</a> męskie. Imię <i>Mirosław</i> jest przykładem <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staropolski\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskiego</a>, złożonego, osobowego imienia dwuczłonowego, które jest <a href=\"https://pl.wikipedia.org/wiki/Relikt\" target=\"_blank\" rel=\"noopener noreferrer\">reliktem</a> <a href=\"https://pl.wikipedia.org/wiki/Poganie\" target=\"_blank\" rel=\"noopener noreferrer\">pogańskich</a> imion używanych we wczesnym średniowieczu przez <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie\" target=\"_blank\" rel=\"noopener noreferrer\">Słowian</a>. Składa się z członów <i>Miro-</i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pras%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">ps.</a> <i>*mirъ</i> „pokój”, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staropolski\" target=\"_blank\" rel=\"noopener noreferrer\">stpol.</a> <i>mir</i>, <i>mier</i> - „pokój, bezpieczeństwo, przyjaźń”) oraz <i>-sław</i> („sława”). Mogło oznaczać „ten, który sławi pokój” albo „ten, który zdobywa sławę poprzez zaprowadzenie porządku, pokoju”. <a href=\"https://pl.wikipedia.org/wiki/Witold_Taszycki\" target=\"_blank\" rel=\"noopener noreferrer\">Witold Taszycki</a> zaliczył je do grupy najstarszych polskich imion osobowych&#8201;.", "Majki": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Majk</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Majka</b>.</p><p>Majka, słowiańskie kobiece imię, pierwotnie diminutiw nazwiska Maria lub Maja, może być to zmiana pisowni Mayka.</p>", "Md Monir Hossain": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mohammed Sadath": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammed</b>.</p><p>Muhammad - muzułmańskie imię i nazwisko. Mahomet jest islamskim prorokiem.</p>", "Marius-David": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marius</b>.</p>Pochodził z niższych warstw społecznych, miał być z zawodu rzemieślnikiem (kowalem), później przypuszczalnie służył w wojsku, lecz nie wiadomo w jakiej funkcji. Po stłumionej w początkach 269 roku rewolcie <a href=\"https://pl.wikipedia.org/wiki/Lelian_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Leliana</a> wzniecił kolejny bunt w <a href=\"https://pl.wikipedia.org/wiki/Moguncja\" target=\"_blank\" rel=\"noopener noreferrer\">Mogontiacum</a> przeciwko władzy <a href=\"https://pl.wikipedia.org/wiki/Wiktoryn_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Wiktoryna</a>, następcy <a href=\"https://pl.wikipedia.org/wiki/Postumus\" target=\"_blank\" rel=\"noopener noreferrer\">Postuma</a>. Według <i><a href=\"https://pl.wikipedia.org/wiki/Historia_Augusta\" target=\"_blank\" rel=\"noopener noreferrer\">Historia Augusta</a></i> jego rządy trwały zaledwie 2-3 dni, czemu jednak przeczy zachowana liczba jego monet. Najpewniej w mennicy w <a href=\"https://pl.wikipedia.org/wiki/Kolonia_(Niemcy)\" target=\"_blank\" rel=\"noopener noreferrer\">Kolonii</a> (<i>Colonia Agrippina</i>) <a href=\"https://pl.wikipedia.org/wiki/Emisja_pieni%C4%85dza\" target=\"_blank\" rel=\"noopener noreferrer\">emitował</a> w swym imieniu niskowartościowe <a href=\"https://pl.wikipedia.org/wiki/Antoninian\" target=\"_blank\" rel=\"noopener noreferrer\">antoniniany</a> typów: AEQUITAS, CONCORDIA MILIT(um), SAEC(uli) FELICITAS, VICTORIA AUG(usti), VIRTUS AUG(usti).", "Morado": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Morad</b>.</p><p>Murad lub Mourad (arabijski: مراد) to arabska nazwa. Jest również powszechne w językach armenijskim, azerbajdżanskim, bengalijskim, tureckim, perskim i berberskim jako męskie imię lub nazwisko i jest powszechnie stosowane w całym świecie muzułmańskim i na Bliskim Wschodzie.</p>", "Marianna": "<b>Marianna</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Marian\" target=\"_blank\" rel=\"noopener noreferrer\">Marian</a>. Potocznie jest ono często błędnie rozumiane jako wynik złożenia dwóch innych imion: <a href=\"https://pl.wikipedia.org/wiki/Maria\" target=\"_blank\" rel=\"noopener noreferrer\">Marii</a> i <a href=\"https://pl.wikipedia.org/wiki/Anna\" target=\"_blank\" rel=\"noopener noreferrer\">Anny</a>, analogicznie do <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">ang.</a>&#160;<em>Maryann</em>.", "Mykel": "<p>Mykel to męskie imię. Znani ludzie z tego nazwiska to: Mykel Benson (ur. 1987), amerykański piłkarz Mykel Board (ur. 1950), amerykańska dziennikarz, muzyka i pisarz Mykal Gray lub Miss Mykie (ur. 1985), amerykańskiej aktorki, osobistości telewizyjnej i artysty nagrywania Mykel Hawke (ur. 1965), amerykańca Mykel Shannon Jenkins (ur. 1969), amerykańczyka aktorka i filmowca Mykel Williams (ur. 2004), amerykajski piłkarzek</p>", "Matveii": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Matvei</b>.</p><p>Matvei lub Matvey (Матвей) jest rosyjską wersją Mateusza. Wśród znanych osób z nazwy są: Matvey Blanter (1903-1990), rosyjski kompozytor muzyki popularnej i filmowej Matvei Bronstein (1906-1938), radziecki fizyk teoretyczny Matvey Frantskevich (ur. 1995), białoruski piłkarz Matvei Gedenshtrom (r.</p>", "Ming-Chun": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ming</b>.</p><p>Ming - biblioteka C do tworzenia plików Adobe Flash (.swf). Może być stosowany jako moduł PHP, pozwalając tworzyć dynamicznie (⁇ na lot ⁇) animację Flash.</p>", "Man Sing": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Man</b>.</p><p>man (od angielskiego manual - wytyczne) - polecenie Unix przeznaczone do formatowania i wyciągania stron odniesienia.</p>", "Md Nayon": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Karim": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Morys": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Moris</b>.</p><p>Giuseppe Giacinto Moris (włoski: Giuseppe Giacinta Moris; 1796 - 1869) - włoski botanik i polityk.</p>", "Marvic": "<p>Marvic to imię, które jest zazwyczaj używane w kontekście męskim. Powszechnie występuje na Filipinach.</p>", "Mikołay": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mykolay</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mikolai</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mikola</b>.</p><p>Mikola to nazwisko: Ananda Mikola (ur. 1980), indonezyjski kierowca samochodu wyścigowego István Mikola (r. 1947), węgierski lekarz i polityk, minister zdrowia od 2001 do 2002 roku Nándor Mikola (1911-2006), fiński-węgierski malarz Nazwa: Święty Mikołaj Mozhaiński lub Mikola Mozhaiski, rosyjska wariantka tradycji św. Mikola Abramchyk (1903-1970), białoruski dziennikarz i polityka Mikola Statkevich (ur. 1956),...</p>", "Meshack": "<p>Meshack to męskie imię. Znani ludzie z nazwiska obejmują: Dumezweni Meshack Mthimkhulu, Motswana polityk Meshack Abel Mwankina (ur. 1987), tanzanii piłkarz Meshack Asare (ur. 1945), ghanański pisarz Meshac Franklin (1722-1839), amerykański polityk Meshak Kondwani, Zimbabwe boksera Meshack Lufile (ur. 1992), kanadyjski piłkarzem koszykówki Meshack Maphangule (ur. 1991), południowoafrykański piłkarze Meshack Mavuso (ur. 1977),...</p>", "Maksym-Bohdan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maksym</b>.</p><b>Maksym</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, utworzone od przymiotnika <i>maximus</i> oznaczający \"największy\", przydomka <a href=\"https://pl.wikipedia.org/wiki/Jowisz_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Jowisza</a>. Istnieją liczni święci prawosławni i katoliccy o tym imieniu: <a href=\"https://pl.wikipedia.org/wiki/Maksym_Wyznawca\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym Wyznawca</a>, <a href=\"https://pl.wikipedia.org/wiki/Maksym_Grek\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym Grek</a>, <a href=\"https://pl.wikipedia.org/wiki/Maksym_Brankowicz\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym Wołoski</a>, <a href=\"https://pl.wikipedia.org/wiki/Maksym_Gorlicki\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym Gorlicki</a>, <a href=\"https://pl.wikipedia.org/wiki/Maksym_z_Riez\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym z Riez</a> i wielu innych.", "Matei-Jador": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Matei</b>.</p><p>Matei (rumuńska: [maˈtej]) jest rumuńskim męskim nazwiskiem i nazwiskiem. Jest odwzajemniony od nazwiska Matthias, a jest spokrewniony z angielską nazwą Matthew.</p>", "Michael Jhonathan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Michael</b>.</p><p>Michael: Botanika Michael - skrócie botaniczne, oznaczające, że autorem taksy jest Edmund Michael. Muzyka ⁇ Michael ⁇ - piosenka grupy Franz Ferdinand, wydana w 2004 roku.</p>", "Marcos Gabriel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marcos</b>.</p><p>Marcos - brytyjski producent samochodów, który wyprodukował samochody sportowe w latach 1959-2007. Nazwa firmy powstała z pierwszych liter nazwisk współzałożycieli.</p>", "Miky": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Miki</b>.</p><b>Miki</b>, <b>łyszczyki</b> – grupa <a href=\"https://pl.wikipedia.org/wiki/Minera%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">minerałów</a> zaliczana do gromady <a href=\"https://pl.wikipedia.org/wiki/Krzemiany\" target=\"_blank\" rel=\"noopener noreferrer\">krzemianów</a>. Nazwa „mika” pochodzi od <a href=\"https://pl.wikipedia.org/wiki/%C5%81ac.\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <i>mica</i> (ziarno) lub <i>micare</i> (błyszczeć).", "Md Sazzad": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Sahin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mihai-Ionuţ": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mihai</b>.</p><p>Mihai (rumuńska wymowa: [miˈhaj]) jest rumuńskim nazwiskiem męskim lub nazwiskiem. To równoważne angielskiej imienia Michael.</p>", "Mobeen": "<p>Mobeen (arabski: مبين; perskiego: مبین) (zwany również Mubeen, Mobin, Mubin) to imię pochodzące od arabskiego słowa (مبين), które jest używane jako poetycki przymiot w literaturze, mowie i kontekście religijnym. Nazwa może być przetłumaczana jako \"wyraźne\", \"jasne\", \"wymowne\", \"wybitne\" lub \"jasne\".</p>", "Md Tonmoy": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Michael William": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Michael</b>.</p><p>Michael: Botanika Michael - skrócie botaniczne, oznaczające, że autorem taksy jest Edmund Michael. Muzyka ⁇ Michael ⁇ - piosenka grupy Franz Ferdinand, wydana w 2004 roku.</p>", "Md Shaiful Islam": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Tawhidul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Martin Elias": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Martin</b>.</p><p>William Charles Lynne Martin (1798 - 1864) - angielski naturalista. Martin był kuratorem muzeum London Zoological Society od 1830 do 1838 roku, aż do czasu, gdy stracił pracę w wyniku zmniejszenia finansowania.</p>", "Malinao": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Malina</b>.</p><b>Malina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, które prawdopodobnie jest zdrobnieniem imienia <a href=\"https://pl.wikipedia.org/wiki/Magdalena\" target=\"_blank\" rel=\"noopener noreferrer\">Magdalena</a>, powstałym na gruncie kilku języków wschodniosłowiańskich bądź w Skandynawii. <a href=\"https://pl.wikipedia.org/wiki/Rada_J%C4%99zyka_Polskiego\" target=\"_blank\" rel=\"noopener noreferrer\">Rada Języka Polskiego</a> ma wątpliwości dotyczące nadawania tego imienia ludziom.", "Muhammed Ashiq": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Md Abu Bakar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Marian-Adrian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marian</b>.</p><b>Marian</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> od imienia <i>Marius</i> lub nazwy rodu <i>Marii</i>. Oznacza „należący do Mariusza, rodu Mariuszów”. Występuje w Polsce od 1332 roku, jako <b>Marzyjan</b>. Forma Marian pojawiła się w Polsce w XVI wieku. W języku angielskim używane jest jako imię żeńskie. W Polsce w żeńskim użyciu w 2025 roku wystąpiło 35 razy.", "Marc-Oliver": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marc</b>.</p><p>Marc: MARC (ang. Machine-Readable Cataloging) - grupa formatów (MARC21, UNIMARC, RUSMAC itp.</p>", "Marcian": "Był jednym z wodzów w armii <a href=\"https://pl.wikipedia.org/wiki/Flawiusz_Ardaburiusz_Aspar\" target=\"_blank\" rel=\"noopener noreferrer\">Aspara</a>, <i>magistra militum</i>, czyli głównodowodzącego armii <a href=\"https://pl.wikipedia.org/wiki/Cesarstwo_Bizanty%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">bizantyńskiej</a>, pochodzącego z <a href=\"https://pl.wikipedia.org/wiki/Ludy_ira%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">irańskiego</a> ludu <a href=\"https://pl.wikipedia.org/wiki/Alanowie\" target=\"_blank\" rel=\"noopener noreferrer\">Alanów</a> (stanowiło to istotną przeszkodę w objęciu przez niego tronu). Cesarzem obrano Marcjana, gdy poślubił siostrę poprzednika, <a href=\"https://pl.wikipedia.org/wiki/Pulcheria_(cesarzowa)\" target=\"_blank\" rel=\"noopener noreferrer\">Pulcherię</a>, choć było to fikcyjne małżeństwo, a Pulcheria do końca życia pozostała dziewicą.", "Mieczysław Józef": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mieczysław</b>.</p><b>Mieczysław</b> – dwuczłonowe <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, które powstało najprawdopodobniej w wyniku błędnego odczytania słowiańskiego imienia złożonego <a href=\"https://pl.wikipedia.org/wiki/Miecis%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Miecisław</a> (którego najstarszy zapis pochodzi z 1257).", "Marie Jacques": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Md Borhan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mykhailo-Maksym": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mykhailo</b>.</p><p>Mykhailo lub Mykhaylo to ukraińskie męskie imię, równoważne angielskim Michałowi. Wśród znanych osób z nazwiskiem są: Mykhaylo Berkos (1861-1919), rosyjski i ukraiński artysta pochodzenia greckiego Mykhayilo Bolotskykh (ur. 1960), ukraiński polityk i wojskowy, pułkownik generalny (Służba Obrony Cywilnej) Mykhayło Brodskyy (ur. 1959), ukraiński polityk, przywódca Partii Wolnych Demokratów i biznesmen Mykhayla Chemberzhi,...</p>", "Mohammed Sohel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammed</b>.</p><p>Muhammad - muzułmańskie imię i nazwisko. Mahomet jest islamskim prorokiem.</p>", "Marius-Valentin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marius</b>.</p>Pochodził z niższych warstw społecznych, miał być z zawodu rzemieślnikiem (kowalem), później przypuszczalnie służył w wojsku, lecz nie wiadomo w jakiej funkcji. Po stłumionej w początkach 269 roku rewolcie <a href=\"https://pl.wikipedia.org/wiki/Lelian_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Leliana</a> wzniecił kolejny bunt w <a href=\"https://pl.wikipedia.org/wiki/Moguncja\" target=\"_blank\" rel=\"noopener noreferrer\">Mogontiacum</a> przeciwko władzy <a href=\"https://pl.wikipedia.org/wiki/Wiktoryn_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Wiktoryna</a>, następcy <a href=\"https://pl.wikipedia.org/wiki/Postumus\" target=\"_blank\" rel=\"noopener noreferrer\">Postuma</a>. Według <i><a href=\"https://pl.wikipedia.org/wiki/Historia_Augusta\" target=\"_blank\" rel=\"noopener noreferrer\">Historia Augusta</a></i> jego rządy trwały zaledwie 2-3 dni, czemu jednak przeczy zachowana liczba jego monet. Najpewniej w mennicy w <a href=\"https://pl.wikipedia.org/wiki/Kolonia_(Niemcy)\" target=\"_blank\" rel=\"noopener noreferrer\">Kolonii</a> (<i>Colonia Agrippina</i>) <a href=\"https://pl.wikipedia.org/wiki/Emisja_pieni%C4%85dza\" target=\"_blank\" rel=\"noopener noreferrer\">emitował</a> w swym imieniu niskowartościowe <a href=\"https://pl.wikipedia.org/wiki/Antoninian\" target=\"_blank\" rel=\"noopener noreferrer\">antoniniany</a> typów: AEQUITAS, CONCORDIA MILIT(um), SAEC(uli) FELICITAS, VICTORIA AUG(usti), VIRTUS AUG(usti).", "Muhammad Saleem": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammad</b>.</p><b>Muhammad</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;مُحَمَّد&#8206;) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wariantami tego imienia są: Mohammed, Mehmed, Mamadu i Mahomet.", "Michał Tomasz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Michał</b>.</p><b>Michał</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִיכָאֵל&#8206; – Mîchā’ēl) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, wywodzące się od <a href=\"https://pl.wikipedia.org/wiki/Archanio%C5%82_Micha%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">jednego z archaniołów</a>. Po hebrajsku znaczy „któż [jest taki] jak Bóg”. Forma żeńska to <a href=\"https://pl.wikipedia.org/wiki/Michalina\" target=\"_blank\" rel=\"noopener noreferrer\">Michalina</a>.", "Mohammed Riaz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammed</b>.</p><p>Muhammad - muzułmańskie imię i nazwisko. Mahomet jest islamskim prorokiem.</p>", "Matias Nahuel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Matias</b>.</p><p>Matías to portugalska wersja Matthias. Matías jest bardzo popularny w Ameryce Łacińskiej, zwłaszcza w Argentynie.</p>", "Md Abdulla Al": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Muhammed Said": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Minh Tâm": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Marec": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Marek</b>.</p><b>Marek</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, należące do wąskiej grupy najstarszych <a href=\"https://pl.wikipedia.org/wiki/Imiona_%C5%82aci%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imion rzymskich</a> (imion właściwych, <i>praenomen</i>, por. <a href=\"https://pl.wikipedia.org/wiki/Tyberiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Tyberiusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Aulus\" target=\"_blank\" rel=\"noopener noreferrer\">Aulus</a>, <a href=\"https://pl.wikipedia.org/wiki/Maniusz\" target=\"_blank\" rel=\"noopener noreferrer\">Maniusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Gajusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Gajusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Lucjusz\" target=\"_blank\" rel=\"noopener noreferrer\">Lucjusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Publiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Publiusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Tytus\" target=\"_blank\" rel=\"noopener noreferrer\">Tytus</a>, <a href=\"https://pl.wikipedia.org/wiki/Serwiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Serwiusz</a>), utworzone z <i>*Mart-ico-s</i> od imienia boga <i><a href=\"https://pl.wikipedia.org/wiki/Mars_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Mars</a></i>, <i>Martis</i> i oznaczające „należący do Marsa, związany z Marsem”. W Polsce imię to jest notowane od <a href=\"https://pl.wikipedia.org/wiki/XIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIII wieku</a>, choć poza współczesnością nie było często spotykane, w formach <i><b>Marek</b></i>, <i><b>Marko</b></i>, <i><b>Margusz</b></i>, <i><b>Markusz</b></i>, <i><b>Merkusz</b></i>. Zapisana została także żeńska <b>Marka</b> (<a href=\"https://pl.wikipedia.org/wiki/1263\" target=\"_blank\" rel=\"noopener noreferrer\">1263</a>) – żeński odpowiednik imienia Marek lub zdrobnienie od imion żeńskich rozpoczynających się na Mar-, takich jak <i>Margorzata</i> (= <a href=\"https://pl.wikipedia.org/wiki/Ma%C5%82gorzata_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Małgorzata</a>) lub <a href=\"https://pl.wikipedia.org/wiki/Maria\" target=\"_blank\" rel=\"noopener noreferrer\">Maria</a> – oraz <a href=\"https://pl.wikipedia.org/wiki/Markus%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Markusław</a>, staropolskie imię utworzone od imienia Marek poprzez dodanie typowej dla imion słowiańskich cząstki -sław. Imię to według danych 2022 r. jest na 10 miejscu najpopularniejszych imion męskich.", "Md Zakaria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Maria Karol": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Millo": "<b>Millo</b> (lub Mello) (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hbr</a>. מילוא), dosł. wypełnienie lub taras – starożytne budowle występujące w miastach izraelskich, np. <a href=\"https://pl.wikipedia.org/wiki/Sychem\" target=\"_blank\" rel=\"noopener noreferrer\">Sychem</a> bądź w <a href=\"https://pl.wikipedia.org/wiki/Jerozolima\" target=\"_blank\" rel=\"noopener noreferrer\">Jerozolimie</a>, będące prawdopodobnie rodzajem umocnionych kamieniami tarasów lub nasypów, mających cywilne znaczenie budowlane – można było na nich stawiać budynki, co w warunkach górskich jest bardzo ważne dla rozwoju miast (patrz <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_S%C4%99dzi%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Sdz</a> 9:6 i 20, <a href=\"https://pl.wikipedia.org/wiki/1_Ksi%C4%99ga_Kr%C3%B3lewska\" target=\"_blank\" rel=\"noopener noreferrer\">1 Krl</a> 9:24, <a href=\"https://pl.wikipedia.org/wiki/2_Ksi%C4%99ga_Kr%C3%B3lewska\" target=\"_blank\" rel=\"noopener noreferrer\">2 Krl</a> 20:21), albo militarne znaczenie budowlane – można było na nich postawić np. mur obronny (patrz 1 Krl 11:27).", "Martin Junior": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Martin</b>.</p><p>William Charles Lynne Martin (1798 - 1864) - angielski naturalista. Martin był kuratorem muzeum London Zoological Society od 1830 do 1838 roku, aż do czasu, gdy stracił pracę w wyniku zmniejszenia finansowania.</p>", "Marcel M": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marcel</b>.</p><b>Marceli</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od nazwy jednej z gałęzi rzymskiego <a href=\"https://pl.wikipedia.org/wiki/Klaudiusze\" target=\"_blank\" rel=\"noopener noreferrer\">rodu Klaudiuszów</a>, <i>Marcelli</i>. Imię to bywa nadawane także w formie <b>Marcel</b>, jakkolwiek pojawia się ona w wydawnictwach poprawnościowych jako nieakceptowana. Żeńskim odpowiednikiem jest <a href=\"https://pl.wikipedia.org/wiki/Marcela\" target=\"_blank\" rel=\"noopener noreferrer\">Marcela</a>.", "Maciejewski": "<b>Maciejewski</b> (forma żeńska: <b>Maciejewska</b>; liczba mnoga: <b>Maciejewscy</b>) – <a href=\"https://pl.wikipedia.org/wiki/Polskie_nazwiska\" target=\"_blank\" rel=\"noopener noreferrer\">polskie nazwisko</a>, powstałe z rdzenia „<a href=\"https://pl.wikipedia.org/wiki/Maciej\" target=\"_blank\" rel=\"noopener noreferrer\">Maciej</a>”, lub od nazw miejscowych <a href=\"https://pl.wikipedia.org/wiki/Maciej%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Maciejów</a>, Maciejewice, <a href=\"https://pl.wikipedia.org/wiki/Maciejowice\" target=\"_blank\" rel=\"noopener noreferrer\">Maciejowice</a>. Na początku <a href=\"https://pl.wikipedia.org/wiki/Lata_90._XX_wieku\" target=\"_blank\" rel=\"noopener noreferrer\">lat 90.</a> <a href=\"https://pl.wikipedia.org/wiki/XX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XX wieku</a> w <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">Polsce</a> nosiło je 31 224 osoby.", "Marius-Cǎtǎlin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marius</b>.</p>Pochodził z niższych warstw społecznych, miał być z zawodu rzemieślnikiem (kowalem), później przypuszczalnie służył w wojsku, lecz nie wiadomo w jakiej funkcji. Po stłumionej w początkach 269 roku rewolcie <a href=\"https://pl.wikipedia.org/wiki/Lelian_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Leliana</a> wzniecił kolejny bunt w <a href=\"https://pl.wikipedia.org/wiki/Moguncja\" target=\"_blank\" rel=\"noopener noreferrer\">Mogontiacum</a> przeciwko władzy <a href=\"https://pl.wikipedia.org/wiki/Wiktoryn_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Wiktoryna</a>, następcy <a href=\"https://pl.wikipedia.org/wiki/Postumus\" target=\"_blank\" rel=\"noopener noreferrer\">Postuma</a>. Według <i><a href=\"https://pl.wikipedia.org/wiki/Historia_Augusta\" target=\"_blank\" rel=\"noopener noreferrer\">Historia Augusta</a></i> jego rządy trwały zaledwie 2-3 dni, czemu jednak przeczy zachowana liczba jego monet. Najpewniej w mennicy w <a href=\"https://pl.wikipedia.org/wiki/Kolonia_(Niemcy)\" target=\"_blank\" rel=\"noopener noreferrer\">Kolonii</a> (<i>Colonia Agrippina</i>) <a href=\"https://pl.wikipedia.org/wiki/Emisja_pieni%C4%85dza\" target=\"_blank\" rel=\"noopener noreferrer\">emitował</a> w swym imieniu niskowartościowe <a href=\"https://pl.wikipedia.org/wiki/Antoninian\" target=\"_blank\" rel=\"noopener noreferrer\">antoniniany</a> typów: AEQUITAS, CONCORDIA MILIT(um), SAEC(uli) FELICITAS, VICTORIA AUG(usti), VIRTUS AUG(usti).", "Milić": "<p>Milić (cyrylicki: Милић) to serbskie imię i nazwisko, a także chorwackie nazwisko. Do osób z tym nazwiskiem należą:</p>", "Md Sultan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mohammad Azharul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Md Mosle": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mohammed Saiful": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammed</b>.</p><p>Muhammad - muzułmańskie imię i nazwisko. Mahomet jest islamskim prorokiem.</p>", "Mihai-Ciprian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mihai</b>.</p><p>Mihai (rumuńska wymowa: [miˈhaj]) jest rumuńskim nazwiskiem męskim lub nazwiskiem. To równoważne angielskiej imienia Michael.</p>", "Muhammad Kashif": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammad</b>.</p><b>Muhammad</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;مُحَمَّد&#8206;) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wariantami tego imienia są: Mohammed, Mehmed, Mamadu i Mahomet.", "Md Rafiq": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mohammed Amine": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammed</b>.</p><p>Muhammad - muzułmańskie imię i nazwisko. Mahomet jest islamskim prorokiem.</p>", "Mohammed Hasan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammed</b>.</p><p>Muhammad - muzułmańskie imię i nazwisko. Mahomet jest islamskim prorokiem.</p>", "Mirza Salman": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mirza</b>.</p><p>Mirza (lat. Mirza) - rodzaj zwierząt mleczarzy z infraodrodu oddziału lemurowych prymatów.</p>", "Minh Cuong": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Marius-Gheorghe": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marius</b>.</p>Pochodził z niższych warstw społecznych, miał być z zawodu rzemieślnikiem (kowalem), później przypuszczalnie służył w wojsku, lecz nie wiadomo w jakiej funkcji. Po stłumionej w początkach 269 roku rewolcie <a href=\"https://pl.wikipedia.org/wiki/Lelian_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Leliana</a> wzniecił kolejny bunt w <a href=\"https://pl.wikipedia.org/wiki/Moguncja\" target=\"_blank\" rel=\"noopener noreferrer\">Mogontiacum</a> przeciwko władzy <a href=\"https://pl.wikipedia.org/wiki/Wiktoryn_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Wiktoryna</a>, następcy <a href=\"https://pl.wikipedia.org/wiki/Postumus\" target=\"_blank\" rel=\"noopener noreferrer\">Postuma</a>. Według <i><a href=\"https://pl.wikipedia.org/wiki/Historia_Augusta\" target=\"_blank\" rel=\"noopener noreferrer\">Historia Augusta</a></i> jego rządy trwały zaledwie 2-3 dni, czemu jednak przeczy zachowana liczba jego monet. Najpewniej w mennicy w <a href=\"https://pl.wikipedia.org/wiki/Kolonia_(Niemcy)\" target=\"_blank\" rel=\"noopener noreferrer\">Kolonii</a> (<i>Colonia Agrippina</i>) <a href=\"https://pl.wikipedia.org/wiki/Emisja_pieni%C4%85dza\" target=\"_blank\" rel=\"noopener noreferrer\">emitował</a> w swym imieniu niskowartościowe <a href=\"https://pl.wikipedia.org/wiki/Antoninian\" target=\"_blank\" rel=\"noopener noreferrer\">antoniniany</a> typów: AEQUITAS, CONCORDIA MILIT(um), SAEC(uli) FELICITAS, VICTORIA AUG(usti), VIRTUS AUG(usti).", "Mădălin-Constantin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mădălin</b>.</p><p>Mădălin to rumuńskie imię i nazwisko mężczyzny, które może odnosić się do: Mădăline Ciucă (ur. 1982), rumuński piłkarz Mădă Lin Lemnaru (ur. 1989), rumuński piłkarze rugby Mădă lin Marius Popa (ur. 1982) rumuński futbolista i menedżer Mădăilin Martin (ur. 1992), rumuńskiego piłkarza Mădălina Mihăescu (ur. 1988), rumuńczyka piłkarka Mădăl Murgan (ur. 1983), rumuńca piłkarzem Mădă l Popa (UR. 1983), rumunskiego piłkarta Mădălini Răileanu (ur....</p>", "Majko": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Majk</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Majka</b>.</p><p>Majka, słowiańskie kobiece imię, pierwotnie diminutiw nazwiska Maria lub Maja, może być to zmiana pisowni Mayka.</p>", "Md Saydur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mădălin-Valentin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mădălin</b>.</p><p>Mădălin to rumuńskie imię i nazwisko mężczyzny, które może odnosić się do: Mădăline Ciucă (ur. 1982), rumuński piłkarz Mădă Lin Lemnaru (ur. 1989), rumuński piłkarze rugby Mădă lin Marius Popa (ur. 1982) rumuński futbolista i menedżer Mădăilin Martin (ur. 1992), rumuńskiego piłkarza Mădălina Mihăescu (ur. 1988), rumuńczyka piłkarka Mădăl Murgan (ur. 1983), rumuńca piłkarzem Mădă l Popa (UR. 1983), rumunskiego piłkarta Mădălini Răileanu (ur....</p>", "Md Mojammel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mustafe": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mustaf</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mustafa</b>.</p><b>Mustafa</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia arabskiego, oznacza „wybrany”.", "Md Pavel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Min Woo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Min</b>.</p><p>Min to niejednoznaczny termin. min - w matematyce i językach programowania oznacza funkcję wyboru najmniejszego ze swoich argumentów, (Min (3, 6, 2) = 2).</p>", "Md Hazrat": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Basir": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Miguel Ignacio": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Miguel</b>.</p><p>Miguel (hisz. Miguel) - hiszpański odpowiednik imienia Michaila.</p>", "Muhammad Jamil": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammad</b>.</p><b>Muhammad</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;مُحَمَّد&#8206;) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wariantami tego imienia są: Mohammed, Mehmed, Mamadu i Mahomet.", "Md Abdur Rahman": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Miško": "<p>Miško (Serbski: Мишко) to sławskie imię męskie. Do wybitnych osób z nazwiskiem należą: Miško Jovanović (1878-1915), agent bosnijskich Serbów Miško Kranjec (1908-1983), słoweński pisarz Miško Mirković (ur. 1966), emerytowany serbski piłkarz Miško Ražnatović (urat. 1966), serbski prawnik i agent sportowy oraz były piłkarzem koszykówki Miško Šuvaković (r. 1954), serbski artysta</p>", "Md Habibur Rahman": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Michał Jerzy": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Michał</b>.</p><b>Michał</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִיכָאֵל&#8206; – Mîchā’ēl) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, wywodzące się od <a href=\"https://pl.wikipedia.org/wiki/Archanio%C5%82_Micha%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">jednego z archaniołów</a>. Po hebrajsku znaczy „któż [jest taki] jak Bóg”. Forma żeńska to <a href=\"https://pl.wikipedia.org/wiki/Michalina\" target=\"_blank\" rel=\"noopener noreferrer\">Michalina</a>.", "Mohamed Saleem": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohamed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Md Aslam": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Nayeem": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Marijuš": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Marius</b>.</p>Pochodził z niższych warstw społecznych, miał być z zawodu rzemieślnikiem (kowalem), później przypuszczalnie służył w wojsku, lecz nie wiadomo w jakiej funkcji. Po stłumionej w początkach 269 roku rewolcie <a href=\"https://pl.wikipedia.org/wiki/Lelian_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Leliana</a> wzniecił kolejny bunt w <a href=\"https://pl.wikipedia.org/wiki/Moguncja\" target=\"_blank\" rel=\"noopener noreferrer\">Mogontiacum</a> przeciwko władzy <a href=\"https://pl.wikipedia.org/wiki/Wiktoryn_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Wiktoryna</a>, następcy <a href=\"https://pl.wikipedia.org/wiki/Postumus\" target=\"_blank\" rel=\"noopener noreferrer\">Postuma</a>. Według <i><a href=\"https://pl.wikipedia.org/wiki/Historia_Augusta\" target=\"_blank\" rel=\"noopener noreferrer\">Historia Augusta</a></i> jego rządy trwały zaledwie 2-3 dni, czemu jednak przeczy zachowana liczba jego monet. Najpewniej w mennicy w <a href=\"https://pl.wikipedia.org/wiki/Kolonia_(Niemcy)\" target=\"_blank\" rel=\"noopener noreferrer\">Kolonii</a> (<i>Colonia Agrippina</i>) <a href=\"https://pl.wikipedia.org/wiki/Emisja_pieni%C4%85dza\" target=\"_blank\" rel=\"noopener noreferrer\">emitował</a> w swym imieniu niskowartościowe <a href=\"https://pl.wikipedia.org/wiki/Antoninian\" target=\"_blank\" rel=\"noopener noreferrer\">antoniniany</a> typów: AEQUITAS, CONCORDIA MILIT(um), SAEC(uli) FELICITAS, VICTORIA AUG(usti), VIRTUS AUG(usti).", "Md Mahamudul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Muhammad Salman": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammad</b>.</p><b>Muhammad</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;مُحَمَّد&#8206;) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wariantami tego imienia są: Mohammed, Mehmed, Mamadu i Mahomet.", "Matthëus": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Matheus</b>.</p><p>Matheus (port. Matheus) - własne imię; rozpowszechnione w postaci nazwisk.</p>", "Michel Yves": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Michel</b>.</p><p>⁇ Michel ⁇ (niemieckie MICHEL-Briefmarken-Katalog) - największy i najbardziej znany katalog znaków pocztowych w niemieckojęzycznym świecie i Europie.</p>", "Md Nurul Islam": "<p>Nurul Islam (Bengali: নূরুল ইসলাম, lit. 'Light of Islam') jest bengalską nazwą męską pochodzącą z arabskiego i może odnosić się do:</p>", "Mohammad Eqbal": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Md Sanjid": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mikołai": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mikola</b>.</p><p>Mikola to nazwisko: Ananda Mikola (ur. 1980), indonezyjski kierowca samochodu wyścigowego István Mikola (r. 1947), węgierski lekarz i polityk, minister zdrowia od 2001 do 2002 roku Nándor Mikola (1911-2006), fiński-węgierski malarz Nazwa: Święty Mikołaj Mozhaiński lub Mikola Mozhaiski, rosyjska wariantka tradycji św. Mikola Abramchyk (1903-1970), białoruski dziennikarz i polityka Mikola Statkevich (ur. 1956),...</p>", "Md Maksudur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mohammad Faruk": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Mohammad Shadat": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Md Muzahidul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mohammed Kamrul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammed</b>.</p><p>Muhammad - muzułmańskie imię i nazwisko. Mahomet jest islamskim prorokiem.</p>", "Mykhayło": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mychaylo</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mykhaylo</b>.</p><p>Mykhailo lub Mykhaylo to ukraińskie męskie imię, równoważne angielskim Michałowi. Wśród znanych osób z nazwiskiem są: Mykhaylo Berkos (1861-1919), rosyjski i ukraiński artysta pochodzenia greckiego Mykhayilo Bolotskykh (ur. 1960), ukraiński polityk i wojskowy, pułkownik generalny (Służba Obrony Cywilnej) Mykhayło Brodskyy (ur. 1959), ukraiński polityk, przywódca Partii Wolnych Demokratów i biznesmen Mykhayla Chemberzhi,...</p>", "Md Harun Or": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mohamed A.": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohamed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Minh Phú": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Michał Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Michał</b>.</p><b>Michał</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִיכָאֵל&#8206; – Mîchā’ēl) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, wywodzące się od <a href=\"https://pl.wikipedia.org/wiki/Archanio%C5%82_Micha%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">jednego z archaniołów</a>. Po hebrajsku znaczy „któż [jest taki] jak Bóg”. Forma żeńska to <a href=\"https://pl.wikipedia.org/wiki/Michalina\" target=\"_blank\" rel=\"noopener noreferrer\">Michalina</a>.", "Marc A": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marc</b>.</p><p>Marc: MARC (ang. Machine-Readable Cataloging) - grupa formatów (MARC21, UNIMARC, RUSMAC itp.</p>", "Mihai-Sorin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mihai</b>.</p><p>Mihai (rumuńska wymowa: [miˈhaj]) jest rumuńskim nazwiskiem męskim lub nazwiskiem. To równoważne angielskiej imienia Michael.</p>", "Myrza": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mirza</b>.</p><p>Mirza (lat. Mirza) - rodzaj zwierząt mleczarzy z infraodrodu oddziału lemurowych prymatów.</p>", "Md Shohidul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Muhammed Shan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Muhammed Yasi̇n": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Md Moniruzzaman": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Muhammad Junaid": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammad</b>.</p><b>Muhammad</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;مُحَمَّد&#8206;) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wariantami tego imienia są: Mohammed, Mehmed, Mamadu i Mahomet.", "Md Mukter": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mattheüs": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Matheus</b>.</p><p>Matheus (port. Matheus) - własne imię; rozpowszechnione w postaci nazwisk.</p>", "Marian Feliks": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marian</b>.</p><b>Marian</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> od imienia <i>Marius</i> lub nazwy rodu <i>Marii</i>. Oznacza „należący do Mariusza, rodu Mariuszów”. Występuje w Polsce od 1332 roku, jako <b>Marzyjan</b>. Forma Marian pojawiła się w Polsce w XVI wieku. W języku angielskim używane jest jako imię żeńskie. W Polsce w żeńskim użyciu w 2025 roku wystąpiło 35 razy.", "Md Shahinur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Matyi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Matii</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mati</b>.</p><p>Mati jest miastem w prowincji Davao Oriental, w Filipinach. To jest stolica prowincji.</p>", "Md Foisal": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Muhammad Abdullah": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammad</b>.</p><b>Muhammad</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;مُحَمَّد&#8206;) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wariantami tego imienia są: Mohammed, Mehmed, Mamadu i Mahomet.", "Mohammad Gias": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Mohammed Subhi": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammed</b>.</p><p>Muhammad - muzułmańskie imię i nazwisko. Mahomet jest islamskim prorokiem.</p>", "Mohammed Said": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammed</b>.</p><p>Muhammad - muzułmańskie imię i nazwisko. Mahomet jest islamskim prorokiem.</p>", "Md Razu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mali": "<p>Mali GPU - rodzina procesorów graficznych od ARM. Graficzne jądro Mali zostało opracowane przez norweskie oddział firmy ARM - ARM Norway (była Falanx).</p>", "Mercy": "<p>Mercy: ⁇ Mercy ⁇ - single brytyjskiej piosenkarki Duffy, wydany w 2008 roku.  ⁇ Mercy ⁇ - single kanadyjskiego piosenkarza, Shaona Mendes'a, wydane w 2016 roku.</p>", "Marcos Augusto": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marcos</b>.</p><p>Marcos - brytyjski producent samochodów, który wyprodukował samochody sportowe w latach 1959-2007. Nazwa firmy powstała z pierwszych liter nazwisk współzałożycieli.</p>", "Md Hasanur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Juwel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Matthew Paul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Matthew</b>.</p><p>William Diller Matthew (ang. William Diller; 19 lutego 1871 - 24 września 1930 w Berkeley) - kanadyjski i amerykański naukowiec-geolog, paleontolog, biogeograf, kurator Muzeum Historii Naturalnej Ameryki, profesor Uniwersytetu Kalifornijskiego w Berkeley, znany popularyzator nauki.</p>", "Mihai-Robert": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mihai</b>.</p><p>Mihai (rumuńska wymowa: [miˈhaj]) jest rumuńskim nazwiskiem męskim lub nazwiskiem. To równoważne angielskiej imienia Michael.</p>", "Md Razaul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mustafa Kemal": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mustafa</b>.</p><b>Mustafa</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia arabskiego, oznacza „wybrany”.", "Md Safikul Islam": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Likhon": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Marc-Alexander": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marc</b>.</p><p>Marc: MARC (ang. Machine-Readable Cataloging) - grupa formatów (MARC21, UNIMARC, RUSMAC itp.</p>", "Md Wasim": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Munna Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Munna</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Muna</b>.</p><p>Muna jest miastem w stanie Yucatán w Meksyku. W 2005 roku liczba mieszkańców miasta wynosiła 11763.</p>", "Mubaraka": "Imię to ma korzenie religijne i wywodzi się od arabskiego rdzenia słowotwórczego <i>b-r-k</i> (&#8207;ب ر ك&#8206;) odnoszącego się do błogosławienia. Pod względem gramatycznym jest to <a href=\"https://pl.wikipedia.org/wiki/Imies%C5%82%C3%B3w_przymiotnikowy_bierny\" target=\"_blank\" rel=\"noopener noreferrer\">imiesłów bierny</a> <a href=\"https://pl.wikipedia.org/wiki/Rodzaj_gramatyczny\" target=\"_blank\" rel=\"noopener noreferrer\">rodzaju żeńskiego</a> III klasy i oznacza dosłownie „błogosławiona, szczęśliwa” (a więc podobnie jak imiona łacińskie <i><a href=\"https://pl.wikipedia.org/wiki/Beata\" target=\"_blank\" rel=\"noopener noreferrer\">Beata</a></i> i <i><a href=\"https://pl.wikipedia.org/wiki/Benedykta\" target=\"_blank\" rel=\"noopener noreferrer\">Benedykta</a></i>).", "Manouchehr": "<p>Manuchehr, Manuchar, Manuchihr lub Manouchehr (perskie: منوچهر, Manūčehr, średnioperskie Manōčihr, Avestan: Manuščiθra) to perskie imię męskie oznaczające \"olicę nieba\". Składa się z dwóch części: Manu (Manou), co w starożytnym języku perskim oznacza \"niebo\", oraz Chehr, co oznacza \"oczek\".</p>", "Mizanur Rahman": "<p>Mizanur Rahman (Bengali: মীজানুর রহমান, lit. 'Równowaga Najbardziej Miłosiernego') jest bengalska męska nazwisko pochodzenia arabskiego.</p>", "Md Sarfaraz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Aftab": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Muhammad Ahmad": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammad</b>.</p><b>Muhammad</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;مُحَمَّد&#8206;) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wariantami tego imienia są: Mohammed, Mehmed, Mamadu i Mahomet.", "Md Masudur Rahman": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Muhamad Abdul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhamad</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Md Ashikur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mannan": "<b>Mannan</b> – rodzaj <a href=\"https://pl.wikipedia.org/wiki/Polisacharyd\" target=\"_blank\" rel=\"noopener noreferrer\">polisacharydów</a> pochodzenia roślinnego zbudowanych z reszt <a href=\"https://pl.wikipedia.org/wiki/Mannoza\" target=\"_blank\" rel=\"noopener noreferrer\">mannozy</a>. Mannan w ostatnim etapie biosyntezy <a href=\"https://pl.wikipedia.org/wiki/Streptomycyna\" target=\"_blank\" rel=\"noopener noreferrer\">streptomycyny</a> indukuje działanie streptymycynazy - <a href=\"https://pl.wikipedia.org/wiki/Enzym\" target=\"_blank\" rel=\"noopener noreferrer\">enzymu</a> rozkładającego streptomycynę B (produkt uboczny) do <a href=\"https://pl.wikipedia.org/wiki/Streptomycyna\" target=\"_blank\" rel=\"noopener noreferrer\">streptomycyny A</a> (pożądany produkt - antybiotyk).", "Md Monowar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mohamed El Mahdi": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohamed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Mircea-Daniel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mircea</b>.</p><p>Mircea jest rumuńskim imieniem męskim, formą sławskiej nazwy Mirče (Мирче), która pochodzi od słowiańskiego słowa mir, co oznacza \"pokój\". Może odnosić się do:</p>", "Mohamed Zakaria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohamed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Md Khaled": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Marian Mieczysław": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marian</b>.</p><b>Marian</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> od imienia <i>Marius</i> lub nazwy rodu <i>Marii</i>. Oznacza „należący do Mariusza, rodu Mariuszów”. Występuje w Polsce od 1332 roku, jako <b>Marzyjan</b>. Forma Marian pojawiła się w Polsce w XVI wieku. W języku angielskim używane jest jako imię żeńskie. W Polsce w żeńskim użyciu w 2025 roku wystąpiło 35 razy.", "Martin Jose": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Martin</b>.</p><p>William Charles Lynne Martin (1798 - 1864) - angielski naturalista. Martin był kuratorem muzeum London Zoological Society od 1830 do 1838 roku, aż do czasu, gdy stracił pracę w wyniku zmniejszenia finansowania.</p>", "Minh Tráng": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Mohammad Ansar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Miguel Francisco": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Miguel</b>.</p><p>Miguel (hisz. Miguel) - hiszpański odpowiednik imienia Michaila.</p>", "Michał Andrzej": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Michał</b>.</p><b>Michał</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִיכָאֵל&#8206; – Mîchā’ēl) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, wywodzące się od <a href=\"https://pl.wikipedia.org/wiki/Archanio%C5%82_Micha%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">jednego z archaniołów</a>. Po hebrajsku znaczy „któż [jest taki] jak Bóg”. Forma żeńska to <a href=\"https://pl.wikipedia.org/wiki/Michalina\" target=\"_blank\" rel=\"noopener noreferrer\">Michalina</a>.", "Md Shimul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Masuk": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mircea-Teodor": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mircea</b>.</p><p>Mircea jest rumuńskim imieniem męskim, formą sławskiej nazwy Mirče (Мирче), która pochodzi od słowiańskiego słowa mir, co oznacza \"pokój\". Może odnosić się do:</p>", "Mohyeldin": "<p>Mohy al-Din (arabski: محيي الدین, ALA-LC: Muḥyī al-Dīn), również pisany jako Mohi al-Din, Mohieddin, Mohyeddin i inne warianty, jest męskim muzułmańskim imieniem składającym się z elementów Muhyi, co oznacza \"odżywiający\" i ad-Din, co oznacza\" wiary\". Do wybitnych osób z tym nazwiskiem należą:</p>", "Mykola-Danylo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mykola</b>.</p><p>Mykola jest ukraińską wariantą męskiego nazwiska \"Nicholas\", co oznacza \"wygrę narodu\". Może odnosić się do:</p>", "Mohammad Mustafa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Maksym-Anton": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maksym</b>.</p><b>Maksym</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, utworzone od przymiotnika <i>maximus</i> oznaczający \"największy\", przydomka <a href=\"https://pl.wikipedia.org/wiki/Jowisz_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Jowisza</a>. Istnieją liczni święci prawosławni i katoliccy o tym imieniu: <a href=\"https://pl.wikipedia.org/wiki/Maksym_Wyznawca\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym Wyznawca</a>, <a href=\"https://pl.wikipedia.org/wiki/Maksym_Grek\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym Grek</a>, <a href=\"https://pl.wikipedia.org/wiki/Maksym_Brankowicz\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym Wołoski</a>, <a href=\"https://pl.wikipedia.org/wiki/Maksym_Gorlicki\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym Gorlicki</a>, <a href=\"https://pl.wikipedia.org/wiki/Maksym_z_Riez\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym z Riez</a> i wielu innych.", "Miłobrat": "<b>Miłobrat</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Miło-</i> (\"miły\", \"miłujący\") i <i>-brat</i> (\"brat\", \"członek wspólnoty rodowej\", \"człowiek bliski\"). Mogło oznaczać \"tego, który miłuje swoich bliskich\".", "Mohammad Bashir": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Maliao": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Malia</b>.</p><p>Malia (lat. Malia grata) - gatunek ptaków z rodziny zardów.</p>", "Mohammad Jahid": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Mihai-Marius": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mihai</b>.</p><p>Mihai (rumuńska wymowa: [miˈhaj]) jest rumuńskim nazwiskiem męskim lub nazwiskiem. To równoważne angielskiej imienia Michael.</p>", "Muhammad Agus": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammad</b>.</p><b>Muhammad</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;مُحَمَّد&#8206;) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wariantami tego imienia są: Mohammed, Mehmed, Mamadu i Mahomet.", "Md Obaidul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Bellal": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mihai-Cosmin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mihai</b>.</p><p>Mihai (rumuńska wymowa: [miˈhaj]) jest rumuńskim nazwiskiem męskim lub nazwiskiem. To równoważne angielskiej imienia Michael.</p>", "Md Moin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Minh Huy": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Md Mominul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Manuel Ernesto": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Manuel</b>.</p><b>Emanuel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od słowa עִמָּנוּאֵל oznaczającego „Bóg z nami”. Imię mesjasza oraz kilku świętych katolickich. Żeński odpowiednik to <a href=\"https://pl.wikipedia.org/wiki/Emanuela\" target=\"_blank\" rel=\"noopener noreferrer\">Emanuela</a>.", "Mohammad Aslam": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Mohammad Tazul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Marius-Dan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marius</b>.</p>Pochodził z niższych warstw społecznych, miał być z zawodu rzemieślnikiem (kowalem), później przypuszczalnie służył w wojsku, lecz nie wiadomo w jakiej funkcji. Po stłumionej w początkach 269 roku rewolcie <a href=\"https://pl.wikipedia.org/wiki/Lelian_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Leliana</a> wzniecił kolejny bunt w <a href=\"https://pl.wikipedia.org/wiki/Moguncja\" target=\"_blank\" rel=\"noopener noreferrer\">Mogontiacum</a> przeciwko władzy <a href=\"https://pl.wikipedia.org/wiki/Wiktoryn_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Wiktoryna</a>, następcy <a href=\"https://pl.wikipedia.org/wiki/Postumus\" target=\"_blank\" rel=\"noopener noreferrer\">Postuma</a>. Według <i><a href=\"https://pl.wikipedia.org/wiki/Historia_Augusta\" target=\"_blank\" rel=\"noopener noreferrer\">Historia Augusta</a></i> jego rządy trwały zaledwie 2-3 dni, czemu jednak przeczy zachowana liczba jego monet. Najpewniej w mennicy w <a href=\"https://pl.wikipedia.org/wiki/Kolonia_(Niemcy)\" target=\"_blank\" rel=\"noopener noreferrer\">Kolonii</a> (<i>Colonia Agrippina</i>) <a href=\"https://pl.wikipedia.org/wiki/Emisja_pieni%C4%85dza\" target=\"_blank\" rel=\"noopener noreferrer\">emitował</a> w swym imieniu niskowartościowe <a href=\"https://pl.wikipedia.org/wiki/Antoninian\" target=\"_blank\" rel=\"noopener noreferrer\">antoniniany</a> typów: AEQUITAS, CONCORDIA MILIT(um), SAEC(uli) FELICITAS, VICTORIA AUG(usti), VIRTUS AUG(usti).", "Mściwój Douglas": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mściwoj</b>.</p><b>Mściwoj</b>, <b>Mszczujwoj</b> – <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów „mścić (się)” i „woj”, oznaczające prawdopodobnie tego, który \"mści swoich współtowarzyszy\". Jego pomorskim odpowiednikiem może być <a href=\"https://pl.wikipedia.org/wiki/Miestwin\" target=\"_blank\" rel=\"noopener noreferrer\">Miestwin</a>. Na temat <a href=\"https://pl.wikipedia.org/wiki/Etymologia\" target=\"_blank\" rel=\"noopener noreferrer\">etymologii</a> patrz również wyjaśnienia pod hasłem <a href=\"https://pl.wikipedia.org/wiki/M%C5%9Bciwoj_I_gda%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">Mściwoj I</a>.", "Mohamed Zied": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohamed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Minh Hoàng": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Madan Lal": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Madan</b>.</p><p>Madan jest miastem w prowincji Smolyan, Bungaria. W 2011 roku liczba ludności wynosiła 5791.</p>", "Minh Ɖức": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Muhamadi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Muhamad</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Mohammad Noor": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Md Ashiqur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Marek Stanisław": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marek</b>.</p><b>Marek</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, należące do wąskiej grupy najstarszych <a href=\"https://pl.wikipedia.org/wiki/Imiona_%C5%82aci%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imion rzymskich</a> (imion właściwych, <i>praenomen</i>, por. <a href=\"https://pl.wikipedia.org/wiki/Tyberiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Tyberiusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Aulus\" target=\"_blank\" rel=\"noopener noreferrer\">Aulus</a>, <a href=\"https://pl.wikipedia.org/wiki/Maniusz\" target=\"_blank\" rel=\"noopener noreferrer\">Maniusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Gajusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Gajusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Lucjusz\" target=\"_blank\" rel=\"noopener noreferrer\">Lucjusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Publiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Publiusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Tytus\" target=\"_blank\" rel=\"noopener noreferrer\">Tytus</a>, <a href=\"https://pl.wikipedia.org/wiki/Serwiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Serwiusz</a>), utworzone z <i>*Mart-ico-s</i> od imienia boga <i><a href=\"https://pl.wikipedia.org/wiki/Mars_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Mars</a></i>, <i>Martis</i> i oznaczające „należący do Marsa, związany z Marsem”. W Polsce imię to jest notowane od <a href=\"https://pl.wikipedia.org/wiki/XIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIII wieku</a>, choć poza współczesnością nie było często spotykane, w formach <i><b>Marek</b></i>, <i><b>Marko</b></i>, <i><b>Margusz</b></i>, <i><b>Markusz</b></i>, <i><b>Merkusz</b></i>. Zapisana została także żeńska <b>Marka</b> (<a href=\"https://pl.wikipedia.org/wiki/1263\" target=\"_blank\" rel=\"noopener noreferrer\">1263</a>) – żeński odpowiednik imienia Marek lub zdrobnienie od imion żeńskich rozpoczynających się na Mar-, takich jak <i>Margorzata</i> (= <a href=\"https://pl.wikipedia.org/wiki/Ma%C5%82gorzata_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Małgorzata</a>) lub <a href=\"https://pl.wikipedia.org/wiki/Maria\" target=\"_blank\" rel=\"noopener noreferrer\">Maria</a> – oraz <a href=\"https://pl.wikipedia.org/wiki/Markus%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Markusław</a>, staropolskie imię utworzone od imienia Marek poprzez dodanie typowej dla imion słowiańskich cząstki -sław. Imię to według danych 2022 r. jest na 10 miejscu najpopularniejszych imion męskich.", "Muhammad Nur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammad</b>.</p><b>Muhammad</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;مُحَمَّد&#8206;) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wariantami tego imienia są: Mohammed, Mehmed, Mamadu i Mahomet.", "Mohammad Ali Ahsan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Michael Ryan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Michael</b>.</p><p>Michael: Botanika Michael - skrócie botaniczne, oznaczające, że autorem taksy jest Edmund Michael. Muzyka ⁇ Michael ⁇ - piosenka grupy Franz Ferdinand, wydana w 2004 roku.</p>", "Md Najmul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Robin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mohammad Saeed": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Mohammad Ashraf": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Mashallah": "<i><b>Maszallah</b></i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;مَا شَاءَ ٱللَّٰهُ&#8206;) – arabska fraza oznaczająca „Wola <a href=\"https://pl.wikipedia.org/wiki/Allah\" target=\"_blank\" rel=\"noopener noreferrer\">Boga</a>” lub „jak Bóg sobie życzy”. Wyraża radość, uznanie, wdzięczność lub pochwałę.", "Merwane": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Merwan</b>.</p><p>Marwan, Merwan lub Marwen lub Mervan (arabski: مروان, romanized: Marwān) jest arabskim męskim imieniem pochodzącym od słowa maruww (مرو) z znaczeniem minerałów, 'flint (-kamień) ', 'kwartz' lub 'twardy kamień prawie czystej krzemiony'. Jednak arabska nazwa kwarcu jest ṣawwān (صَوَّان).</p>", "Marian-Ionuț": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marian</b>.</p><b>Marian</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> od imienia <i>Marius</i> lub nazwy rodu <i>Marii</i>. Oznacza „należący do Mariusza, rodu Mariuszów”. Występuje w Polsce od 1332 roku, jako <b>Marzyjan</b>. Forma Marian pojawiła się w Polsce w XVI wieku. W języku angielskim używane jest jako imię żeńskie. W Polsce w żeńskim użyciu w 2025 roku wystąpiło 35 razy.", "Michel Jean": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Michel</b>.</p><p>⁇ Michel ⁇ (niemieckie MICHEL-Briefmarken-Katalog) - największy i najbardziej znany katalog znaków pocztowych w niemieckojęzycznym świecie i Europie.</p>", "Mykola-Andrii": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mykola</b>.</p><p>Mykola jest ukraińską wariantą męskiego nazwiska \"Nicholas\", co oznacza \"wygrę narodu\". Może odnosić się do:</p>", "Mohammad Ahsan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Md Khokon": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mai Long": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mai</b>.</p><b>Mai</b> – imię dwupłciowe używane w wielu państwach świata.", "Minh Thái": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Md Fazle": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Marc Robert": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marc</b>.</p><p>Marc: MARC (ang. Machine-Readable Cataloging) - grupa formatów (MARC21, UNIMARC, RUSMAC itp.</p>", "Minh Toan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Md Ashek": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Muhammed Ömer": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Md Rejaul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Hasib": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mario Alexander": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mario</b>.</p><p>Mario (jap. Mario Mario, angielski.</p>", "Muhammad Iqbal": "Powrócił do <a href=\"https://pl.wikipedia.org/wiki/Indie\" target=\"_blank\" rel=\"noopener noreferrer\">Indii</a>, aby podjąć praktykę prawniczą i został mianowany <a href=\"https://pl.wikipedia.org/wiki/Profesor\" target=\"_blank\" rel=\"noopener noreferrer\">profesorem</a> filozofii. Zdobył pozycję czołowego poety tworzącego w językach <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_urdu\" target=\"_blank\" rel=\"noopener noreferrer\">urdu</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_perski\" target=\"_blank\" rel=\"noopener noreferrer\">perskim</a>. Uczestniczył w konferencjach okrągłego stołu w 1931 i 1932 roku. Był mistykiem przybierając imię <i>„Ja” i Jedności <a href=\"https://pl.wikipedia.org/wiki/B%C3%B3g\" target=\"_blank\" rel=\"noopener noreferrer\">Boga</a></i>. Jego wykłady zebrane w tomie <i>Odbudowa religijnej myśli islamskiej</i> (org.: <i>The Reconstruction of Religious Thought in Islam</i>), wydanym w 1934 r., odegrały ważną rolę w umacnianiu wiary we własne siły wśród społeczności muzułmańskiej. W programowym przemówieniu do członków <a href=\"https://pl.wikipedia.org/wiki/Liga_Muzu%C5%82ma%C5%84ska\" target=\"_blank\" rel=\"noopener noreferrer\">Ligi Muzułmańskiej</a>, której był aktywnym działaczem, podczas jej konferencji w <a href=\"https://pl.wikipedia.org/wiki/Prajagrad%C5%BA\" target=\"_blank\" rel=\"noopener noreferrer\">Allahabadzie</a>, przedstawił koncepcję oddzielnego <a href=\"https://pl.wikipedia.org/wiki/Pa%C5%84stwo\" target=\"_blank\" rel=\"noopener noreferrer\">państwa</a> muzułmańskiego, o charakterze <a href=\"https://pl.wikipedia.org/wiki/Republika_islamska\" target=\"_blank\" rel=\"noopener noreferrer\">republiki islamskiej</a>, w północno-zachodnich Indiach. W kwestii tej dyskutował m.in. z <a href=\"https://pl.wikipedia.org/wiki/Mahatma_Gandhi\" target=\"_blank\" rel=\"noopener noreferrer\">Mahatmą Gandhim</a>. Doczekała się ona jednak realizacji dopiero 9 lat po jego śmierci w postaci państwowości <a href=\"https://pl.wikipedia.org/wiki/Pakistan\" target=\"_blank\" rel=\"noopener noreferrer\">pakistańskiej</a>.", "Md Abul Kalam": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mannu": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Manu</b>.</p><p>Emmanuel Laurent Peti (francuski: Emmanuel Laurent Petit; urodz.</p>", "Mykyto": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mikito</b>.</p><p>Mikito (pisanie: 右人 lub 幹人) to męskie japońskie imię. Wśród znanych osób z nazwiskiem są: Mikito Tachizaki (立崎 幹人; ur. 1988), japoński biatleta Mikito Takayasu (高安 右人; 1860-1938), japoński oftalmolog</p>", "Mohamed Yusuf": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohamed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Marius-Paul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marius</b>.</p>Pochodził z niższych warstw społecznych, miał być z zawodu rzemieślnikiem (kowalem), później przypuszczalnie służył w wojsku, lecz nie wiadomo w jakiej funkcji. Po stłumionej w początkach 269 roku rewolcie <a href=\"https://pl.wikipedia.org/wiki/Lelian_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Leliana</a> wzniecił kolejny bunt w <a href=\"https://pl.wikipedia.org/wiki/Moguncja\" target=\"_blank\" rel=\"noopener noreferrer\">Mogontiacum</a> przeciwko władzy <a href=\"https://pl.wikipedia.org/wiki/Wiktoryn_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Wiktoryna</a>, następcy <a href=\"https://pl.wikipedia.org/wiki/Postumus\" target=\"_blank\" rel=\"noopener noreferrer\">Postuma</a>. Według <i><a href=\"https://pl.wikipedia.org/wiki/Historia_Augusta\" target=\"_blank\" rel=\"noopener noreferrer\">Historia Augusta</a></i> jego rządy trwały zaledwie 2-3 dni, czemu jednak przeczy zachowana liczba jego monet. Najpewniej w mennicy w <a href=\"https://pl.wikipedia.org/wiki/Kolonia_(Niemcy)\" target=\"_blank\" rel=\"noopener noreferrer\">Kolonii</a> (<i>Colonia Agrippina</i>) <a href=\"https://pl.wikipedia.org/wiki/Emisja_pieni%C4%85dza\" target=\"_blank\" rel=\"noopener noreferrer\">emitował</a> w swym imieniu niskowartościowe <a href=\"https://pl.wikipedia.org/wiki/Antoninian\" target=\"_blank\" rel=\"noopener noreferrer\">antoniniany</a> typów: AEQUITAS, CONCORDIA MILIT(um), SAEC(uli) FELICITAS, VICTORIA AUG(usti), VIRTUS AUG(usti).", "Maksimillian": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maximillian</b>.</p><p>Maksymilian lub Maximillian (Maximiliaan w języku holenderskim i Maximilien w językach francuskich) to męskie imię. Nazwa \"Max\" jest skróceniem \"Maximilian\" oraz kilku innych nazw, w tym, ale nie ograniczając się do Maxwell.</p>", "Maksym-Valentyn": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maksym</b>.</p><b>Maksym</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, utworzone od przymiotnika <i>maximus</i> oznaczający \"największy\", przydomka <a href=\"https://pl.wikipedia.org/wiki/Jowisz_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Jowisza</a>. Istnieją liczni święci prawosławni i katoliccy o tym imieniu: <a href=\"https://pl.wikipedia.org/wiki/Maksym_Wyznawca\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym Wyznawca</a>, <a href=\"https://pl.wikipedia.org/wiki/Maksym_Grek\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym Grek</a>, <a href=\"https://pl.wikipedia.org/wiki/Maksym_Brankowicz\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym Wołoski</a>, <a href=\"https://pl.wikipedia.org/wiki/Maksym_Gorlicki\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym Gorlicki</a>, <a href=\"https://pl.wikipedia.org/wiki/Maksym_z_Riez\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym z Riez</a> i wielu innych.", "Md Humayon": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mohamed Kamaleldin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohamed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Maria Ryszard": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Margarit": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Margarita</b>.</p><p>Margarita to meksykański koktajl zawierający tequila, pomarańczową wodę i wodę z cynamonu, często rozproszoną solą na szklance. Wypłaty są przygotowywane poprzez wstrząsanie z kamieni (na skalę), wstrząsnięcie z kamieniami (zamrożona margarita), lub bez kamieni (pić prosto).</p>", "Maciej Stanisław": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maciej</b>.</p><b>Maciej</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, pochodzenia hebrajskiego: <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מַתִּתְיָהוּ&#8206; <i>Mattitjahu</i>, oznaczające „dar <a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a>”.", "Myke": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mike</b>.</p><p>Mike (ang. Mike): ⁇ Mike ⁇ - amerykański film dramatyczny z 1926 roku.</p>", "Marian-Valentin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marian</b>.</p><b>Marian</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> od imienia <i>Marius</i> lub nazwy rodu <i>Marii</i>. Oznacza „należący do Mariusza, rodu Mariuszów”. Występuje w Polsce od 1332 roku, jako <b>Marzyjan</b>. Forma Marian pojawiła się w Polsce w XVI wieku. W języku angielskim używane jest jako imię żeńskie. W Polsce w żeńskim użyciu w 2025 roku wystąpiło 35 razy.", "Moustafa Ahmed Ahmed": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Moustafa</b>.</p><p>Mustafa (arabski: مصطفى, romanized: Muṣṭafā) jest jednym z imion islamskiego proroka Mahometa. W arabskim oznacza \"wybrany, wybrany, wyznaczony, preferujący\".</p>", "Mohammad Tarequl": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Mieshko": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mieszko</b>.</p><b>Mieszko</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, najprawdopodobniej forma skrócona imienia <a href=\"https://pl.wikipedia.org/wiki/Miecis%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Miecisław</a>. Imię popularne w <a href=\"https://pl.wikipedia.org/wiki/Piastowie\" target=\"_blank\" rel=\"noopener noreferrer\">dynastii piastowskiej</a>, pierwotnie niewystępujące poza nią i nieposiadające nazewniczych równoważników słowiańskich.", "Mohammad Rezaul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Md Asad": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mohamed A": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohamed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Mario-Adi": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mario</b>.</p><p>Mario (jap. Mario Mario, angielski.</p>", "Mohammed Shibili": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammed</b>.</p><p>Muhammad - muzułmańskie imię i nazwisko. Mahomet jest islamskim prorokiem.</p>", "Manga": "<b>Manga</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;漫画&#59; wymowa (<a href=\"https://pl.wikipedia.org/wiki/IPA\" target=\"_blank\" rel=\"noopener noreferrer\">IPA</a>): <a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_nosowa_dwuwargowa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">m</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_otwarta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">a</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_nosowa_tylnoj%C4%99zykowo-mi%C4%99kkopodniebienna_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">ŋ</a><a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">g</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_otwarta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">a</a>) – komiks, obraz, rysunek, szkic, <a href=\"https://pl.wikipedia.org/wiki/Karykatura\" target=\"_blank\" rel=\"noopener noreferrer\">karykatura</a>. Japońskie słowo wywodzące się ze sposobu ozdabiania <a href=\"https://pl.wikipedia.org/wiki/Rycina\" target=\"_blank\" rel=\"noopener noreferrer\">rycin</a> i innych form <a href=\"https://pl.wikipedia.org/wiki/Sztuka_u%C5%BCytkowa\" target=\"_blank\" rel=\"noopener noreferrer\">sztuki użytkowej</a>. Współcześnie używane poza <a href=\"https://pl.wikipedia.org/wiki/Japonia\" target=\"_blank\" rel=\"noopener noreferrer\">Japonią</a> oznacza japoński <a href=\"https://pl.wikipedia.org/wiki/Komiks\" target=\"_blank\" rel=\"noopener noreferrer\">komiks</a>.", "Md Nasim": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Meiir": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Meir</b>.</p><p>Meir (Hebrajsky: מֵאִיר) jest żydowskim imieniem męskim i okazjonalnym nazwiskiem. To znaczy \"który świeci\".</p>", "Marcos Vinicio": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marcos</b>.</p><p>Marcos - brytyjski producent samochodów, który wyprodukował samochody sportowe w latach 1959-2007. Nazwa firmy powstała z pierwszych liter nazwisk współzałożycieli.</p>", "Michel Claude": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Michel</b>.</p><p>⁇ Michel ⁇ (niemieckie MICHEL-Briefmarken-Katalog) - największy i najbardziej znany katalog znaków pocztowych w niemieckojęzycznym świecie i Europie.</p>", "Md Abu Bakkar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Muhammed Anas": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Mattheos": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Matheos</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mateos</b>.</p><p>Mateos to hiszpańskie nazwisko i albanskie i etyopskie nazwisko. Do wybitnych osób z tym nazwiskiem należą:</p>", "Maria H.": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Md Mohin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mohammed Naseef": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammed</b>.</p><p>Muhammad - muzułmańskie imię i nazwisko. Mahomet jest islamskim prorokiem.</p>", "Md Mizanoor": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mohammed Rafi": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammed</b>.</p><p>Muhammad - muzułmańskie imię i nazwisko. Mahomet jest islamskim prorokiem.</p>", "Mohammed Safeer": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammed</b>.</p><p>Muhammad - muzułmańskie imię i nazwisko. Mahomet jest islamskim prorokiem.</p>", "Mahmudul Hasan": "<p>Mahmudul Hasan to męskie imię arabskiego pochodzenia, co oznacza \"trustee of the truth\". Wśród znanych nosicieli nazwy są:</p>", "Md Riyad": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Minh Tư": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Muhammed Salih": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Md Fakhrul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Minh Que": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Marian-Cosmin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marian</b>.</p><b>Marian</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> od imienia <i>Marius</i> lub nazwy rodu <i>Marii</i>. Oznacza „należący do Mariusza, rodu Mariuszów”. Występuje w Polsce od 1332 roku, jako <b>Marzyjan</b>. Forma Marian pojawiła się w Polsce w XVI wieku. W języku angielskim używane jest jako imię żeńskie. W Polsce w żeńskim użyciu w 2025 roku wystąpiło 35 razy.", "Md Rafin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mohammed E": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammed</b>.</p><p>Muhammad - muzułmańskie imię i nazwisko. Mahomet jest islamskim prorokiem.</p>", "Maciej Paweł": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maciej</b>.</p><b>Maciej</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, pochodzenia hebrajskiego: <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מַתִּתְיָהוּ&#8206; <i>Mattitjahu</i>, oznaczające „dar <a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a>”.", "Mohammad Saiful": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohammad</b>.</p><p>Muhammad lub Mohammad może odnosić się do: Muhammad Mohammad Khan Qajar Mohammad Reza Pahlavi Mohammad Khatami</p>", "Maksym-Stepan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maksym</b>.</p><b>Maksym</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, utworzone od przymiotnika <i>maximus</i> oznaczający \"największy\", przydomka <a href=\"https://pl.wikipedia.org/wiki/Jowisz_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Jowisza</a>. Istnieją liczni święci prawosławni i katoliccy o tym imieniu: <a href=\"https://pl.wikipedia.org/wiki/Maksym_Wyznawca\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym Wyznawca</a>, <a href=\"https://pl.wikipedia.org/wiki/Maksym_Grek\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym Grek</a>, <a href=\"https://pl.wikipedia.org/wiki/Maksym_Brankowicz\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym Wołoski</a>, <a href=\"https://pl.wikipedia.org/wiki/Maksym_Gorlicki\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym Gorlicki</a>, <a href=\"https://pl.wikipedia.org/wiki/Maksym_z_Riez\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym z Riez</a> i wielu innych.", "Mihai-": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mihai</b>.</p><p>Mihai (rumuńska wymowa: [miˈhaj]) jest rumuńskim nazwiskiem męskim lub nazwiskiem. To równoważne angielskiej imienia Michael.</p>", "Md Raqibul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Montan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Montana</b>.</p>Nazwa prawdopodobnie pochodzi od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hiszpa%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">hiszpańskiego</a> słowa <em>montaña</em>, które znaczy „góra”. Chociaż Montana kojarzona jest przede wszystkim z położonymi na jej obszarze górami, około 60% terytorium stanu pokrywa <a href=\"https://pl.wikipedia.org/wiki/Preria\" target=\"_blank\" rel=\"noopener noreferrer\">preria</a>, wchodząca w skład <a href=\"https://pl.wikipedia.org/wiki/Wielkie_R%C3%B3wniny\" target=\"_blank\" rel=\"noopener noreferrer\">Wielkich Równin</a>. Region nazywany jest „Stanem Skarbów” (<em>Treasure State</em>) ze względu na jego ogromne bogactwo mineralne, a także „Krainą lśniących gór” (<em>Land of the Shining Mountains</em>) i „Krainą wielkiego nieba” (<em>Big Sky Country</em>). Zróżnicowana gospodarka Montany historycznie bazuje na rolnictwie, górnictwie i przemyśle drzewnym. W XXI wieku na znaczeniu zyskały usługi, finanse, nieruchomości, czy turystyka. W Montanie znajduje się <a href=\"https://pl.wikipedia.org/wiki/Park_Narodowy_Glacier_(USA)\" target=\"_blank\" rel=\"noopener noreferrer\">Park Narodowy Glacier</a> oraz północny, niewielki fragment <a href=\"https://pl.wikipedia.org/wiki/Park_Narodowy_Yellowstone\" target=\"_blank\" rel=\"noopener noreferrer\">Parku Narodowego Yellowstone</a>. Przez stan przechodzi <a href=\"https://pl.wikipedia.org/wiki/Wododzia%C5%82_kontynentalny_Ameryki\" target=\"_blank\" rel=\"noopener noreferrer\">wododział kontynentalny Ameryki</a>.", "Marian-Andrei": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marian</b>.</p><b>Marian</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> od imienia <i>Marius</i> lub nazwy rodu <i>Marii</i>. Oznacza „należący do Mariusza, rodu Mariuszów”. Występuje w Polsce od 1332 roku, jako <b>Marzyjan</b>. Forma Marian pojawiła się w Polsce w XVI wieku. W języku angielskim używane jest jako imię żeńskie. W Polsce w żeńskim użyciu w 2025 roku wystąpiło 35 razy.", "Md Jalal Uddin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Muhammad Khalid": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammad</b>.</p><b>Muhammad</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;مُحَمَّد&#8206;) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wariantami tego imienia są: Mohammed, Mehmed, Mamadu i Mahomet.", "Md Sakhawat": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Jabad": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Minh Viên": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Md Nannu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Maksym-Vasyl": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maksym</b>.</p><b>Maksym</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, utworzone od przymiotnika <i>maximus</i> oznaczający \"największy\", przydomka <a href=\"https://pl.wikipedia.org/wiki/Jowisz_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Jowisza</a>. Istnieją liczni święci prawosławni i katoliccy o tym imieniu: <a href=\"https://pl.wikipedia.org/wiki/Maksym_Wyznawca\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym Wyznawca</a>, <a href=\"https://pl.wikipedia.org/wiki/Maksym_Grek\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym Grek</a>, <a href=\"https://pl.wikipedia.org/wiki/Maksym_Brankowicz\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym Wołoski</a>, <a href=\"https://pl.wikipedia.org/wiki/Maksym_Gorlicki\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym Gorlicki</a>, <a href=\"https://pl.wikipedia.org/wiki/Maksym_z_Riez\" target=\"_blank\" rel=\"noopener noreferrer\">Maksym z Riez</a> i wielu innych.", "Md Mahfujur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Minh Hong": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Manuel Alfredo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Manuel</b>.</p><b>Emanuel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od słowa עִמָּנוּאֵל oznaczającego „Bóg z nami”. Imię mesjasza oraz kilku świętych katolickich. Żeński odpowiednik to <a href=\"https://pl.wikipedia.org/wiki/Emanuela\" target=\"_blank\" rel=\"noopener noreferrer\">Emanuela</a>.", "Moise-Iosif": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Moise</b>.</p><p>Moise jest nazwiskiem i nazwiskiem, z różnymi pisowniami w jego francuskim i rumuńskim pochodzeniu, które oba pochodzą z imienia Mojżesz: Moïse jest francuskim pisownią Mojżesza, podczas gdy Moise jest rumuńskie pisownią. Jako nazwisko, Moisè i Mosè to włoskie pisownię Mojżesza.</p>", "Mszczuj": "<b>Mszczuj</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, najprawdopodobniej wariant imienia <a href=\"https://pl.wikipedia.org/wiki/M%C5%9Bciwuj\" target=\"_blank\" rel=\"noopener noreferrer\">Mściwuj</a>.", "Mansoor Hasan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mansoor</b>.</p><p>Mansour (arabickie: منصور, Manṣūr); również pisane Mounsor, Monsur (Bengali), Mansoor, Manser, Mansur, Mansyur (indonezyjski) lub Mensur (tyrki), to męskie arabskie imię oznaczające \"Ten, który zwycięża\", z arabskiego korzenia naṣr (نصر), oznaczające \"wygrę\". Pierwszym znanym nosicielem nazwy był Mansur ibn Sarjun, bizantyjski gubernator Damaszku pod koniec lat 500 i na początku lat 600, który poddał miasto muzułmanom w 635 r. Inni ludzie nazywają się Mansur...</p>", "Mihnea-Teodor": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mihnea</b>.</p><p>Mihnea jest rumuńskim językiem męskim, które może odnosić się do: Mihnea cel Rău Mihnea Turcitul Mihnea III Mihnea Chioveanu Mihnea Motoc Mihnea-Ion Năstase Mihnea Popa</p>", "Md Mohidul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Maria Bronisław": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Müslim": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Muslima</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Muslim</b>.</p><p>Muzułmanie (arabski: al-Muslimūn - muslimoni) to wyznawcy islamu - religii monoteistycznej pochodzącej od Abrahama. Wierzą, że Koran - religijny tekst, który stanowi podstawę islamu - jest objawieniem od Allaha i przekazanym Muhammadowi - i jest ostatnim posłańcem Boga.</p>", "Md Riajul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mohamed El Bachir": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohamed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Md Osman": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Kayum": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Mahmudur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Md Mosharof": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Marc Andrew": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marc</b>.</p><p>Marc: MARC (ang. Machine-Readable Cataloging) - grupa formatów (MARC21, UNIMARC, RUSMAC itp.</p>", "Md Burhan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Muhammad Umer": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammad</b>.</p><b>Muhammad</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;مُحَمَّد&#8206;) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wariantami tego imienia są: Mohammed, Mehmed, Mamadu i Mahomet.", "Melani": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Melany</b>.</p><p>Melanie to kobiece imię pochodzące od greckiego μελανία (melania), \"czarność\", a od μέλας (melas), oznaczające \"ciemny\". Urodzony w łacinie przez dwóch świętych, Melanię Starszą i jej wnuczkę Melanię Młodszą, nazwę wprowadzili do Anglii Normanie w francuskiej formie Melanie.</p>", "Md Fahad": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mihai-Florin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mihai</b>.</p><p>Mihai (rumuńska wymowa: [miˈhaj]) jest rumuńskim nazwiskiem męskim lub nazwiskiem. To równoważne angielskiej imienia Michael.</p>", "Mustafa Hakan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mustafa</b>.</p><b>Mustafa</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia arabskiego, oznacza „wybrany”.", "Mohamed Ismail": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohamed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Md Babul Hossain": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Marius-Ovidiu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marius</b>.</p>Pochodził z niższych warstw społecznych, miał być z zawodu rzemieślnikiem (kowalem), później przypuszczalnie służył w wojsku, lecz nie wiadomo w jakiej funkcji. Po stłumionej w początkach 269 roku rewolcie <a href=\"https://pl.wikipedia.org/wiki/Lelian_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Leliana</a> wzniecił kolejny bunt w <a href=\"https://pl.wikipedia.org/wiki/Moguncja\" target=\"_blank\" rel=\"noopener noreferrer\">Mogontiacum</a> przeciwko władzy <a href=\"https://pl.wikipedia.org/wiki/Wiktoryn_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Wiktoryna</a>, następcy <a href=\"https://pl.wikipedia.org/wiki/Postumus\" target=\"_blank\" rel=\"noopener noreferrer\">Postuma</a>. Według <i><a href=\"https://pl.wikipedia.org/wiki/Historia_Augusta\" target=\"_blank\" rel=\"noopener noreferrer\">Historia Augusta</a></i> jego rządy trwały zaledwie 2-3 dni, czemu jednak przeczy zachowana liczba jego monet. Najpewniej w mennicy w <a href=\"https://pl.wikipedia.org/wiki/Kolonia_(Niemcy)\" target=\"_blank\" rel=\"noopener noreferrer\">Kolonii</a> (<i>Colonia Agrippina</i>) <a href=\"https://pl.wikipedia.org/wiki/Emisja_pieni%C4%85dza\" target=\"_blank\" rel=\"noopener noreferrer\">emitował</a> w swym imieniu niskowartościowe <a href=\"https://pl.wikipedia.org/wiki/Antoninian\" target=\"_blank\" rel=\"noopener noreferrer\">antoniniany</a> typów: AEQUITAS, CONCORDIA MILIT(um), SAEC(uli) FELICITAS, VICTORIA AUG(usti), VIRTUS AUG(usti).", "Mostafa Saad": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mostafa</b>.</p><p>Mustafa sultan (tat. Mostafa, Mostafa; umysł.</p>", "Md Rakibur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Miguel Iii": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Miguel</b>.</p><p>Miguel (hisz. Miguel) - hiszpański odpowiednik imienia Michaila.</p>", "Minh Thien": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Md Rahat": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Marek Roman": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marek</b>.</p><b>Marek</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, należące do wąskiej grupy najstarszych <a href=\"https://pl.wikipedia.org/wiki/Imiona_%C5%82aci%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imion rzymskich</a> (imion właściwych, <i>praenomen</i>, por. <a href=\"https://pl.wikipedia.org/wiki/Tyberiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Tyberiusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Aulus\" target=\"_blank\" rel=\"noopener noreferrer\">Aulus</a>, <a href=\"https://pl.wikipedia.org/wiki/Maniusz\" target=\"_blank\" rel=\"noopener noreferrer\">Maniusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Gajusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Gajusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Lucjusz\" target=\"_blank\" rel=\"noopener noreferrer\">Lucjusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Publiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Publiusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Tytus\" target=\"_blank\" rel=\"noopener noreferrer\">Tytus</a>, <a href=\"https://pl.wikipedia.org/wiki/Serwiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Serwiusz</a>), utworzone z <i>*Mart-ico-s</i> od imienia boga <i><a href=\"https://pl.wikipedia.org/wiki/Mars_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Mars</a></i>, <i>Martis</i> i oznaczające „należący do Marsa, związany z Marsem”. W Polsce imię to jest notowane od <a href=\"https://pl.wikipedia.org/wiki/XIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIII wieku</a>, choć poza współczesnością nie było często spotykane, w formach <i><b>Marek</b></i>, <i><b>Marko</b></i>, <i><b>Margusz</b></i>, <i><b>Markusz</b></i>, <i><b>Merkusz</b></i>. Zapisana została także żeńska <b>Marka</b> (<a href=\"https://pl.wikipedia.org/wiki/1263\" target=\"_blank\" rel=\"noopener noreferrer\">1263</a>) – żeński odpowiednik imienia Marek lub zdrobnienie od imion żeńskich rozpoczynających się na Mar-, takich jak <i>Margorzata</i> (= <a href=\"https://pl.wikipedia.org/wiki/Ma%C5%82gorzata_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Małgorzata</a>) lub <a href=\"https://pl.wikipedia.org/wiki/Maria\" target=\"_blank\" rel=\"noopener noreferrer\">Maria</a> – oraz <a href=\"https://pl.wikipedia.org/wiki/Markus%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Markusław</a>, staropolskie imię utworzone od imienia Marek poprzez dodanie typowej dla imion słowiańskich cząstki -sław. Imię to według danych 2022 r. jest na 10 miejscu najpopularniejszych imion męskich.", "Marius-Claudiu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marius</b>.</p>Pochodził z niższych warstw społecznych, miał być z zawodu rzemieślnikiem (kowalem), później przypuszczalnie służył w wojsku, lecz nie wiadomo w jakiej funkcji. Po stłumionej w początkach 269 roku rewolcie <a href=\"https://pl.wikipedia.org/wiki/Lelian_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Leliana</a> wzniecił kolejny bunt w <a href=\"https://pl.wikipedia.org/wiki/Moguncja\" target=\"_blank\" rel=\"noopener noreferrer\">Mogontiacum</a> przeciwko władzy <a href=\"https://pl.wikipedia.org/wiki/Wiktoryn_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Wiktoryna</a>, następcy <a href=\"https://pl.wikipedia.org/wiki/Postumus\" target=\"_blank\" rel=\"noopener noreferrer\">Postuma</a>. Według <i><a href=\"https://pl.wikipedia.org/wiki/Historia_Augusta\" target=\"_blank\" rel=\"noopener noreferrer\">Historia Augusta</a></i> jego rządy trwały zaledwie 2-3 dni, czemu jednak przeczy zachowana liczba jego monet. Najpewniej w mennicy w <a href=\"https://pl.wikipedia.org/wiki/Kolonia_(Niemcy)\" target=\"_blank\" rel=\"noopener noreferrer\">Kolonii</a> (<i>Colonia Agrippina</i>) <a href=\"https://pl.wikipedia.org/wiki/Emisja_pieni%C4%85dza\" target=\"_blank\" rel=\"noopener noreferrer\">emitował</a> w swym imieniu niskowartościowe <a href=\"https://pl.wikipedia.org/wiki/Antoninian\" target=\"_blank\" rel=\"noopener noreferrer\">antoniniany</a> typów: AEQUITAS, CONCORDIA MILIT(um), SAEC(uli) FELICITAS, VICTORIA AUG(usti), VIRTUS AUG(usti).", "Md Ershad": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Muhammad Adeel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammad</b>.</p><b>Muhammad</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;مُحَمَّد&#8206;) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wariantami tego imienia są: Mohammed, Mehmed, Mamadu i Mahomet.", "Md Feroz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Madan Krishna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Madan</b>.</p><p>Madan jest miastem w prowincji Smolyan, Bungaria. W 2011 roku liczba ludności wynosiła 5791.</p>", "Mohamed Rafi": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohamed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Md Manik": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Marko-Ivan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marko</b>.</p><b>Marek</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, należące do wąskiej grupy najstarszych <a href=\"https://pl.wikipedia.org/wiki/Imiona_%C5%82aci%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imion rzymskich</a> (imion właściwych, <i>praenomen</i>, por. <a href=\"https://pl.wikipedia.org/wiki/Tyberiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Tyberiusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Aulus\" target=\"_blank\" rel=\"noopener noreferrer\">Aulus</a>, <a href=\"https://pl.wikipedia.org/wiki/Maniusz\" target=\"_blank\" rel=\"noopener noreferrer\">Maniusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Gajusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Gajusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Lucjusz\" target=\"_blank\" rel=\"noopener noreferrer\">Lucjusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Publiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Publiusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Tytus\" target=\"_blank\" rel=\"noopener noreferrer\">Tytus</a>, <a href=\"https://pl.wikipedia.org/wiki/Serwiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Serwiusz</a>), utworzone z <i>*Mart-ico-s</i> od imienia boga <i><a href=\"https://pl.wikipedia.org/wiki/Mars_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Mars</a></i>, <i>Martis</i> i oznaczające „należący do Marsa, związany z Marsem”. W Polsce imię to jest notowane od <a href=\"https://pl.wikipedia.org/wiki/XIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIII wieku</a>, choć poza współczesnością nie było często spotykane, w formach <i><b>Marek</b></i>, <i><b>Marko</b></i>, <i><b>Margusz</b></i>, <i><b>Markusz</b></i>, <i><b>Merkusz</b></i>. Zapisana została także żeńska <b>Marka</b> (<a href=\"https://pl.wikipedia.org/wiki/1263\" target=\"_blank\" rel=\"noopener noreferrer\">1263</a>) – żeński odpowiednik imienia Marek lub zdrobnienie od imion żeńskich rozpoczynających się na Mar-, takich jak <i>Margorzata</i> (= <a href=\"https://pl.wikipedia.org/wiki/Ma%C5%82gorzata_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Małgorzata</a>) lub <a href=\"https://pl.wikipedia.org/wiki/Maria\" target=\"_blank\" rel=\"noopener noreferrer\">Maria</a> – oraz <a href=\"https://pl.wikipedia.org/wiki/Markus%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Markusław</a>, staropolskie imię utworzone od imienia Marek poprzez dodanie typowej dla imion słowiańskich cząstki -sław. Imię to według danych 2022 r. jest na 10 miejscu najpopularniejszych imion męskich.", "Md Suman": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Matwei": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Matwey</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Matvey</b>.</p><p>Matvei lub Matvey (Матвей) jest rosyjską wersją Mateusza. Wśród znanych osób z nazwy są: Matvey Blanter (1903-1990), rosyjski kompozytor muzyki popularnej i filmowej Matvei Bronstein (1906-1938), radziecki fizyk teoretyczny Matvey Frantskevich (ur. 1995), białoruski piłkarz Matvei Gedenshtrom (r.</p>", "Md Ansarul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Minh Vuong": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Maria L.": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Marius-George": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marius</b>.</p>Pochodził z niższych warstw społecznych, miał być z zawodu rzemieślnikiem (kowalem), później przypuszczalnie służył w wojsku, lecz nie wiadomo w jakiej funkcji. Po stłumionej w początkach 269 roku rewolcie <a href=\"https://pl.wikipedia.org/wiki/Lelian_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Leliana</a> wzniecił kolejny bunt w <a href=\"https://pl.wikipedia.org/wiki/Moguncja\" target=\"_blank\" rel=\"noopener noreferrer\">Mogontiacum</a> przeciwko władzy <a href=\"https://pl.wikipedia.org/wiki/Wiktoryn_(uzurpator)\" target=\"_blank\" rel=\"noopener noreferrer\">Wiktoryna</a>, następcy <a href=\"https://pl.wikipedia.org/wiki/Postumus\" target=\"_blank\" rel=\"noopener noreferrer\">Postuma</a>. Według <i><a href=\"https://pl.wikipedia.org/wiki/Historia_Augusta\" target=\"_blank\" rel=\"noopener noreferrer\">Historia Augusta</a></i> jego rządy trwały zaledwie 2-3 dni, czemu jednak przeczy zachowana liczba jego monet. Najpewniej w mennicy w <a href=\"https://pl.wikipedia.org/wiki/Kolonia_(Niemcy)\" target=\"_blank\" rel=\"noopener noreferrer\">Kolonii</a> (<i>Colonia Agrippina</i>) <a href=\"https://pl.wikipedia.org/wiki/Emisja_pieni%C4%85dza\" target=\"_blank\" rel=\"noopener noreferrer\">emitował</a> w swym imieniu niskowartościowe <a href=\"https://pl.wikipedia.org/wiki/Antoninian\" target=\"_blank\" rel=\"noopener noreferrer\">antoniniany</a> typów: AEQUITAS, CONCORDIA MILIT(um), SAEC(uli) FELICITAS, VICTORIA AUG(usti), VIRTUS AUG(usti).", "Muhammad Nasir": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammad</b>.</p><b>Muhammad</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;مُحَمَّد&#8206;) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wariantami tego imienia są: Mohammed, Mehmed, Mamadu i Mahomet.", "Md Shanto": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Muhammed Nur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Md Murshed": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Miguel Eduardo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Miguel</b>.</p><p>Miguel (hisz. Miguel) - hiszpański odpowiednik imienia Michaila.</p>", "Md Ala": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Mátyas": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Matias</b>.</p><p>Matías to portugalska wersja Matthias. Matías jest bardzo popularny w Ameryce Łacińskiej, zwłaszcza w Argentynie.</p>", "Muhammad Zubair": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammad</b>.</p><b>Muhammad</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;مُحَمَّد&#8206;) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wariantami tego imienia są: Mohammed, Mehmed, Mamadu i Mahomet.", "Maria Bolesław": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Muhammad Rizqi": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Muhammad</b>.</p><b>Muhammad</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;مُحَمَّد&#8206;) – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wariantami tego imienia są: Mohammed, Mehmed, Mamadu i Mahomet.", "Md Mobarak": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Md</b>.</p><b>Mendelew</b> (<b>Md</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>mendelevium</em>) – <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a> z grupy <a href=\"https://pl.wikipedia.org/wiki/Aktynowce\" target=\"_blank\" rel=\"noopener noreferrer\">aktynowców</a> w <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_okresowy_pierwiastk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">układzie okresowym</a>. Nazwa pochodzi od nazwiska chemika <a href=\"https://pl.wikipedia.org/wiki/Dmitrij_Mendelejew\" target=\"_blank\" rel=\"noopener noreferrer\">Dmitrija Mendelejewa</a>. Czasami w literaturze jest stosowany błędny symbol Mv.", "Małgorzata": "<b>Małgorzata</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Margarita</em>, które pochodziło od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;μαργαρίτης <i>margarites</i> oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Per%C5%82y_naturalne\" target=\"_blank\" rel=\"noopener noreferrer\">perłę</a>”, które ma źródło w formie <a href=\"https://pl.wikipedia.org/wiki/Derywacja_(j%C4%99zykoznawstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">derywowanej</a> od <a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sanskryckiego</a> मञ्यरी <i>mañjarī</i> oznaczającego m.in. „perłę”, „pąk kwiatowy”, „kwiat”, „<a href=\"https://pl.wikipedia.org/wiki/Li%C5%9B%C4%87\" target=\"_blank\" rel=\"noopener noreferrer\">listowie</a> (w formie ornamentu na budynku)”.", "Marzena": "<b>Marzena</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, które powstało najprawdopodobniej jako zdrobnienie <a href=\"https://pl.wikipedia.org/wiki/Ma%C5%82gorzata_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Małgorzaty</a> lub <a href=\"https://pl.wikipedia.org/wiki/Marzanna_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Marzanny</a>. Istnieje możliwość, że zdrabniano tak <a href=\"https://pl.wikipedia.org/wiki/Marta_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Martę</a> lub <a href=\"https://pl.wikipedia.org/wiki/Maria\" target=\"_blank\" rel=\"noopener noreferrer\">Marię</a>.", "Mariola": "<b>Mariola</b> – imię żeńskie. Pierwotnie było zdrobnieniem od imienia <a href=\"https://pl.wikipedia.org/wiki/Maria\" target=\"_blank\" rel=\"noopener noreferrer\">Maria</a> lub skrótem od podwójnego imienia Maria Jolanta. Obecnie stanowi odrębne imię. Występuje przede wszystkim w Polsce.", "Mirosława": "<b>Mirosława</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> żeńskie, złożone z członów <i>Miro-</i> (<i>pokój</i>, <i>spokój</i>, <i>dobro</i>) oraz <i>-sława</i> (<i>sława</i>). Mogło oznaczać <i>ta, która sławi pokój</i>. W źródłach polskich poświadczone od <a href=\"https://pl.wikipedia.org/wiki/1222\" target=\"_blank\" rel=\"noopener noreferrer\">1222</a> roku. <a href=\"https://pl.wikipedia.org/wiki/Anagram\" target=\"_blank\" rel=\"noopener noreferrer\">Anagram</a> tego imienia też jest żeńskim imieniem – <a href=\"https://pl.wikipedia.org/wiki/S%C5%82awomira\" target=\"_blank\" rel=\"noopener noreferrer\">Sławomira</a>.", "Milena": "<b>Milena</b> lub <b>Milana</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, używane w językach <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_bu%C5%82garski\" target=\"_blank\" rel=\"noopener noreferrer\">bułgarskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_czeski\" target=\"_blank\" rel=\"noopener noreferrer\">czeskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_s%C5%82owacki\" target=\"_blank\" rel=\"noopener noreferrer\">słowackim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbsko-chorwacki\" target=\"_blank\" rel=\"noopener noreferrer\">chorwackim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">polskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbski\" target=\"_blank\" rel=\"noopener noreferrer\">serbskim</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_s%C5%82owe%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">słoweńskim</a>. Zawiera pierwiastek <i>mil</i> oznaczający „miły”. Męskim odpowiednikiem imienia jest <a href=\"https://pl.wikipedia.org/wiki/Milan_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Milan</a>.", "Michalina": "<b>Michalina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Micha%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Michał</a>. Oznacza „któż [jest] jak Bóg”. Imię to nadawane jest w tej formie w Polsce przynajmniej od <a href=\"https://pl.wikipedia.org/wiki/1744\" target=\"_blank\" rel=\"noopener noreferrer\">1744</a> roku, natomiast już w średniowieczu notowano jako żeński odpowiednik Michała formę <i><b>Michaelis</b></i> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>), zdrobniale – Michałka. Wśród imion nadawanych nowo narodzonym dzieciom, Michalina w 2018 r. zajmowała 24. miejsce w grupie imion żeńskich.", "Marlena": "<b>Marlena</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, formowane na dwa sposoby:", "Malwina": "<b>Malwina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia celtyckiego lub germańskiego. Imię to może pochodzić od galickiego imienia Malamhin składającego się ze słów mala mhinn – „gładkie czoło” lub z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staro-wysoko-niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">staro-wysoko-niemieckiego</a>: mahal – „sąd, sprawiedliwość” oraz wini „przyjaciel”, można więc przetłumaczyć je jako „strzegąca praw, prawowierna”. W XVIII wieku szkocki poeta <a href=\"https://pl.wikipedia.org/wiki/James_Macpherson\" target=\"_blank\" rel=\"noopener noreferrer\">James Macpherson</a> użył je w tzw. <i>pieśniach <a href=\"https://pl.wikipedia.org/wiki/Osjan_(Macpherson)\" target=\"_blank\" rel=\"noopener noreferrer\">Osjana</a></i> – Malwina była narzeczoną Oskara, syna Osjana. Poezję osjaniczną przełożył na język polski m.in. <a href=\"https://pl.wikipedia.org/wiki/Ignacy_Krasicki\" target=\"_blank\" rel=\"noopener noreferrer\">Ignacy Krasicki</a>. W literaturze polskiej wykorzystał to imię <a href=\"https://pl.wikipedia.org/wiki/Ludwik_Kropi%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">Ludwik Kropiński</a> w utworze <i>Miłość malująca obraz Malwiny</i>, a w romansie sentymentalnym <i><a href=\"https://pl.wikipedia.org/wiki/Malwina,_czyli_domy%C5%9Blno%C5%9B%C4%87_serca\" target=\"_blank\" rel=\"noopener noreferrer\">Malwina, czyli domyślność serca</a></i> <a href=\"https://pl.wikipedia.org/wiki/Maria_Wirtemberska\" target=\"_blank\" rel=\"noopener noreferrer\">Maria z Czartoryskich Wirtemberska</a>. Literatura i media przyczyniły się do wzrostu popularności imienia.", "Matylda": "<b>Matylda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staro-wysoko-niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">języka staro-wysoko-niemieckiego</a> – słów <i>maht</i> (potęga, władza) oraz <i>hild(is)</i> (walka). Tłumaczy się jako „ta, która jest silna, odważna w walce”.", "Magda": "<b>Magda</b> – zdrobnienie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Magdalena\" target=\"_blank\" rel=\"noopener noreferrer\">Magdalena</a>. Występuje jednak również w Polsce jako samodzielne imię, pomimo prawnego zakazu nadawania imion w formie zdrobniałej.", "Mieczysława": "<b>Mieczysława</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie. Żeński odpowiednik męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Mieczys%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Mieczysław</a>. Patronką tego imienia jest bł. <a href=\"https://pl.wikipedia.org/wiki/Mieczys%C5%82awa_Kowalska\" target=\"_blank\" rel=\"noopener noreferrer\">Mieczysława Kowalska</a>, jedna ze <a href=\"https://pl.wikipedia.org/wiki/108_b%C5%82ogos%C5%82awionych_m%C4%99czennik%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">108 błogosławionych męczenników</a> II wojny światowej.", "Marika": "<b>Marika</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzące od imienia „<a href=\"https://pl.wikipedia.org/wiki/Maria\" target=\"_blank\" rel=\"noopener noreferrer\">Maria</a>”. Jest <a href=\"https://pl.wikipedia.org/wiki/W%C4%99gry\" target=\"_blank\" rel=\"noopener noreferrer\">węgierską</a> formą tego imienia, chociaż znane jest także w Bułgarii i na terenie byłej Jugosławii. Imię jest również zniemczoną formą zdrobnienia „Maryjka” występującego w <a href=\"https://pl.wikipedia.org/wiki/Etnolekt_%C5%9Bl%C4%85ski\" target=\"_blank\" rel=\"noopener noreferrer\">etnolekcie śląskim</a>.", "Marzanna": "Imię bogini wywodzone jest z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_praindoeuropejski\" target=\"_blank\" rel=\"noopener noreferrer\">praindoeuropejskiego</a> rdzenia <i>*mar-</i>, <i>*mor-</i>, oznaczającego śmierć. <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_s%C5%82owacki\" target=\"_blank\" rel=\"noopener noreferrer\">Słowacka</a> forma <a href=\"https://pl.wikipedia.org/wiki/Teonim\" target=\"_blank\" rel=\"noopener noreferrer\">teonimu</a> <i>Ma(r)muriena</i> sugeruje ewentualne związki z <a href=\"https://pl.wikipedia.org/wiki/Mars_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Marsem</a> (Marmorem, Mamersem, Mamuriusem Veturiusem). Śmierć Marzanny wraz z końcem zimy przeciwstawia ją symbolizującemu wiosnę <a href=\"https://pl.wikipedia.org/wiki/Jary%C5%82o\" target=\"_blank\" rel=\"noopener noreferrer\">Jaryle</a>, który rodził się wraz z nadejściem wiosny&#8201;.", "Melania": "<b>Melania</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;μέλας, znaczącego „czarna”.", "Marcela": "<b>Marcela</b> – imię żeńskie, odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> męskiego <a href=\"https://pl.wikipedia.org/wiki/Marceli\" target=\"_blank\" rel=\"noopener noreferrer\">Marceli</a>.", "Mirela": "<b>Mirela</b>, <b>Mirella</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, pochodzące z <a href=\"https://pl.wikipedia.org/wiki/Dialekt_prowansalski\" target=\"_blank\" rel=\"noopener noreferrer\">dialektu prowansalskiego</a> <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_oksyta%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">języka oksytańskiego</a>, od imienia <i>Mirèio</i>. Zostało ono użyte po raz pierwszy w <a href=\"https://pl.wikipedia.org/wiki/Mirejo\" target=\"_blank\" rel=\"noopener noreferrer\">jednym z poematów</a> przez poetę <a href=\"https://pl.wikipedia.org/wiki/Fr%C3%A9d%C3%A9ric_Mistral\" target=\"_blank\" rel=\"noopener noreferrer\">Frédérica Mistrala</a>, który wywiódł <i>Mirèio</i> prawdopodobnie od słowa <i>mirar</i>, w dialekcie <a href=\"https://pl.wikipedia.org/wiki/Prowansja\" target=\"_blank\" rel=\"noopener noreferrer\">prowansalskim</a> oznaczającego „podziwiana” (z <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <i>mirare</i> „podziwiać”). Mirela może także stanowić skrócenie włoskiego imienia <i>Mirabella</i>.", "Maryla": "<b>Maryla</b> – forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Maria\" target=\"_blank\" rel=\"noopener noreferrer\">Maria</a> pochodząca od romańskiego zdrobnienia pierwowzoru.", "Marina": "Imię Maryna jest żeńskim odpowiednikiem imienia <a href=\"https://pl.wikipedia.org/wiki/Maryn\" target=\"_blank\" rel=\"noopener noreferrer\">Maryn</a>, w Polsce niezwykle rzadkim (w 1994 roku nosiła je jedna osoba, w roku 2001 – 203 osoby, zaś w wariancie <i>Marina</i> – 362). Imię to wywodzi się od imienia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Marinus</em>, a to z kolei powstało z przymiotnika <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>marinus</em> („morski”). Imię Maryna – rozumiane jako żeński odpowiednik imienia Maryn – poświadczone jest w Polsce już w XV wieku (najwcześniej w 1443 roku). Zdrobnienie od niego brzmi Marynia. Marina to cudzoziemski wariant imienia Maryna; trudno powiedzieć, skąd przybyło do Polski, z uwagi na podobną formę w prawie wszystkich językach europejskich.", "Maryia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mirella": "<b>Mirela</b>, <b>Mirella</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, pochodzące z <a href=\"https://pl.wikipedia.org/wiki/Dialekt_prowansalski\" target=\"_blank\" rel=\"noopener noreferrer\">dialektu prowansalskiego</a> <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_oksyta%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">języka oksytańskiego</a>, od imienia <i>Mirèio</i>. Zostało ono użyte po raz pierwszy w <a href=\"https://pl.wikipedia.org/wiki/Mirejo\" target=\"_blank\" rel=\"noopener noreferrer\">jednym z poematów</a> przez poetę <a href=\"https://pl.wikipedia.org/wiki/Fr%C3%A9d%C3%A9ric_Mistral\" target=\"_blank\" rel=\"noopener noreferrer\">Frédérica Mistrala</a>, który wywiódł <i>Mirèio</i> prawdopodobnie od słowa <i>mirar</i>, w dialekcie <a href=\"https://pl.wikipedia.org/wiki/Prowansja\" target=\"_blank\" rel=\"noopener noreferrer\">prowansalskim</a> oznaczającego „podziwiana” (z <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <i>mirare</i> „podziwiać”). Mirela może także stanowić skrócenie włoskiego imienia <i>Mirabella</i>.", "Mila": "<p>Mylka drniysta (lat. Mila caespitosa) - jedyny gatunek jaktusu z rodu Mylka (lat.</p>", "Manuela": "<b>Manuela</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <i><b>Manuel</b></i>, będącego skróconą formą biblijnego imienia <a href=\"https://pl.wikipedia.org/wiki/Emanuel\" target=\"_blank\" rel=\"noopener noreferrer\">Emanuel</a>. Manuela jest skróconą formą imienia <a href=\"https://pl.wikipedia.org/wiki/Emanuela\" target=\"_blank\" rel=\"noopener noreferrer\">Emanuela</a>.", "Marcjanna": "<b>Marcjana</b>, również <b>Marcjanna</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Marcjan\" target=\"_blank\" rel=\"noopener noreferrer\">Marcjan</a>. Wśród świętych m.in. św. Marcjana z Cezarei Mauretańskiej.", "Marietta": "<b>Marietta</b>, <i>Marieta</i> – imię zapożyczone z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">języka włoskiego</a>, w którym funkcjonuje jako zdrobnienie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Maria\" target=\"_blank\" rel=\"noopener noreferrer\">Maria</a> lub jako imię nadawane samodzielnie.", "Malina": "<b>Malina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, które prawdopodobnie jest zdrobnieniem imienia <a href=\"https://pl.wikipedia.org/wiki/Magdalena\" target=\"_blank\" rel=\"noopener noreferrer\">Magdalena</a>, powstałym na gruncie kilku języków wschodniosłowiańskich bądź w Skandynawii. <a href=\"https://pl.wikipedia.org/wiki/Rada_J%C4%99zyka_Polskiego\" target=\"_blank\" rel=\"noopener noreferrer\">Rada Języka Polskiego</a> ma wątpliwości dotyczące nadawania tego imienia ludziom.", "Maiia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maia</b>.</p><p>Maia (grek. Μαῖα; lat. Maia), w starożytnej greckiej religii, była jedną z Pleiad i matką Hermesa. Maia była córką Atlas i Pleione the Oceanid, a była najstarszą z siedmiu Pleiad.</p>", "Margarita": "<p>Margarita to meksykański koktajl zawierający tequila, pomarańczową wodę i wodę z cynamonu, często rozproszoną solą na szklance. Wypłaty są przygotowywane poprzez wstrząsanie z kamieni (na skalę), wstrząsnięcie z kamieniami (zamrożona margarita), lub bez kamieni (pić prosto).</p>", "Melisa": "<b>Melisa</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, oznacza „pszczołę” (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;μέλισσα). W <a href=\"https://pl.wikipedia.org/wiki/Mitologia_grecka\" target=\"_blank\" rel=\"noopener noreferrer\">greckiej mitologii</a> Melissa była jedną z <a href=\"https://pl.wikipedia.org/wiki/Nimfy\" target=\"_blank\" rel=\"noopener noreferrer\">nimf</a> opiekujących się małym <a href=\"https://pl.wikipedia.org/wiki/Zeus\" target=\"_blank\" rel=\"noopener noreferrer\">Zeusem</a>.", "Majka": "<p>Majka, słowiańskie kobiece imię, pierwotnie diminutiw nazwiska Maria lub Maja, może być to zmiana pisowni Mayka.</p>", "Marita": "<b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maia": "<p>Maia (grek. Μαῖα; lat. Maia), w starożytnej greckiej religii, była jedną z Pleiad i matką Hermesa. Maia była córką Atlas i Pleione the Oceanid, a była najstarszą z siedmiu Pleiad.</p>", "Monica": "<p>Monica Denise Brown (ang. Monica Denise Brown), w dziewczynstwie - Arnold (ang.</p>", "Melissa": "<p>Melissa (lat. Melissa) - rodzaj wieloletnich trawnic roślin rodziny Jasnowotków (Lamiaceae).</p>", "Margaret": "<p>Margaret (jap. マーガレット) - japoński czasopism manga, wydany dwa razy w miesiącu przez firmę Shueisha.</p>", "Margareta": "<b>Małgorzata</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Margarita</em>, które pochodziło od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;μαργαρίτης <i>margarites</i> oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Per%C5%82y_naturalne\" target=\"_blank\" rel=\"noopener noreferrer\">perłę</a>”, które ma źródło w formie <a href=\"https://pl.wikipedia.org/wiki/Derywacja_(j%C4%99zykoznawstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">derywowanej</a> od <a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sanskryckiego</a> मञ्यरी <i>mañjarī</i> oznaczającego m.in. „perłę”, „pąk kwiatowy”, „kwiat”, „<a href=\"https://pl.wikipedia.org/wiki/Li%C5%9B%C4%87\" target=\"_blank\" rel=\"noopener noreferrer\">listowie</a> (w formie ornamentu na budynku)”.", "Melanie": "<p>Melanie Melanie to siódmy album studiowy piosenkarki Celine Dion. Melanie - jedna z marek handlowych białoruskiej fabryki cukier ⁇ Spartak ⁇ .</p>", "Mylana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Milana</b>.</p><b>Milena</b> lub <b>Milana</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, używane w językach <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_bu%C5%82garski\" target=\"_blank\" rel=\"noopener noreferrer\">bułgarskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_czeski\" target=\"_blank\" rel=\"noopener noreferrer\">czeskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_s%C5%82owacki\" target=\"_blank\" rel=\"noopener noreferrer\">słowackim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbsko-chorwacki\" target=\"_blank\" rel=\"noopener noreferrer\">chorwackim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">polskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbski\" target=\"_blank\" rel=\"noopener noreferrer\">serbskim</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_s%C5%82owe%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">słoweńskim</a>. Zawiera pierwiastek <i>mil</i> oznaczający „miły”. Męskim odpowiednikiem imienia jest <a href=\"https://pl.wikipedia.org/wiki/Milan_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Milan</a>.", "Martha": "<p>Martha może odnosić się do: Martha Vasconcellos Martha Chase Martha Greenblatt Święta Matka Kościoła Katolickiego.</p>", "Miłosława": "<b>Miłosława</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> żeńskie, złożone z członów <i>Miło-</i> („miły”, „miłujący”) i <i>-sława</i> („sława”). Znaczenie imienia: „miła sławie”. Poświadczone w źródłach polskich jako Miłosława (XII wiek) i Miełosława (XIII–XIV wiek).", "Matilda": "<p>⁇ Matilda ⁇ to piosenka angielskiego alternatywnego indy-grupu alt-J z ich debiutanckiego albumu studiowego An Awesome Wave, który premierują w sieci 10 stycznia 2012 roku, single został wydany split z ⁇ Fitzpleasure ⁇ 24 lutego i single były dostępne do pobierania cyfrowego i na 10' winylu. Piosenka została napisana przez członków zespołu i wyprodukowana przez Charliego Andrew'a. Piosenka jest jakiegoś rodzaju hołdem dla bohaterki Matilda z filmu Leon z 1994 roku.</p>", "Mercedes": "Od imienia <a href=\"https://pl.wikipedia.org/wiki/Merc%C3%A9d%C3%A8s_Jellinek\" target=\"_blank\" rel=\"noopener noreferrer\">Mercédès Jellinek</a>, córki <a href=\"https://pl.wikipedia.org/wiki/Emil_Jellinek\" target=\"_blank\" rel=\"noopener noreferrer\">Emila Jellinka</a>, generalnego przedstawiciela firmy <a href=\"https://pl.wikipedia.org/wiki/Daimler-Motoren-Gesellschaft\" target=\"_blank\" rel=\"noopener noreferrer\">Daimler</a>, pochodzi nazwa marki samochodów <a href=\"https://pl.wikipedia.org/wiki/Mercedes-Benz\" target=\"_blank\" rel=\"noopener noreferrer\">Mercedes</a>. W Polsce bardzo rzadko używane ze względu na spółgłoskowy wygłos oraz fakt, iż wyraz ten bardziej znany jest jako marka samochodu (i powszechnie postrzegany jako posiadający rodzaj męski), niż imię żeńskie.", "Margaryta": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Margarita</b>.</p><p>Margarita to meksykański koktajl zawierający tequila, pomarańczową wodę i wodę z cynamonu, często rozproszoną solą na szklance. Wypłaty są przygotowywane poprzez wstrząsanie z kamieni (na skalę), wstrząsnięcie z kamieniami (zamrożona margarita), lub bez kamieni (pić prosto).</p>", "Miroslava": "<p>Miroslava Šternová (czeski: Miroslava Sternová; 26 lutego 1926, Praga, Czechosłowacja - 9 marca 1955, Meksyk) - meksykańska aktorka pochodzenia czeskiego.</p>", "Malvina": "<p>Malvina to żeńskie imię pochodzące z szkockiego gaelickiego Mala-mhìn, co oznacza \"gładkie czoło\". Został wynaleziony przez 18 wieku szkockiego poety Jamesa Macphersona.</p>", "Mirona": "<b>Mirona</b> – żeński odpowiednik pochodzącego z języka greckiego <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Miron\" target=\"_blank\" rel=\"noopener noreferrer\">Miron</a>.", "Malgorzata": "<p>Małgorzata jest powszechną polską nazwą pochodzącą z łacińskiego Margarita z starożytnego greckiego: μαργαρίτης, romanized: margarítēs, lit. \"perla\".</p>", "Melody": "<p>Melody: Melody (ur. 1990) - hiszpańska piosenkarka.</p>", "Mija": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mia</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Marianne": "<p>Marianne (przesłanie [maʁjan]) jest państwowym ciałem Republiki Francuskiej od czasów Rewolucji Francuskiej, jest ciałem wolności, równości, braterstwa i rozumu, a także jest obrazem Boski Wolności. Marianne była wystawiona w wielu miejscach we Francji i zajmowała honorowe stanowisko w sądach miejskich i sądach prawnych.</p>", "Marysia": "<b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Molly": "<p>Olga Juryjevna Seryabkina (ur. 12 kwietnia 1985 r. w Moskwie), znana również pod pseudonimem Molly, była rosyjską piosenkarką, autorką piosenek, poetą, aktorką i telewizorką.</p>", "Maura": "<b>Maura</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Maur_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Maur</a>. W językach <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">angielskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_szkocki_gaelicki\" target=\"_blank\" rel=\"noopener noreferrer\">szkockim</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_irlandzki\" target=\"_blank\" rel=\"noopener noreferrer\">irlandzkim</a> istnieje imię o identycznym brzmieniu, a wywodzone jest od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_celtyckie\" target=\"_blank\" rel=\"noopener noreferrer\">celtyckiego</a> słowa <i>mór</i> oznaczającego wielki, wspaniały. W angielskim używany także jako zdrobniona forma irlandzkiej formy imienia <a href=\"https://pl.wikipedia.org/wiki/Maria\" target=\"_blank\" rel=\"noopener noreferrer\">Maria</a> – <i>Maire</i> (wymawiane <i>Moira</i>). Istnieje kilka świętych katolickich o tym imieniu.", "Maka": "<p>Kisi Keomaka \"Maka\" Unufe (ur. 28 września 1991 w Provo) - amerykański rugbyści, występujący w pozycji winga.</p>", "Mathilde": "<p>Matilda (francuski: Matilda, francuski: Matilde, francuski r. Mathilde, nieźle.</p>", "Monique": "<p>Monik (ang. Monique, prawdziwe imię Shammara Abdul-Khaaliq; rodzina.</p>", "Maksymiliana": "<b>Maksymiliana</b>, <b>Maksymilianna</b> – żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Maksymilian\" target=\"_blank\" rel=\"noopener noreferrer\">Maksymilian</a>. Imiona te pochodzą od nazwiska rodu <a href=\"https://pl.wikipedia.org/wiki/Emiliusze\" target=\"_blank\" rel=\"noopener noreferrer\">Emiliuszów</a>.", "Milada": "<b>Miłosława</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> żeńskie, złożone z członów <i>Miło-</i> („miły”, „miłujący”) i <i>-sława</i> („sława”). Znaczenie imienia: „miła sławie”. Poświadczone w źródłach polskich jako Miłosława (XII wiek) i Miełosława (XIII–XIV wiek).", "Milagros": "<p>Milagros może odnosić się do: Milagros, Burgos, miasto w prowincji Burgos, Kastilia i Leon, Hiszpania. Milagros, Masbate, jest miastem trzecim w prowincji Masbate w Filipinach.</p>", "Mykhailyna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mikhailina</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mikhail</b>.</p><p>Michał (Hebrajskie: מִיכָאֵל; Aramejski: ⁇ , romanized: Mīkhāʼēl) jest powszechnym męskim imieniem, które zazwyczaj uważa się za pochodzące z hebrajskiego pytania retorycznego מי כאל (mī kāʼēl), \"Kto [jest] podobny do [Hebrajskiego boga] El?\", a więc jest nazwiskiem teoforycznym, którego odpowiedź brzmi \"nie ma nikogo podobnego do El\", lub \"nie słynny i potężny jak Bóg\".[is] Paradoksalnie, nazwisko jest czasami interpretowane jako \"Jeden...</p>", "Maria Teresa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Martika": "<p>Martyka (ang. Martika, pełne imię: Marta Marrero, angielski.</p>", "Miła": "<b>Miła</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia słowiańskiego.", "Mabel": "<p>Mabel Alabama-Perl Mcway (ang. Mabel Alabama-Pearl McVey; rodzaj.</p>", "Mirra": "<b>Mirra</b>, mira – wonna <a href=\"https://pl.wikipedia.org/wiki/%C5%BBywica\" target=\"_blank\" rel=\"noopener noreferrer\">żywica</a> otrzymywana z drzew i krzewów należących do rodzaju <a href=\"https://pl.wikipedia.org/wiki/Balsamowiec\" target=\"_blank\" rel=\"noopener noreferrer\">balsamowiec</a> (<i>Commiphora</i>). Uważa się, że najlepsza pochodzi z <a href=\"https://pl.wikipedia.org/wiki/Balsamowiec_mirra\" target=\"_blank\" rel=\"noopener noreferrer\">balsamowca mirry</a> (<i>Commiphora abyssinica</i>), możliwe jest jednak uzyskiwanie jej również z innych gatunków balsamowca, np. <i><a href=\"https://pl.wikipedia.org/wiki/Commiphora_kataf\" target=\"_blank\" rel=\"noopener noreferrer\">Commiphora kataf</a></i> i <i><a href=\"https://pl.wikipedia.org/wiki/Commiphora_myrrha\" target=\"_blank\" rel=\"noopener noreferrer\">Commiphora myrrha</a></i>. Nazwa <i>mirra</i> wywodzi się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">języków semickich</a>, por. <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_aramejski\" target=\"_blank\" rel=\"noopener noreferrer\">aram.</a>&#160;&#8207;ܡܪܝܪܐ&#8206; <i>murr</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;مر&#8206; <i>murr</i> (w obydwu językach: „gorzka”; to słowo wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/Praj%C4%99zyk\" target=\"_blank\" rel=\"noopener noreferrer\">prasemickiego</a> <a href=\"https://pl.wikipedia.org/wiki/Rdze%C5%84_(j%C4%99zykoznawstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">rdzenia</a> <i>m-r-r</i>). W hebrajskiej <i><a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">Biblii</a></i> opisana jest słowem <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מוֹר&#8206; <i>môr</i> (lub <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מֹר&#8206; <i>mōr</i>).", "Magdalene": "<p>Magdalene to drugi album brytyjskiej piosenkarki i autora piosenek FKA twigs, wydany 8 listopada 2019 roku przez wytwórnię Young Turks.</p>", "Mela": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mel</b>.</p><p>Mel jest miastem w prowincji Belluno w regionie Veneto, znajdującym się około 170 km na północ od Wenecji i około 14 km na południowo-zachodni od Belluno i około 16 km na północy od Feltre. Na dzień 31 grudnia 2004 roku mieście miało ludności 6,311 i powierzchnię 85,7 km2.</p>", "Margaretta": "<p>Margaretta może być: Nazwa kobiety, głównie nadawana dla Szweckich i Rumunów. Margaretta (misjonarka) (~1369 - ~1425).</p>", "Marcella": "<p>Marcella (lat. Marcella) - święta IV wieku.</p>", "Miroslawa": "<p>Mirosława (polskie wymowa: [mirɔˈswava]) jest polskim imieniem kobiecy. Jest to kobieca forma Mirosław, pochodząca z słowiańskich elementów mirŭ (\"pokój, świat\") i slava (\"sława\").</p>", "Mariel": "<p>Republika Marii L. (ludzka. Mariel Republika, górnik.</p>", "Masza": "<b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Milaniia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Milania</b>.</p><p>Melania to kobiece imię pochodzące z łacińskiego pochodzenia, które pochodzi od greckiego słowa melaina (μέλαινα), żeńskiej formy przymiotów melas (μέλας), co oznacza \"czarny\" lub \"ciemny\". Nazwa ta nosiła dwie święte Melania Starszą i jej wnuczka Melania Młodsza, a pochodzenie nazwy Melanie.</p>", "Margherita": "<p>Margherita jest miastem statystycznym (census town) w hrabstwie Tinsukia w stanie Assam, India.</p>", "Milenia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mileni</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Milen</b>.</p><p>Milen (bułgarski: Милен) to bułgarskie męskie imię. Wśród znanych osób z tej nazwy są: Milen Bonev (ur. 1986), bułgarski piłkarz, obecnie grający dla Kaliakra Kavarna jako obrońca Milen Dobrev (ur. 1980), bułgarski ciężarosta Milen Hristov (ur. 1977), bułgara piłkarza piłkarka, który obecnie gra dla Neftochimic Burgas jako półbrzeg Milen Lahchev (ur., 1987), bułgaria piłkarze, obecnie gry...</p>", "Maria Magdalena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mya": "<p>Mya - rodzaj morskich dwustronnych małp z rodziny Myidae.</p>", "Mirabella": "<b>Mirabella</b> - współcześnie powstałe <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, początkowo używane w krajach <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_francuski\" target=\"_blank\" rel=\"noopener noreferrer\"> francusko</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">angielskojęzycznych</a> jako <i>Mirabelle</i>, pochodzące od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> słowa <i>mirabilis</i> oznaczającego \"wspaniały\".", "Marcia": "<p>Marcia (lat. Marcia, około 79 roku życia - po 49 roku.</p>", "Madona": "<p>Madonna Louise Ciccone (; włoska: [tʃikˈkoːne]; urodzona 16 sierpnia 1958) jest amerykańską piosenkarką, kompozytorką i aktorką. Nazywana \"królową muzyki pop\", Madonna jest znana z ciągłego tworzenia i elastyczności w produkcji muzyki, tworzeniu i występowaniu na żywo.</p>", "Madlen": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Madlena</b>.</p><b>Magdalena</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od przydomka <a href=\"https://pl.wikipedia.org/wiki/Maria_Magdalena\" target=\"_blank\" rel=\"noopener noreferrer\">Marii Magdaleny</a>, czyli Marii z <a href=\"https://pl.wikipedia.org/wiki/Magdala_(Izrael)\" target=\"_blank\" rel=\"noopener noreferrer\">Magdali</a>, wioski leżącej w pobliżu <a href=\"https://pl.wikipedia.org/wiki/Jezioro_Tyberiadzkie\" target=\"_blank\" rel=\"noopener noreferrer\">Jeziora Tyberiadzkiego (Galilejskiego)</a>.", "Madlena": "<b>Magdalena</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od przydomka <a href=\"https://pl.wikipedia.org/wiki/Maria_Magdalena\" target=\"_blank\" rel=\"noopener noreferrer\">Marii Magdaleny</a>, czyli Marii z <a href=\"https://pl.wikipedia.org/wiki/Magdala_(Izrael)\" target=\"_blank\" rel=\"noopener noreferrer\">Magdali</a>, wioski leżącej w pobliżu <a href=\"https://pl.wikipedia.org/wiki/Jezioro_Tyberiadzkie\" target=\"_blank\" rel=\"noopener noreferrer\">Jeziora Tyberiadzkiego (Galilejskiego)</a>.", "Maribel": "<p>Maribel to hiszpańska nazwa, utworzona jako skrócenie od María Isabel. Alternatywnie, jest to angielskie nazwisko, połączona wersja Mary i Belle.</p>", "Marisol": "<p>Marisol (Hiszpańska: Marisol) - hiszpańskie imię.</p>", "Masha": "<p>W języku rosyjskim Masha (Маша) jest diminutiwem Maryi. Tak samo jak w ukraińskim jest diminutiw Marii lub Mariya.</p>", "Mélanie": "<p>Melanie to kobiece imię pochodzące od greckiego μελανία (melania), \"czarność\", a od μέλας (melas), oznaczające \"ciemny\". Urodzony w łacinie przez dwóch świętych, Melanię Starszą i jej wnuczkę Melanię Młodszą, nazwę wprowadzili do Anglii Normanie w francuskiej formie Melanie.</p>", "Mirjam": "<b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mădălina": "<p>Mădălina to rumuńska kobieca nazwa, która może odnosić się do: Mădăline Cioveie (ur. 1983), rumuńska gimnastka aerobowa Mădălină Diana Ghenea (ur. 1987), rumuńskiej włoskiej aktorki i modelu Mădălinei Gojnea (ur. 1987), rumuńskiego tenisa Mădăliny Manole (1967-2010), rumuński pop artysta Mădălino Zamfirescu (ur. 1994), rumuńczyka piłkarka ręka</p>", "Mayya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maya</b>.</p><p>Maya: Autodesk Maya to redaktor grafiki trójwymiarowej. Maya - album Banco de Gaia z 1994 roku.</p>", "Melaniya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Melania</b>.</p><b>Melania</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;μέλας, znaczącego „czarna”.", "Mirabela": "<p>Mirabela jest miastem w stanie Minas Gerais w Brazylii. Miasto ma powierzchnię 720 828 km2, liczba ludności w 2007 roku wynosi 12769 osób, a jego gęstość jest 17,9 osób/km2.</p>", "Meta": "<p>Meta to wieloznaczny termin.</p>", "Melana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Melan</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Melani</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Melany</b>.</p><p>Melanie to kobiece imię pochodzące od greckiego μελανία (melania), \"czarność\", a od μέλας (melas), oznaczające \"ciemny\". Urodzony w łacinie przez dwóch świętych, Melanię Starszą i jej wnuczkę Melanię Młodszą, nazwę wprowadzili do Anglii Normanie w francuskiej formie Melanie.</p>", "Macieja": "<b>Macieja</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Maciej\" target=\"_blank\" rel=\"noopener noreferrer\">Maciej</a>. Patronką tego imienia jest bł. <a href=\"https://pl.wikipedia.org/wiki/Macieja_Nazzarei\" target=\"_blank\" rel=\"noopener noreferrer\">Macieja Nazzarei</a>, klaryska (zm. ok. 1320).", "Medea": "<p>Media: Medea (grek. Μήδεια) - w starożytnej mitologii greckiej córka kolchydskiego króla Eeta, obdarzona darem magii.</p>", "Malia": "<p>Malia (lat. Malia grata) - gatunek ptaków z rodziny zardów.</p>", "Markéta": "<p>Dragomira, częściej nazwała na duńskim ładzie Dagmar (w chrzcie - Margarita lub Market, czeski Markéta; 1186, Maisen - 24 maja 1212 lub 24 maja 1213, Dania), - królowa-konsorty Danii, żona króla Waldemara II, córka króla Czechy (Bohemii) Pršemysa Otakara I i jego żony Adelgejdy Maisenskiej.</p>", "Mierosława": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mierosław</b>.</p><b>Mirosław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie imię</a> męskie. Imię <i>Mirosław</i> jest przykładem <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staropolski\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskiego</a>, złożonego, osobowego imienia dwuczłonowego, które jest <a href=\"https://pl.wikipedia.org/wiki/Relikt\" target=\"_blank\" rel=\"noopener noreferrer\">reliktem</a> <a href=\"https://pl.wikipedia.org/wiki/Poganie\" target=\"_blank\" rel=\"noopener noreferrer\">pogańskich</a> imion używanych we wczesnym średniowieczu przez <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie\" target=\"_blank\" rel=\"noopener noreferrer\">Słowian</a>. Składa się z członów <i>Miro-</i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pras%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">ps.</a> <i>*mirъ</i> „pokój”, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staropolski\" target=\"_blank\" rel=\"noopener noreferrer\">stpol.</a> <i>mir</i>, <i>mier</i> - „pokój, bezpieczeństwo, przyjaźń”) oraz <i>-sław</i> („sława”). Mogło oznaczać „ten, który sławi pokój” albo „ten, który zdobywa sławę poprzez zaprowadzenie porządku, pokoju”. <a href=\"https://pl.wikipedia.org/wiki/Witold_Taszycki\" target=\"_blank\" rel=\"noopener noreferrer\">Witold Taszycki</a> zaliczył je do grupy najstarszych polskich imion osobowych&#8201;.", "Morgane": "<p>Morgan (francuski: Morgan, urodziny.</p>", "Mary Ann": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mary</b>.</p><p>Mary: Mary (Mary, rzadko Marie) - angielskie nazwisko kobiece, odpowiadające rosyjskiej nazwie Maria. Jest to jedno z najstarszych nazw zachowanych do naszych czasów.</p>", "Matea": "<b>Matea</b> – żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Mateusz\" target=\"_blank\" rel=\"noopener noreferrer\">Mateusz</a>. W <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">Polsce</a> rzadko używana.", "Maria Del Carmen": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Myra": "<p>Myra (lat. Myra) - rodzaj krabów morza z rodziny Leucosiidae z rodu Eubrachyura (Heterotremata). Znane jest około 20 gatunków.</p>", "Madonna": "<p>Madonna (ang. Madonna; rodzaj.</p>", "Morena": "<b>Morena:</b> 1. Wszelki materiał skalny składający się z przemieszanych <a href=\"https://pl.wikipedia.org/wiki/Frakcja_(geologia)\" target=\"_blank\" rel=\"noopener noreferrer\">frakcji</a> różnej wielkości (bloki skalne, <a href=\"https://pl.wikipedia.org/wiki/G%C5%82az\" target=\"_blank\" rel=\"noopener noreferrer\">głazy</a>, <a href=\"https://pl.wikipedia.org/wiki/%C5%BBwir\" target=\"_blank\" rel=\"noopener noreferrer\">żwiry</a>, <a href=\"https://pl.wikipedia.org/wiki/Piasek\" target=\"_blank\" rel=\"noopener noreferrer\">piaski</a>, <a href=\"https://pl.wikipedia.org/wiki/Py%C5%82_(ska%C5%82a)\" target=\"_blank\" rel=\"noopener noreferrer\">pyły</a>), <a href=\"https://pl.wikipedia.org/wiki/Glina\" target=\"_blank\" rel=\"noopener noreferrer\">gliny</a>, transportowanych i osadzanych przez lodowiec, pochodzących głównie z niszczenia jego podłoża, ze zboczy wznoszących się ponad powierzchnię lodowca, jak również przynoszonych przez <a href=\"https://pl.wikipedia.org/wiki/Lawina\" target=\"_blank\" rel=\"noopener noreferrer\">lawiny</a> i wiatr.", "Magnolia": "<p>Magnolia (lat. Magnolia) - rodzaj roślin kwiatowych z rodziny Magnoliaceae, zawierający około 240 gatunków.</p>", "Milly": "<p>Milly jest gminą w prowincji Manche w północno-zachodniej Francji. Znajduje się w regionie o średniej wysokości 103 metrów nad poziomem morza.</p>", "Milania": "<p>Melania to kobiece imię pochodzące z łacińskiego pochodzenia, które pochodzi od greckiego słowa melaina (μέλαινα), żeńskiej formy przymiotów melas (μέλας), co oznacza \"czarny\" lub \"ciemny\". Nazwa ta nosiła dwie święte Melania Starszą i jej wnuczka Melania Młodsza, a pochodzenie nazwy Melanie.</p>", "Margaux": "<p>Margaux to gmina w prowincji Gironde, w francuskim regionie Nouvelle-Aquitaine, licząca 1338 mieszkańców (w 1999 r.). Światowo słynne z czerwonego wina.</p>", "Maxima": "<p>Maxima to wolny system algebra komputerowa napisany w języku Common Lisp. Wynosi się z systemu Macsyma, opracowanego w MIT w latach 1968-1982 w ramach projektu Project MAC, finansowanego przez Departament Energii USA (DOE) i inne organizacje państwowe.</p>", "Mary Grace": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mary</b>.</p><p>Mary: Mary (Mary, rzadko Marie) - angielskie nazwisko kobiece, odpowiadające rosyjskiej nazwie Maria. Jest to jedno z najstarszych nazw zachowanych do naszych czasów.</p>", "Mariella": "<p>Mariella - 11-palowy rejs pasażerski i autostopowy par z finskiego koncernu statkowego Viking Line. Wykonuje regularne lotu na trasie Helsinka-Mariehamn/Longnes-Stokholm.</p>", "Miria": "<p>Miria może odnosić się do: Miria, Mali Miria, Niger Miria jest również nazwiskiem dla kobiet. W języku maorskim Mīria jest transliteracją imienia Amelia.</p>", "Mykhailina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mikhailina</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mikhail</b>.</p><p>Michał (Hebrajskie: מִיכָאֵל; Aramejski: ⁇ , romanized: Mīkhāʼēl) jest powszechnym męskim imieniem, które zazwyczaj uważa się za pochodzące z hebrajskiego pytania retorycznego מי כאל (mī kāʼēl), \"Kto [jest] podobny do [Hebrajskiego boga] El?\", a więc jest nazwiskiem teoforycznym, którego odpowiedź brzmi \"nie ma nikogo podobnego do El\", lub \"nie słynny i potężny jak Bóg\".[is] Paradoksalnie, nazwisko jest czasami interpretowane jako \"Jeden...</p>", "Macarena": "<p>⁇ Macarena ⁇ (wygłaszane ⁇ Macarena ⁇) - piosenka hiszpańskiego duetu muzycznego Los del Río z ich albumu z 1993 roku A mí me gusta. Piosenka stała się międzynarodowym hitem w latach 1996-1997.</p>", "Milka": "<p>Milka (r. Milka) - marka czekolady należąca do firmy Mondelēz International.</p>", "Melany": "<p>Melanie to kobiece imię pochodzące od greckiego μελανία (melania), \"czarność\", a od μέλας (melas), oznaczające \"ciemny\". Urodzony w łacinie przez dwóch świętych, Melanię Starszą i jej wnuczkę Melanię Młodszą, nazwę wprowadzili do Anglii Normanie w francuskiej formie Melanie.</p>", "Mikayla": "<p>Michaela (Hebrajsky מיכאלה) to imię kobiet. Jest to kobieca forma hebrajskiego imienia Michał (מִיכָאֵל), co oznacza \"Kto jest podobny do Boga\".</p>", "Maria-Magdalena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mary Jane": "<p>Mary Jane, Mary-Jane lub Mary Jayne to podwójne imię, które może odnosić się do:</p>", "Millena": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Milena</b>.</p><b>Milena</b> lub <b>Milana</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, używane w językach <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_bu%C5%82garski\" target=\"_blank\" rel=\"noopener noreferrer\">bułgarskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_czeski\" target=\"_blank\" rel=\"noopener noreferrer\">czeskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_s%C5%82owacki\" target=\"_blank\" rel=\"noopener noreferrer\">słowackim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbsko-chorwacki\" target=\"_blank\" rel=\"noopener noreferrer\">chorwackim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">polskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbski\" target=\"_blank\" rel=\"noopener noreferrer\">serbskim</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_s%C5%82owe%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">słoweńskim</a>. Zawiera pierwiastek <i>mil</i> oznaczający „miły”. Męskim odpowiednikiem imienia jest <a href=\"https://pl.wikipedia.org/wiki/Milan_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Milan</a>.", "Maria Alejandra": "<p>María Alejandra lub Marialejandra to hiszpańskie imię żeńskie, które może odnosić się do Marii Alejandra Bravo (ur. 1961), meksykańskiej biochemicznej María Alejandra Guzmán (ur. 1984), dominikanskiej gospodarki telewizyjnej i radiowej, aktorki i modelu María Alejandra Idrobo (ur. 1988), kolumbijskiej sprinterki Marialejandra Marrero (ur. 1991), wenezuelskiej osobowości internetowej Marialejandra Martín (ur. 1964), wenezuelskiej aktorki Maria Alejandra Quintanilla (ur. 1990),...</p>", "Mata": "<p>Mata jest miastem w brazylijskim stanie Rio Grande do Sul. Miasto ma powierzchnię 312,12 km2, liczba ludności w 2007 roku wynosi 5291 osób, a jego gęstość wynosi 16,95 osób/km2.</p>", "Maria Jose": "<p>María José to hiszpańskie imię dla kobiet. Maria José to portugalska imiona dla kobiet.</p>", "Marilou": "<p>Mary Lou, Mary-Lou, Marylou lub Marilou to żeńskie imię. To kombinacja nazw Mary i Lou.</p>", "Maria Antonina": "<p>Maria Antonina jest kobiece związek, nazwę nazwa od imion Miriam i Antonius. Do wybitnych osób, o których mowa w tym imieniu, należą: Maria Antonina Kratochwil (1881-1942), Austriackiego-Węgierskiego beatyfikowanego męczennika Maria Antonina Boniecka, znana jako Maria Boniecka (1910-1978), polska autorka i nauczycielka Maria Antonina Czaplicka, znane jako Maria Czaplicko, (1884-1921), polska antropolog kultura</p>", "Mayia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mayya</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maya</b>.</p><p>Maya: Autodesk Maya to redaktor grafiki trójwymiarowej. Maya - album Banco de Gaia z 1994 roku.</p>", "Maiya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maia</b>.</p><p>Maia (grek. Μαῖα; lat. Maia), w starożytnej greckiej religii, była jedną z Pleiad i matką Hermesa. Maia była córką Atlas i Pleione the Oceanid, a była najstarszą z siedmiu Pleiad.</p>", "Marga": "Chrząszcze o wydłużonym ciele. Głowę mają owalną lub okrągławą, węższą od <a href=\"https://pl.wikipedia.org/wiki/Przedplecze\" target=\"_blank\" rel=\"noopener noreferrer\">przedplecza</a>, o <a href=\"https://pl.wikipedia.org/wiki/Skro%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">skroniach</a> od spodu zwykle odgraniczonych ostrą listewką, a oczach różnych rozmiarów. Znajdujące się na głowie punkty <a href=\"https://pl.wikipedia.org/wiki/Czo%C5%82o_(anatomia)\" target=\"_blank\" rel=\"noopener noreferrer\">czołowe</a>, ciemieniowe i skroniowe są istotne w <a href=\"https://pl.wikipedia.org/wiki/Oznaczanie_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">oznaczaniu</a>. Paciorkowate czułki mają pierwszy człon krótszy niż dwa następne razem wzięte. Aparat gębowy cechują <a href=\"https://pl.wikipedia.org/wiki/Warga_g%C3%B3rna\" target=\"_blank\" rel=\"noopener noreferrer\">warga górna</a> o przedniej krawędzi wykrojonej, niewykrojonej lub wciętej, <a href=\"https://pl.wikipedia.org/wiki/%C5%BBuwaczka\" target=\"_blank\" rel=\"noopener noreferrer\">żuwaczki</a> z jednym lub dwoma zębami na krawędziach wewnętrznych, ostatni człon głaszczków szczękowych nie krótszy i węższy od poprzedniego, zaostrzony lub wrzecionowaty u szczytu, a ostatni człon krótkich <a href=\"https://pl.wikipedia.org/wiki/G%C5%82aszczki_wargowe\" target=\"_blank\" rel=\"noopener noreferrer\">głaszczków wargowych</a> stożkowaty lub wrzecionowaty i dłuższy od poprzedniego. <a href=\"https://pl.wikipedia.org/wiki/Przedtu%C5%82%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Przedtułów</a> cechuje się <a href=\"https://pl.wikipedia.org/wiki/Skleryt\" target=\"_blank\" rel=\"noopener noreferrer\">zesklerotyzowanymi</a> epimerami trójkątnego kształtu. <a href=\"https://pl.wikipedia.org/wiki/Przedplecze\" target=\"_blank\" rel=\"noopener noreferrer\">Przedplecze</a> zwykle ma dwa grzbietowe rzędy po 2–4 punkty oraz parę dużych punktów przy brzegach bocznych, zaś jego <a href=\"https://pl.wikipedia.org/wiki/Epipleury\" target=\"_blank\" rel=\"noopener noreferrer\">epipleury</a> są podwinięte na spód i z boku niewidoczne. Przednia para odnóży ma u obu płci rozszerzone <a href=\"https://pl.wikipedia.org/wiki/Stopa_sze%C5%9Bcionog%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">stopy</a>.", "Myla": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mila</b>.</p><p>Mylka drniysta (lat. Mila caespitosa) - jedyny gatunek jaktusu z rodu Mylka (lat.</p>", "Miłana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Milan</b>.</p><b>Milan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię słowiańskie</a>. Jedno z licznych <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">zdrobnień od imion słowiańskich</a> zaczynających się na <i>Miło-</i>, takich jak <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82obor\" target=\"_blank\" rel=\"noopener noreferrer\">Miłobor</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82obrat\" target=\"_blank\" rel=\"noopener noreferrer\">Miłobrat</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82ogost_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miłogost</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82ogost_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miłgost</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82orad\" target=\"_blank\" rel=\"noopener noreferrer\">Miłorad</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82os%C5%82aw_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miłosław</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82os%C5%82aw_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miełosław</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82ostryj\" target=\"_blank\" rel=\"noopener noreferrer\">Miłostryj</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82owit\" target=\"_blank\" rel=\"noopener noreferrer\">Miłowit</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82owit\" target=\"_blank\" rel=\"noopener noreferrer\">Miłwit</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82osz\" target=\"_blank\" rel=\"noopener noreferrer\">Miłosz</a>. Obecnie imię Milan używane jest także samodzielnie.", "Maria Krystyna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Marta-Mariia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marta</b>.</p><b>Marta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. Wywodzi się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_aramejski\" target=\"_blank\" rel=\"noopener noreferrer\">aramejskiego</a> rzeczownika <i>mar</i>, <i>mar(a)tha, marta</i>, oznaczającego „pani domu, gospodyni, pani”. W Polsce po raz pierwszy zanotowano je w 1265 roku. Do dawnych zdrobnień zaliczała się np. Marusza (wsł., od wsł. <i>Marchwa</i>), oraz m.in. <i>Marocha, Marsza, Marszka, Marucha, Maruchna, Maruszka</i> (też od innych imion na Ma-, np. od <a href=\"https://pl.wikipedia.org/wiki/Ma%C5%82gorzata_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Małgorzaty</a>). Istnieje ponad 10 świętych katolickich o tym imieniu.", "Meghan": "<p>Megan to waliska nazwisko kobiece, pierwotnie maleńka forma Margaret. Margaret pochodzi od greckiego μαργαρίτης (margarítēs), łacińskiego margarīta, \"perła\".</p>", "Mścisława": "<b>Mścisława</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z dwóch członów: <i>Mści-</i> (\"mścić\") i <i>-sława</i> (\"sława\"). Mogło oznaczać \"tę, która zdobywa sławę mszcząc się na swych wrogach\". Poświadczone w źródłach jako Mścisława (1360) i formach zdrobniałych Mścicha (1394), Mścichna (1383).", "Morgana": "Przedstawiana zawsze jako obdarzona wielką mocą czarodziejka, żeński odpowiednik Merlina i jego mocy, w niektórych wersjach legendy działa przeciwko królowi Arturowi i jego żonie <a href=\"https://pl.wikipedia.org/wiki/Ginewra\" target=\"_blank\" rel=\"noopener noreferrer\">Ginewrze</a>. W <i><a href=\"https://pl.wikipedia.org/wiki/%C5%9Amier%C4%87_Artura\" target=\"_blank\" rel=\"noopener noreferrer\">Le Morte d’Arthur</a></i> <a href=\"https://pl.wikipedia.org/wiki/Thomas_Malory\" target=\"_blank\" rel=\"noopener noreferrer\">Thomasa Malory’ego</a> jest nieszczęśliwą żoną króla Uriena, spiskującą przeciwko Arturowi i pragnącą zapewnić władzę swojemu ukochanemu Akkolonowi.", "Mariza": "<p>Mariza (Mariza, pełne imię - Mariza duż Re'ysz Nunes, port. Marisa dos Reis Nunes) - portugalska piosenkarka, wykonawczyni fadu.</p>", "Markiza": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Markiz</b>.</p>Wyraz pochodzi z francuskiego <i>marquis</i>, które wywodzi się najwyraźniej z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a> słowa oznaczającego granicę (<i>mark</i>). W języku niemieckim odpowiadający tytuł to <i>Markgraf</i>, co można analizować jako <i>Mark + graf</i> = granica + <a href=\"https://pl.wikipedia.org/wiki/Hrabia\" target=\"_blank\" rel=\"noopener noreferrer\">hrabia</a>, tj. hrabia opiekujący się granicami. Dawniej hrabia, który chronił granice, był bardziej uprzywilejowany od innych hrabiów, co tłumaczy stosunkowo wysoką pozycję w hierarchii, tym bardziej, że mógł zdobyte na sąsiadach (przeważnie barbarzyńcach) ziemie dodawać do swojej domeny.", "Mariko": "<b>Mariko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;まりこ, マリコ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Meli̇s": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Melisa</b>.</p><b>Melisa</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, oznacza „pszczołę” (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;μέλισσα). W <a href=\"https://pl.wikipedia.org/wiki/Mitologia_grecka\" target=\"_blank\" rel=\"noopener noreferrer\">greckiej mitologii</a> Melissa była jedną z <a href=\"https://pl.wikipedia.org/wiki/Nimfy\" target=\"_blank\" rel=\"noopener noreferrer\">nimf</a> opiekujących się małym <a href=\"https://pl.wikipedia.org/wiki/Zeus\" target=\"_blank\" rel=\"noopener noreferrer\">Zeusem</a>.", "Maria Anna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria Fernanda": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Muna": "<p>Muna jest miastem w stanie Yucatán w Meksyku. W 2005 roku liczba mieszkańców miasta wynosiła 11763.</p>", "Miliana": "<p>Miliana jest miastem w prowincji Ain Defla w Algierii. W 2002 roku liczba ludności wynosiła 39 662.</p>", "Maree": "<p>Maree to imię i nazwisko. Może być używany jako wariant Marie.</p>", "Mine": "<p>Mine może odnosić się do: Mine, Yamaguchi \"Mine\" (piosenka The 1975), 2018 \"Mine\", 2017 \"Mine\". (piosenta Beyoncé), 2013 \"Mine\"; 2023 \"Mine\"? (pioseta Alice Glass), 2018 \"mine\"? (pieśeta Taylor Swift), 2010</p>", "Meerim": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Merim</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Merima</b>.</p><p>Merima to imiona żeńskie, które ma oddzielne pochodzenie habesha i słowiańskie.</p>", "Miłochna": "<b>Miłochna</b> – forma pochodna (zdrobnienie) od staropolskich <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imion</a> żeńskich rozpoczynających się na <i>Miło-</i>, takich jak <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82os%C5%82awa\" target=\"_blank\" rel=\"noopener noreferrer\">Miłosława</a>. Poświadczone w źródłach polskich od XIII wieku (1265 rok).", "Mariama": "<p>Mariama to imię kobiety. Może odnosić się do: Mariama Bâ (1929-1981), wenejskiej pisarki i feministki Mariama Gaye (ur. 1993), gambijsko-szwedzkiej modelu Mariama Barry, senegalijskiej powieścipowieściarzy Mariama Sonah Bah (ur. 1978), gwinejskiej judoki Mariama Souley Bana (ur. 1987), nigerijskiej pływaczki Mariama Dalanda Barry (ur. 1991), gwinejska praktykantka taekwondo Mariama Gamatié Bayard (ur. 1958), nigerińskiej politykki i działacki na rzecz praw kobiet Mariama Camara ...</p>", "Mariia-Viktoriia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Miley": "<p>Miley Ray Cyrus (urodzina Destiny Hope Cyrus; 23 listopada 1992) jest amerykańską piosenkarką, muzyką i aktorką. Jest wpływową postacią pop, znana z ciągle zmieniającego się stylu artystycznego i \"złupnych\" wzorów.</p>", "Maritta": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Marita</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Miss": "<p>Miss - trzeci studiowy album rosyjskiej piosenkarki Dory, wydany 3 czerwca 2022 roku na wytwórni Rhymes Music. Album zawiera 13 utworów.</p>", "Márta": "<p>Marta jest nazwiskiem żeńskim pochodzącym z aramejskiej nazwy ⁇ (Mârtâ, w syryckim alfabetze, מָרְתָא w hebrajskim), który tłumaczy się jako \"damo\" w języku angielskim. W kulturze rzymskiej miał męską formę \"Martinus\".</p>", "Madelaine": "<p>Madelaine to kobiece imię. To wariant nazwiska Madeleine.</p>", "Mariyana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mariyan</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Marian</b>.</p><b>Marian</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> od imienia <i>Marius</i> lub nazwy rodu <i>Marii</i>. Oznacza „należący do Mariusza, rodu Mariuszów”. Występuje w Polsce od 1332 roku, jako <b>Marzyjan</b>. Forma Marian pojawiła się w Polsce w XVI wieku. W języku angielskim używane jest jako imię żeńskie. W Polsce w żeńskim użyciu w 2025 roku wystąpiło 35 razy.", "Maria Barbara": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Marivic": "<p>Marivic to filipińskie imię pochodzące od nazwisk María i Victoria, które mogą odnosić się do: Marivic Co-Pilar (ur. 1971), filipiński polityk Marivic Velaine Meneses (ur. 1995), filipińskiego piłkarza siatkówki</p>", "Maria Zofia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mikhalina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Michalina</b>.</p><b>Michalina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Micha%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Michał</a>. Oznacza „któż [jest] jak Bóg”. Imię to nadawane jest w tej formie w Polsce przynajmniej od <a href=\"https://pl.wikipedia.org/wiki/1744\" target=\"_blank\" rel=\"noopener noreferrer\">1744</a> roku, natomiast już w średniowieczu notowano jako żeński odpowiednik Michała formę <i><b>Michaelis</b></i> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>), zdrobniale – Michałka. Wśród imion nadawanych nowo narodzonym dzieciom, Michalina w 2018 r. zajmowała 24. miejsce w grupie imion żeńskich.", "Maria Jadwiga": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria De Los Angeles": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mirna": "<p>Mirna jest samorządem (słowenijski občine, mniejszość - občina) w Dolenjska regionie Słowenii. Mirna ma powierzchnię km2, populacja, według sondażu z 31 marca 2002 roku, jest ludźmi.</p>", "Madalena": "<p>Madalena jest miastem w Brazylii. Miasto ma powierzchnię 1034,773 km2, liczba ludności w 2007 roku wynosi 15950 osób, a jego gęstość wynosi 15,41 osoby/km2.</p>", "Margie": "<p>Margie to kobiece imię, zazwyczaj skrótowana forma (hipokoryzm) powiązanych nazw Margaret, Marjorie lub Margarita, które wszystkie oznaczają \"perła\". Margie może odnosić się do:</p>", "Madelyn": "<p>Madelyn lub Madalyn to żeńskie imię, wariant Madeline lub Madeleine. Do wybitnych osób z tymi nazwami należą:</p>", "Miho": "<b>Miho</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;みほ, ミホ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Maria Helena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mayumi": "<b>Mayumi</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;まゆみ, マユミ) – głównie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>, rzadko noszone przez mężczyzn.", "Maria Jolanta": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Macy": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maci</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mac</b>.</p><p>Macintosh [ˈmækɪntɒʃ] lub Mac [mæk] - linia komputerów osobistych produkowanych przez Apple. Pracują pod zarządzaniem systemami operacyjnymi rodziny Mac OS, możliwe jest również praca na OS Windows NT, A/UX, NeXTSTEP, BeOS/Haiku, GNU/Linux i Rhapsody.</p>", "Maria Elżbieta": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mai Anh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mai</b>.</p><b>Mai</b> – imię dwupłciowe używane w wielu państwach świata.", "Mary Joy": "<p>Mary Joy to kobiece imię. Wśród znanych osób z tym nazwiskiem są: Mary Joy Dela Cruz Baron, urodzina Majoy Baron (urodzona w 1995 roku), filipinańska piłkarka siatkówki Mary Joy Langdon (urodzony w 1951 roku), angielska katolickia zakonnica i strażak Mary Joy Tabal (urodzone w 1989 roku), filibinańska biegaczka maratonu</p>", "Maryta": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Marita</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria Camila": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Montserrat": "<p>Montserrat (MONT-sə-RAT) jest brytyjskim Terytorium Morza Pozdrowego w Karaibach. Jest częścią Wysp Leeward, północnej części łańcucha Małych Antyli w Indiach Zachodnich.</p>", "Margareth": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Margaret</b>.</p><p>Margaret (jap. マーガレット) - japoński czasopism manga, wydany dwa razy w miesiącu przez firmę Shueisha.</p>", "Marilena": "<p>Marilena to miasto w brazylijskim stanie Paraná. Miasto to ma powierzchnię 232,366 km2, liczba ludności w 2007 roku wynosi 6715 osób, a jego gęstość wynosi 29,2 osoby/km2.</p>", "Mélissa": "<p>Melissa to kobiece imię. Nazwa pochodzi od greckiego słowa μέλισσα (mélissa), \"pszczoły\", które z kolei pochodzi od μέλι (meli), \"miód\".</p>", "Mareike": "<p>Marijke, czasami germańska Mareike, to holenderskie kobiece imię. To pierwotnie diminutiw Mary.</p>", "Memory": "<p>Memory (z angielskiego - ⁇ memmemować ⁇): ⁇ Memory ⁇ - główna tema muzyka Andrew Lloyd Webbera ⁇ Koshki ⁇ Memory - demo-zapis metalowej grupy S. C. A. L. P.</p>", "Medarda": "<b>Medarda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a> imienia męskiego <a href=\"https://pl.wikipedia.org/wiki/Medard_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Medard</a>, powstałego z członów <i>maht</i> — \"potęga, władza, moc, męstwo\" oraz <i>hart</i> — \"silny, odważny, śmiały\".", "Mili": "<b>mili</b> (<b>m</b>) – przedrostek <a href=\"https://pl.wikipedia.org/wiki/Jednostka_miary\" target=\"_blank\" rel=\"noopener noreferrer\">jednostki</a> <a href=\"https://pl.wikipedia.org/wiki/Miara_(metrologia)\" target=\"_blank\" rel=\"noopener noreferrer\">miary</a> oznaczający mnożnik 0,001 = 10 (jedna tysięczna).", "Melitta": "<p>Melitta Group (rosyjski: Melitta Grupa) - niemiecka firma, która zajmuje się różnymi dziedzinami biznesu, której głównymi kierunkami działalności są produkcja i sprzedaż produktów firmy w dziedzinie gotowania kawy (biotnicznych i profesjonalnych maszyn kawy, kawy, akceswari) i herbaty, przechowywania i przygotowywania jedzenia, a także domowego sprzątania.</p>", "Mariyam": "<p>Maryam lub Mariam (Hebrajskie: מרים; Aramejski Imperial: ⁇; Arabski: مريم) jest aramejską formą biblijnej nazwy Miriam (nazwa prorokiny Miriam, siostry Mojżesza). Jest to szczególnie imię Maryi, matki Jezusa.</p>", "Monalisa": "<p>Mona Lisa lub La Joconde (La Gioconda lub La Jocondé, Obraz Lisa Gherardini, żona Francesco del Giocondo) to 16-wieczny portret malarski na drewnianym płytce w Florencji przez Leonarda da Vinci w okresie renesansu włoskiego. Dzieło należy do rządu francuskiego i jest obecnie wystawiane w muzeum Louvre w Paryżu, Francja pod nazwą Obraz Lisa Gherardini, żona Francesco del Giocondo.</p>", "Mía": "<p>Mia to powszechne nazwisko dla niektórych gatunków w rodzinnym rodzinniku Mia (Saccharum), oprócz szczurów, łach. Są to tradycyjne, trwałe, tradycyjne zioła z rodziny Andropogoneae (Poaceae), rodzimie w tropikach i w ciepłych regionach Starego Świata.</p>", "Maurycja": "<b>Maurycja</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, żeński odpowiednik imion <a href=\"https://pl.wikipedia.org/wiki/Maurycy\" target=\"_blank\" rel=\"noopener noreferrer\">Maurycy</a> i <a href=\"https://pl.wikipedia.org/wiki/Maurycjusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Maurycjusz</a>. Wywodzi się od słowa oznaczającego „pochodząca z Mauretanii”, „Maur”.", "Mirtha": "<p>Mirtha to imię kobiety. Do wybitnych osób z nazwiskiem należą: Mirtha Brock (ur. 9 kwietnia 1970), Kolumbijska sportowca Mirtha Colón (ur. 1951), hondurańska aktywistka Mirtha Dermisache (1940-2012), argentyńska artystka Mirth Legrand (ur. 1927), argentyńska aktorka i prezenterka telewizji Mirtha Marrero, kubańska rzuca Mirth Michelle (ur. 1984), amerykańska aktorka Mirtho N.</p>", "Maëlle": "<p>Mael Pistoja (francuski: Mael Pistaia). Maëlle Pistoia, rodzaj.</p>", "Mahsa": "<p>Mahsa lub Mahsā jest imieniem żeńskim pochodzącym z Persu. Nazwa ma znaczenie \"jak księżyc\".</p>", "Marie-Louise": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Millenia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Milenia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mileni</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Milen</b>.</p><p>Milen (bułgarski: Милен) to bułgarskie męskie imię. Wśród znanych osób z tej nazwy są: Milen Bonev (ur. 1986), bułgarski piłkarz, obecnie grający dla Kaliakra Kavarna jako obrońca Milen Dobrev (ur. 1980), bułgarski ciężarosta Milen Hristov (ur. 1977), bułgara piłkarza piłkarka, który obecnie gra dla Neftochimic Burgas jako półbrzeg Milen Lahchev (ur., 1987), bułgaria piłkarze, obecnie gry...</p>", "Mansi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Måns</b>.</p><p>Måns to szwedzka męska nazwa, która może odnosić się do Måns, fikcyjnego kota w Pelle Svanslös dziecka historii Gösta Knutsson 8536 Måns, niewielkiej planety nazwanej po kota Måns Andersson, 17-wieczny szwedzki odkrywca Måns Ekvall (ur. 1995), szwedzkiej piłkarz Måns Forsfjäll (ur. 2002), szwedyckiego obrońca hokeja na lodzie Måns Gahrton (ur. 1961), szwedeski autor Måns Grenhagen (ur. 1993), szwedski kierowca wyścigów Måns Groundstroem (ur....</p>", "Mania": "<p>Mania (stylizowana M A N I A, oficjalna nazwa Mania: A Fall Out Boy LP) - siódmy album studio amerykańskiego zespołu rockowego Fall Out Boy, wydany 19 stycznia 2018 roku na wytwórniach Island Records i DCD2 Records jako następny po 2015 roku albumie American Beauty/American Psycho. Przed wydaniem albumu wydano pięć singli: ⁇ Young and Menace ⁇ , ⁇ Champion ⁇ , ??The Last of the Real Ones ⁇ , ⁇ Hold Me Tight or Don't ⁇ i ⁇ Wilson (Expensive...</p>", "Maria Józefa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Margrit": "<p>Margrit to imię, co odpowiada angielskiej nazwie Margaret. Wśród znanych osób z tego nazwiska są: Margrit Bolli (1919-2017), szwajcarska tancerka Margrit Brückner (ur. 1946), niemiecki socjolog i profesor Margrit Conrad (1918-2005), szwajcarski piosenkarz Margrit Gertsch (ur. 1939), szwajcarka narciarka Alpinowa Margrit Hess (ur. 1947), szwajcaria biegaczka średniej odległości Margrit Kennedy (1939 -2013), niemiecka architekt, profesor, ekolog, autor i...</p>", "Maika": "<p>Dziewczyna z chmur (Słowacko: Spadla z oblakov, \"Spadła z obłoku-płuk\", Wietnam: Maika - Dziewczyna spadająca z nieba) to film telewizyjny science fiction nadawany w języku słowackim dla dzieci w 1978 roku. Film jest bardzo popularny w Czechoslovakie i wielu krajach na świecie.</p>", "Maria Del Pilar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Margaritta": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Margarita</b>.</p><p>Margarita to meksykański koktajl zawierający tequila, pomarańczową wodę i wodę z cynamonu, często rozproszoną solą na szklance. Wypłaty są przygotowywane poprzez wstrząsanie z kamieni (na skalę), wstrząsnięcie z kamieniami (zamrożona margarita), lub bez kamieni (pić prosto).</p>", "Mariia-Khrystyna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mi̇ne": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Min</b>.</p><p>Min to niejednoznaczny termin. min - w matematyce i językach programowania oznacza funkcję wyboru najmniejszego ze swoich argumentów, (Min (3, 6, 2) = 2).</p>", "Maria Irena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Marzia": "<p>Marcia Chelberg (szwedzka. Marzia Kjellberg, w dziewictwie - Bizonjín (italijczyka.</p>", "Maria Stanisława": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maryann": "<p>Mary Ann lub Maryann lub Mary Anne to kobiece imię, połączenie nazw Mary i Anne. Może odnosić się do:</p>", "Maria Ewa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Meredith": "<b>Meredith</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_walijski\" target=\"_blank\" rel=\"noopener noreferrer\">walijskiego</a>, początkowo męskie, od imienia Maredudd – \"wielki pan\"; w XX wieku używane również jako imię żeńskie. Występuje też jako <a href=\"https://pl.wikipedia.org/wiki/Nazwisko\" target=\"_blank\" rel=\"noopener noreferrer\">nazwisko</a>.", "Makayla": "<p>Michaela (Hebrajsky מיכאלה) to imię kobiet. Jest to kobieca forma hebrajskiego imienia Michał (מִיכָאֵל), co oznacza \"Kto jest podobny do Boga\".</p>", "Minji": "<p>To jest jeden z nich, Kim. Kim Min-ji (Hangul: 김민지; Hanja: 金 ⁇ 池; ur. 7 maja 2004), popularnie znana pod pseudonimem Minji, jest koreańską piosenkarką, członkiem zespołu NewJeans przez ADOR, spółkę zależną HYBE założoną i zarządzającą.</p>", "Melanya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Melany</b>.</p><p>Melanie to kobiece imię pochodzące od greckiego μελανία (melania), \"czarność\", a od μέλας (melas), oznaczające \"ciemny\". Urodzony w łacinie przez dwóch świętych, Melanię Starszą i jej wnuczkę Melanię Młodszą, nazwę wprowadzili do Anglii Normanie w francuskiej formie Melanie.</p>", "Minerva": "<p>Minerva, The International Review of Ancient Art and Archaeology (Minerwa, Międzynarodowy przegląd sztuki antycznej i archeologii) - czasopismo naukowe, publikujące materiały o wystawach, wykopalniach i muzeach, wywiadach, notatkach, sprawozdaniach z aukcji, materiałach nowych, a także recenzjach książek. Występuje raz w dwóch miesiącach.</p>", "Małgorzata Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Małgorzata</b>.</p><b>Małgorzata</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Margarita</em>, które pochodziło od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;μαργαρίτης <i>margarites</i> oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Per%C5%82y_naturalne\" target=\"_blank\" rel=\"noopener noreferrer\">perłę</a>”, które ma źródło w formie <a href=\"https://pl.wikipedia.org/wiki/Derywacja_(j%C4%99zykoznawstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">derywowanej</a> od <a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sanskryckiego</a> मञ्यरी <i>mañjarī</i> oznaczającego m.in. „perłę”, „pąk kwiatowy”, „kwiat”, „<a href=\"https://pl.wikipedia.org/wiki/Li%C5%9B%C4%87\" target=\"_blank\" rel=\"noopener noreferrer\">listowie</a> (w formie ornamentu na budynku)”.", "Mariane": "<p>Marianne to imię kobiety. Jest to francuska wersja greckiego Mariamne, który jest wariantem Maryi, ostatecznie z hebrajskiego Miriam (מִרְיָם Miryám), Mirjam (aramejski: Mariam).</p>", "Mayra Alejandra": "<p>Mayra Alejandra [my'rah / aleh-han'-drah] (7 maja 1958 - 17 kwietnia 2014) była wenezuelską aktorką filmową i telewizyjną.</p>", "Maria Janina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Marcina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Marc</b>.</p><p>Marc: MARC (ang. Machine-Readable Cataloging) - grupa formatów (MARC21, UNIMARC, RUSMAC itp.</p>", "Megumi": "<b>Megumi</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;めぐみ, メグミ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Malva": "<p>Malwa, lub Proswyrnik (lat. Málva), - rodzaj trawianowych roślin rodziny Malvaceae, typowy rodzaj tej rodziny.</p>", "Maria Del Mar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mary-Ann": "<p>Mary Ann lub Maryann lub Mary Anne to kobiece imię, połączenie nazw Mary i Anne. Może odnosić się do:</p>", "Miyuki": "<b>Miyuki</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;みゆき, ミユキ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Maksymilianna": "<b>Maksymiliana</b>, <b>Maksymilianna</b> – żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Maksymilian\" target=\"_blank\" rel=\"noopener noreferrer\">Maksymilian</a>. Imiona te pochodzą od nazwiska rodu <a href=\"https://pl.wikipedia.org/wiki/Emiliusze\" target=\"_blank\" rel=\"noopener noreferrer\">Emiliuszów</a>.", "Maria Władysława": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mariia-Anastasiia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mary Rose": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mary</b>.</p><p>Mary: Mary (Mary, rzadko Marie) - angielskie nazwisko kobiece, odpowiadające rosyjskiej nazwie Maria. Jest to jedno z najstarszych nazw zachowanych do naszych czasów.</p>", "Marie-Christine": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Melanija": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Melania</b>.</p><b>Melania</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;μέλας, znaczącego „czarna”.", "Mariiana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mariian</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Marian</b>.</p><b>Marian</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> od imienia <i>Marius</i> lub nazwy rodu <i>Marii</i>. Oznacza „należący do Mariusza, rodu Mariuszów”. Występuje w Polsce od 1332 roku, jako <b>Marzyjan</b>. Forma Marian pojawiła się w Polsce w XVI wieku. W języku angielskim używane jest jako imię żeńskie. W Polsce w żeńskim użyciu w 2025 roku wystąpiło 35 razy.", "Madalina": "<p>Mădălina to rumuńska kobieca nazwa, która może odnosić się do: Mădăline Cioveie (ur. 1983), rumuńska gimnastka aerobowa Mădălină Diana Ghenea (ur. 1987), rumuńskiej włoskiej aktorki i modelu Mădălinei Gojnea (ur. 1987), rumuńskiego tenisa Mădăliny Manole (1967-2010), rumuński pop artysta Mădălino Zamfirescu (ur. 1994), rumuńczyka piłkarka ręka</p>", "Maria Danuta": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Midori": "<b>Midori</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;みどり, ミドリ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Minka": "<p>Minka (ur. 7 września 1970 -) jest koreańsko-amerykańską gwiazdą filmową i tenisistą.</p>", "Melia": "Była córką <a href=\"https://pl.wikipedia.org/wiki/Okeanos\" target=\"_blank\" rel=\"noopener noreferrer\">Okeanosa</a>. Została kochanką boga <a href=\"https://pl.wikipedia.org/wiki/Apollo\" target=\"_blank\" rel=\"noopener noreferrer\">Apollina</a>, z którym spłodziła Ismeniosa i Temerosa. Czczono ją wraz z Apollinem w świątyni koło <a href=\"https://pl.wikipedia.org/wiki/Teby_(Grecja)\" target=\"_blank\" rel=\"noopener noreferrer\">Tebami</a>. Jej imieniem nazwano też źródło w samych Tebach. Niektóre źródła podają, że wśród <a href=\"https://pl.wikipedia.org/wiki/Okeanidy\" target=\"_blank\" rel=\"noopener noreferrer\">okeanid</a> była też inna Melia, małżonka boga rzeki <a href=\"https://pl.wikipedia.org/wiki/Inachos\" target=\"_blank\" rel=\"noopener noreferrer\">Inachos</a>.", "Malgosia": "<p>Małgosia to polskie imię dla kobiet. Jest to diminutiw nazwiska Małgorzata.</p>", "Malwa": "<b>Malwa</b>, topolówka (<i>Alcea</i> <a href=\"https://pl.wikipedia.org/wiki/Karol_Linneusz\" target=\"_blank\" rel=\"noopener noreferrer\">L.</a>) – <a href=\"https://pl.wikipedia.org/wiki/Rodzaj_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">rodzaj</a> roślin z rodziny <a href=\"https://pl.wikipedia.org/wiki/%C5%9Alazowate\" target=\"_blank\" rel=\"noopener noreferrer\">ślazowatych</a>. Podawanych jest z niego ok. 60, 70, 80 <a href=\"https://pl.wikipedia.org/wiki/Gatunek_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">gatunków</a>. Pochodzą one głównie ze wschodniej części basenu Morza Śródziemnego (tylko w <a href=\"https://pl.wikipedia.org/wiki/Turcja\" target=\"_blank\" rel=\"noopener noreferrer\">Turcji</a> rośnie 18 gatunków). Poza tym rosną w południowej i wschodniej Europie oraz południowo-zachodniej i centralnej Azji. W <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">Polsce</a> jako przejściowo dziczejącą (<a href=\"https://pl.wikipedia.org/wiki/Efemerofit\" target=\"_blank\" rel=\"noopener noreferrer\">efemerofit</a>) stwierdzono tylko malwę pomarszczoną <i>A. rugosa</i>. W naturze przedstawiciele tego rodzaju rosną na suchych, często skalistych siedliskach.", "Maria Cristina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mi̇ra": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mir</b>.</p><b>Mir</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskiego.</a> Powstało jako zdrobnienie imion np: <a href=\"https://pl.wikipedia.org/wiki/Miros%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Mirosław</a>, <a href=\"https://pl.wikipedia.org/wiki/Jaromir\" target=\"_blank\" rel=\"noopener noreferrer\">Jaromir</a>, <a href=\"https://pl.wikipedia.org/wiki/S%C5%82awomir\" target=\"_blank\" rel=\"noopener noreferrer\">Sławomir</a>, <a href=\"https://pl.wikipedia.org/wiki/Radomir\" target=\"_blank\" rel=\"noopener noreferrer\">Radomir</a>, Stanimir itd.", "Margrethe": "<p>Margret (h) e jest alternatywnym pisownieniem kobiecej nazwy Margaret. Wśród takich osób znajdują się: Margrete lub Margaret I z Danii (1353-1412), królowa Danii i królowa Norwegii i Szwecji z małżeństwa Margrethe II z Danii (ur. 1940), królowo regnant z Danii od 1972 do 2024 Margaret z Szwecji, królowa Norweska (około roku 1412).</p>", "Meagan": "<p>Megan to waliska nazwisko kobiece, pierwotnie maleńka forma Margaret. Margaret pochodzi od greckiego μαργαρίτης (margarítēs), łacińskiego margarīta, \"perła\".</p>", "Mariia-Sofiia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mahira": "<p>Mahira jest miastem censusem Barddhaman w stanie Bengal Zachód, India.</p>", "Mamerta": "<b>Mamerta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_italskie\" target=\"_blank\" rel=\"noopener noreferrer\">italskiego</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Mamert\" target=\"_blank\" rel=\"noopener noreferrer\">Mamert</a>, wywodzącego się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_oskijski\" target=\"_blank\" rel=\"noopener noreferrer\">oskijskiego</a> lub sabińskiego wariantu imienia boga <a href=\"https://pl.wikipedia.org/wiki/Mars_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Marsa</a> – <i>Mamers</i>, który w przypadkach zależnych (np. <i>Mamertis</i>) miał temat <i>Mamert</i>.", "Mellisa": "<p>Mellisa to kobiece imię; podobne do Melissa. Znanymi osobami z nazwiskiem są: Mellisa Hollingsworth (ur. 1980), kanadyjska sportowca Mellisa Santokhi-Seenacherry, Pierwsza Dama Surinamu</p>", "Maryka": "<p>Maryka to imię. Do znanych osób z nazwiskiem należą: Maryka Groenewald (fl.</p>", "Minh Trang": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Mikela": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mikel</b>.</p><p>Mikel jest baskijską adaptacją nazwiska Michaela. Nazwa Mikel pochodzi od hebrajskiego słowa Micha'el, co oznacza \"Kto jest jak Bóg\".</p>", "Melanii": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Melani</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Melany</b>.</p><p>Melanie to kobiece imię pochodzące od greckiego μελανία (melania), \"czarność\", a od μέλας (melas), oznaczające \"ciemny\". Urodzony w łacinie przez dwóch świętych, Melanię Starszą i jej wnuczkę Melanię Młodszą, nazwę wprowadzili do Anglii Normanie w francuskiej formie Melanie.</p>", "Mândra": "<p>Mandra jest gmina w Brașov County, Rumunii. W 2002 roku liczba ludności wynosiła 2933 osoby.</p>", "Marie-Anne": "<p>Marie Anne, Marie-Anne lub Marie-Ann to femininowe słowo, które może odnosić się do:</p>", "Maria Del Rosario": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mitchelle": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mitchell</b>.</p><p>Mitchell, Mitchell (ang. Mitchell, Mitchel) - angielskie nazwisko.</p>", "Maria Angelica": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mǎdǎlina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mădălin</b>.</p><p>Mădălin to rumuńskie imię i nazwisko mężczyzny, które może odnosić się do: Mădăline Ciucă (ur. 1982), rumuński piłkarz Mădă Lin Lemnaru (ur. 1989), rumuński piłkarze rugby Mădă lin Marius Popa (ur. 1982) rumuński futbolista i menedżer Mădăilin Martin (ur. 1992), rumuńskiego piłkarza Mădălina Mihăescu (ur. 1988), rumuńczyka piłkarka Mădăl Murgan (ur. 1983), rumuńca piłkarzem Mădă l Popa (UR. 1983), rumunskiego piłkarta Mădălini Răileanu (ur....</p>", "Michiko": "<b>Michiko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;みちこ, ミチコ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Manoni": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Manon</b>.</p><p>Manon to opera pięciu występów francuskiego kompozytora Jules Masseneta. Wśród scenarzystów tej opery byli Henri Meilhac i Philippe Gille.</p>", "Masako": "W dniu 22 października 2019 jej małżonek, cesarz Naruhito, formalnie ogłosił swoją intronizację oraz przyjął gratulacje od przedstawicieli narodu japońskiego i licznych gości zagranicznych. Główna ceremonia intronizacji o nazwie „Sokuirei-Seiden-no-gi” odbyła się w Pałacu Cesarskim w Tokio.", "Maria Isabel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Minh Chau": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Mariia-Mariana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mariia-Diana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Milanna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Milana</b>.</p><b>Milena</b> lub <b>Milana</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, używane w językach <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_bu%C5%82garski\" target=\"_blank\" rel=\"noopener noreferrer\">bułgarskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_czeski\" target=\"_blank\" rel=\"noopener noreferrer\">czeskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_s%C5%82owacki\" target=\"_blank\" rel=\"noopener noreferrer\">słowackim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbsko-chorwacki\" target=\"_blank\" rel=\"noopener noreferrer\">chorwackim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">polskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbski\" target=\"_blank\" rel=\"noopener noreferrer\">serbskim</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_s%C5%82owe%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">słoweńskim</a>. Zawiera pierwiastek <i>mil</i> oznaczający „miły”. Męskim odpowiednikiem imienia jest <a href=\"https://pl.wikipedia.org/wiki/Milan_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Milan</a>.", "Maeva": "<p>Maeva lub Maëva to kobiece imię. Znanymi osobami z nazwiska są: Maëva Charbonnier (ur. 1991), francuska pływaczka synchronizowana Maëva Contion (ur. 1992), francuska obstawiarka Maëva Coucke (ur. 1994), francuska modelowa i Miss France 2018 Maeva Douma (ur. 2005), kamerunska krykerka Maeva Marcus, amerykańska historyk Maeva Sarrasin (ur. 1987), szwajcarka piłkarka Maëva Squiban (ur. 2002), francuska rowerka</p>", "Misaki": "<b>Misaki</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;みさき, ミサキ) – popularne żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>, jest także używane jako nazwisko, bardzo rzadko używane jako imię męskie.", "Maria Paula": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maarit": "<b>Maarit Helena Hurmerinta</b> (z domu <b>Äijö</b>, ur. <a href=\"https://pl.wikipedia.org/wiki/10_listopada\" target=\"_blank\" rel=\"noopener noreferrer\">10 listopada</a> <a href=\"https://pl.wikipedia.org/wiki/1953\" target=\"_blank\" rel=\"noopener noreferrer\">1953</a> w <a href=\"https://pl.wikipedia.org/wiki/Helsinki\" target=\"_blank\" rel=\"noopener noreferrer\">Helsinkach</a>) jest fińską <a href=\"https://pl.wikipedia.org/wiki/%C5%9Apiew\" target=\"_blank\" rel=\"noopener noreferrer\">piosenkarką</a> i <a href=\"https://pl.wikipedia.org/wiki/Muzyk\" target=\"_blank\" rel=\"noopener noreferrer\">muzykiem</a>. Występuje pod imieniem <b>Maarit</b>.", "Maria Małgorzata": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria Kazimiera": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Małgosia": "<b>Małgorzata</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Margarita</em>, które pochodziło od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;μαργαρίτης <i>margarites</i> oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Per%C5%82y_naturalne\" target=\"_blank\" rel=\"noopener noreferrer\">perłę</a>”, które ma źródło w formie <a href=\"https://pl.wikipedia.org/wiki/Derywacja_(j%C4%99zykoznawstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">derywowanej</a> od <a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sanskryckiego</a> मञ्यरी <i>mañjarī</i> oznaczającego m.in. „perłę”, „pąk kwiatowy”, „kwiat”, „<a href=\"https://pl.wikipedia.org/wiki/Li%C5%9B%C4%87\" target=\"_blank\" rel=\"noopener noreferrer\">listowie</a> (w formie ornamentu na budynku)”.", "Marie-Sophie": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Marcellina": "<p>Marcellina jest miastem w prowincji Rzymu w włoskiej regionie Latium, oddzielnie około 30 km na północny wschód od Rzymu. Na dzień 31 grudnia 2004 roku mieście miało 5.913 mieszkańców i obszarze 15,3 km2.</p>", "Marzieh": "<p>Marzieh (arabsko: مرضية), (perskiego: مرضیه) jest imieniem żeńskim często używanym w perskim. W perskim i urdu wymawia się jako Marzia.</p>", "Mariiam": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mariam</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria Aleksandra": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mariolla": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mariola</b>.</p><b>Mariola</b> – imię żeńskie. Pierwotnie było zdrobnieniem od imienia <a href=\"https://pl.wikipedia.org/wiki/Maria\" target=\"_blank\" rel=\"noopener noreferrer\">Maria</a> lub skrótem od podwójnego imienia Maria Jolanta. Obecnie stanowi odrębne imię. Występuje przede wszystkim w Polsce.", "Maryiana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mariiana</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mariian</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Marian</b>.</p><b>Marian</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> od imienia <i>Marius</i> lub nazwy rodu <i>Marii</i>. Oznacza „należący do Mariusza, rodu Mariuszów”. Występuje w Polsce od 1332 roku, jako <b>Marzyjan</b>. Forma Marian pojawiła się w Polsce w XVI wieku. W języku angielskim używane jest jako imię żeńskie. W Polsce w żeńskim użyciu w 2025 roku wystąpiło 35 razy.", "Mirosława Kazimiera": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mirosława</b>.</p><b>Mirosława</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> żeńskie, złożone z członów <i>Miro-</i> (<i>pokój</i>, <i>spokój</i>, <i>dobro</i>) oraz <i>-sława</i> (<i>sława</i>). Mogło oznaczać <i>ta, która sławi pokój</i>. W źródłach polskich poświadczone od <a href=\"https://pl.wikipedia.org/wiki/1222\" target=\"_blank\" rel=\"noopener noreferrer\">1222</a> roku. <a href=\"https://pl.wikipedia.org/wiki/Anagram\" target=\"_blank\" rel=\"noopener noreferrer\">Anagram</a> tego imienia też jest żeńskim imieniem – <a href=\"https://pl.wikipedia.org/wiki/S%C5%82awomira\" target=\"_blank\" rel=\"noopener noreferrer\">Sławomira</a>.", "Marjatta": "<p>Marjatta to fińskie imię dla kobiet. Jego dzień imienia obchodzony jest 15 sierpnia.</p>", "Mariia-Marta": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria Franciszka": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria Ludwika": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Malini": "<p>Mălini jest gmina w prowincji Suceava, Rumunii. W 2002 roku liczba ludności wynosiła 7206.</p>", "Mi̇na": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Min</b>.</p><p>Min to niejednoznaczny termin. min - w matematyce i językach programowania oznacza funkcję wyboru najmniejszego ze swoich argumentów, (Min (3, 6, 2) = 2).</p>", "Maria Victoria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mariyka": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Marika</b>.</p><b>Marika</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzące od imienia „<a href=\"https://pl.wikipedia.org/wiki/Maria\" target=\"_blank\" rel=\"noopener noreferrer\">Maria</a>”. Jest <a href=\"https://pl.wikipedia.org/wiki/W%C4%99gry\" target=\"_blank\" rel=\"noopener noreferrer\">węgierską</a> formą tego imienia, chociaż znane jest także w Bułgarii i na terenie byłej Jugosławii. Imię jest również zniemczoną formą zdrobnienia „Maryjka” występującego w <a href=\"https://pl.wikipedia.org/wiki/Etnolekt_%C5%9Bl%C4%85ski\" target=\"_blank\" rel=\"noopener noreferrer\">etnolekcie śląskim</a>.", "Mami": "<b>Mami</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;まみ, マミ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Mai Linh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mai</b>.</p><b>Mai</b> – imię dwupłciowe używane w wielu państwach świata.", "Mariia-Veronika": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maryjane": "<p>Mary Jane, Mary-Jane lub Mary Jayne to podwójne imię, które może odnosić się do:</p>", "Milaniya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Milania</b>.</p><p>Melania to kobiece imię pochodzące z łacińskiego pochodzenia, które pochodzi od greckiego słowa melaina (μέλαινα), żeńskiej formy przymiotów melas (μέλας), co oznacza \"czarny\" lub \"ciemny\". Nazwa ta nosiła dwie święte Melania Starszą i jej wnuczka Melania Młodsza, a pochodzenie nazwy Melanie.</p>", "Mylena": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Milena</b>.</p><b>Milena</b> lub <b>Milana</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, używane w językach <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_bu%C5%82garski\" target=\"_blank\" rel=\"noopener noreferrer\">bułgarskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_czeski\" target=\"_blank\" rel=\"noopener noreferrer\">czeskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_s%C5%82owacki\" target=\"_blank\" rel=\"noopener noreferrer\">słowackim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbsko-chorwacki\" target=\"_blank\" rel=\"noopener noreferrer\">chorwackim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">polskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbski\" target=\"_blank\" rel=\"noopener noreferrer\">serbskim</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_s%C5%82owe%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">słoweńskim</a>. Zawiera pierwiastek <i>mil</i> oznaczający „miły”. Męskim odpowiednikiem imienia jest <a href=\"https://pl.wikipedia.org/wiki/Milan_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Milan</a>.", "Michéle": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Michel</b>.</p><p>⁇ Michel ⁇ (niemieckie MICHEL-Briefmarken-Katalog) - największy i najbardziej znany katalog znaków pocztowych w niemieckojęzycznym świecie i Europie.</p>", "Manizha": "<p>Maniaż Dalirovna Sangin (ur. Hamrajewa; rod.</p>", "Mishelle": "<p>Mishelle - rumuński projekt muzyczny utworzony w 2011 roku. W ramach projektu ⁇ Mishelle ⁇ w okresie od 2011 roku występowały dwie różne wokalistki: Michaela Ożog (rzym.</p>", "Manvi": "<p>Manvi jest gminą Raichur w stanie Karnataka, India.</p>", "Mariia-Solomiia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mirja": "<p>Mirja to imię. Do znanych osób z nazwiskiem należą: Mirja Boes (ur. 1971), niemiecka komika, aktorka i piosenkarka Mirja Breitholtz, szwedzka autorka piosenek i producentka Mirja Hietamies (1931-2013), fińska narciarka Mirja Jämes (1924-2020), fińska były narciarka w przeszkodzie Mirja Lehtonen (1942-2009), fińska skierka w przeszkoszach Mirja Mane (1929-1974), fińska aktorka Mirja Ojanen (ur. 1967), fińskie narciarka z orientacją narciarską Mirja...</p>", "Mariia-Olena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Minh Thu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Milli": "<p>Mili (abbreviated m) to przedewód napisany bezpośrednio przed międzynarodową jednostką pomiaru, aby wskazać liczbę mniejszą niż 1000 razy. Wielkość ta została ogłoszona w 1973 roku, a uznana od 1795 roku, latynsko oznaczając tysiąc.</p>", "Mirit": "<p>Mirit to kobiece imię. Do wybitnych osób z tym nazwiskiem należą: Mirit I.</p>", "Mays": "<p>Cukrowa kukurydza, również mios (lat. Zéa máys) - jednoroczna trawniczo-kulturowa roślina, jedyny kulturalny przedstawiciel rodu kukurydzy (Zea) rodziny Zlaki (Poaceae).</p>", "Muslima": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Muslim</b>.</p><p>Muzułmanie (arabski: al-Muslimūn - muslimoni) to wyznawcy islamu - religii monoteistycznej pochodzącej od Abrahama. Wierzą, że Koran - religijny tekst, który stanowi podstawę islamu - jest objawieniem od Allaha i przekazanym Muhammadowi - i jest ostatnim posłańcem Boga.</p>", "Malu": "<p>Malú (szp. Malú, pełne imię Maria Lucia Sanchez Benitez (hisp.</p>", "Mariska": "<p>Mariska to imię kobiece. Wśród osób, które go nosiły, są: Mariska (rapper) (ur. 1979), fińska solista, były partner w Mariska &amp; Pahat Sudet Mariska Aldrich (1881-1965), amerykańska piosenkarka i aktorka Mariska Beijer, holenderka w wózku inwalidzkim koszykówka Mariska Hargitay (ur. 1964), amerykańskiej aktorki filmowej i telewizyjnej Mariska Huisman (ur. 1983), holenderskiej maratonisty i speedskaterki Mariska Hulscher (ur. 1964)...</p>", "Maria Grażyna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Melano": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Melan</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Melani</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Melany</b>.</p><p>Melanie to kobiece imię pochodzące od greckiego μελανία (melania), \"czarność\", a od μέλας (melas), oznaczające \"ciemny\". Urodzony w łacinie przez dwóch świętych, Melanię Starszą i jej wnuczkę Melanię Młodszą, nazwę wprowadzili do Anglii Normanie w francuskiej formie Melanie.</p>", "Maksi": "<p>Maksi jest miastem i nagar panchayatem Shajapur w stanie Madhya Pradesh, India.</p>", "Merida": "<p>Merida Industry Co. , Ltd - tajwańska firma zajmująca się projektowaniem, produkcją i sprzedażą rowerów; jeden z największych producentów rowerów, drugi po wielkości w Tajwanie, po Giant.</p>", "Madlene": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Madlen</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Madlena</b>.</p><b>Magdalena</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od przydomka <a href=\"https://pl.wikipedia.org/wiki/Maria_Magdalena\" target=\"_blank\" rel=\"noopener noreferrer\">Marii Magdaleny</a>, czyli Marii z <a href=\"https://pl.wikipedia.org/wiki/Magdala_(Izrael)\" target=\"_blank\" rel=\"noopener noreferrer\">Magdali</a>, wioski leżącej w pobliżu <a href=\"https://pl.wikipedia.org/wiki/Jezioro_Tyberiadzkie\" target=\"_blank\" rel=\"noopener noreferrer\">Jeziora Tyberiadzkiego (Galilejskiego)</a>.", "Mariia-Mahdalyna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maryanne": "<p>Maryanne to imię. Wśród znanych osób z tej nazwy są: Maryanne Amacher (1938-2009), amerykański kompozytor i artysta instalacji Maryanne Connelly (ur. 1945), demokratyczna polityka w Nowym Jersey i były burmistrz Fanwood Maryanne Demasi, australijska reporterka naukowa i prezenterka z ABC Catalyst Maryanne Ellison Simmons (ur. 1949), amerykański artysta i pisarz oraz żona gracza baseballu Ted Simmons Maryanne J.</p>", "Maria Bożena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Marketa": "<p>Markéta jest kobiece czeskie imię, równoważne angielskiej Margaret. Znanymi osobami z nazwiska są: Markéta Hajdu (ur. 1974), czeski rzucacz młotami Markéta Irglová (ur. 1988), czeska muzyczka i aktorka Markéta Jánská (ur. 1981), czeskowa modelka Markéda Pekarová Adamová (ur. 1984), czeską były polityk Markéta Vondroušová (ur., 1999), czeskiej tenisistka Markéto Štroblová (urat. 1988), czechka aktorka pornograficzna</p>", "Mahbuba": "<p>Mahboba lub Mahbuba to kobiece imię arabskiego pochodzenia. Do wybitnych osób z tym nazwiskiem należą:</p>", "Marie-Luise": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Maria Gabriela": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria Luiza": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria Wanda": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mariia-Alina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mahnaz": "<p>Mahnaz to żeńskie imię pochodzące z Persu. Do wybitnych osób z tym nazwiskiem należą:</p>", "Marie-Claire": "<p>Marie-Claire to imię. Jest to połączenie nazw Marie i Claire, które pochodzą z francuskiego.</p>", "Maria Elena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Małgorzata Kazimiera": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Małgorzata</b>.</p><b>Małgorzata</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Margarita</em>, które pochodziło od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;μαργαρίτης <i>margarites</i> oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Per%C5%82y_naturalne\" target=\"_blank\" rel=\"noopener noreferrer\">perłę</a>”, które ma źródło w formie <a href=\"https://pl.wikipedia.org/wiki/Derywacja_(j%C4%99zykoznawstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">derywowanej</a> od <a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sanskryckiego</a> मञ्यरी <i>mañjarī</i> oznaczającego m.in. „perłę”, „pąk kwiatowy”, „kwiat”, „<a href=\"https://pl.wikipedia.org/wiki/Li%C5%9B%C4%87\" target=\"_blank\" rel=\"noopener noreferrer\">listowie</a> (w formie ornamentu na budynku)”.", "Mariann": "<p>Mariann to żeńskie imię pochodzące od Marii, podobnie jak Marianne, Mariana i Marian. Może odnosić się do: Mariann Aalda (ur. 1948), amerykańskiej aktorki Mariann Ambrus (1956-2007), węgierskiej rąbkarki Mariann Bienz, brytyjskiej biologii molekularnej Mariann Birkedal (ur. 1987), norweskiej królowej urody Mariann Budde (ur. 1959), amerykańskiego biskupa Mariann Byerwalter, amerykańskiego biznesmenki Mariann Domonkos, kanadyjskiej tenisistki stołowej Mariann Fischer Boel ...</p>", "Miwa": "<b>Miwa</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;みわ, ミワ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>, może być używane jako nazwisko.", "Marcyna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Marc</b>.</p><p>Marc: MARC (ang. Machine-Readable Cataloging) - grupa formatów (MARC21, UNIMARC, RUSMAC itp.</p>", "Maria Katarzyna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Marie-France": "<p>Marie-France to francuskie kobiece imię. Do wybitnych osób z nazwiskiem należą: Marie-France (aktorka) (urodzona 1943), francuska aktorka Marie-France Alvarez, francuska aktorką Marie-France Banc (1876-1965), francuska zakonnica, Righteous Among the Nations Marie-France Bazzo, kanadyjska nadawczyni Marie-France Beaufils (urodzony 1946), członek Senatu Francji Marie-France Boyer (urodzono 1938), francuska aktryska i śpiewaczka Marie-France Cohen, francuska moda...</p>", "Maria Eugenia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mariia-Anna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Manami": "<b>Manami</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;まなみ, マナミ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Moe": "Postacie będące źródłem tej reakcji, zwane „postaciami <i>moe</i>”&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;萌えキャラ&#32;<i>moe kyara</i>), pochodzą najczęściej z <a href=\"https://pl.wikipedia.org/wiki/Manga\" target=\"_blank\" rel=\"noopener noreferrer\">mang</a> i <a href=\"https://pl.wikipedia.org/wiki/Anime\" target=\"_blank\" rel=\"noopener noreferrer\">anime</a>, a także gier i powieści zawierających ilustracje w tym stylu. W ich projektach determinującą rolę odgrywa obecność czynników afektywnych, „czynników <i>moe</i>”&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;萌え要素&#32;<i>moe yōso</i>), rozpoznawalnych w kulturze <a href=\"https://pl.wikipedia.org/wiki/Otaku\" target=\"_blank\" rel=\"noopener noreferrer\">otaku</a> – są to zarówno atrybuty wizualne, np. kocie uszy, strój pokojówki i zielone włosy, jak i inne cechy, takie jak osobowość, sposób mówienia, zawód czy sytuacja, w jakiej postać się znajduje.", "Mariia-Marharyta": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria-Alexandra": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Marie-Laure": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Mojmira": "<b>Mojmira</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Mojmir_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Mojmir</a>. Znaczenie imienia: \"mój pokój\", \"mój skarb\". W tej formie imię nienotowane w źródłach staropolskich.", "Maryne": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maryn</b>.</p><b>Maryn</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzące od przymiotnika <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>marinus</em> („morski”). Wersją oboczną jest <a href=\"https://pl.wikipedia.org/wiki/Maryniusz\" target=\"_blank\" rel=\"noopener noreferrer\">Maryniusz</a>. Wśród patronów tego imienia św.&#160;<a href=\"https://pl.wikipedia.org/wiki/Maryn_z_San_Marino\" target=\"_blank\" rel=\"noopener noreferrer\">Maryn</a>, od imienia którego pochodzi nazwa państwa <a href=\"https://pl.wikipedia.org/wiki/San_Marino\" target=\"_blank\" rel=\"noopener noreferrer\">San Marino</a>.", "Maricica": "<p>Maricica to rumuńska kobieta: Maricica Puică (zrodzona Luca), emeryturka rumuńskie biegaczka olimpijskiej średniej odległości. Maricica Țăran, emerytowana Rumunsk-niemiecka remarka olimpijska</p>", "Milani": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Milan</b>.</p><b>Milan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię słowiańskie</a>. Jedno z licznych <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">zdrobnień od imion słowiańskich</a> zaczynających się na <i>Miło-</i>, takich jak <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82obor\" target=\"_blank\" rel=\"noopener noreferrer\">Miłobor</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82obrat\" target=\"_blank\" rel=\"noopener noreferrer\">Miłobrat</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82ogost_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miłogost</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82ogost_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miłgost</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82orad\" target=\"_blank\" rel=\"noopener noreferrer\">Miłorad</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82os%C5%82aw_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miłosław</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82os%C5%82aw_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miełosław</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82ostryj\" target=\"_blank\" rel=\"noopener noreferrer\">Miłostryj</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82owit\" target=\"_blank\" rel=\"noopener noreferrer\">Miłowit</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82owit\" target=\"_blank\" rel=\"noopener noreferrer\">Miłwit</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82osz\" target=\"_blank\" rel=\"noopener noreferrer\">Miłosz</a>. Obecnie imię Milan używane jest także samodzielnie.", "Maryi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mary</b>.</p><p>Mary: Mary (Mary, rzadko Marie) - angielskie nazwisko kobiece, odpowiadające rosyjskiej nazwie Maria. Jest to jedno z najstarszych nazw zachowanych do naszych czasów.</p>", "Maria-Andreea": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Marie Anne": "<p>Marie Anne, Marie-Anne lub Marie-Ann to femininowe słowo, które może odnosić się do:</p>", "Momoko": "<b>Momoko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;桃子,百子,ももこ,モモコ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Mehreen": "<p>Mehreen (perskie: مهرین), również przetransliterowana jako Mehreen, jest kobiece perskie imię, co oznacza \"słoneczne\" lub \"miłowane\". \"Mehr\" oznacza słońce lub miłość w języku perskim.</p>", "Miyu": "<b>Miyu</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;みゆ, ミユ) – głównie żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>, bardzo rzadko noszone przez mężczyzn.", "Maria Joanna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria Christina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Melchiora": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Melchior</b>.</p>Imię „Melchior” pochodzi od słowa oznaczającego „Bóg jest moją światłością”, „król światła”. Melchior wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> słowa <i>melech</i> i oznacza króla. Imię jest przypisywane jednemu z <a href=\"https://pl.wikipedia.org/wiki/Trzej_Kr%C3%B3lowie\" target=\"_blank\" rel=\"noopener noreferrer\">trzech mędrców</a> (królów, magów) z <a href=\"https://pl.wikipedia.org/wiki/Objawienie_Pa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">Nowego Testamentu</a>.", "Marie-Therese": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Marie-Pierre": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Mahshid": "<p>Mahshid (perskie: مهشید, mahshīd lub mahsheed, z mah [księżyc] + shīd [słońce]; \"księżyca i słońce\") to perskie imię dla kobiet.[sun] Mahshid tłumaczy również księżyc i słońce (\"mah\" + \" (khor) shid\").</p>", "Mieczyslawa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mieczysław</b>.</p><b>Mieczysław</b> – dwuczłonowe <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, które powstało najprawdopodobniej w wyniku błędnego odczytania słowiańskiego imienia złożonego <a href=\"https://pl.wikipedia.org/wiki/Miecis%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Miecisław</a> (którego najstarszy zapis pochodzi z 1257).", "Mariia-Tereza": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Melba": "<b>Melba</b> (fr. <i>pêche(s) Melba</i>, ang. <i>Peach Melba</i>) – <a href=\"https://pl.wikipedia.org/wiki/Deser\" target=\"_blank\" rel=\"noopener noreferrer\">deser</a> przygotowywany ze świeżych <a href=\"https://pl.wikipedia.org/wiki/Brzoskwinia_zwyczajna\" target=\"_blank\" rel=\"noopener noreferrer\">brzoskwiń</a>, <a href=\"https://pl.wikipedia.org/wiki/Lody\" target=\"_blank\" rel=\"noopener noreferrer\">lodów waniliowych</a> i słodzonego przecieru truskawkowego (względnie malinowego), znanego jako <b>sos melba</b> (<i>sauce Melba</i>). Przepis opracował <a href=\"https://pl.wikipedia.org/wiki/Auguste_Escoffier\" target=\"_blank\" rel=\"noopener noreferrer\">Auguste Escoffier</a>, reformator i kodyfikator <a href=\"https://pl.wikipedia.org/wiki/Kuchnia_francuska\" target=\"_blank\" rel=\"noopener noreferrer\">kuchni francuskiej</a>, na cześć australijskiej śpiewaczki <a href=\"https://pl.wikipedia.org/wiki/Nellie_Melba\" target=\"_blank\" rel=\"noopener noreferrer\">Nellie Melby</a>. Dokładniejsze informacje o jego powstaniu mają przy tym często charakter anegdotyczny – rozmijają się nawet relacje samych Escoffiera i Melby. Istnieją także inne dania nazwane imieniem Melby i kojarzone z Escoffierem, jak starsze niż melba <b>pêches au cygne</b> wzorowane na łabędziu z <i><a href=\"https://pl.wikipedia.org/wiki/Lohengrin_(opera)\" target=\"_blank\" rel=\"noopener noreferrer\">Lohengrina</a></i>, a także odmiany oryginalnej melby, w tym <b>poires Melba</b> (gruszki melba) i <b>fraises Melba</b> (truskawki melba). Znane są też tosty melba (<i>Melba toasts</i>), a także rodzaj <a href=\"https://pl.wikipedia.org/wiki/Garnirowanie\" target=\"_blank\" rel=\"noopener noreferrer\">garnirunku</a> z pomidorów o tej nazwie.", "Mariia-Kateryna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mariana-Mariia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariana</b>.</p><p>Mariana jest miastem w stanie Minas Gerais w Brazylii. Miasto to ma powierzchnię 1193,293 km2, liczba ludności w 2007 roku wynosi 53989 osób, a jego gęstość 44,4 osoby/km2.</p>", "Maria Lourdes": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mariia-Yuliia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria Halina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Marie Louise": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Momina": "Od 30 maja 2010 roku zespół szkół w Mominie nosi imię mjr. Jana Piwnika „Ponurego”. Momina znajduje się także na liście miejscowości <i>Szlaków tysiąclecia po Ziemi Kieleckiej</i> <a href=\"https://pl.wikipedia.org/wiki/Wojew%C3%B3dztwo_%C5%9Bwi%C4%99tokrzyskie\" target=\"_blank\" rel=\"noopener noreferrer\">świętokrzyskiego</a> oddziału <a href=\"https://pl.wikipedia.org/wiki/Polskie_Towarzystwo_Turystyczno-Krajoznawcze\" target=\"_blank\" rel=\"noopener noreferrer\">PTTK</a> z 1966 roku.", "Mariika": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Marika</b>.</p><b>Marika</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzące od imienia „<a href=\"https://pl.wikipedia.org/wiki/Maria\" target=\"_blank\" rel=\"noopener noreferrer\">Maria</a>”. Jest <a href=\"https://pl.wikipedia.org/wiki/W%C4%99gry\" target=\"_blank\" rel=\"noopener noreferrer\">węgierską</a> formą tego imienia, chociaż znane jest także w Bułgarii i na terenie byłej Jugosławii. Imię jest również zniemczoną formą zdrobnienia „Maryjka” występującego w <a href=\"https://pl.wikipedia.org/wiki/Etnolekt_%C5%9Bl%C4%85ski\" target=\"_blank\" rel=\"noopener noreferrer\">etnolekcie śląskim</a>.", "Mariia-Yelyzaveta": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Madoka": "<b>Madoka</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;まどか, マドカ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>, może być używane jako nazwisko.", "Maebh": "<p>Maeve, Meave, Maev lub Maiv, Maiev, Mabh (mayv) to żeńskie imię pochodzenia irlandzkiego. Pochodzi od irlandzkiego imienia Méabh, które było pisowane Meadhbh lub Maedhbh w wczesnym współczesnym irlandzkim, Me ⁇ lub Mea ⁇ w irlandzkim środku i Medb w starym irlandzkim.</p>", "Mariia-Mahdalena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maisy": "<p>Maisie, złożone również z Maisy lub innych drobnych odmian, jest imieniem żeńskim. Jest to forma szkóckiego gaelicznego imienia Mairead lub irlandzkiego imienia Mairéad, które są równoważne angielskiej nazwy Margaret.</p>", "Maria Bogumiła": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria Stefania": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Milanka": "<p>Milan (cyrylicki: Милан) jest powszechną sławską nazwą męską, a mniej powszechnie rzymską nazwę. Pochodzi z słowiańskiego elementu mil, co oznacza miłość, miłość i łaskę.</p>", "Maria-Mădălina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Meghana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Meghan</b>.</p><p>Megan to waliska nazwisko kobiece, pierwotnie maleńka forma Margaret. Margaret pochodzi od greckiego μαργαρίτης (margarítēs), łacińskiego margarīta, \"perła\".</p>", "Mariia-Anhelina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mariia-Stefaniia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria Urszula": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mikiko": "<p>Mikiko (pisanie: 幹子, 美樹子, 美起子, 美紀子, 美希子 lub みきこ w hiragana) to kobiece japońskie imię. Znanymi osobami z nazwiska są: Mikiko Ando (安藤 美希子; ur. 1992), japoński ciężarosta Mikiko Enomoto (⁇ 本 充希子; Ur. 1973), japońska aktorka głosowa Mikiko Futagami (二上 美紀子; urodzona 1969), japońskiego emeryturę zawodową zapałka Mikiko Hagiwara (⁇ 原 美樹子; ur., 1970), japończyka koszykarka kobieca Mikiko Hara (ur. 1967), japo...</p>", "Mai Chi": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mai</b>.</p><b>Mai</b> – imię dwupłciowe używane w wielu państwach świata.", "Maria Belen": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria Cecilia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mhairi": "<p>Mhairi lub Mhàiri to szkocka żeńska nazwa, ostatecznie pochodząca z nazwiska Mary. Etymologicznie jest to błędna forma, oparta na szkockiej gaelickiej formy vokatywnej Mhàiri , z imiennego Màiri [ˈmaːɾjɪ].</p>", "Malwine": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Malwin</b>.</p><b>Malwin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, stanowiące męski odpowiednik żeńskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Malwina\" target=\"_blank\" rel=\"noopener noreferrer\">Malwina</a>, pochodzenia literackiego.", "Mi̇la": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Myla</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mila</b>.</p><p>Mylka drniysta (lat. Mila caespitosa) - jedyny gatunek jaktusu z rodu Mylka (lat.</p>", "Marcelline": "<p>Marceline lub Marcelline mogą odnosić się do:</p>", "Minjung": "Król Goguryeo <b>Minjung</b> (? – 48) – czwarty król <a href=\"https://pl.wikipedia.org/wiki/Goguryeo\" target=\"_blank\" rel=\"noopener noreferrer\">Goguryeo</a>, największego spośród <a href=\"https://pl.wikipedia.org/wiki/Trzy_Kr%C3%B3lestwa_Korei\" target=\"_blank\" rel=\"noopener noreferrer\">Trzech Królestw Korei</a>. Panował w latach 44-48. Był piątym synem drugiego władcy króla <a href=\"https://pl.wikipedia.org/wiki/Yuri_(w%C5%82adca_Goguryeo)\" target=\"_blank\" rel=\"noopener noreferrer\">Yuriego</a>. Informacje o jego życiu pochodzą głównie z koreańskich kronik <a href=\"https://pl.wikipedia.org/wiki/Samguk_Sagi\" target=\"_blank\" rel=\"noopener noreferrer\">Samguk Sagi</a> i <a href=\"https://pl.wikipedia.org/wiki/Samguk_Yusa\" target=\"_blank\" rel=\"noopener noreferrer\">Samguk Yusa</a>.", "Michala": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Michał</b>.</p><b>Michał</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִיכָאֵל&#8206; – Mîchā’ēl) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, wywodzące się od <a href=\"https://pl.wikipedia.org/wiki/Archanio%C5%82_Micha%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">jednego z archaniołów</a>. Po hebrajsku znaczy „któż [jest taki] jak Bóg”. Forma żeńska to <a href=\"https://pl.wikipedia.org/wiki/Michalina\" target=\"_blank\" rel=\"noopener noreferrer\">Michalina</a>.", "Marioara": "<p>Marioara to rumuńska kobieta, pochodząca od Marii: Marioara Popescu, rumuńska rumownika olimpijską Marioara Munteanu, rumuńską kobieta ciężarnoszczywistka Marioara Murărescu, rumunską piosenkarkę i producentkę folklorycznych programów telewizyjnych Marioara Trașcă, emeryturę rumuńskiego rumownina Marioara Trifan, amerykańską pianistkę i dyrygentę</p>", "Mingzhu": "<p>Mingzhu (chiny: 明珠; pinyin: Míngzhū) to chińskie imię żeńskie. Znani ludzie z nazwiskiem to: Yin Mingzhu (1904-1989), chińska aktorka Wu Mingzhu (urodzona 1930), chiński agronom Dong Mingzhu (1954), chińska biznesmena Li Mingzhu (1962)</p>", "Mariianna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Marianna</b>.</p><b>Marianna</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Marian\" target=\"_blank\" rel=\"noopener noreferrer\">Marian</a>. Potocznie jest ono często błędnie rozumiane jako wynik złożenia dwóch innych imion: <a href=\"https://pl.wikipedia.org/wiki/Maria\" target=\"_blank\" rel=\"noopener noreferrer\">Marii</a> i <a href=\"https://pl.wikipedia.org/wiki/Anna\" target=\"_blank\" rel=\"noopener noreferrer\">Anny</a>, analogicznie do <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">ang.</a>&#160;<em>Maryann</em>.", "Marcjana": "<b>Marcjana</b>, również <b>Marcjanna</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Marcjan\" target=\"_blank\" rel=\"noopener noreferrer\">Marcjan</a>. Wśród świętych m.in. św. Marcjana z Cezarei Mauretańskiej.", "Maria Del Rocio": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Monic": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Monica</b>.</p><p>Monica Denise Brown (ang. Monica Denise Brown), w dziewczynstwie - Arnold (ang.</p>", "Maria-Gabriela": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mariusza": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mariusz</b>.</p><b>Mariusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od nazwy rzymskiego rodu Mariuszów lub imienia boga wojny Marsa. W Polsce od <a href=\"https://pl.wikipedia.org/wiki/XIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIII wieku</a>.", "May Ann": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>May</b>.</p><p>May to imię. May to skrócie botaniczne, które oznacza, że May jest autorem taksy.</p>", "Michelina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Michel</b>.</p><p>⁇ Michel ⁇ (niemieckie MICHEL-Briefmarken-Katalog) - największy i najbardziej znany katalog znaków pocztowych w niemieckojęzycznym świecie i Europie.</p>", "Mylaniia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Milaniia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Milania</b>.</p><p>Melania to kobiece imię pochodzące z łacińskiego pochodzenia, które pochodzi od greckiego słowa melaina (μέλαινα), żeńskiej formy przymiotów melas (μέλας), co oznacza \"czarny\" lub \"ciemny\". Nazwa ta nosiła dwie święte Melania Starszą i jej wnuczka Melania Młodsza, a pochodzenie nazwy Melanie.</p>", "Méabh": "<p>Medb (staroirlandzką [mjeðβ]), później wypełniony jako Meadhbh (średnioirlandzkie [mjɛɣβ]), Méabh (a) ]) i Méibh (irlandzkiego [mjeːvj]), a często angliczowany jako Maeve (MAYV), jest królową Connacht w cyklu Ulster w mitologii irlandzkiej. Jej mąż w głównych opowieściach cyklu jest Ailill mac Máta, chociaż miała kilka mężów przed nim, którzy byli również królami Connacht.</p>", "Maialen": "<p>Maialen to baskijska kobieca nazwa, równoważna angielskiej Madeleine lub Magdalene. Znani ludzie z nazwiska to: Maialen Axpe (ur. 1993), hiszpański pole vaulter Maialen Chourraut (ur. 1983), hiszpania slalom canoeist Maialen Diez (ur. 1995), hiszpanii piosenkarz i muzyka Maialen García (ur. 1990), hiszpaniański hokejista terenowy Maialen Lujanbio (ur. 1976), hiszpianin Baskijski poeta Maialen Zelaia (ur. 1988), hiszpanijski piłkarz piłki nożnej</p>", "Mariia-Ivanna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Merci": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mercy</b>.</p><p>Mercy: ⁇ Mercy ⁇ - single brytyjskiej piosenkarki Duffy, wydany w 2008 roku.  ⁇ Mercy ⁇ - single kanadyjskiego piosenkarza, Shaona Mendes'a, wydane w 2016 roku.</p>", "Mobina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mobin</b>.</p><p>Mobeen (arabski: مبين; perskiego: مبین) (zwany również Mubeen, Mobin, Mubin) to imię pochodzące od arabskiego słowa (مبين), które jest używane jako poetycki przymiot w literaturze, mowie i kontekście religijnym. Nazwa może być przetłumaczana jako \"wyraźne\", \"jasne\", \"wymowne\", \"wybitne\" lub \"jasne\".</p>", "Maruta": "<b>Maruta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pierwotnie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Persowie\" target=\"_blank\" rel=\"noopener noreferrer\">perskiego</a>, oznaczające \"boża posłanka\". Patronem tego imienia jest św. Marut z Mezopotamii.", "Marie-Noëlle": "<p>Marie-Noëlle to francuskie imię kobiece, składające się z nazw Marie i Noëlle. Wśród znanych osób z imieniem: Marie-Noëlle Ada (ur. 1990), Gabonska tytułowa mistrzowa w konkursie piękności Marie-Noelle Battistel (ur. 1956), francuska politykka Marie-Noille Gibelli (ur. 1957), monegaska politykką Marie-Nobelle Koyara (ur. 1955), minister obrony Republiki Środkowoafrykańskiej Marie-Noël Lienemann (ur. 1951), francuska...</p>", "Mayte": "<p>Maite, zespelany również Mayté, Maytee, Maytte lub (w francuskim) Maïté, jest nazwą żeńską pochodzenia iberyjskiego popularną w całym świecie hiszpańskim i Brazylii. Nazwa jest baskickim słowem oznaczającym \"miłość\", choć może być również nazwa \"María Teresa\" i \"María Esther\".</p>", "Murielle": "<p>Murielle to kobiece imię. Mieszkańcy tej nazwy to: Murielle Ahouré (ur. 1987), biegaczka z Irlandii Murielle Celimene, przedstawicielka Martyniki w Miss Earth 2004 Murielle Magellan (ur. 1967), francuska pisarka i reżyserka teatralna Murielle Adrienne Orais, modelka, ekologistka, pielęgniarka i królowa piękności z Filipin, Murielle Telio, amerykańska aktorka</p>", "Michalle": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Michale</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Michał</b>.</p><b>Michał</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִיכָאֵל&#8206; – Mîchā’ēl) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, wywodzące się od <a href=\"https://pl.wikipedia.org/wiki/Archanio%C5%82_Micha%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">jednego z archaniołów</a>. Po hebrajsku znaczy „któż [jest taki] jak Bóg”. Forma żeńska to <a href=\"https://pl.wikipedia.org/wiki/Michalina\" target=\"_blank\" rel=\"noopener noreferrer\">Michalina</a>.", "Mariia-Oleksandra": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Marie-Madeleine": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Mutsumi": "<b>Mutsumi</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;むつみ, ムツミ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>, użwane także jako nazwisko, rzadko używane jako imię męskie.", "Mariia-Emiliia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria-Teresa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria Monika": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Marketta": "<p>Margaret to kobiece imię, co oznacza \"perła\". Jest pochodzenia łacińskiego, przez starożytny grecki i ostatecznie od starożytnego irańskiego.</p>", "Moraa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mora</b>.</p><p>Mora to rodzaj roślin kwiatowych z rodziny Białego.</p>", "Mekdes": "<p>Mekdes (zwany również Mekedes, Mekides lub Merkedes) to imiona żeńskie pochodzące z Etiopii. Znani ludzie z nazwiska to: Mekides Abebe (ur. 2001), etyopski biegacz Mekedes Alemeshete, etyopska biegacz długodystansowa Mekdes Bekele, etyopijski biegacz mekdes Daba Feyssa, etypijski polityk Strony wyświetlające krótkie opisy skierowanych celów Mekdes (śpiewacz) (ur. 1998), duńsko-etyopski piosenkarz i...</p>", "Mysha": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Misha</b>.</p><p>Misha (rosyjski: Миша), znana również jako Mishka (rosycki: Мишка) lub Mishka Olimpijski (rosyński: Олимпийский Мишка), to nazwisko rosyjskiego niedźwiedzia z 1980 r. Stwór został zaprojektowany przez malarza ilustrującego dziecięce książki Victora Chizhikowa.</p>", "Marie-Lou": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Mai Trang": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mai</b>.</p><b>Mai</b> – imię dwupłciowe używane w wielu państwach świata.", "Mykhalina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mikhalina</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Michalina</b>.</p><b>Michalina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Micha%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Michał</a>. Oznacza „któż [jest] jak Bóg”. Imię to nadawane jest w tej formie w Polsce przynajmniej od <a href=\"https://pl.wikipedia.org/wiki/1744\" target=\"_blank\" rel=\"noopener noreferrer\">1744</a> roku, natomiast już w średniowieczu notowano jako żeński odpowiednik Michała formę <i><b>Michaelis</b></i> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>), zdrobniale – Michałka. Wśród imion nadawanych nowo narodzonym dzieciom, Michalina w 2018 r. zajmowała 24. miejsce w grupie imion żeńskich.", "Maria Esther": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Marie-Claude": "<p>Marie-Claude to francuska kobieca grupa. Wśród znanych osób z nazwiskiem są: Marie-Claude Arnaud, francuski matematyk Marie-Claode Asselin, kanadyjski narciarz w stylu wolnym Marie-Claide Audet (ur. 1962), kanadyjska rowerka Marie-Clade Beaud (1946-2024), francuski muzeumista Marie-Claud Beaudeau (ur. 1937), francuski polityk Marie- Claude Bibeau (ur., 1970), kanadyjski polityk Marie -Claude Bierre, francuski paterz Marie-Clauda ...</p>", "Mary Anne": "<p>Mary Ann lub Maryann lub Mary Anne to kobiece imię, połączenie nazw Mary i Anne. Może odnosić się do:</p>", "Minh Thư": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Mahboubeh": "<p>Mahboubeh to kobiece imię. Mieszkańcy nazwiska to: Mahboubeh Abbasgholizadeh (ur. 1958), irańska działaczka ds. praw kobiet, badacz i twórca filmowy Mahboubeh Honarian (ur. 1962), irańsko-kanadyjski filmowiec dokumentalny Mahboubeh Barbari Zharfi (ur. 1991), irańscy judoka</p>", "Minerwa": "<b>Minerwa</b> (łac. <i>Minerva</i>) – w <a href=\"https://pl.wikipedia.org/wiki/Mitologia_rzymska\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii rzymskiej</a> pierwotnie <a href=\"https://pl.wikipedia.org/wiki/Bogini\" target=\"_blank\" rel=\"noopener noreferrer\">bogini</a> <a href=\"https://pl.wikipedia.org/wiki/Sztuka\" target=\"_blank\" rel=\"noopener noreferrer\">sztuki</a> i <a href=\"https://pl.wikipedia.org/wiki/Rzemios%C5%82o\" target=\"_blank\" rel=\"noopener noreferrer\">rzemiosła</a>, <a href=\"https://pl.wikipedia.org/wiki/M%C4%85dro%C5%9B%C4%87\" target=\"_blank\" rel=\"noopener noreferrer\">mądrości</a>, <a href=\"https://pl.wikipedia.org/wiki/Nauka\" target=\"_blank\" rel=\"noopener noreferrer\">nauki</a> i <a href=\"https://pl.wikipedia.org/wiki/Literatura\" target=\"_blank\" rel=\"noopener noreferrer\">literatury</a> oraz wojny słusznej. Jest to prawdopodobnie bogini pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Etruskowie\" target=\"_blank\" rel=\"noopener noreferrer\">etruskiego</a> (znana jest etruska bogini <a href=\"https://pl.wikipedia.org/wiki/Menrva\" target=\"_blank\" rel=\"noopener noreferrer\">Menrva</a>). Razem z <a href=\"https://pl.wikipedia.org/wiki/Jowisz_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Jowiszem</a> i <a href=\"https://pl.wikipedia.org/wiki/Junona\" target=\"_blank\" rel=\"noopener noreferrer\">Junoną</a> tworzyła <a href=\"https://pl.wikipedia.org/wiki/Tr%C3%B3jca_Kapitoli%C5%84ska\" target=\"_blank\" rel=\"noopener noreferrer\">Trójcę Kapitolińską</a>.", "Marysol": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Marisol</b>.</p><p>Marisol (Hiszpańska: Marisol) - hiszpańskie imię.</p>", "Maria-Anna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "María Del Carmen": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria-Denisa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Marie Claire": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Maria Laura": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mykhaylyna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mikhailina</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mikhail</b>.</p><p>Michał (Hebrajskie: מִיכָאֵל; Aramejski: ⁇ , romanized: Mīkhāʼēl) jest powszechnym męskim imieniem, które zazwyczaj uważa się za pochodzące z hebrajskiego pytania retorycznego מי כאל (mī kāʼēl), \"Kto [jest] podobny do [Hebrajskiego boga] El?\", a więc jest nazwiskiem teoforycznym, którego odpowiedź brzmi \"nie ma nikogo podobnego do El\", lub \"nie słynny i potężny jak Bóg\".[is] Paradoksalnie, nazwisko jest czasami interpretowane jako \"Jeden...</p>", "Mindy": "<p>Mindy to kobiece imię. Nie przeprowadzono żadnych badań dokumentujących nazwę, a specjaliści nie są pewni jej dokładnego pochodzenia.</p>", "Minh Ngoc": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Maité": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mayte</b>.</p><p>Maite, zespelany również Mayté, Maytee, Maytte lub (w francuskim) Maïté, jest nazwą żeńską pochodzenia iberyjskiego popularną w całym świecie hiszpańskim i Brazylii. Nazwa jest baskickim słowem oznaczającym \"miłość\", choć może być również nazwa \"María Teresa\" i \"María Esther\".</p>", "Maria Róża": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mia-Marie": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mia</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria-Rebeca": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Minha": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Magdalena Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Magdalena</b>.</p><b>Magdalena</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od przydomka <a href=\"https://pl.wikipedia.org/wiki/Maria_Magdalena\" target=\"_blank\" rel=\"noopener noreferrer\">Marii Magdaleny</a>, czyli Marii z <a href=\"https://pl.wikipedia.org/wiki/Magdala_(Izrael)\" target=\"_blank\" rel=\"noopener noreferrer\">Magdali</a>, wioski leżącej w pobliżu <a href=\"https://pl.wikipedia.org/wiki/Jezioro_Tyberiadzkie\" target=\"_blank\" rel=\"noopener noreferrer\">Jeziora Tyberiadzkiego (Galilejskiego)</a>.", "Maëlys": "<p>Maëlys to francuskie nazwisko kobiece pochodzące z bretonów. Jest to kobieca forma nazwy Maël, co oznacza \"szef\" lub \"książę\".</p>", "Maria De Las Mercedes": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Marjory": "<p>Marjory to imię kobiece, wariant pisowni Margery lub Marjorie. Czasami jest skrócony na Marj.</p>", "Mesua": "Drzewa z gatunku <i>Mesua ferrea</i> traktowane są jako święte w Indiach i w <a href=\"https://pl.wikipedia.org/wiki/Wietnam\" target=\"_blank\" rel=\"noopener noreferrer\">Wietnamie</a>, gdzie sadzone są przy świątyniach. Jest to jedno z tzw. <a href=\"https://pl.wikipedia.org/wiki/Drzewo_%C5%BCelazne\" target=\"_blank\" rel=\"noopener noreferrer\">drzew żelaznych</a> – jest tak twarde i ciężkie, że nie nadaje się do obróbki siekierami, lecz wyłącznie maszynowej. Wykorzystywane jest do wyrobu słupów, podkładów kolejowych i na <a href=\"https://pl.wikipedia.org/wiki/Fornir\" target=\"_blank\" rel=\"noopener noreferrer\">fornir</a>, dawniej wykonywano z niego <a href=\"https://pl.wikipedia.org/wiki/W%C5%82%C3%B3cznia\" target=\"_blank\" rel=\"noopener noreferrer\">włócznie</a>. Pachnące kwiaty wykorzystywane są w lecznictwie, kosmetyce (w tym w przemyśle perfumeryjnym) oraz do aromatyzowania wypełnienia poduszek. Nasiona zawierają 79% oleju i stanowią główne źródło tego surowca dla ludu <a href=\"https://pl.wikipedia.org/wiki/Dai_(mniejszo%C5%9B%C4%87_narodowa)\" target=\"_blank\" rel=\"noopener noreferrer\">Dai</a>. Ze względu na znaczenie użytkowe i ozdobne kwiaty gatunek <i>M. ferrea</i> jest popularnie uprawiany, zwłaszcza w Indiach i na <a href=\"https://pl.wikipedia.org/wiki/Jawa\" target=\"_blank\" rel=\"noopener noreferrer\">Jawie</a>.", "Maybelle": "<p>Maybelle to nazwisko żeńskie, które może odnosić się do Maybelle Blair (ur. 1927), amerykańskiej piłkarki bejsbolowej Maybelle Carter (1909-1978), amerykańskiej muzyki country Maybelle Gilliland (1906-1971), amerykański sportowca torów Maybelle Goodlander (1882-1959), amerykańca Maybelle Marston (1895-1983), amerykańczyka contralto Maybelle Stephens Mitchell (1872-1919), amerykajska sufraga Maybelle Maud Park (1871-1946), amerykaanka lekarz Maybelle ...</p>", "Mariia-Milana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria Regina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Melannie": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Melanie</b>.</p><p>Melanie Melanie to siódmy album studiowy piosenkarki Celine Dion. Melanie - jedna z marek handlowych białoruskiej fabryki cukier ⁇ Spartak ⁇ .</p>", "Meggie": "<p>Meggie to kobiece imię i nazwa. Może odnosić się do:</p>", "Mariia-Zlata": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maryke": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Marike</b>.</p><p>Marieke (holenderska wymowa: [maːˈrikə]), również śpiewana jako Marike, jest nazwiskiem żeńskim w języku holenderskim, diminutiwem Marii. W języku polskim, greckim i japońskim jest to odpowiednik Marika.</p>", "Martha Lucia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Martha</b>.</p><p>Martha może odnosić się do: Martha Vasconcellos Martha Chase Martha Greenblatt Święta Matka Kościoła Katolickiego.</p>", "Marllena": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Marlena</b>.</p><b>Marlena</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, formowane na dwa sposoby:", "Mariia-Oksana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mai Phương": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mai</b>.</p><b>Mai</b> – imię dwupłciowe używane w wielu państwach świata.", "Matina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Matin</b>.</p><p>Matin lub MATIN może odnosić się do: Al-Matin, imienia Boga w islamskim Morning (świt, wczesny dzień, przeddzień) w średniowiecznym angielskim</p>", "Minh Nguyet": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Makeda": "<b>Makeda</b> – pierwsza znana królowa <a href=\"https://pl.wikipedia.org/wiki/Kr%C3%B3lestwo_Saba\" target=\"_blank\" rel=\"noopener noreferrer\">Saby</a>. Makeda to imię wywodzące się z tradycji <a href=\"https://pl.wikipedia.org/wiki/Etiopia\" target=\"_blank\" rel=\"noopener noreferrer\">etiopskiej</a>; w <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">islamskich</a> przekazach nazywana była Bilkis (<b>بلقيس</b> <i>Bilqīs</i>). Inne wersje jej imienia to Nikaule oraz Nicaula.", "Mykhalyna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mikhalina</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Michalina</b>.</p><b>Michalina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Micha%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Michał</a>. Oznacza „któż [jest] jak Bóg”. Imię to nadawane jest w tej formie w Polsce przynajmniej od <a href=\"https://pl.wikipedia.org/wiki/1744\" target=\"_blank\" rel=\"noopener noreferrer\">1744</a> roku, natomiast już w średniowieczu notowano jako żeński odpowiednik Michała formę <i><b>Michaelis</b></i> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>), zdrobniale – Michałka. Wśród imion nadawanych nowo narodzonym dzieciom, Michalina w 2018 r. zajmowała 24. miejsce w grupie imion żeńskich.", "Mariia-Valeriia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Marziya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Marzia</b>.</p><p>Marcia Chelberg (szwedzka. Marzia Kjellberg, w dziewictwie - Bizonjín (italijczyka.</p>", "Maria Agnieszka": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Miloslawa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Miłosław</b>.</p><b>Miłosław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie</a>/<a href=\"https://pl.wikipedia.org/wiki/Dzieje_imion_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie</a> imię męskie, złożone z członów <i>Miło-</i> (\"miły\", \"miłujący\") i <i>-sław</i> (\"sława\"). Znaczenie imienia: \"miły sławie\". Jednym ze stosowanych zdrobnień tego imienia, obok współczesnego \"Miłek\" i staropolskiego \"Miłko\", jest <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82osz\" target=\"_blank\" rel=\"noopener noreferrer\">Miłosz</a>.", "Mellanie": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Melanie</b>.</p><p>Melanie Melanie to siódmy album studiowy piosenkarki Celine Dion. Melanie - jedna z marek handlowych białoruskiej fabryki cukier ⁇ Spartak ⁇ .</p>", "Miłorada": "<b>Miłorada</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie imię żeńskie</a> złożone z członów Mił- (\"miła\", \"miłująca\") i -rada (\"być zadowolonym, chętnym, cieszyć się\" lub radzić - \"troszczyć się, dbać o coś\"). Męski odpowiednik: <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82orad\" target=\"_blank\" rel=\"noopener noreferrer\">Miłorad</a>.", "Miryna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mir</b>.</p><b>Mir</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskiego.</a> Powstało jako zdrobnienie imion np: <a href=\"https://pl.wikipedia.org/wiki/Miros%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Mirosław</a>, <a href=\"https://pl.wikipedia.org/wiki/Jaromir\" target=\"_blank\" rel=\"noopener noreferrer\">Jaromir</a>, <a href=\"https://pl.wikipedia.org/wiki/S%C5%82awomir\" target=\"_blank\" rel=\"noopener noreferrer\">Sławomir</a>, <a href=\"https://pl.wikipedia.org/wiki/Radomir\" target=\"_blank\" rel=\"noopener noreferrer\">Radomir</a>, Stanimir itd.", "Mirsada": "<p>Mirsada lub Mersada to bosniackie imię żeńskie, które może odnosić się do następujących osób: Mirsada Bajraktarević (1951-1976), bosniacka piosenkarka i autorka Mersada Bećirspahić (urodzona 1957), bosniackiej koszykarki Mirsada Burić (ur. 1970), bosniacki biegacz długodystansowy</p>", "Mary Jean": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mary</b>.</p><p>Mary: Mary (Mary, rzadko Marie) - angielskie nazwisko kobiece, odpowiadające rosyjskiej nazwie Maria. Jest to jedno z najstarszych nazw zachowanych do naszych czasów.</p>", "Marie Jeanne": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Morela": "<b>Morela</b> (<i>Armeniaca</i> Scop. ≡ <i>Prunus</i> subgen. <i>Prunus</i> sect. <i>Armeniaca</i>) – <a href=\"https://pl.wikipedia.org/wiki/Rodzaj_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">rodzaj</a>, podrodzaj lub <a href=\"https://pl.wikipedia.org/wiki/Sekcja_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">sekcja</a> (w zależności od ujęcia klasyfikacyjnego) roślin z rodziny <a href=\"https://pl.wikipedia.org/wiki/R%C3%B3%C5%BCowate\" target=\"_blank\" rel=\"noopener noreferrer\">różowatych</a>. Ze względu na zagnieżdżenie w obrębie rodzaju <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aliwa\" target=\"_blank\" rel=\"noopener noreferrer\">śliwa</a> <i>Prunus</i> zwykle wyróżniany w randze sekcji, co oznacza, że gatunki zaliczane są do rodzaju <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aliwa\" target=\"_blank\" rel=\"noopener noreferrer\">śliwa</a> (<i>Prunus</i>).", "Maria Elisabeth": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Medeea": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Medea</b>.</p><p>Media: Medea (grek. Μήδεια) - w starożytnej mitologii greckiej córka kolchydskiego króla Eeta, obdarzona darem magii.</p>", "Mairead": "<p>Mairead, złożony również jako Maighread, jest imieniem kobiece, szkockim gaelickim odpowiednikiem Margaret. Irlandzką formą jest Mairéad, Máiréad, Maighréad lub Máighréad.</p>", "Morenike": "<p>Morẹ́nikẹ́ to nigeryjskie kobiece imię pochodzenia joruba, co oznacza \"Znalazłem kogoś, kogo kocham\" lub \"Jestem kochaną\". Jego pochodzenie można wyśledzić na południowo-zachodni Nigerię.</p>", "Mariia-Karina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Marie-Ange": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Maria Do Carmo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Manea": "<b>Manea</b>, <i>Mannea</i> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81ac.\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Patronka tego imienia, św. Manea, jest wspominana razem ze swoim mężem, św. <a href=\"https://pl.wikipedia.org/wiki/Marcelin_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Marcelinem</a>, trybunem, oraz z synami – św. <a href=\"https://pl.wikipedia.org/wiki/Jan\" target=\"_blank\" rel=\"noopener noreferrer\">Janem</a>, <a href=\"https://pl.wikipedia.org/wiki/Piotr_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Piotrem</a> i <a href=\"https://pl.wikipedia.org/wiki/Serapion\" target=\"_blank\" rel=\"noopener noreferrer\">Serapionem</a>.", "Mia-Sophie": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mia</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maybell": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maybelle</b>.</p><p>Maybelle to nazwisko żeńskie, które może odnosić się do Maybelle Blair (ur. 1927), amerykańskiej piłkarki bejsbolowej Maybelle Carter (1909-1978), amerykańskiej muzyki country Maybelle Gilliland (1906-1971), amerykański sportowca torów Maybelle Goodlander (1882-1959), amerykańca Maybelle Marston (1895-1983), amerykańczyka contralto Maybelle Stephens Mitchell (1872-1919), amerykajska sufraga Maybelle Maud Park (1871-1946), amerykaanka lekarz Maybelle ...</p>", "Maria De Los Milagros": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mai Lan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mai</b>.</p><b>Mai</b> – imię dwupłciowe używane w wielu państwach świata.", "Maliya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Malia</b>.</p><p>Malia (lat. Malia grata) - gatunek ptaków z rodziny zardów.</p>", "Mădălina-Elena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mădălina</b>.</p><p>Mădălina to rumuńska kobieca nazwa, która może odnosić się do: Mădăline Cioveie (ur. 1983), rumuńska gimnastka aerobowa Mădălină Diana Ghenea (ur. 1987), rumuńskiej włoskiej aktorki i modelu Mădălinei Gojnea (ur. 1987), rumuńskiego tenisa Mădăliny Manole (1967-2010), rumuński pop artysta Mădălino Zamfirescu (ur. 1994), rumuńczyka piłkarka ręka</p>", "Maimuna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maymuna</b>.</p><p>Maymūna (ميمونة) to arabskie imię dla kobiet. Wersje w języku angielskim obejmują: Maimoonah, Maymoonah, Maimuna (h), Maimouna, Mahmuna i Mehmoona, Maimuma, Mymouna (h) Mymona.</p>", "Marta Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marta</b>.</p><b>Marta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. Wywodzi się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_aramejski\" target=\"_blank\" rel=\"noopener noreferrer\">aramejskiego</a> rzeczownika <i>mar</i>, <i>mar(a)tha, marta</i>, oznaczającego „pani domu, gospodyni, pani”. W Polsce po raz pierwszy zanotowano je w 1265 roku. Do dawnych zdrobnień zaliczała się np. Marusza (wsł., od wsł. <i>Marchwa</i>), oraz m.in. <i>Marocha, Marsza, Marszka, Marucha, Maruchna, Maruszka</i> (też od innych imion na Ma-, np. od <a href=\"https://pl.wikipedia.org/wiki/Ma%C5%82gorzata_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Małgorzaty</a>). Istnieje ponad 10 świętych katolickich o tym imieniu.", "Maria Clara": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Michalina Karolina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Michalina</b>.</p><b>Michalina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Micha%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Michał</a>. Oznacza „któż [jest] jak Bóg”. Imię to nadawane jest w tej formie w Polsce przynajmniej od <a href=\"https://pl.wikipedia.org/wiki/1744\" target=\"_blank\" rel=\"noopener noreferrer\">1744</a> roku, natomiast już w średniowieczu notowano jako żeński odpowiednik Michała formę <i><b>Michaelis</b></i> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>), zdrobniale – Michałka. Wśród imion nadawanych nowo narodzonym dzieciom, Michalina w 2018 r. zajmowała 24. miejsce w grupie imion żeńskich.", "Monina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mon</b>.</p><p>Mon może oznaczać: Miasto miasta Mon w stanie Nagaland, Indie Nowoczesna Indie Nagaland, India Wyspa Mon w Danie Mianmarskie Narody i języki Naród Mon (lub Mon) w południowo-wschodniej Azji Mońskie (narodu Mon) w grupie języków Mon-Khmer Odmienne MON jest kodem IATA Monarch Airlines Powieść Mon (門) Soseki Natsume Japoński mon (文) jest popularny w Japonii</p>", "Maria Alexandra": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria-Cristina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Marie Thérèse": "<p>Marie Thérèse lub Marie-Thérèse może odnosić się do: Marie-Thèrèse Abena Ondoa (ur. 1942), kamerońska polityk i minister Marie-Thérése Armentero (ur. 1965), szwajcarskiej pływaczki Marie-Thérés Assiga Ahanda (1941-2014), kamerońskiej pisarzy i chemik Marie-Thèrese Auffray (1912-1990), francuskiej artystki Marie-Thérese Bocoum, niezależnej ekspertki Narodów Zjednoczonych Marie Théresse Françoise Boisselet (1731-1800), francuskiego mistrza królewskiej Marie-Théryse Bonnet (ur. ...</p>", "Maria Renata": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Marziia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Marzia</b>.</p><p>Marcia Chelberg (szwedzka. Marzia Kjellberg, w dziewictwie - Bizonjín (italijczyka.</p>", "Maci": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mac</b>.</p><p>Macintosh [ˈmækɪntɒʃ] lub Mac [mæk] - linia komputerów osobistych produkowanych przez Apple. Pracują pod zarządzaniem systemami operacyjnymi rodziny Mac OS, możliwe jest również praca na OS Windows NT, A/UX, NeXTSTEP, BeOS/Haiku, GNU/Linux i Rhapsody.</p>", "Maria De Fátima": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Marry": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mary</b>.</p><p>Mary: Mary (Mary, rzadko Marie) - angielskie nazwisko kobiece, odpowiadające rosyjskiej nazwie Maria. Jest to jedno z najstarszych nazw zachowanych do naszych czasów.</p>", "Mari-Anna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mari</b>.</p><p>Mari to miasto w brazylijskim stanie Paraíba. Miasto ma powierzchnię 154,726 km2, liczba ludności w 2007 roku wynosi 20634 osób, a jego gęstość 133,4 osób/km2.</p>", "Meris": "<p>Meris to rodzaj motów z rodziny Geometridae opisywany przez George Duryea Hulst w 1896 roku.</p>", "Maria Hanna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mubina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mubin</b>.</p><p>Mobeen (arabski: مبين; perskiego: مبین) (zwany również Mubeen, Mobin, Mubin) to imię pochodzące od arabskiego słowa (مبين), które jest używane jako poetycki przymiot w literaturze, mowie i kontekście religijnym. Nazwa może być przetłumaczana jako \"wyraźne\", \"jasne\", \"wymowne\", \"wybitne\" lub \"jasne\".</p>", "Miłosza": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Miłosz</b>.</p><b>Miłosz</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a> oznaczające „tego, który jest miłowany”, będące pierwotnie zdrobnieniem dwuczłonowych imion takich jak: <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82obor\" target=\"_blank\" rel=\"noopener noreferrer\">Miłobor</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82obrat\" target=\"_blank\" rel=\"noopener noreferrer\">Miłobrat</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82ogost_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miłogost</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82ogost_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miłgost</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82orad\" target=\"_blank\" rel=\"noopener noreferrer\">Miłorad</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82os%C5%82aw_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miłosław</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82os%C5%82aw_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miełosław</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82ostryj\" target=\"_blank\" rel=\"noopener noreferrer\">Miłostryj</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82owit\" target=\"_blank\" rel=\"noopener noreferrer\">Miłowit</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82owit\" target=\"_blank\" rel=\"noopener noreferrer\">Miłwit</a>. Forma Miłosz została zapisana już w <a href=\"https://pl.wikipedia.org/wiki/1136\" target=\"_blank\" rel=\"noopener noreferrer\">1136</a> roku w <a href=\"https://pl.wikipedia.org/wiki/Bulla_gnie%C5%BAnie%C5%84ska\" target=\"_blank\" rel=\"noopener noreferrer\">Bulli gnieźnieńskiej</a>.", "Maria-Sofia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Marilu": "<p>Marilu lub Marilú to żeńskie imię lub nazwa, która może odnosić się do: Marilú (lalka), argentyńskiej lalki mody produkowanej w latach 1932-1960. Marilú (śpiewacz) (1927-2023), meksykańska piosenkarka i aktorka</p>", "Machiko": "<b>Machiko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;まちこ, マチコ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Maria Margarita": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mai Huong": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mai</b>.</p><b>Mai</b> – imię dwupłciowe używane w wielu państwach świata.", "Miletta": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mileta</b>.</p><p>Mileta (Serbski: Милета) to serbskie, chorwackie i murzynskie imię męskie, a także nazwisko. Znanymi osobami z nazwiskiem są: Mężczyzna Mileta Andrejević (1925-1989), amerykański malarz Mileta Jakšić (1863-1935), serbska poeta Mileta Lisica (urodzona 1966), serbsko-słowenijska piłkarz koszykówki Mileta Poskurica (ur. 1954), serbska polityk Mileta Radojković (1778-1852), serbska urzędnik Mileta Radulović (ur. 1981),...</p>", "Mariell": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mariel</b>.</p><p>Republika Marii L. (ludzka. Mariel Republika, górnik.</p>", "Magdalena Barbara": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Magdalena</b>.</p><b>Magdalena</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od przydomka <a href=\"https://pl.wikipedia.org/wiki/Maria_Magdalena\" target=\"_blank\" rel=\"noopener noreferrer\">Marii Magdaleny</a>, czyli Marii z <a href=\"https://pl.wikipedia.org/wiki/Magdala_(Izrael)\" target=\"_blank\" rel=\"noopener noreferrer\">Magdali</a>, wioski leżącej w pobliżu <a href=\"https://pl.wikipedia.org/wiki/Jezioro_Tyberiadzkie\" target=\"_blank\" rel=\"noopener noreferrer\">Jeziora Tyberiadzkiego (Galilejskiego)</a>.", "Mariia-Liliia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria Czesława": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Matrena": "<p>Matryona lub Matrena (rosyjski: Матрёна) to rosyjskie imię żeńskie pochodzące z łacińskiej matrona. Formy zmniejszające: Mottya, Mottря, Matrёха, Matryoša, Matręшка, Marя, Matya, Matyła.</p>", "Mariia-Evelina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Marike": "<p>Marieke (holenderska wymowa: [maːˈrikə]), również śpiewana jako Marike, jest nazwiskiem żeńskim w języku holenderskim, diminutiwem Marii. W języku polskim, greckim i japońskim jest to odpowiednik Marika.</p>", "Monica Alejandra": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Monica</b>.</p><p>Monica Denise Brown (ang. Monica Denise Brown), w dziewczynstwie - Arnold (ang.</p>", "Monica Patricia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Monica</b>.</p><p>Monica Denise Brown (ang. Monica Denise Brown), w dziewczynstwie - Arnold (ang.</p>", "Marie Madeleine": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Mallory": "<p>Mallory to angielskie nazwisko. Warianty pisowni obejmują Mallary, Mallery, Malorie, Mallorie, Mallerie i Mallorey.</p>", "Monica-Elena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Monica</b>.</p><p>Monica Denise Brown (ang. Monica Denise Brown), w dziewczynstwie - Arnold (ang.</p>", "Maria Rosa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Makaria": "<b>Makaria</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Greka\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od słowa <i>makários</i> oznaczającego „szczęśliwy”. Patronką tego imienia jest św. Makaria, wspominana razem ze św. <a href=\"https://pl.wikipedia.org/wiki/Maksyma_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Maksymą</a> i św. <a href=\"https://pl.wikipedia.org/wiki/January\" target=\"_blank\" rel=\"noopener noreferrer\">Januarym</a>.", "Merilyn": "<p>Merilyn to kobiece imię.</p>", "Mechthilda": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mechthild</b>.</p><p>Mechthild to żeńskie germańskie imię. Jest to stara forma nazwiska Matilda i oznacza \"silny w walce, silny bojownik\".</p>", "Min Jung": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Min</b>.</p><p>Min to niejednoznaczny termin. min - w matematyce i językach programowania oznacza funkcję wyboru najmniejszego ze swoich argumentów, (Min (3, 6, 2) = 2).</p>", "Merlina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Merlin</b>.</p>Trzeci cykl walijskiej triady podaje, że Clas Myrrdin (Samotnia Merlina)&#160;była nazwą Wielkiej Brytanii. Według niektórych (A.O.H. Jarmana), słowo Myrddin jest walijską wersją rzymskiej nazwy Carmarthen. Kontrastuje to z popularnym, lecz fałszywym ludowym przekazem, że miasto zostało nazwane na cześć wieszcza. Nazwa Carmarthen wywodzi się od rzymskiej nazwy miasta Moridunum, które pochodzi od nazwy \"moridunon\" oznaczającej morską twierdzę.", "Maria Valentina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Marziyeh": "<p>Marzieh (arabsko: مرضية), (perskiego: مرضیه) jest imieniem żeńskim często używanym w perskim. W perskim i urdu wymawia się jako Marzia.</p>", "Miljana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Miljan</b>.</p><p>Miljan to męskie imię pochodzenia sławskiego południa. Do wybitnych osób z nazwiskiem należą: Miljan Goljović (ur. 1971), urodzony w Serbii emeryturę koszykarza słoneckiego Miljan Govedarica (ur. 1994), bosnianki piłkarz Miljan Miljanić (1930-2012), serbski trener piłki nożnej Miljan Mrdaković (ura. 1982), serbski piłkarze Miljan Pavković (urat. 1981), serbski koszykarz Miljana Radović (r. 1975), emeryturze piłki noży w Czarnogórze Miljan...</p>", "Mitsuki": "<b>Mitsuki</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;みつき, ミツキ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Milanya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Milania</b>.</p><p>Melania to kobiece imię pochodzące z łacińskiego pochodzenia, które pochodzi od greckiego słowa melaina (μέλαινα), żeńskiej formy przymiotów melas (μέλας), co oznacza \"czarny\" lub \"ciemny\". Nazwa ta nosiła dwie święte Melania Starszą i jej wnuczka Melania Młodsza, a pochodzenie nazwy Melanie.</p>", "Mia-Rose": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mia</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mikhailina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mikhail</b>.</p><p>Michał (Hebrajskie: מִיכָאֵל; Aramejski: ⁇ , romanized: Mīkhāʼēl) jest powszechnym męskim imieniem, które zazwyczaj uważa się za pochodzące z hebrajskiego pytania retorycznego מי כאל (mī kāʼēl), \"Kto [jest] podobny do [Hebrajskiego boga] El?\", a więc jest nazwiskiem teoforycznym, którego odpowiedź brzmi \"nie ma nikogo podobnego do El\", lub \"nie słynny i potężny jak Bóg\".[is] Paradoksalnie, nazwisko jest czasami interpretowane jako \"Jeden...</p>", "Maria Paola": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria-Anais": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Millana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Milana</b>.</p><b>Milena</b> lub <b>Milana</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, używane w językach <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_bu%C5%82garski\" target=\"_blank\" rel=\"noopener noreferrer\">bułgarskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_czeski\" target=\"_blank\" rel=\"noopener noreferrer\">czeskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_s%C5%82owacki\" target=\"_blank\" rel=\"noopener noreferrer\">słowackim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbsko-chorwacki\" target=\"_blank\" rel=\"noopener noreferrer\">chorwackim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">polskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbski\" target=\"_blank\" rel=\"noopener noreferrer\">serbskim</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_s%C5%82owe%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">słoweńskim</a>. Zawiera pierwiastek <i>mil</i> oznaczający „miły”. Męskim odpowiednikiem imienia jest <a href=\"https://pl.wikipedia.org/wiki/Milan_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Milan</a>.", "Maria De Lourdes": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria Fe": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mária-Magdolna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria De Las Nieves": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mai Phuong": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mai</b>.</p><b>Mai</b> – imię dwupłciowe używane w wielu państwach świata.", "Muguette": "<p>Muguette to kobiece imię. Znanymi osobami z nazwiska są: Muguette Dini (ur. 1940), francuska polityka Muguette \"Megs\" Jenkins (1917-1998), angielska aktorka</p>", "Maria Anastazja": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Michiyo": "<p>Michiyo (pisanie: 道世, 道代, 路代, 真世, 充代, 通世, 迪与, 美千代, 実千代, 美智代, 美知依, 美知代, 三千代 lub みちよ w hiragana) jest unisex japońskie imię. Wśród znanych osób z tej nazwy są: Michiyo Akaishi (赤石 路代; ur. 1959), japoński artysta manga Michiyo Aratama (新珠 三千代; 1930-2001), japońska aktorka Michiyo Aryto (有藤 通世; ur. 1946), japoński piłkarz bejsbolowy Michiyo Azusa (⁇ みちよ; 1943-2020), japońskiego piosenkarza i aktorki Michiyo Fujimaru (藤丸 真世; ur . 1979), japończyk...</p>", "Maria Teodozja": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Monica Liliana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Monica</b>.</p><p>Monica Denise Brown (ang. Monica Denise Brown), w dziewczynstwie - Arnold (ang.</p>", "Mirjami": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mirjam</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria Pia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mojra": "W różnych literackich przekazach wywodzono odmienne ich pochodzenie. U <a href=\"https://pl.wikipedia.org/wiki/Homer\" target=\"_blank\" rel=\"noopener noreferrer\">Homera</a> jest jedna Mojra, natomiast według <i><a href=\"https://pl.wikipedia.org/wiki/Theogonia\" target=\"_blank\" rel=\"noopener noreferrer\">Theogonii</a></i> <a href=\"https://pl.wikipedia.org/wiki/Hezjod\" target=\"_blank\" rel=\"noopener noreferrer\">Hezjoda</a> były one trzema córkami <a href=\"https://pl.wikipedia.org/wiki/Zeus\" target=\"_blank\" rel=\"noopener noreferrer\">Zeusa</a> i <a href=\"https://pl.wikipedia.org/wiki/Temida_(tytanida)\" target=\"_blank\" rel=\"noopener noreferrer\">Temidy</a>, noszącymi imiona: <a href=\"https://pl.wikipedia.org/wiki/Kloto\" target=\"_blank\" rel=\"noopener noreferrer\">Kloto</a> („Prządka” nici żywota), <a href=\"https://pl.wikipedia.org/wiki/Lachesis\" target=\"_blank\" rel=\"noopener noreferrer\">Lachesis</a> („Udzielająca”, która tej nici strzeże) i <a href=\"https://pl.wikipedia.org/wiki/Atropos\" target=\"_blank\" rel=\"noopener noreferrer\">Atropos</a> („Nieodwracalna”, która ją przecina). Według innych źródeł były one córkami Nocy i <a href=\"https://pl.wikipedia.org/wiki/Ereb\" target=\"_blank\" rel=\"noopener noreferrer\">Erebu</a> lub <a href=\"https://pl.wikipedia.org/wiki/Kronos\" target=\"_blank\" rel=\"noopener noreferrer\">Kronosa</a>, albo <a href=\"https://pl.wikipedia.org/wiki/Gaja_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Gai</a> i <a href=\"https://pl.wikipedia.org/wiki/Okeanos\" target=\"_blank\" rel=\"noopener noreferrer\">Okeanosa</a>. Symbolizowały <a href=\"https://pl.wikipedia.org/wiki/Staro%C5%BCytna_Grecja\" target=\"_blank\" rel=\"noopener noreferrer\">starogreckie</a> pojęcia <a href=\"https://pl.wikipedia.org/wiki/Filozofia\" target=\"_blank\" rel=\"noopener noreferrer\">filozoficzno</a>-mitologiczne dotyczące losu ludzkiego i porządku świata. Ich siostrami były <a href=\"https://pl.wikipedia.org/wiki/Hory\" target=\"_blank\" rel=\"noopener noreferrer\">Hory</a> i <a href=\"https://pl.wikipedia.org/wiki/Charyty\" target=\"_blank\" rel=\"noopener noreferrer\">Charyty</a>. Były boginiami życia i śmierci oraz znały przyszłość ludzi i bogów. Jako jedyne nie podlegały też władzy <a href=\"https://pl.wikipedia.org/wiki/Bogowie_olimpijscy\" target=\"_blank\" rel=\"noopener noreferrer\">bogów olimpijskich</a>.", "Maria Antonia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria Bożenna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maryiam": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mariiam</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mariam</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Marta-Oleksandra": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marta</b>.</p><b>Marta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. Wywodzi się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_aramejski\" target=\"_blank\" rel=\"noopener noreferrer\">aramejskiego</a> rzeczownika <i>mar</i>, <i>mar(a)tha, marta</i>, oznaczającego „pani domu, gospodyni, pani”. W Polsce po raz pierwszy zanotowano je w 1265 roku. Do dawnych zdrobnień zaliczała się np. Marusza (wsł., od wsł. <i>Marchwa</i>), oraz m.in. <i>Marocha, Marsza, Marszka, Marucha, Maruchna, Maruszka</i> (też od innych imion na Ma-, np. od <a href=\"https://pl.wikipedia.org/wiki/Ma%C5%82gorzata_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Małgorzaty</a>). Istnieje ponad 10 świętych katolickich o tym imieniu.", "Mateia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Matei</b>.</p><p>Matei (rumuńska: [maˈtej]) jest rumuńskim męskim nazwiskiem i nazwiskiem. Jest odwzajemniony od nazwiska Matthias, a jest spokrewniony z angielską nazwą Matthew.</p>", "Maria Carolina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Margrita": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Margrit</b>.</p><p>Margrit to imię, co odpowiada angielskiej nazwie Margaret. Wśród znanych osób z tego nazwiska są: Margrit Bolli (1919-2017), szwajcarska tancerka Margrit Brückner (ur. 1946), niemiecki socjolog i profesor Margrit Conrad (1918-2005), szwajcarski piosenkarz Margrit Gertsch (ur. 1939), szwajcarka narciarka Alpinowa Margrit Hess (ur. 1947), szwajcaria biegaczka średniej odległości Margrit Kennedy (1939 -2013), niemiecka architekt, profesor, ekolog, autor i...</p>", "Mariia-Elina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria Yolanda": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maleka": "<p>Maleka może odnosić się do: Maleka Begum (ur. 1944), akademik z Bangladeszu Maleka Higgins, amerykańska ofiara strzelania Maleka Parvin, Bangladeszka gracz kabaddi Audrey Maleka, południowoafrykański polityk Shahnaz Parvin Maleka, Bangladeszki gracz kabaddy</p>", "Masuma": "<p>Masuma (arabsko: معصومة, romanized: Ma'ṣūm; japoński: 増実) jest kobiece imię pochodzenia arabskiego, które tłumaczy na \"niewinne\"; a także męskie imię pochodzenia japońskiego, które tłumasza na \"rozszerzenie, życzliwość\". Najbardziej znane jest to, że to imię zostało stosowane do Masuma e Qum, znanej powszechnie jako Fatimah bint Musa (r.</p>", "Michale": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Michał</b>.</p><b>Michał</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִיכָאֵל&#8206; – Mîchā’ēl) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, wywodzące się od <a href=\"https://pl.wikipedia.org/wiki/Archanio%C5%82_Micha%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">jednego z archaniołów</a>. Po hebrajsku znaczy „któż [jest taki] jak Bóg”. Forma żeńska to <a href=\"https://pl.wikipedia.org/wiki/Michalina\" target=\"_blank\" rel=\"noopener noreferrer\">Michalina</a>.", "Marlenna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Marlena</b>.</p><b>Marlena</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, formowane na dwa sposoby:", "Marie Helene": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Mi Young": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mi</b>.</p><p>Mi może być: Mi (powieść), znakiem E Mi (ty), a to jest powieść wietnamska.</p>", "Maria De Fatima": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mariia-Yana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria Walentyna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Marie-Josée": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Mohamed Saad": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohamed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Maria Yaneth": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mariia Viktoriia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Monika Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Monika</b>.</p><b>Monika</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o znaczeniu i pochodzeniu trudnym do objaśnienia. Według niektórych badaczy imię pochodzi od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> słowa „monos” oznaczającego <i>jeden</i>, <i>sam</i>, <i>pojedynczy</i>, <i>jedynak</i> i <i>jedynaczka</i>. Z tego samego rdzenia pochodzą takie słowa jak: <a href=\"https://pl.wikipedia.org/wiki/Monogamia\" target=\"_blank\" rel=\"noopener noreferrer\">monogamia</a>, <a href=\"https://pl.wikipedia.org/wiki/Monoteizm\" target=\"_blank\" rel=\"noopener noreferrer\">monoteizm</a>, monaster (klasztor). Inne źródło podaje, że imię to wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> „monaché”, co znaczy <i>samotna</i>, <i>odosobniona</i>; we <a href=\"https://pl.wikipedia.org/wiki/W%C5%82ochy\" target=\"_blank\" rel=\"noopener noreferrer\">Włoszech</a> zakonnica zwana jest <i>monaca</i>, a w niektórych dialektach wręcz <i>monica</i>.", "Marta-Viktoriia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marta</b>.</p><b>Marta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. Wywodzi się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_aramejski\" target=\"_blank\" rel=\"noopener noreferrer\">aramejskiego</a> rzeczownika <i>mar</i>, <i>mar(a)tha, marta</i>, oznaczającego „pani domu, gospodyni, pani”. W Polsce po raz pierwszy zanotowano je w 1265 roku. Do dawnych zdrobnień zaliczała się np. Marusza (wsł., od wsł. <i>Marchwa</i>), oraz m.in. <i>Marocha, Marsza, Marszka, Marucha, Maruchna, Maruszka</i> (też od innych imion na Ma-, np. od <a href=\"https://pl.wikipedia.org/wiki/Ma%C5%82gorzata_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Małgorzaty</a>). Istnieje ponad 10 świętych katolickich o tym imieniu.", "Minea": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mine</b>.</p><p>Mine może odnosić się do: Mine, Yamaguchi \"Mine\" (piosenka The 1975), 2018 \"Mine\", 2017 \"Mine\". (piosenta Beyoncé), 2013 \"Mine\"; 2023 \"Mine\"? (pioseta Alice Glass), 2018 \"mine\"? (pieśeta Taylor Swift), 2010</p>", "Mabell": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mabel</b>.</p><p>Mabel Alabama-Perl Mcway (ang. Mabel Alabama-Pearl McVey; rodzaj.</p>", "Minami": "<b>Minami</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;みなみ, ミナミ, 南) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a> noszone częściej przez kobiety niż przez mężczyzn. Jest używane jako imię, nazwisko lub nazwa miejsca.", "Mariia-Nikol": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria Lyn": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maymuna": "<p>Maymūna (ميمونة) to arabskie imię dla kobiet. Wersje w języku angielskim obejmują: Maimoonah, Maymoonah, Maimuna (h), Maimouna, Mahmuna i Mehmoona, Maimuma, Mymouna (h) Mymona.</p>", "Minh Hien": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Maria Łucja": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria-Mirela": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria Cecylia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria Henryka": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria-Claudia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Marzana": "Znaczenie użytkowe mają zwłaszcza ci przedstawiciele rodzaju, z których korzeni pozyskuje się czerwony barwnik. W Europie jest to <a href=\"https://pl.wikipedia.org/wiki/Marzana_barwierska\" target=\"_blank\" rel=\"noopener noreferrer\">marzana barwierska</a> <i>R. tinctoria</i>, a w <a href=\"https://pl.wikipedia.org/wiki/Indie\" target=\"_blank\" rel=\"noopener noreferrer\">Indiach</a> – marzana sercolistna <i>R. cordifolia</i>. Jako roślina lecznicza wykorzystywana jest zwłaszcza <i>R. peregrina</i>.", "Maria-Patricia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Marsa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mars</b>.</p><b>Mars</b> – czwarta od <a href=\"https://pl.wikipedia.org/wiki/S%C5%82o%C5%84ce\" target=\"_blank\" rel=\"noopener noreferrer\">Słońca</a> <a href=\"https://pl.wikipedia.org/wiki/Planeta\" target=\"_blank\" rel=\"noopener noreferrer\">planeta</a> <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_S%C5%82oneczny\" target=\"_blank\" rel=\"noopener noreferrer\">Układu Słonecznego</a>. Krąży między orbitą <a href=\"https://pl.wikipedia.org/wiki/Ziemia\" target=\"_blank\" rel=\"noopener noreferrer\">Ziemi</a> a <a href=\"https://pl.wikipedia.org/wiki/Pas_planetoid\" target=\"_blank\" rel=\"noopener noreferrer\">pasem planetoid</a> dzielącym go od orbity <a href=\"https://pl.wikipedia.org/wiki/Jowisz\" target=\"_blank\" rel=\"noopener noreferrer\">Jowisza</a>. Planeta została nazwana od imienia rzymskiego boga wojny – <a href=\"https://pl.wikipedia.org/wiki/Mars_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Marsa</a>, ze względu na <a href=\"https://pl.wikipedia.org/wiki/Barwa\" target=\"_blank\" rel=\"noopener noreferrer\">barwę</a>, która przy obserwacji z <a href=\"https://pl.wikipedia.org/wiki/Ziemia\" target=\"_blank\" rel=\"noopener noreferrer\">Ziemi</a> wydaje się rdzawo-czerwona i kojarzyła się starożytnym <a href=\"https://pl.wikipedia.org/wiki/Rzymianie\" target=\"_blank\" rel=\"noopener noreferrer\">Rzymianom</a> z pożogą wojenną. Odcień ten bierze się od <a href=\"https://pl.wikipedia.org/wiki/Tlenki_%C5%BCelaza\" target=\"_blank\" rel=\"noopener noreferrer\">tlenków żelaza</a> pokrywających powierzchnię. Mars jest <a href=\"https://pl.wikipedia.org/wiki/Planeta_wewn%C4%99trzna\" target=\"_blank\" rel=\"noopener noreferrer\">planetą wewnętrzną</a> z cienką <a href=\"https://pl.wikipedia.org/wiki/Atmosfera\" target=\"_blank\" rel=\"noopener noreferrer\">atmosferą</a>, o powierzchni usianej <a href=\"https://pl.wikipedia.org/wiki/Krater_uderzeniowy\" target=\"_blank\" rel=\"noopener noreferrer\">kraterami uderzeniowymi</a>, podobnie jak powierzchnia <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99%C5%BCyc\" target=\"_blank\" rel=\"noopener noreferrer\">Księżyca</a> i wielu innych ciał <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_S%C5%82oneczny\" target=\"_blank\" rel=\"noopener noreferrer\">Układu Słonecznego</a>. Powierzchnia wykazuje formy podobne do ziemskich: <a href=\"https://pl.wikipedia.org/wiki/Wulkan\" target=\"_blank\" rel=\"noopener noreferrer\">wulkany</a>, <a href=\"https://pl.wikipedia.org/wiki/Dolina\" target=\"_blank\" rel=\"noopener noreferrer\">doliny</a>, <a href=\"https://pl.wikipedia.org/wiki/Kanion\" target=\"_blank\" rel=\"noopener noreferrer\">kaniony</a>, <a href=\"https://pl.wikipedia.org/wiki/Pustynia\" target=\"_blank\" rel=\"noopener noreferrer\">pustynie</a> i polarne czapy lodowe. Okres obrotu wokół własnej osi jest niewiele dłuższy niż ziemski i wynosi 24,6229 godziny (24 h 37 m 22 s). Na Marsie znajduje się najwyższe <a href=\"https://pl.wikipedia.org/wiki/Wzniesienie\" target=\"_blank\" rel=\"noopener noreferrer\">wzniesienie</a> w Układzie Słonecznym – <a href=\"https://pl.wikipedia.org/wiki/Olympus_Mons\" target=\"_blank\" rel=\"noopener noreferrer\">Olympus Mons</a> i największy kanion – <a href=\"https://pl.wikipedia.org/wiki/Valles_Marineris\" target=\"_blank\" rel=\"noopener noreferrer\">Valles Marineris</a>. Gładki obszar równinny <a href=\"https://pl.wikipedia.org/wiki/Vastitas_Borealis\" target=\"_blank\" rel=\"noopener noreferrer\">Vastitas Borealis</a> na półkuli północnej, który obejmuje 40% powierzchni planety, może być pozostałością ogromnego uderzenia. W przeciwieństwie do <a href=\"https://pl.wikipedia.org/wiki/Ziemia\" target=\"_blank\" rel=\"noopener noreferrer\">Ziemi</a>, Mars jest mało aktywny <a href=\"https://pl.wikipedia.org/wiki/Geologia\" target=\"_blank\" rel=\"noopener noreferrer\">geologicznie</a> i nie zachodzą na nim zjawiska <a href=\"https://pl.wikipedia.org/wiki/Tektonika_p%C5%82yt\" target=\"_blank\" rel=\"noopener noreferrer\">tektoniczne</a>.", "Markella": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Marcella</b>.</p><p>Marcella (lat. Marcella) - święta IV wieku.</p>", "Mariia-Violetta": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mariia-Snizhana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mariña": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maryna</b>.</p>Imię Maryna jest żeńskim odpowiednikiem imienia <a href=\"https://pl.wikipedia.org/wiki/Maryn\" target=\"_blank\" rel=\"noopener noreferrer\">Maryn</a>, w Polsce niezwykle rzadkim (w 1994 roku nosiła je jedna osoba, w roku 2001 – 203 osoby, zaś w wariancie <i>Marina</i> – 362). Imię to wywodzi się od imienia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Marinus</em>, a to z kolei powstało z przymiotnika <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>marinus</em> („morski”). Imię Maryna – rozumiane jako żeński odpowiednik imienia Maryn – poświadczone jest w Polsce już w XV wieku (najwcześniej w 1443 roku). Zdrobnienie od niego brzmi Marynia. Marina to cudzoziemski wariant imienia Maryna; trudno powiedzieć, skąd przybyło do Polski, z uwagi na podobną formę w prawie wszystkich językach europejskich.", "Maria Andrea": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mellany": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Melany</b>.</p><p>Melanie to kobiece imię pochodzące od greckiego μελανία (melania), \"czarność\", a od μέλας (melas), oznaczające \"ciemny\". Urodzony w łacinie przez dwóch świętych, Melanię Starszą i jej wnuczkę Melanię Młodszą, nazwę wprowadzili do Anglii Normanie w francuskiej formie Melanie.</p>", "Maria Wiesława": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria Weronika": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Marié": "<p>Marie lub Marié (まりえ、マリエ) to kobiece japońskie imię. Czasami \"e\" jest napisana z ostrymi akcentami lub innymi diacritykami, aby oznaczyć, że jest wypowiedziana, i aby odróżnić ją od etymologicznie niezwiązanej francuskiej i angielskiej nazwy Marie.</p>", "Maria-Camelia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Marta-Sofiia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marta</b>.</p><b>Marta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. Wywodzi się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_aramejski\" target=\"_blank\" rel=\"noopener noreferrer\">aramejskiego</a> rzeczownika <i>mar</i>, <i>mar(a)tha, marta</i>, oznaczającego „pani domu, gospodyni, pani”. W Polsce po raz pierwszy zanotowano je w 1265 roku. Do dawnych zdrobnień zaliczała się np. Marusza (wsł., od wsł. <i>Marchwa</i>), oraz m.in. <i>Marocha, Marsza, Marszka, Marucha, Maruchna, Maruszka</i> (też od innych imion na Ma-, np. od <a href=\"https://pl.wikipedia.org/wiki/Ma%C5%82gorzata_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Małgorzaty</a>). Istnieje ponad 10 świętych katolickich o tym imieniu.", "Maria De La Paz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria Aniela": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Min Kumari": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Min</b>.</p><p>Min to niejednoznaczny termin. min - w matematyce i językach programowania oznacza funkcję wyboru najmniejszego ze swoich argumentów, (Min (3, 6, 2) = 2).</p>", "Mariia-Karolina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Marie Gabrielle": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "María Del Pilar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria Angela": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Marie Françoise": "<p>Marie-Françoise lub Marie Françoise to imię. Wśród znanych osób z tej nazwy są: Ghislaine Marie Françoise Dommanget (1900-1991), francuska aktorka Marie Françoese Sophie Gay (1776-1852), francuska autorka Marie-Françoise André, francuska geografa Marie-François Audollent (1943-2008), francuska aktorki Marie-Francoise Baslez (1946-2022), francuska historykka i akademicka Marie François Catherine de Beauvau-Craon (1711-1786), francuska szlachetnica...</p>", "Mai Khanh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mai</b>.</p><b>Mai</b> – imię dwupłciowe używane w wielu państwach świata.", "Maria Dolores": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maja-Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maja</b>.</p><b>Maja</b> – imię żeńskie pochodzenia greckiego, wywodzące się od słowa <i>μαῖα (maia)</i> oznaczającego „dobrą matkę”, „damę” lub „przybraną matkę”. W mitologiach greckiej i rzymskiej <a href=\"https://pl.wikipedia.org/wiki/Maja_(mitologia_grecka)\" target=\"_blank\" rel=\"noopener noreferrer\">Maja</a> była najstarszą z <a href=\"https://pl.wikipedia.org/wiki/Nimfy\" target=\"_blank\" rel=\"noopener noreferrer\">nimf</a> – <a href=\"https://pl.wikipedia.org/wiki/Plejady_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Plejad</a>, córek <a href=\"https://pl.wikipedia.org/wiki/Zeus\" target=\"_blank\" rel=\"noopener noreferrer\">Zeusa</a> i <a href=\"https://pl.wikipedia.org/wiki/Plejone_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Plejone</a>, oraz matką <a href=\"https://pl.wikipedia.org/wiki/Hermes\" target=\"_blank\" rel=\"noopener noreferrer\">Hermesa</a>.", "Marie-Thérése": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Marie Barbara": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Mary Fe": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mary</b>.</p><p>Mary: Mary (Mary, rzadko Marie) - angielskie nazwisko kobiece, odpowiadające rosyjskiej nazwie Maria. Jest to jedno z najstarszych nazw zachowanych do naszych czasów.</p>", "Marie-Hélène": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Maria Luisa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mara-Ioana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mara</b>.</p><b>Mara</b> – włoskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> (hebr. מָרָא), występujące w <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starym Testamencie</a>.", "Marie-Caroline": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Marie-Line": "<p>Marie-Line to kobiece słowo, które nosi: Marie-Lane Marolany, nazwisko urodzenia Marie Line, francuska piosenkarka, która wzięła udział w konkursie piosenki Eurovision 1998 Marie-Lline Pollet, belgijska paraatleta w latach 80. i 90. Marie-Lune Reynaud (ur. 1954), francuska polityk</p>", "Maria Alicja": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Motoko": "<b>Motoko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;もとこ, モトコ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Maria-Ionela": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mariia-Myroslava": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria Marta": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria-Bianca": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Martha Isabel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Martha</b>.</p><p>Martha może odnosić się do: Martha Vasconcellos Martha Chase Martha Greenblatt Święta Matka Kościoła Katolickiego.</p>", "Marie-Thérèse": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Maria Luz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Marie-Rose": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Mozhgan": "<p>Mozhgan, również pisane Mojgan Mezhgan (perskiej: مژگان) Mozhgān IPA: [mɔʒˈɡɒːn] i Mozhan jest perską nazwą dla dziewcząt. Mozhgan jest wielokrotną formą Mozhy (perskiej: مژه) IPA: [mɔʒɛ], co oznacza \"mięśnie\".</p>", "Maria Wiktoria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Majola": "<b>Majola</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81ac.\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, od słowa oznaczającego \"maj\". Patronem tego imienia jest św. <a href=\"https://pl.wikipedia.org/wiki/Majol\" target=\"_blank\" rel=\"noopener noreferrer\">Majol</a>, opat <a href=\"https://pl.wikipedia.org/wiki/Cluny\" target=\"_blank\" rel=\"noopener noreferrer\">Cluny</a> (<a href=\"https://pl.wikipedia.org/wiki/X_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">X wiek</a>).", "Maia-Sonia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maia</b>.</p><p>Maia (grek. Μαῖα; lat. Maia), w starożytnej greckiej religii, była jedną z Pleiad i matką Hermesa. Maia była córką Atlas i Pleione the Oceanid, a była najstarszą z siedmiu Pleiad.</p>", "Marylyn": "<p>Marilyn to kobiece imię.</p>", "Monica Del Pilar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Monica</b>.</p><p>Monica Denise Brown (ang. Monica Denise Brown), w dziewczynstwie - Arnold (ang.</p>", "Mironia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mironi</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Miron</b>.</p><b>Miron</b> (<i>Myron</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa <i>myron</i> oznaczającego „wonny olejek, pachnidło”.", "Mihret": "<p>Mihret to męskie imię i nazwisko. Na Bałkanach Mihret jest popularny wśród bosniaków w dawnych krajach Jugosłowiańskiej.</p>", "Maria-Elena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Minh Ánh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Marie Catherine": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Michaëla": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Michael</b>.</p><p>Michael: Botanika Michael - skrócie botaniczne, oznaczające, że autorem taksy jest Edmund Michael. Muzyka ⁇ Michael ⁇ - piosenka grupy Franz Ferdinand, wydana w 2004 roku.</p>", "Mikelina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mikel</b>.</p><p>Mikel jest baskijską adaptacją nazwiska Michaela. Nazwa Mikel pochodzi od hebrajskiego słowa Micha'el, co oznacza \"Kto jest jak Bóg\".</p>", "Mi Jung": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mi</b>.</p><p>Mi może być: Mi (powieść), znakiem E Mi (ty), a to jest powieść wietnamska.</p>", "Maria Angeles": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Minh Hang": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Minh Nguyệt": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Melisa-Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Melisa</b>.</p><b>Melisa</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, oznacza „pszczołę” (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;μέλισσα). W <a href=\"https://pl.wikipedia.org/wiki/Mitologia_grecka\" target=\"_blank\" rel=\"noopener noreferrer\">greckiej mitologii</a> Melissa była jedną z <a href=\"https://pl.wikipedia.org/wiki/Nimfy\" target=\"_blank\" rel=\"noopener noreferrer\">nimf</a> opiekujących się małym <a href=\"https://pl.wikipedia.org/wiki/Zeus\" target=\"_blank\" rel=\"noopener noreferrer\">Zeusem</a>.", "Maria-Nicoleta": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Marie-Charlotte": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Marie-José": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Maurine": "<p>Maurine może odnosić się do: Miejsca: Maurine (strumień), Mecklenburg-Vorpommern, Niemcy Maurine, Missouri, społeczność w Stanach Zjednoczonych Maurine, Dakota Południowa, społecznością w Stanach zjednoczonych Ludzi: Maurine, (piłkarz) (ur. 1986), brazylijską piłkarz Maurine Karagianis (ur. 1950), kanadyjską politykę Maurine Brown Neuberger (1907-2000), amerykańską senatorkę z Oregonu Maurine Dallas Watkins (1896-1969), amerykańską dziennikarz i dramatykę Maurina...</p>", "Mbali": "<p>Mbali to kobiece imię, które oznacza \" kwiat. \" Mbali, Ouham-Fafa, wioska w prefekturze Ouham - Fafa, Republika Środkowoafrykańska język Mbali, niewielki język Bantu Angoli Mbali Dhlamini, artysta południowoafryki Mbali Ntuli (ur. 1988), południo Afrykański polityk Mbali Sigidi, południowa Afrykańskie nadawca sportowy</p>", "Małgorzata Zofia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Małgorzata</b>.</p><b>Małgorzata</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Margarita</em>, które pochodziło od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;μαργαρίτης <i>margarites</i> oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Per%C5%82y_naturalne\" target=\"_blank\" rel=\"noopener noreferrer\">perłę</a>”, które ma źródło w formie <a href=\"https://pl.wikipedia.org/wiki/Derywacja_(j%C4%99zykoznawstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">derywowanej</a> od <a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sanskryckiego</a> मञ्यरी <i>mañjarī</i> oznaczającego m.in. „perłę”, „pąk kwiatowy”, „kwiat”, „<a href=\"https://pl.wikipedia.org/wiki/Li%C5%9B%C4%87\" target=\"_blank\" rel=\"noopener noreferrer\">listowie</a> (w formie ornamentu na budynku)”.", "Maria Bronisława": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Miłowana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Miłowan</b>.</p><b>Miłowan</b> – słowiańskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie jednoczłonowe, utworzone z członu <i>Miło-</i> (\"miłować\"). Wzmiankowane w dokumentach z 1136 roku. Może oznaczać: miłowany. Popularne zwłaszcza w <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie_po%C5%82udniowi\" target=\"_blank\" rel=\"noopener noreferrer\">krajach południowosłowiańskich</a>", "Mariia-Nadiia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mitzi": "<p>Mitzi lub Mitzy (czasami Mitzie) to żeńskie imię pochodzenia niemieckiego. Pierwotnie nazwa dla dziewcząt z imieniem Maria w niemieckojęzycznych populacjach, Mitzi stała się własną nazwą, nawet poza Niemcami.</p>", "Miae": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mia</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mariia-Kamila": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria Johanna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Monica Andrea": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Monica</b>.</p><p>Monica Denise Brown (ang. Monica Denise Brown), w dziewczynstwie - Arnold (ang.</p>", "Maria Juliana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Magdalena Władysława": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Magdalena</b>.</p><b>Magdalena</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od przydomka <a href=\"https://pl.wikipedia.org/wiki/Maria_Magdalena\" target=\"_blank\" rel=\"noopener noreferrer\">Marii Magdaleny</a>, czyli Marii z <a href=\"https://pl.wikipedia.org/wiki/Magdala_(Izrael)\" target=\"_blank\" rel=\"noopener noreferrer\">Magdali</a>, wioski leżącej w pobliżu <a href=\"https://pl.wikipedia.org/wiki/Jezioro_Tyberiadzkie\" target=\"_blank\" rel=\"noopener noreferrer\">Jeziora Tyberiadzkiego (Galilejskiego)</a>.", "Melannia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Melania</b>.</p><b>Melania</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;μέλας, znaczącego „czarna”.", "Marta Cecilia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marta</b>.</p><b>Marta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. Wywodzi się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_aramejski\" target=\"_blank\" rel=\"noopener noreferrer\">aramejskiego</a> rzeczownika <i>mar</i>, <i>mar(a)tha, marta</i>, oznaczającego „pani domu, gospodyni, pani”. W Polsce po raz pierwszy zanotowano je w 1265 roku. Do dawnych zdrobnień zaliczała się np. Marusza (wsł., od wsł. <i>Marchwa</i>), oraz m.in. <i>Marocha, Marsza, Marszka, Marucha, Maruchna, Maruszka</i> (też od innych imion na Ma-, np. od <a href=\"https://pl.wikipedia.org/wiki/Ma%C5%82gorzata_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Małgorzaty</a>). Istnieje ponad 10 świętych katolickich o tym imieniu.", "Marie-Catherine": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Magdallena": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Magdalena</b>.</p><b>Magdalena</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od przydomka <a href=\"https://pl.wikipedia.org/wiki/Maria_Magdalena\" target=\"_blank\" rel=\"noopener noreferrer\">Marii Magdaleny</a>, czyli Marii z <a href=\"https://pl.wikipedia.org/wiki/Magdala_(Izrael)\" target=\"_blank\" rel=\"noopener noreferrer\">Magdali</a>, wioski leżącej w pobliżu <a href=\"https://pl.wikipedia.org/wiki/Jezioro_Tyberiadzkie\" target=\"_blank\" rel=\"noopener noreferrer\">Jeziora Tyberiadzkiego (Galilejskiego)</a>.", "Marta-Mariya": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marta</b>.</p><b>Marta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. Wywodzi się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_aramejski\" target=\"_blank\" rel=\"noopener noreferrer\">aramejskiego</a> rzeczownika <i>mar</i>, <i>mar(a)tha, marta</i>, oznaczającego „pani domu, gospodyni, pani”. W Polsce po raz pierwszy zanotowano je w 1265 roku. Do dawnych zdrobnień zaliczała się np. Marusza (wsł., od wsł. <i>Marchwa</i>), oraz m.in. <i>Marocha, Marsza, Marszka, Marucha, Maruchna, Maruszka</i> (też od innych imion na Ma-, np. od <a href=\"https://pl.wikipedia.org/wiki/Ma%C5%82gorzata_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Małgorzaty</a>). Istnieje ponad 10 świętych katolickich o tym imieniu.", "Milana-Mariia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Milana</b>.</p><b>Milena</b> lub <b>Milana</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, używane w językach <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_bu%C5%82garski\" target=\"_blank\" rel=\"noopener noreferrer\">bułgarskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_czeski\" target=\"_blank\" rel=\"noopener noreferrer\">czeskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_s%C5%82owacki\" target=\"_blank\" rel=\"noopener noreferrer\">słowackim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbsko-chorwacki\" target=\"_blank\" rel=\"noopener noreferrer\">chorwackim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">polskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbski\" target=\"_blank\" rel=\"noopener noreferrer\">serbskim</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_s%C5%82owe%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">słoweńskim</a>. Zawiera pierwiastek <i>mil</i> oznaczający „miły”. Męskim odpowiednikiem imienia jest <a href=\"https://pl.wikipedia.org/wiki/Milan_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Milan</a>.", "Maja-Lena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maja</b>.</p><b>Maja</b> – imię żeńskie pochodzenia greckiego, wywodzące się od słowa <i>μαῖα (maia)</i> oznaczającego „dobrą matkę”, „damę” lub „przybraną matkę”. W mitologiach greckiej i rzymskiej <a href=\"https://pl.wikipedia.org/wiki/Maja_(mitologia_grecka)\" target=\"_blank\" rel=\"noopener noreferrer\">Maja</a> była najstarszą z <a href=\"https://pl.wikipedia.org/wiki/Nimfy\" target=\"_blank\" rel=\"noopener noreferrer\">nimf</a> – <a href=\"https://pl.wikipedia.org/wiki/Plejady_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Plejad</a>, córek <a href=\"https://pl.wikipedia.org/wiki/Zeus\" target=\"_blank\" rel=\"noopener noreferrer\">Zeusa</a> i <a href=\"https://pl.wikipedia.org/wiki/Plejone_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Plejone</a>, oraz matką <a href=\"https://pl.wikipedia.org/wiki/Hermes\" target=\"_blank\" rel=\"noopener noreferrer\">Hermesa</a>.", "Margrith": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Margrit</b>.</p><p>Margrit to imię, co odpowiada angielskiej nazwie Margaret. Wśród znanych osób z tego nazwiska są: Margrit Bolli (1919-2017), szwajcarska tancerka Margrit Brückner (ur. 1946), niemiecki socjolog i profesor Margrit Conrad (1918-2005), szwajcarski piosenkarz Margrit Gertsch (ur. 1939), szwajcarka narciarka Alpinowa Margrit Hess (ur. 1947), szwajcaria biegaczka średniej odległości Margrit Kennedy (1939 -2013), niemiecka architekt, profesor, ekolog, autor i...</p>", "Maanasa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maanas</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Manas</b>.</p><p>Manas (stylownik: 玛纳斯县; substylownik; ślonski: 玛納斯县; ślony: Mǎnàsī Xiàn, vietnamski: Mǎnásī Xiàn; uygurski: Manas ناھىيىسى , ULY: Manas Nahiyisi, UPNY: Manas Nah ⁇ iyisi?) jest okręgem samorządu Azji narodowego muzułmańskiego, regionu samorządowego Tangiu, China. Obecnie mieści się w stanie Manas (玛纳斯), na brzegu rzeki Manas, wschodniej od Czarnogórza.</p>", "Milana-Anna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Milana</b>.</p><b>Milena</b> lub <b>Milana</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, używane w językach <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_bu%C5%82garski\" target=\"_blank\" rel=\"noopener noreferrer\">bułgarskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_czeski\" target=\"_blank\" rel=\"noopener noreferrer\">czeskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_s%C5%82owacki\" target=\"_blank\" rel=\"noopener noreferrer\">słowackim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbsko-chorwacki\" target=\"_blank\" rel=\"noopener noreferrer\">chorwackim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">polskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbski\" target=\"_blank\" rel=\"noopener noreferrer\">serbskim</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_s%C5%82owe%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">słoweńskim</a>. Zawiera pierwiastek <i>mil</i> oznaczający „miły”. Męskim odpowiednikiem imienia jest <a href=\"https://pl.wikipedia.org/wiki/Milan_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Milan</a>.", "Marie Dominique": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Mellania": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Melania</b>.</p><b>Melania</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;μέλας, znaczącego „czarna”.", "Marie Marguerite": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Maksymina": "<b>Maksymina</b> – żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Maksymin\" target=\"_blank\" rel=\"noopener noreferrer\">Maksymin</a> o pochodzeniu łacińskim.", "Magdalena Anna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Magdalena</b>.</p><b>Magdalena</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od przydomka <a href=\"https://pl.wikipedia.org/wiki/Maria_Magdalena\" target=\"_blank\" rel=\"noopener noreferrer\">Marii Magdaleny</a>, czyli Marii z <a href=\"https://pl.wikipedia.org/wiki/Magdala_(Izrael)\" target=\"_blank\" rel=\"noopener noreferrer\">Magdali</a>, wioski leżącej w pobliżu <a href=\"https://pl.wikipedia.org/wiki/Jezioro_Tyberiadzkie\" target=\"_blank\" rel=\"noopener noreferrer\">Jeziora Tyberiadzkiego (Galilejskiego)</a>.", "Maria-Aurora": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mariia-Yevheniia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Munavar": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Munawar</b>.</p><p>Munawar to imię i nazwisko. Do osób z tym nazwiskiem należą:</p>", "Min Ji": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Min</b>.</p><p>Min to niejednoznaczny termin. min - w matematyce i językach programowania oznacza funkcję wyboru najmniejszego ze swoich argumentów, (Min (3, 6, 2) = 2).</p>", "Mumtaz Mati": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mumtaz</b>.</p><p>Mumtaz (arabski: ممتاز) oznacza \"wystarczający\" w języku arabskim. Może być używana do sygnału pochwały za osiągnięcie, podobnego w znaczeniu do bravo i kudos.</p>", "Maria-Marta": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Małgorzata Anna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Małgorzata</b>.</p><b>Małgorzata</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Margarita</em>, które pochodziło od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;μαργαρίτης <i>margarites</i> oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Per%C5%82y_naturalne\" target=\"_blank\" rel=\"noopener noreferrer\">perłę</a>”, które ma źródło w formie <a href=\"https://pl.wikipedia.org/wiki/Derywacja_(j%C4%99zykoznawstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">derywowanej</a> od <a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sanskryckiego</a> मञ्यरी <i>mañjarī</i> oznaczającego m.in. „perłę”, „pąk kwiatowy”, „kwiat”, „<a href=\"https://pl.wikipedia.org/wiki/Li%C5%9B%C4%87\" target=\"_blank\" rel=\"noopener noreferrer\">listowie</a> (w formie ornamentu na budynku)”.", "Maria Justina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "María Isabel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mbalenhle": "<p>Mbalenhle to imiona żeńskie, pochodzące od słowa Nguni mbali, co oznacza \" kwiat. \"Wśród znanych osób z nazwiskiem są: Mbali Khumalo, południowoafrykańska królowa piękności, Miss Soweto 2024 Mbalenhl Mavimbela, połudnoafrykańskiej aktorki Enhle Mbali Mlotshwa (ur. 1988), południo Afrykańskiej aktorki.</p>", "Minh Vy": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Mary Christine": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mary</b>.</p><p>Mary: Mary (Mary, rzadko Marie) - angielskie nazwisko kobiece, odpowiadające rosyjskiej nazwie Maria. Jest to jedno z najstarszych nazw zachowanych do naszych czasów.</p>", "Maria Jesus": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Marie Grace": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Mariasole": "<p>Mariasole to powszechne kobiece włoskie imię. Wśród znanych osób z tej nazwy są: Mariasole Di Maio (ur. 2001), włoska aktorka Mariasole Pollio (ur. 2003), włoski aktor, telewizyjny prezenter i radiowizdor</p>", "Maria-Anastasia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria Konstancja": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Marta Barbara": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marta</b>.</p><b>Marta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. Wywodzi się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_aramejski\" target=\"_blank\" rel=\"noopener noreferrer\">aramejskiego</a> rzeczownika <i>mar</i>, <i>mar(a)tha, marta</i>, oznaczającego „pani domu, gospodyni, pani”. W Polsce po raz pierwszy zanotowano je w 1265 roku. Do dawnych zdrobnień zaliczała się np. Marusza (wsł., od wsł. <i>Marchwa</i>), oraz m.in. <i>Marocha, Marsza, Marszka, Marucha, Maruchna, Maruszka</i> (też od innych imion na Ma-, np. od <a href=\"https://pl.wikipedia.org/wiki/Ma%C5%82gorzata_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Małgorzaty</a>). Istnieje ponad 10 świętych katolickich o tym imieniu.", "Mingjia": "<b>Szkoła nazw</b> (<i>logiści</i>, <i>dialektycy</i>, <i>sofiści</i>) – jedna ze starożytnych <a href=\"https://pl.wikipedia.org/wiki/Filozofia_chi%C5%84ska\" target=\"_blank\" rel=\"noopener noreferrer\">chińskich szkół filozoficznych</a>, rozwijająca się w <a href=\"https://pl.wikipedia.org/wiki/Okres_Walcz%C4%85cych_Kr%C3%B3lestw\" target=\"_blank\" rel=\"noopener noreferrer\">Okresie Walczących Królestw</a>, znanym także jako okres „<a href=\"https://pl.wikipedia.org/wiki/Sto_szk%C3%B3%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Stu szkół</a>”. Jej przedstawiciele poświęcali się badaniom nad znaczeniami pojęć, ich systematyką i dociekaniem sposobów poprawnego rozumowania. Mimo iż szkoła nazw była niewielka i nie wywarła dużego wpływu na późniejsze systemy filozoficzne Państwa Środka, jest warta uwagi ze względu na fakt, iż była jedyną chińską szkołą myślową zajmującą się <a href=\"https://pl.wikipedia.org/wiki/Logika\" target=\"_blank\" rel=\"noopener noreferrer\">logiką</a> i problemami <a href=\"https://pl.wikipedia.org/wiki/Epistemologia\" target=\"_blank\" rel=\"noopener noreferrer\">epistemologicznymi</a>. Za twórcę szkoły uchodzi żyjący w VI wieku p.n.e. prawnik <a href=\"https://pl.wikipedia.org/wiki/Deng_Xi\" target=\"_blank\" rel=\"noopener noreferrer\">Deng Xi</a>.", "Maria Eleni": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Małgorzata Jadwiga": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Małgorzata</b>.</p><b>Małgorzata</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Margarita</em>, które pochodziło od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;μαργαρίτης <i>margarites</i> oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Per%C5%82y_naturalne\" target=\"_blank\" rel=\"noopener noreferrer\">perłę</a>”, które ma źródło w formie <a href=\"https://pl.wikipedia.org/wiki/Derywacja_(j%C4%99zykoznawstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">derywowanej</a> od <a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sanskryckiego</a> मञ्यरी <i>mañjarī</i> oznaczającego m.in. „perłę”, „pąk kwiatowy”, „kwiat”, „<a href=\"https://pl.wikipedia.org/wiki/Li%C5%9B%C4%87\" target=\"_blank\" rel=\"noopener noreferrer\">listowie</a> (w formie ornamentu na budynku)”.", "Maria Francisca": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maia-Larisa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maia</b>.</p><p>Maia (grek. Μαῖα; lat. Maia), w starożytnej greckiej religii, była jedną z Pleiad i matką Hermesa. Maia była córką Atlas i Pleione the Oceanid, a była najstarszą z siedmiu Pleiad.</p>", "Missy": "<p>Missy lub Missie to żeńskie imię, często skrócona forma Melissa.</p>", "Minako": "<b>Minako</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;みなこ, ミナコ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Milagros Sarita": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Milagros</b>.</p><p>Milagros może odnosić się do: Milagros, Burgos, miasto w prowincji Burgos, Kastilia i Leon, Hiszpania. Milagros, Masbate, jest miastem trzecim w prowincji Masbate w Filipinach.</p>", "Man Kumari": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Man</b>.</p><p>man (od angielskiego manual - wytyczne) - polecenie Unix przeznaczone do formatowania i wyciągania stron odniesienia.</p>", "Mohamed Shadab": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohamed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Maria-Narcisa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Milanija": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Milania</b>.</p><p>Melania to kobiece imię pochodzące z łacińskiego pochodzenia, które pochodzi od greckiego słowa melaina (μέλαινα), żeńskiej formy przymiotów melas (μέλας), co oznacza \"czarny\" lub \"ciemny\". Nazwa ta nosiła dwie święte Melania Starszą i jej wnuczka Melania Młodsza, a pochodzenie nazwy Melanie.</p>", "Maria-Luiza": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maëla": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maël</b>.</p><p>Mael (V wiek, Bretany lub Bretany, metropolia Francji - V wiek, Bardsi, Guinet) - święty odchodnik z Walii. Dzień Pamięci - 13 maja.</p>", "Marella": "<p>Marela, Marella lub Marrella mogą odnosić się do:</p>", "Marie E.": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Magdalena Agnieszka": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Magdalena</b>.</p><b>Magdalena</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od przydomka <a href=\"https://pl.wikipedia.org/wiki/Maria_Magdalena\" target=\"_blank\" rel=\"noopener noreferrer\">Marii Magdaleny</a>, czyli Marii z <a href=\"https://pl.wikipedia.org/wiki/Magdala_(Izrael)\" target=\"_blank\" rel=\"noopener noreferrer\">Magdali</a>, wioski leżącej w pobliżu <a href=\"https://pl.wikipedia.org/wiki/Jezioro_Tyberiadzkie\" target=\"_blank\" rel=\"noopener noreferrer\">Jeziora Tyberiadzkiego (Galilejskiego)</a>.", "Melissa-Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Melissa</b>.</p><p>Melissa (lat. Melissa) - rodzaj wieloletnich trawnic roślin rodziny Jasnowotków (Lamiaceae).</p>", "Macha": "Wraz z <a href=\"https://pl.wikipedia.org/wiki/Anann\" target=\"_blank\" rel=\"noopener noreferrer\">Anann</a> i <a href=\"https://pl.wikipedia.org/wiki/Badb\" target=\"_blank\" rel=\"noopener noreferrer\">Badb</a> tworzyła triumwirat bogiń wojny, należąc do grupy irlandzkich bóstw wojny. Karmiła się głowami swoich wrogów, lecz podobno często leczyła rannych. Uważano, że była <a href=\"https://pl.wikipedia.org/wiki/Monarcha\" target=\"_blank\" rel=\"noopener noreferrer\">królową</a> <a href=\"https://pl.wikipedia.org/wiki/Ulster\" target=\"_blank\" rel=\"noopener noreferrer\">Ulsteru</a>, której stolicę na cześć jej imienia nazwano Emain Macha. Ona i inne wcielenia Morrigan (Badb i <a href=\"https://pl.wikipedia.org/wiki/Nemain\" target=\"_blank\" rel=\"noopener noreferrer\">Nemhain</a>) wspomagały lud <a href=\"https://pl.wikipedia.org/wiki/Tuatha_de_Danaan\" target=\"_blank\" rel=\"noopener noreferrer\">Tuatha de Danaan</a> w walce z plemieniem <a href=\"https://pl.wikipedia.org/wiki/Fir_Bolg\" target=\"_blank\" rel=\"noopener noreferrer\">Firbolgów</a>.", "Marcelia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Marceli</b>.</p><b>Marceli</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od nazwy jednej z gałęzi rzymskiego <a href=\"https://pl.wikipedia.org/wiki/Klaudiusze\" target=\"_blank\" rel=\"noopener noreferrer\">rodu Klaudiuszów</a>, <i>Marcelli</i>. Imię to bywa nadawane także w formie <b>Marcel</b>, jakkolwiek pojawia się ona w wydawnictwach poprawnościowych jako nieakceptowana. Żeńskim odpowiednikiem jest <a href=\"https://pl.wikipedia.org/wiki/Marcela\" target=\"_blank\" rel=\"noopener noreferrer\">Marcela</a>.", "Moyra": "<p>Moyra to imię kobiece. Wśród znanych osób z tym nazwiskiem są: Moyra Allen (1921-1996), kanadyjska pielęgniarka Moyra Barry (1886-1960), irlandzka artystka Moyra Browne (1918-2016), brytyjska pielęgnówka Moyra Caldecott (1927-2015), brytyjska autorka Moyra Davey (urodzona w 1958 r.), amerykańska artystka moyra Donaldson (urodzony w 1956 r.), północnoirlandzkiaca autorka Moira Fraser (1923-2009), australijskiej aktorki Moyra Hiscox (urodzono w 1937 r.), brytyjska biegaczka średniej odległości</p>", "Mariia-Zoriana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Monica Tatiana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Monica</b>.</p><p>Monica Denise Brown (ang. Monica Denise Brown), w dziewczynstwie - Arnold (ang.</p>", "Maria Esperanza": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria Waleria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria Elizabeth": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Marie-Emilie": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Magdalena Teresa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Magdalena</b>.</p><b>Magdalena</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od przydomka <a href=\"https://pl.wikipedia.org/wiki/Maria_Magdalena\" target=\"_blank\" rel=\"noopener noreferrer\">Marii Magdaleny</a>, czyli Marii z <a href=\"https://pl.wikipedia.org/wiki/Magdala_(Izrael)\" target=\"_blank\" rel=\"noopener noreferrer\">Magdali</a>, wioski leżącej w pobliżu <a href=\"https://pl.wikipedia.org/wiki/Jezioro_Tyberiadzkie\" target=\"_blank\" rel=\"noopener noreferrer\">Jeziora Tyberiadzkiego (Galilejskiego)</a>.", "Mei-Ling": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mei</b>.</p><p>- Nie, nie, nie. Mei - Mei (dinosaur) MEI - Matsushita Electric Industrial Co.</p>", "Maria Concepcion": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mélani": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Melany</b>.</p><p>Melanie to kobiece imię pochodzące od greckiego μελανία (melania), \"czarność\", a od μέλας (melas), oznaczające \"ciemny\". Urodzony w łacinie przez dwóch świętych, Melanię Starszą i jej wnuczkę Melanię Młodszą, nazwę wprowadzili do Anglii Normanie w francuskiej formie Melanie.</p>", "Medeea-Raisa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Medeea</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Medea</b>.</p><p>Media: Medea (grek. Μήδεια) - w starożytnej mitologii greckiej córka kolchydskiego króla Eeta, obdarzona darem magii.</p>", "Miss Sunisa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Miss</b>.</p><p>Miss - trzeci studiowy album rosyjskiej piosenkarki Dory, wydany 3 czerwca 2022 roku na wytwórni Rhymes Music. Album zawiera 13 utworów.</p>", "Maria Liza": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Marie Noëlle": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Maria Julia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mełanija": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Melania</b>.</p><b>Melania</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;μέλας, znaczącego „czarna”.", "Marie Sophie": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Maria Elisa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Małgorzata Ewa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Małgorzata</b>.</p><b>Małgorzata</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Margarita</em>, które pochodziło od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;μαργαρίτης <i>margarites</i> oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Per%C5%82y_naturalne\" target=\"_blank\" rel=\"noopener noreferrer\">perłę</a>”, które ma źródło w formie <a href=\"https://pl.wikipedia.org/wiki/Derywacja_(j%C4%99zykoznawstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">derywowanej</a> od <a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sanskryckiego</a> मञ्यरी <i>mañjarī</i> oznaczającego m.in. „perłę”, „pąk kwiatowy”, „kwiat”, „<a href=\"https://pl.wikipedia.org/wiki/Li%C5%9B%C4%87\" target=\"_blank\" rel=\"noopener noreferrer\">listowie</a> (w formie ornamentu na budynku)”.", "Maria-Larisa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria Fanny": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria-Adela": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria-Mirabela": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mary Isabel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mary</b>.</p><p>Mary: Mary (Mary, rzadko Marie) - angielskie nazwisko kobiece, odpowiadające rosyjskiej nazwie Maria. Jest to jedno z najstarszych nazw zachowanych do naszych czasów.</p>", "Marianna Janina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marianna</b>.</p><b>Marianna</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Marian\" target=\"_blank\" rel=\"noopener noreferrer\">Marian</a>. Potocznie jest ono często błędnie rozumiane jako wynik złożenia dwóch innych imion: <a href=\"https://pl.wikipedia.org/wiki/Maria\" target=\"_blank\" rel=\"noopener noreferrer\">Marii</a> i <a href=\"https://pl.wikipedia.org/wiki/Anna\" target=\"_blank\" rel=\"noopener noreferrer\">Anny</a>, analogicznie do <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">ang.</a>&#160;<em>Maryann</em>.", "Maria Trinidad": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria Eleonora": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mari-Nikol": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mari</b>.</p><p>Mari to miasto w brazylijskim stanie Paraíba. Miasto ma powierzchnię 154,726 km2, liczba ludności w 2007 roku wynosi 20634 osób, a jego gęstość 133,4 osób/km2.</p>", "Mariiami": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mariami</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mariam</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria Catalina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Monica-Andreea": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Monica</b>.</p><p>Monica Denise Brown (ang. Monica Denise Brown), w dziewczynstwie - Arnold (ang.</p>", "Mi Ran": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mi</b>.</p><p>Mi może być: Mi (powieść), znakiem E Mi (ty), a to jest powieść wietnamska.</p>", "Maria Paz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mariia-Ilona": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Marléne": "<p>Marlene to niemieckie imię dla kobiet. Jest wywodzona z Maryi w połączeniu z Magdaleny.</p>", "Mariita": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Marita</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Marijka": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Marika</b>.</p><b>Marika</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzące od imienia „<a href=\"https://pl.wikipedia.org/wiki/Maria\" target=\"_blank\" rel=\"noopener noreferrer\">Maria</a>”. Jest <a href=\"https://pl.wikipedia.org/wiki/W%C4%99gry\" target=\"_blank\" rel=\"noopener noreferrer\">węgierską</a> formą tego imienia, chociaż znane jest także w Bułgarii i na terenie byłej Jugosławii. Imię jest również zniemczoną formą zdrobnienia „Maryjka” występującego w <a href=\"https://pl.wikipedia.org/wiki/Etnolekt_%C5%9Bl%C4%85ski\" target=\"_blank\" rel=\"noopener noreferrer\">etnolekcie śląskim</a>.", "Melanie Rae": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Melanie</b>.</p><p>Melanie Melanie to siódmy album studiowy piosenkarki Celine Dion. Melanie - jedna z marek handlowych białoruskiej fabryki cukier ⁇ Spartak ⁇ .</p>", "Maria Inmaculada": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mariia Oleksandra": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria Dorota": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria-Natalia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mi Sun": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mi</b>.</p><p>Mi może być: Mi (powieść), znakiem E Mi (ty), a to jest powieść wietnamska.</p>", "Mildreda": "<b>Mildreda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, składające się z członów <i>mil- //mild-</i> (\"miłosierna, szczera, dobra\") i <i>-red // -rad</i> (\"pomoc, rada, ratunek\").", "Mi Hyang": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mi</b>.</p><p>Mi może być: Mi (powieść), znakiem E Mi (ty), a to jest powieść wietnamska.</p>", "Maria Irene": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mi Hyun": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mi</b>.</p><p>Mi może być: Mi (powieść), znakiem E Mi (ty), a to jest powieść wietnamska.</p>", "Mădălina-Gabriela": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mădălina</b>.</p><p>Mădălina to rumuńska kobieca nazwa, która może odnosić się do: Mădăline Cioveie (ur. 1983), rumuńska gimnastka aerobowa Mădălină Diana Ghenea (ur. 1987), rumuńskiej włoskiej aktorki i modelu Mădălinei Gojnea (ur. 1987), rumuńskiego tenisa Mădăliny Manole (1967-2010), rumuński pop artysta Mădălino Zamfirescu (ur. 1994), rumuńczyka piłkarka ręka</p>", "Maria-Daniela": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria Patricia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria Edith": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Man Ling": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Man</b>.</p><p>man (od angielskiego manual - wytyczne) - polecenie Unix przeznaczone do formatowania i wyciągania stron odniesienia.</p>", "Miss Thapanee": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Miss</b>.</p><p>Miss - trzeci studiowy album rosyjskiej piosenkarki Dory, wydany 3 czerwca 2022 roku na wytwórni Rhymes Music. Album zawiera 13 utworów.</p>", "Mykhailyna-Khrystyna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mykhailyna</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mikhailina</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mikhail</b>.</p><p>Michał (Hebrajskie: מִיכָאֵל; Aramejski: ⁇ , romanized: Mīkhāʼēl) jest powszechnym męskim imieniem, które zazwyczaj uważa się za pochodzące z hebrajskiego pytania retorycznego מי כאל (mī kāʼēl), \"Kto [jest] podobny do [Hebrajskiego boga] El?\", a więc jest nazwiskiem teoforycznym, którego odpowiedź brzmi \"nie ma nikogo podobnego do El\", lub \"nie słynny i potężny jak Bóg\".[is] Paradoksalnie, nazwisko jest czasami interpretowane jako \"Jeden...</p>", "Maria Adelajda": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Meliana": "Imiona wszystkich Majarów pochodzą z quenyi.", "Migdalia": "<p>Migdalia to imię kobiece. Znanymi osobami z nazwiska są: Migdalia Cruz (ur. 1958), amerykański pisarz sztuk, teatru muzycznego i opery Migdalia González (ur. 1973), polityk z Portoryka Migdalia Padilla, polityk z Puerto Rico Migdalia Pérez, kubański piłkarz baseballu</p>", "Maria Guadalupe": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Monica Bibiana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Monica</b>.</p><p>Monica Denise Brown (ang. Monica Denise Brown), w dziewczynstwie - Arnold (ang.</p>", "Maria Lidia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mikalina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mikal</b>.</p><b>Mikal</b> (hebr. מיכל; skrócona forma imienia <i>Michael</i> − <i>kto jest jak Bóg</i>) − córka <a href=\"https://pl.wikipedia.org/wiki/Saul_(kr%C3%B3l_Izraela)\" target=\"_blank\" rel=\"noopener noreferrer\">Saula</a>, króla Izraela, pierwsza żona króla <a href=\"https://pl.wikipedia.org/wiki/Dawid_(kr%C3%B3l_Izraela)\" target=\"_blank\" rel=\"noopener noreferrer\">Dawida</a>. Zapis historii Mikal przekazują <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijne</a> Księgi Samuela.", "Mama": "W <a href=\"https://pl.wikipedia.org/wiki/Prawo_rodzinne\" target=\"_blank\" rel=\"noopener noreferrer\">prawie rodzinnym</a> matka jest <a href=\"https://pl.wikipedia.org/wiki/Wst%C4%99pny\" target=\"_blank\" rel=\"noopener noreferrer\">wstępną</a> <a href=\"https://pl.wikipedia.org/wiki/Pokrewie%C5%84stwo\" target=\"_blank\" rel=\"noopener noreferrer\">krewną</a> <a href=\"https://pl.wikipedia.org/wiki/Stopie%C5%84_pokrewie%C5%84stwa\" target=\"_blank\" rel=\"noopener noreferrer\">pierwszego stopnia</a> w <a href=\"https://pl.wikipedia.org/wiki/Stopie%C5%84_pokrewie%C5%84stwa\" target=\"_blank\" rel=\"noopener noreferrer\">linii prostej</a>, od którego dziecko <a href=\"https://pl.wikipedia.org/wiki/Pochodzenie_dziecka\" target=\"_blank\" rel=\"noopener noreferrer\">pochodzi</a> bezpośrednio. W <a href=\"https://pl.wikipedia.org/wiki/Genealogia\" target=\"_blank\" rel=\"noopener noreferrer\">genealogii</a> matkę i dziecko łączy <a href=\"https://pl.wikipedia.org/wiki/Filiacja\" target=\"_blank\" rel=\"noopener noreferrer\">filiacja</a>, a matkę z <a href=\"https://pl.wikipedia.org/wiki/Ojciec\" target=\"_blank\" rel=\"noopener noreferrer\">ojcem</a> łączy <a href=\"https://pl.wikipedia.org/wiki/Koicja\" target=\"_blank\" rel=\"noopener noreferrer\">koicja</a>.", "Merisa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Meris</b>.</p><p>Meris to rodzaj motów z rodziny Geometridae opisywany przez George Duryea Hulst w 1896 roku.</p>", "Maria-Catalina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria Justyna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria-Irina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria-Cătălina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Myria": "<b>Myria</b> <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> (<i>ma</i> = 10&#160;000) i <b>myrio</b> (<i>mo</i> = 1/10&#160;000) – przedrostki używane w starszych wersjach <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_SI\" target=\"_blank\" rel=\"noopener noreferrer\">systemu metrycznego</a>, nie będące częścią <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_SI\" target=\"_blank\" rel=\"noopener noreferrer\">układu SI</a>. Przedrostki te pochodzą z greckiego μύριοι (mýrioi), oznaczającego zarówno „dziesięć tysięcy” jak i „nieskończenie wielka liczba” (podobne znaczenie ma także 10&#160;000 w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_chi%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">kulturze chińskiej</a>).", "Maria-Cosmina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Milena Patricia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Milena</b>.</p><b>Milena</b> lub <b>Milana</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, używane w językach <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_bu%C5%82garski\" target=\"_blank\" rel=\"noopener noreferrer\">bułgarskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_czeski\" target=\"_blank\" rel=\"noopener noreferrer\">czeskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_s%C5%82owacki\" target=\"_blank\" rel=\"noopener noreferrer\">słowackim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbsko-chorwacki\" target=\"_blank\" rel=\"noopener noreferrer\">chorwackim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">polskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbski\" target=\"_blank\" rel=\"noopener noreferrer\">serbskim</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_s%C5%82owe%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">słoweńskim</a>. Zawiera pierwiastek <i>mil</i> oznaczający „miły”. Męskim odpowiednikiem imienia jest <a href=\"https://pl.wikipedia.org/wiki/Milan_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Milan</a>.", "Mây": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mai</b>.</p><b>Mai</b> – imię dwupłciowe używane w wielu państwach świata.", "Maria Ximena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mi̇a": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mya</b>.</p><p>Mya - rodzaj morskich dwustronnych małp z rodziny Myidae.</p>", "Marie Pauline": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Maria Do Mar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mely": "<p>Melly, Mely lub Mellie mogą odnosić się do:</p>", "Meli̇ssa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Melisa</b>.</p><b>Melisa</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, oznacza „pszczołę” (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;μέλισσα). W <a href=\"https://pl.wikipedia.org/wiki/Mitologia_grecka\" target=\"_blank\" rel=\"noopener noreferrer\">greckiej mitologii</a> Melissa była jedną z <a href=\"https://pl.wikipedia.org/wiki/Nimfy\" target=\"_blank\" rel=\"noopener noreferrer\">nimf</a> opiekujących się małym <a href=\"https://pl.wikipedia.org/wiki/Zeus\" target=\"_blank\" rel=\"noopener noreferrer\">Zeusem</a>.", "Meaza": "<p>Meaza (amharski: መዓዛ) to etyopskie nazwisko kobiece. Wśród znanych osób z imieniem: Meaza Ashenafi (ur. 1964), etyopska prawnika i działaczka na rzecz praw kobiet Meaza Mohammed, etyopski dziennikarz i działacka na rzecz praw człowieka</p>", "Meadhbh": "<p>Medb (staroirlandzką [mjeðβ]), później wypełniony jako Meadhbh (średnioirlandzkie [mjɛɣβ]), Méabh (a) ]) i Méibh (irlandzkiego [mjeːvj]), a często angliczowany jako Maeve (MAYV), jest królową Connacht w cyklu Ulster w mitologii irlandzkiej. Jej mąż w głównych opowieściach cyklu jest Ailill mac Máta, chociaż miała kilka mężów przed nim, którzy byli również królami Connacht.</p>", "Małgorzata Julia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Małgorzata</b>.</p><b>Małgorzata</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Margarita</em>, które pochodziło od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;μαργαρίτης <i>margarites</i> oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Per%C5%82y_naturalne\" target=\"_blank\" rel=\"noopener noreferrer\">perłę</a>”, które ma źródło w formie <a href=\"https://pl.wikipedia.org/wiki/Derywacja_(j%C4%99zykoznawstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">derywowanej</a> od <a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sanskryckiego</a> मञ्यरी <i>mañjarī</i> oznaczającego m.in. „perłę”, „pąk kwiatowy”, „kwiat”, „<a href=\"https://pl.wikipedia.org/wiki/Li%C5%9B%C4%87\" target=\"_blank\" rel=\"noopener noreferrer\">listowie</a> (w formie ornamentu na budynku)”.", "Maliia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Malia</b>.</p><p>Malia (lat. Malia grata) - gatunek ptaków z rodziny zardów.</p>", "Marta Anna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marta</b>.</p><b>Marta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. Wywodzi się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_aramejski\" target=\"_blank\" rel=\"noopener noreferrer\">aramejskiego</a> rzeczownika <i>mar</i>, <i>mar(a)tha, marta</i>, oznaczającego „pani domu, gospodyni, pani”. W Polsce po raz pierwszy zanotowano je w 1265 roku. Do dawnych zdrobnień zaliczała się np. Marusza (wsł., od wsł. <i>Marchwa</i>), oraz m.in. <i>Marocha, Marsza, Marszka, Marucha, Maruchna, Maruszka</i> (też od innych imion na Ma-, np. od <a href=\"https://pl.wikipedia.org/wiki/Ma%C5%82gorzata_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Małgorzaty</a>). Istnieje ponad 10 świętych katolickich o tym imieniu.", "Mariia-Roksolana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mariia-Renata": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Margy": "<p>Margy to kobiece imię. Wśród znanych osób z tej nazwy są: Margy Conditt, były republikański członek Izby Reprezentantów Ohio, Margy Hart, striptizerka z Nowego Jorku, brytyjska reżyserka i producentka Margy Osmond, australijska biznesmena Margy Reed, imię urodzenia Marthy Raye Margy Windeyer, australijski bibliotekarz i feministka</p>", "Mariia-Bozhena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria Manuela": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maribell": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maribel</b>.</p><p>Maribel to hiszpańska nazwa, utworzona jako skrócenie od María Isabel. Alternatywnie, jest to angielskie nazwisko, połączona wersja Mary i Belle.</p>", "Mia-Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mia</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mariia-Vitaliia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "María José": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria-Ioana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria-Antonina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Marianna-Yuliia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marianna</b>.</p><b>Marianna</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Marian\" target=\"_blank\" rel=\"noopener noreferrer\">Marian</a>. Potocznie jest ono często błędnie rozumiane jako wynik złożenia dwóch innych imion: <a href=\"https://pl.wikipedia.org/wiki/Maria\" target=\"_blank\" rel=\"noopener noreferrer\">Marii</a> i <a href=\"https://pl.wikipedia.org/wiki/Anna\" target=\"_blank\" rel=\"noopener noreferrer\">Anny</a>, analogicznie do <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">ang.</a>&#160;<em>Maryann</em>.", "Mechthild": "<p>Mechthild to żeńskie germańskie imię. Jest to stara forma nazwiska Matilda i oznacza \"silny w walce, silny bojownik\".</p>", "Maria-Elisa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Małgorzata Barbara": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Małgorzata</b>.</p><b>Małgorzata</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Margarita</em>, które pochodziło od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;μαργαρίτης <i>margarites</i> oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Per%C5%82y_naturalne\" target=\"_blank\" rel=\"noopener noreferrer\">perłę</a>”, które ma źródło w formie <a href=\"https://pl.wikipedia.org/wiki/Derywacja_(j%C4%99zykoznawstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">derywowanej</a> od <a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sanskryckiego</a> मञ्यरी <i>mañjarī</i> oznaczającego m.in. „perłę”, „pąk kwiatowy”, „kwiat”, „<a href=\"https://pl.wikipedia.org/wiki/Li%C5%9B%C4%87\" target=\"_blank\" rel=\"noopener noreferrer\">listowie</a> (w formie ornamentu na budynku)”.", "Marta-Anastasiia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marta</b>.</p><b>Marta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. Wywodzi się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_aramejski\" target=\"_blank\" rel=\"noopener noreferrer\">aramejskiego</a> rzeczownika <i>mar</i>, <i>mar(a)tha, marta</i>, oznaczającego „pani domu, gospodyni, pani”. W Polsce po raz pierwszy zanotowano je w 1265 roku. Do dawnych zdrobnień zaliczała się np. Marusza (wsł., od wsł. <i>Marchwa</i>), oraz m.in. <i>Marocha, Marsza, Marszka, Marucha, Maruchna, Maruszka</i> (też od innych imion na Ma-, np. od <a href=\"https://pl.wikipedia.org/wiki/Ma%C5%82gorzata_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Małgorzaty</a>). Istnieje ponad 10 świętych katolickich o tym imieniu.", "Michell Alexandra": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Michell</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Michelle</b>.</p><p>⁇ Michelle ⁇ (z angielskiego - ⁇ Mishel ⁇) - miłosna balada angielskiego zespołu rockowego The Beatles, napisana przez Paula McCartney'ego (pisanego przez J.</p>", "Madalen": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Madalena</b>.</p><p>Madalena jest miastem w Brazylii. Miasto ma powierzchnię 1034,773 km2, liczba ludności w 2007 roku wynosi 15950 osób, a jego gęstość wynosi 15,41 osoby/km2.</p>", "Marie A": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Mèlanie": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Melani</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Melany</b>.</p><p>Melanie to kobiece imię pochodzące od greckiego μελανία (melania), \"czarność\", a od μέλας (melas), oznaczające \"ciemny\". Urodzony w łacinie przez dwóch świętych, Melanię Starszą i jej wnuczkę Melanię Młodszą, nazwę wprowadzili do Anglii Normanie w francuskiej formie Melanie.</p>", "Maria Sophie": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maia-Ioana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maia</b>.</p><p>Maia (grek. Μαῖα; lat. Maia), w starożytnej greckiej religii, była jedną z Pleiad i matką Hermesa. Maia była córką Atlas i Pleione the Oceanid, a była najstarszą z siedmiu Pleiad.</p>", "Monika Joanna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Monika</b>.</p><b>Monika</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o znaczeniu i pochodzeniu trudnym do objaśnienia. Według niektórych badaczy imię pochodzi od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> słowa „monos” oznaczającego <i>jeden</i>, <i>sam</i>, <i>pojedynczy</i>, <i>jedynak</i> i <i>jedynaczka</i>. Z tego samego rdzenia pochodzą takie słowa jak: <a href=\"https://pl.wikipedia.org/wiki/Monogamia\" target=\"_blank\" rel=\"noopener noreferrer\">monogamia</a>, <a href=\"https://pl.wikipedia.org/wiki/Monoteizm\" target=\"_blank\" rel=\"noopener noreferrer\">monoteizm</a>, monaster (klasztor). Inne źródło podaje, że imię to wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> „monaché”, co znaczy <i>samotna</i>, <i>odosobniona</i>; we <a href=\"https://pl.wikipedia.org/wiki/W%C5%82ochy\" target=\"_blank\" rel=\"noopener noreferrer\">Włoszech</a> zakonnica zwana jest <i>monaca</i>, a w niektórych dialektach wręcz <i>monica</i>.", "Maria Mieczysława": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria Theresia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Małgorzata Elżbieta": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Małgorzata</b>.</p><b>Małgorzata</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Margarita</em>, które pochodziło od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;μαργαρίτης <i>margarites</i> oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Per%C5%82y_naturalne\" target=\"_blank\" rel=\"noopener noreferrer\">perłę</a>”, które ma źródło w formie <a href=\"https://pl.wikipedia.org/wiki/Derywacja_(j%C4%99zykoznawstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">derywowanej</a> od <a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sanskryckiego</a> मञ्यरी <i>mañjarī</i> oznaczającego m.in. „perłę”, „pąk kwiatowy”, „kwiat”, „<a href=\"https://pl.wikipedia.org/wiki/Li%C5%9B%C4%87\" target=\"_blank\" rel=\"noopener noreferrer\">listowie</a> (w formie ornamentu na budynku)”.", "Milagros Del Valle": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Milagros</b>.</p><p>Milagros może odnosić się do: Milagros, Burgos, miasto w prowincji Burgos, Kastilia i Leon, Hiszpania. Milagros, Masbate, jest miastem trzecim w prowincji Masbate w Filipinach.</p>", "Mai-Lan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mai</b>.</p><b>Mai</b> – imię dwupłciowe używane w wielu państwach świata.", "Mari Carmen": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mari</b>.</p><p>Mari to miasto w brazylijskim stanie Paraíba. Miasto ma powierzchnię 154,726 km2, liczba ludności w 2007 roku wynosi 20634 osób, a jego gęstość 133,4 osób/km2.</p>", "Milane": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Milan</b>.</p><b>Milan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię słowiańskie</a>. Jedno z licznych <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">zdrobnień od imion słowiańskich</a> zaczynających się na <i>Miło-</i>, takich jak <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82obor\" target=\"_blank\" rel=\"noopener noreferrer\">Miłobor</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82obrat\" target=\"_blank\" rel=\"noopener noreferrer\">Miłobrat</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82ogost_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miłogost</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82ogost_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miłgost</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82orad\" target=\"_blank\" rel=\"noopener noreferrer\">Miłorad</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82os%C5%82aw_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miłosław</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82os%C5%82aw_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miełosław</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82ostryj\" target=\"_blank\" rel=\"noopener noreferrer\">Miłostryj</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82owit\" target=\"_blank\" rel=\"noopener noreferrer\">Miłowit</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82owit\" target=\"_blank\" rel=\"noopener noreferrer\">Miłwit</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82osz\" target=\"_blank\" rel=\"noopener noreferrer\">Miłosz</a>. Obecnie imię Milan używane jest także samodzielnie.", "Marie Alice": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Miss Kanjana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Miss</b>.</p><p>Miss - trzeci studiowy album rosyjskiej piosenkarki Dory, wydany 3 czerwca 2022 roku na wytwórni Rhymes Music. Album zawiera 13 utworów.</p>", "Małgorzata Róża": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Małgorzata</b>.</p><b>Małgorzata</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Margarita</em>, które pochodziło od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;μαργαρίτης <i>margarites</i> oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Per%C5%82y_naturalne\" target=\"_blank\" rel=\"noopener noreferrer\">perłę</a>”, które ma źródło w formie <a href=\"https://pl.wikipedia.org/wiki/Derywacja_(j%C4%99zykoznawstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">derywowanej</a> od <a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sanskryckiego</a> मञ्यरी <i>mañjarī</i> oznaczającego m.in. „perłę”, „pąk kwiatowy”, „kwiat”, „<a href=\"https://pl.wikipedia.org/wiki/Li%C5%9B%C4%87\" target=\"_blank\" rel=\"noopener noreferrer\">listowie</a> (w formie ornamentu na budynku)”.", "Maya-Rebeca": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maya</b>.</p><p>Maya: Autodesk Maya to redaktor grafiki trójwymiarowej. Maya - album Banco de Gaia z 1994 roku.</p>", "Mion": "<b>Miony</b> – nietrwałe <a href=\"https://pl.wikipedia.org/wiki/Cz%C4%85stka_elementarna\" target=\"_blank\" rel=\"noopener noreferrer\">cząstki elementarne</a>, należące do <a href=\"https://pl.wikipedia.org/wiki/Lepton_(mechanika_kwantowa)\" target=\"_blank\" rel=\"noopener noreferrer\">leptonów</a>. Występują w dwóch stanach ładunkowych (będących wzajemnie <a href=\"https://pl.wikipedia.org/wiki/Antymateria\" target=\"_blank\" rel=\"noopener noreferrer\">antycząstkami</a>) μ i μ. Oznacza się je <a href=\"https://pl.wikipedia.org/wiki/Minusku%C5%82a\" target=\"_blank\" rel=\"noopener noreferrer\">minuskułą</a> greckiej litery <a href=\"https://pl.wikipedia.org/wiki/My_(litera)\" target=\"_blank\" rel=\"noopener noreferrer\">my</a>.", "Małgorzata Teresa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Małgorzata</b>.</p><b>Małgorzata</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Margarita</em>, które pochodziło od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;μαργαρίτης <i>margarites</i> oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Per%C5%82y_naturalne\" target=\"_blank\" rel=\"noopener noreferrer\">perłę</a>”, które ma źródło w formie <a href=\"https://pl.wikipedia.org/wiki/Derywacja_(j%C4%99zykoznawstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">derywowanej</a> od <a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sanskryckiego</a> मञ्यरी <i>mañjarī</i> oznaczającego m.in. „perłę”, „pąk kwiatowy”, „kwiat”, „<a href=\"https://pl.wikipedia.org/wiki/Li%C5%9B%C4%87\" target=\"_blank\" rel=\"noopener noreferrer\">listowie</a> (w formie ornamentu na budynku)”.", "Marie Irena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Maria Alina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mitsuko": "<b>Mitsuko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;みつこ, ミツコ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Maria Christine": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mariia-Vita": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria Josefa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Marijane": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mariane</b>.</p><p>Marianne to imię kobiety. Jest to francuska wersja greckiego Mariamne, który jest wariantem Maryi, ostatecznie z hebrajskiego Miriam (מִרְיָם Miryám), Mirjam (aramejski: Mariam).</p>", "Monika Teresa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Monika</b>.</p><b>Monika</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o znaczeniu i pochodzeniu trudnym do objaśnienia. Według niektórych badaczy imię pochodzi od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> słowa „monos” oznaczającego <i>jeden</i>, <i>sam</i>, <i>pojedynczy</i>, <i>jedynak</i> i <i>jedynaczka</i>. Z tego samego rdzenia pochodzą takie słowa jak: <a href=\"https://pl.wikipedia.org/wiki/Monogamia\" target=\"_blank\" rel=\"noopener noreferrer\">monogamia</a>, <a href=\"https://pl.wikipedia.org/wiki/Monoteizm\" target=\"_blank\" rel=\"noopener noreferrer\">monoteizm</a>, monaster (klasztor). Inne źródło podaje, że imię to wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> „monaché”, co znaczy <i>samotna</i>, <i>odosobniona</i>; we <a href=\"https://pl.wikipedia.org/wiki/W%C5%82ochy\" target=\"_blank\" rel=\"noopener noreferrer\">Włoszech</a> zakonnica zwana jest <i>monaca</i>, a w niektórych dialektach wręcz <i>monica</i>.", "Majja": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maja</b>.</p><b>Maja</b> – imię żeńskie pochodzenia greckiego, wywodzące się od słowa <i>μαῖα (maia)</i> oznaczającego „dobrą matkę”, „damę” lub „przybraną matkę”. W mitologiach greckiej i rzymskiej <a href=\"https://pl.wikipedia.org/wiki/Maja_(mitologia_grecka)\" target=\"_blank\" rel=\"noopener noreferrer\">Maja</a> była najstarszą z <a href=\"https://pl.wikipedia.org/wiki/Nimfy\" target=\"_blank\" rel=\"noopener noreferrer\">nimf</a> – <a href=\"https://pl.wikipedia.org/wiki/Plejady_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Plejad</a>, córek <a href=\"https://pl.wikipedia.org/wiki/Zeus\" target=\"_blank\" rel=\"noopener noreferrer\">Zeusa</a> i <a href=\"https://pl.wikipedia.org/wiki/Plejone_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Plejone</a>, oraz matką <a href=\"https://pl.wikipedia.org/wiki/Hermes\" target=\"_blank\" rel=\"noopener noreferrer\">Hermesa</a>.", "Metoda": "<b>Metoda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Greka\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Metody\" target=\"_blank\" rel=\"noopener noreferrer\">Metody</a>. Wywodzi się od słowa <i>methodos</i> - \"kroczący właściwą drogą\".", "Milosława": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Miłosław</b>.</p><b>Miłosław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie</a>/<a href=\"https://pl.wikipedia.org/wiki/Dzieje_imion_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie</a> imię męskie, złożone z członów <i>Miło-</i> (\"miły\", \"miłujący\") i <i>-sław</i> (\"sława\"). Znaczenie imienia: \"miły sławie\". Jednym ze stosowanych zdrobnień tego imienia, obok współczesnego \"Miłek\" i staropolskiego \"Miłko\", jest <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82osz\" target=\"_blank\" rel=\"noopener noreferrer\">Miłosz</a>.", "Maria-Rita": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Moni": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mon</b>.</p><p>Mon może oznaczać: Miasto miasta Mon w stanie Nagaland, Indie Nowoczesna Indie Nagaland, India Wyspa Mon w Danie Mianmarskie Narody i języki Naród Mon (lub Mon) w południowo-wschodniej Azji Mońskie (narodu Mon) w grupie języków Mon-Khmer Odmienne MON jest kodem IATA Monarch Airlines Powieść Mon (門) Soseki Natsume Japoński mon (文) jest popularny w Japonii</p>", "Marie-Astrid": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Milanne": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Milane</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Milan</b>.</p><b>Milan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię słowiańskie</a>. Jedno z licznych <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">zdrobnień od imion słowiańskich</a> zaczynających się na <i>Miło-</i>, takich jak <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82obor\" target=\"_blank\" rel=\"noopener noreferrer\">Miłobor</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82obrat\" target=\"_blank\" rel=\"noopener noreferrer\">Miłobrat</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82ogost_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miłogost</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82ogost_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miłgost</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82orad\" target=\"_blank\" rel=\"noopener noreferrer\">Miłorad</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82os%C5%82aw_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miłosław</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82os%C5%82aw_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Miełosław</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82ostryj\" target=\"_blank\" rel=\"noopener noreferrer\">Miłostryj</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82owit\" target=\"_blank\" rel=\"noopener noreferrer\">Miłowit</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82owit\" target=\"_blank\" rel=\"noopener noreferrer\">Miłwit</a>, <a href=\"https://pl.wikipedia.org/wiki/Mi%C5%82osz\" target=\"_blank\" rel=\"noopener noreferrer\">Miłosz</a>. Obecnie imię Milan używane jest także samodzielnie.", "Marytta": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maryta</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Marita</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Milana-Viktoriia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Milana</b>.</p><b>Milena</b> lub <b>Milana</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, używane w językach <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_bu%C5%82garski\" target=\"_blank\" rel=\"noopener noreferrer\">bułgarskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_czeski\" target=\"_blank\" rel=\"noopener noreferrer\">czeskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_s%C5%82owacki\" target=\"_blank\" rel=\"noopener noreferrer\">słowackim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbsko-chorwacki\" target=\"_blank\" rel=\"noopener noreferrer\">chorwackim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">polskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbski\" target=\"_blank\" rel=\"noopener noreferrer\">serbskim</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_s%C5%82owe%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">słoweńskim</a>. Zawiera pierwiastek <i>mil</i> oznaczający „miły”. Męskim odpowiednikiem imienia jest <a href=\"https://pl.wikipedia.org/wiki/Milan_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Milan</a>.", "Milenna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Milena</b>.</p><b>Milena</b> lub <b>Milana</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, używane w językach <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_bu%C5%82garski\" target=\"_blank\" rel=\"noopener noreferrer\">bułgarskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_czeski\" target=\"_blank\" rel=\"noopener noreferrer\">czeskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_s%C5%82owacki\" target=\"_blank\" rel=\"noopener noreferrer\">słowackim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbsko-chorwacki\" target=\"_blank\" rel=\"noopener noreferrer\">chorwackim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">polskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbski\" target=\"_blank\" rel=\"noopener noreferrer\">serbskim</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_s%C5%82owe%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">słoweńskim</a>. Zawiera pierwiastek <i>mil</i> oznaczający „miły”. Męskim odpowiednikiem imienia jest <a href=\"https://pl.wikipedia.org/wiki/Milan_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Milan</a>.", "Maty": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mati</b>.</p><p>Mati jest miastem w prowincji Davao Oriental, w Filipinach. To jest stolica prowincji.</p>", "Moral": "<b>Moral</b> właściwie <b>Kamil Michalak</b> (ur. <a href=\"https://pl.wikipedia.org/wiki/24_sierpnia\" target=\"_blank\" rel=\"noopener noreferrer\">24 sierpnia</a> <a href=\"https://pl.wikipedia.org/wiki/1985\" target=\"_blank\" rel=\"noopener noreferrer\">1985</a> w <a href=\"https://pl.wikipedia.org/wiki/D%C4%85browa_G%C3%B3rnicza\" target=\"_blank\" rel=\"noopener noreferrer\">Dąbrowie Górniczej</a>) – polski <a href=\"https://pl.wikipedia.org/wiki/Raper\" target=\"_blank\" rel=\"noopener noreferrer\">raper</a> i <a href=\"https://pl.wikipedia.org/wiki/Producent_muzyczny\" target=\"_blank\" rel=\"noopener noreferrer\">producent muzyczny</a>. Kamil Michalak znany jest przede wszystkim z występów w duecie wraz raperem <a href=\"https://pl.wikipedia.org/wiki/Gano_(raper)\" target=\"_blank\" rel=\"noopener noreferrer\">Gano</a> wraz z którym nagrał dwie płyty. Prowadzi także solową działalność artystyczną. Współtworzy także formację All Star-Team i kolektyw Gopside.", "Marie Elisabeth": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Mileni": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Milen</b>.</p><p>Milen (bułgarski: Милен) to bułgarskie męskie imię. Wśród znanych osób z tej nazwy są: Milen Bonev (ur. 1986), bułgarski piłkarz, obecnie grający dla Kaliakra Kavarna jako obrońca Milen Dobrev (ur. 1980), bułgarski ciężarosta Milen Hristov (ur. 1977), bułgara piłkarza piłkarka, który obecnie gra dla Neftochimic Burgas jako półbrzeg Milen Lahchev (ur., 1987), bułgaria piłkarze, obecnie gry...</p>", "Mahaut": "<p>Mahaut (w współczesnym francuskim: [mao], w starym francuskim:[maˈhawθ]) jest starym francuskiej formą nazwy Mathilde i odpowiednikiem angielskiego Maud, obecnie zazwyczaj występuje jako nazwisko. Może odnosić się do:</p>", "Mia-Rozalia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mia</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Magdalena Marie": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Magdalena</b>.</p><b>Magdalena</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od przydomka <a href=\"https://pl.wikipedia.org/wiki/Maria_Magdalena\" target=\"_blank\" rel=\"noopener noreferrer\">Marii Magdaleny</a>, czyli Marii z <a href=\"https://pl.wikipedia.org/wiki/Magdala_(Izrael)\" target=\"_blank\" rel=\"noopener noreferrer\">Magdali</a>, wioski leżącej w pobliżu <a href=\"https://pl.wikipedia.org/wiki/Jezioro_Tyberiadzkie\" target=\"_blank\" rel=\"noopener noreferrer\">Jeziora Tyberiadzkiego (Galilejskiego)</a>.", "Marie Joy": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Mélany": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Melani</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Melany</b>.</p><p>Melanie to kobiece imię pochodzące od greckiego μελανία (melania), \"czarność\", a od μέλας (melas), oznaczające \"ciemny\". Urodzony w łacinie przez dwóch świętych, Melanię Starszą i jej wnuczkę Melanię Młodszą, nazwę wprowadzili do Anglii Normanie w francuskiej formie Melanie.</p>", "Magdalena Janina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Magdalena</b>.</p><b>Magdalena</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od przydomka <a href=\"https://pl.wikipedia.org/wiki/Maria_Magdalena\" target=\"_blank\" rel=\"noopener noreferrer\">Marii Magdaleny</a>, czyli Marii z <a href=\"https://pl.wikipedia.org/wiki/Magdala_(Izrael)\" target=\"_blank\" rel=\"noopener noreferrer\">Magdali</a>, wioski leżącej w pobliżu <a href=\"https://pl.wikipedia.org/wiki/Jezioro_Tyberiadzkie\" target=\"_blank\" rel=\"noopener noreferrer\">Jeziora Tyberiadzkiego (Galilejskiego)</a>.", "Marie Blanche": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Maria Lilia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mudita": "<b>Mudita</b> – jest <a href=\"https://pl.wikipedia.org/wiki/Buddyzm\" target=\"_blank\" rel=\"noopener noreferrer\">buddyjskim</a> określeniem pochodzącym z języka <a href=\"https://pl.wikipedia.org/wiki/P%C4%81li\" target=\"_blank\" rel=\"noopener noreferrer\">pali</a> i <a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sanskrytu</a>, które oznacza <a href=\"https://pl.wikipedia.org/wiki/Rado%C5%9B%C4%87_(emocja)\" target=\"_blank\" rel=\"noopener noreferrer\">radość</a> z powodu pomyślności innych, <b>empatyczną radość</b>, <b>radosne współczucie</b>, <b>altruistyczną radość</b>, <b>współradość</b>. Można spotkać się też z określeniem <b>najwyższa radość</b>. Mudita jest czasem przedstawiana jako przeciwieństwo przyjemności czerpanej z czyjegoś nieszczęścia (w języku niemieckim istnieje określający to termin <a href=\"https://pl.wikipedia.org/wiki/Schadenfreude\" target=\"_blank\" rel=\"noopener noreferrer\">Schadenfreude</a>). Mudita jest trzecią z <a href=\"https://pl.wikipedia.org/wiki/Cztery_Niezmierzono%C5%9Bci\" target=\"_blank\" rel=\"noopener noreferrer\">Czterech Niezmierzoności</a>.", "Mariia-Tetiana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Martha Yolima": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Martha</b>.</p><p>Martha może odnosić się do: Martha Vasconcellos Martha Chase Martha Greenblatt Święta Matka Kościoła Katolickiego.</p>", "Maria-Simina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mónia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Moni</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mon</b>.</p><p>Mon może oznaczać: Miasto miasta Mon w stanie Nagaland, Indie Nowoczesna Indie Nagaland, India Wyspa Mon w Danie Mianmarskie Narody i języki Naród Mon (lub Mon) w południowo-wschodniej Azji Mońskie (narodu Mon) w grupie języków Mon-Khmer Odmienne MON jest kodem IATA Monarch Airlines Powieść Mon (門) Soseki Natsume Japoński mon (文) jest popularny w Japonii</p>", "Marie Alina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Maria Chiara": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mai Ha": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mai</b>.</p><b>Mai</b> – imię dwupłciowe używane w wielu państwach świata.", "Marie-Elizabeth": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Miss Chutima": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Miss</b>.</p><p>Miss - trzeci studiowy album rosyjskiej piosenkarki Dory, wydany 3 czerwca 2022 roku na wytwórni Rhymes Music. Album zawiera 13 utworów.</p>", "Marie-Christin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Maryianna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mariianna</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Marianna</b>.</p><b>Marianna</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Marian\" target=\"_blank\" rel=\"noopener noreferrer\">Marian</a>. Potocznie jest ono często błędnie rozumiane jako wynik złożenia dwóch innych imion: <a href=\"https://pl.wikipedia.org/wiki/Maria\" target=\"_blank\" rel=\"noopener noreferrer\">Marii</a> i <a href=\"https://pl.wikipedia.org/wiki/Anna\" target=\"_blank\" rel=\"noopener noreferrer\">Anny</a>, analogicznie do <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">ang.</a>&#160;<em>Maryann</em>.", "Maria Emilia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mirela-Rebeca": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mirela</b>.</p><b>Mirela</b>, <b>Mirella</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, pochodzące z <a href=\"https://pl.wikipedia.org/wiki/Dialekt_prowansalski\" target=\"_blank\" rel=\"noopener noreferrer\">dialektu prowansalskiego</a> <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_oksyta%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">języka oksytańskiego</a>, od imienia <i>Mirèio</i>. Zostało ono użyte po raz pierwszy w <a href=\"https://pl.wikipedia.org/wiki/Mirejo\" target=\"_blank\" rel=\"noopener noreferrer\">jednym z poematów</a> przez poetę <a href=\"https://pl.wikipedia.org/wiki/Fr%C3%A9d%C3%A9ric_Mistral\" target=\"_blank\" rel=\"noopener noreferrer\">Frédérica Mistrala</a>, który wywiódł <i>Mirèio</i> prawdopodobnie od słowa <i>mirar</i>, w dialekcie <a href=\"https://pl.wikipedia.org/wiki/Prowansja\" target=\"_blank\" rel=\"noopener noreferrer\">prowansalskim</a> oznaczającego „podziwiana” (z <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <i>mirare</i> „podziwiać”). Mirela może także stanowić skrócenie włoskiego imienia <i>Mirabella</i>.", "Mithu": "<p>Mithu to indyjskie imię żeńskie. Do wybitnych osób z tym nazwiskiem należą:</p>", "Maria Daniela": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Marta Ewa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marta</b>.</p><b>Marta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. Wywodzi się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_aramejski\" target=\"_blank\" rel=\"noopener noreferrer\">aramejskiego</a> rzeczownika <i>mar</i>, <i>mar(a)tha, marta</i>, oznaczającego „pani domu, gospodyni, pani”. W Polsce po raz pierwszy zanotowano je w 1265 roku. Do dawnych zdrobnień zaliczała się np. Marusza (wsł., od wsł. <i>Marchwa</i>), oraz m.in. <i>Marocha, Marsza, Marszka, Marucha, Maruchna, Maruszka</i> (też od innych imion na Ma-, np. od <a href=\"https://pl.wikipedia.org/wiki/Ma%C5%82gorzata_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Małgorzaty</a>). Istnieje ponad 10 świętych katolickich o tym imieniu.", "Min Ah": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Min</b>.</p><p>Min to niejednoznaczny termin. min - w matematyce i językach programowania oznacza funkcję wyboru najmniejszego ze swoich argumentów, (Min (3, 6, 2) = 2).</p>", "Marry Ann": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marry</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mary</b>.</p><p>Mary: Mary (Mary, rzadko Marie) - angielskie nazwisko kobiece, odpowiadające rosyjskiej nazwie Maria. Jest to jedno z najstarszych nazw zachowanych do naszych czasów.</p>", "Marie-Sylvie": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Maria Romana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mariia-Vladyslava": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mariia-Vasylyna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria Rozalia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mariia-Yaryna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Monica Lorena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Monica</b>.</p><p>Monica Denise Brown (ang. Monica Denise Brown), w dziewczynstwie - Arnold (ang.</p>", "Myłana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Milana</b>.</p><b>Milena</b> lub <b>Milana</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, używane w językach <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_bu%C5%82garski\" target=\"_blank\" rel=\"noopener noreferrer\">bułgarskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_czeski\" target=\"_blank\" rel=\"noopener noreferrer\">czeskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_s%C5%82owacki\" target=\"_blank\" rel=\"noopener noreferrer\">słowackim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbsko-chorwacki\" target=\"_blank\" rel=\"noopener noreferrer\">chorwackim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">polskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbski\" target=\"_blank\" rel=\"noopener noreferrer\">serbskim</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_s%C5%82owe%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">słoweńskim</a>. Zawiera pierwiastek <i>mil</i> oznaczający „miły”. Męskim odpowiednikiem imienia jest <a href=\"https://pl.wikipedia.org/wiki/Milan_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Milan</a>.", "Merim": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Merima</b>.</p><p>Merima to imiona żeńskie, które ma oddzielne pochodzenie habesha i słowiańskie.</p>", "Maria Soledad": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Meave": "<p>Medb (staroirlandzką [mjeðβ]), później wypełniony jako Meadhbh (średnioirlandzkie [mjɛɣβ]), Méabh (a) ]) i Méibh (irlandzkiego [mjeːvj]), a często angliczowany jako Maeve (MAYV), jest królową Connacht w cyklu Ulster w mitologii irlandzkiej. Jej mąż w głównych opowieściach cyklu jest Ailill mac Máta, chociaż miała kilka mężów przed nim, którzy byli również królami Connacht.</p>", "Mohamed Gouda Saleh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mohamed</b>.</p><p>Muhammad (Arabia; żył około 570 - 632) lub Mohamed (Han-Vietnam: German Pastor), był arabskim wysoconymi przywódcą religijnym, politycznym i wojskowym i założycielem islamu. W islamskim nauczaniu uważa się, że był prorokiem, którego Bóg posłał do głoszenia i potwierdzenia monoteizmu Adama, Abrahama, Mojżesza, Iza i poprzednich proroków.</p>", "Marie-Paule": "<p>Marie-Paule to femininowe słowo, które może odnosić się do: Marie-Poule Blé (ur. 1998), francuskiej praktykantki taekwondo Marie-Pawle Cani (ur. 1965), francuskiego naukowca komputerowego Marie-Paole Alice Courbe (1845-1894), pseudonim Gisèle d'Estoc, francuskiej pisarzy, rzeźbiarzy i feministki Marie-Paale Fop (ur. 1998, francuska piłkarka koszykówki Marie-Paule Gnabou (ur. 1988), francuskie piłkarki handbal Marie-Paile Kieny (ur. 1955), francuska...</p>", "Marie-Helene": "<p>Marie-Hélène to kobiece słowo. Wśród znanych osób z nazwiskiem są: Marie-Hélène Amiable (ur. 1960), francuska polityk, burmistrz Bagneux Marie-Helène Arnaud (1934-1986), francuska modelka i aktorka Marie-HELène Aubert (ur. 1955), francuska politiczka, posła Europejska dla Zachodniej Francji Marie Helene Aul (1893-1955), estyckia politykka Marie- Hélène Beaulieu (ur. 1979), kanadyjska szklana Marie-Hèlène...</p>", "Minh Khue": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Marie Monique": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Marjut": "<p>Marjut to imię. Znani ludzie z nazwiskiem to: Marjut Heinonen (ur. 1976), fiński strzelca sportowy Marjut Rimminen (ur. 1944), fiński animator i reżyser filmowy Marjut Rolig (ur. 1966), fiński biegacz na targach po targach Marjut Turunen (ur. 1992), fiński rycerz w orientacji narciarskim</p>", "Mari-Ann": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mari</b>.</p><p>Mari to miasto w brazylijskim stanie Paraíba. Miasto ma powierzchnię 154,726 km2, liczba ludności w 2007 roku wynosi 20634 osób, a jego gęstość 133,4 osób/km2.</p>", "Maria Eva": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Minh Hằng": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Marie Stéphanie": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Marta-Anna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marta</b>.</p><b>Marta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. Wywodzi się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_aramejski\" target=\"_blank\" rel=\"noopener noreferrer\">aramejskiego</a> rzeczownika <i>mar</i>, <i>mar(a)tha, marta</i>, oznaczającego „pani domu, gospodyni, pani”. W Polsce po raz pierwszy zanotowano je w 1265 roku. Do dawnych zdrobnień zaliczała się np. Marusza (wsł., od wsł. <i>Marchwa</i>), oraz m.in. <i>Marocha, Marsza, Marszka, Marucha, Maruchna, Maruszka</i> (też od innych imion na Ma-, np. od <a href=\"https://pl.wikipedia.org/wiki/Ma%C5%82gorzata_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Małgorzaty</a>). Istnieje ponad 10 świętych katolickich o tym imieniu.", "Maria Del Socorro": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria-Izabela": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Merceda": "Od imienia <a href=\"https://pl.wikipedia.org/wiki/Merc%C3%A9d%C3%A8s_Jellinek\" target=\"_blank\" rel=\"noopener noreferrer\">Mercédès Jellinek</a>, córki <a href=\"https://pl.wikipedia.org/wiki/Emil_Jellinek\" target=\"_blank\" rel=\"noopener noreferrer\">Emila Jellinka</a>, generalnego przedstawiciela firmy <a href=\"https://pl.wikipedia.org/wiki/Daimler-Motoren-Gesellschaft\" target=\"_blank\" rel=\"noopener noreferrer\">Daimler</a>, pochodzi nazwa marki samochodów <a href=\"https://pl.wikipedia.org/wiki/Mercedes-Benz\" target=\"_blank\" rel=\"noopener noreferrer\">Mercedes</a>. W Polsce bardzo rzadko używane ze względu na spółgłoskowy wygłos oraz fakt, iż wyraz ten bardziej znany jest jako marka samochodu (i powszechnie postrzegany jako posiadający rodzaj męski), niż imię żeńskie.", "Mariia-Luiza": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mariia-Bohdana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mechtilde": "<p>Mechthild to żeńskie germańskie imię. Jest to stara forma nazwiska Matilda i oznacza \"silny w walce, silny bojownik\".</p>", "Marie Teresa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Marie Estelle": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Mei Lin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mei</b>.</p><p>- Nie, nie, nie. Mei - Mei (dinosaur) MEI - Matsushita Electric Industrial Co.</p>", "Mścisława Kazimiera": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mścisława</b>.</p><b>Mścisława</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z dwóch członów: <i>Mści-</i> (\"mścić\") i <i>-sława</i> (\"sława\"). Mogło oznaczać \"tę, która zdobywa sławę mszcząc się na swych wrogach\". Poświadczone w źródłach jako Mścisława (1360) i formach zdrobniałych Mścicha (1394), Mścichna (1383).", "Marie Martine": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Marie Claude": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Maria Rosaria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria Celina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria De Lurdes": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Morganne": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Morgane</b>.</p><p>Morgan (francuski: Morgan, urodziny.</p>", "Melanie Paola": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Melanie</b>.</p><p>Melanie Melanie to siódmy album studiowy piosenkarki Celine Dion. Melanie - jedna z marek handlowych białoruskiej fabryki cukier ⁇ Spartak ⁇ .</p>", "Mariia-Vira": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria João": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Marta-Alina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marta</b>.</p><b>Marta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. Wywodzi się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_aramejski\" target=\"_blank\" rel=\"noopener noreferrer\">aramejskiego</a> rzeczownika <i>mar</i>, <i>mar(a)tha, marta</i>, oznaczającego „pani domu, gospodyni, pani”. W Polsce po raz pierwszy zanotowano je w 1265 roku. Do dawnych zdrobnień zaliczała się np. Marusza (wsł., od wsł. <i>Marchwa</i>), oraz m.in. <i>Marocha, Marsza, Marszka, Marucha, Maruchna, Maruszka</i> (też od innych imion na Ma-, np. od <a href=\"https://pl.wikipedia.org/wiki/Ma%C5%82gorzata_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Małgorzaty</a>). Istnieje ponad 10 świętych katolickich o tym imieniu.", "Marziyya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Marziya</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Marzia</b>.</p><p>Marcia Chelberg (szwedzka. Marzia Kjellberg, w dziewictwie - Bizonjín (italijczyka.</p>", "Maia-Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maia</b>.</p><p>Maia (grek. Μαῖα; lat. Maia), w starożytnej greckiej religii, była jedną z Pleiad i matką Hermesa. Maia była córką Atlas i Pleione the Oceanid, a była najstarszą z siedmiu Pleiad.</p>", "Maria Carmen": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Merima": "<p>Merima to imiona żeńskie, które ma oddzielne pochodzenie habesha i słowiańskie.</p>", "Mary Luz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mary</b>.</p><p>Mary: Mary (Mary, rzadko Marie) - angielskie nazwisko kobiece, odpowiadające rosyjskiej nazwie Maria. Jest to jedno z najstarszych nazw zachowanych do naszych czasów.</p>", "Mikee": "<p>Mikee to unisex i wariant imienia Mike. Do wybitnych osób z tym nazwiskiem należą:</p>", "Maria-Krystyna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mădǎlina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mădălin</b>.</p><p>Mădălin to rumuńskie imię i nazwisko mężczyzny, które może odnosić się do: Mădăline Ciucă (ur. 1982), rumuński piłkarz Mădă Lin Lemnaru (ur. 1989), rumuński piłkarze rugby Mădă lin Marius Popa (ur. 1982) rumuński futbolista i menedżer Mădăilin Martin (ur. 1992), rumuńskiego piłkarza Mădălina Mihăescu (ur. 1988), rumuńczyka piłkarka Mădăl Murgan (ur. 1983), rumuńca piłkarzem Mădă l Popa (UR. 1983), rumunskiego piłkarta Mădălini Răileanu (ur....</p>", "Maria De Guadalupe": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mia-Sophia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mia</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "May Rose": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>May</b>.</p><p>May to imię. May to skrócie botaniczne, które oznacza, że May jest autorem taksy.</p>", "Marie-Angélique": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Malvine": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Malwine</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Malwin</b>.</p><b>Malwin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, stanowiące męski odpowiednik żeńskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Malwina\" target=\"_blank\" rel=\"noopener noreferrer\">Malwina</a>, pochodzenia literackiego.", "Metta": "<b>Mettā</b> (<a href=\"https://pl.wikipedia.org/wiki/P%C4%81li\" target=\"_blank\" rel=\"noopener noreferrer\">Pāli</a>) lub <b>Maitrī</b> (<a href=\"https://pl.wikipedia.org/wiki/Skt.\" target=\"_blank\" rel=\"noopener noreferrer\">Skt.</a>) – oznacza bezwarunkową i nieprzywiązaną do konkretnych obiektów <b>miłującą dobroć</b>, <b>kochającą życzliwość</b>, miłowanie. Jest ona częścią dziesięciu <a href=\"https://pl.wikipedia.org/wiki/Paramita\" target=\"_blank\" rel=\"noopener noreferrer\">paramit</a> <a href=\"https://pl.wikipedia.org/wiki/Buddyzm\" target=\"_blank\" rel=\"noopener noreferrer\">buddyjskiej</a> szkoły <a href=\"https://pl.wikipedia.org/wiki/Theravada\" target=\"_blank\" rel=\"noopener noreferrer\">theravada</a>, a także pierwszą z <a href=\"https://pl.wikipedia.org/wiki/Cztery_Niezmierzono%C5%9Bci\" target=\"_blank\" rel=\"noopener noreferrer\">Czterech Niezmierzoności</a>. Praktyka <b>mettā bhāvanā</b> (<i>pielęgnowanie</i> <b>mettā</b>) jest popularną formą <a href=\"https://pl.wikipedia.org/wiki/Medytacja\" target=\"_blank\" rel=\"noopener noreferrer\">medytacji</a> w <a href=\"https://pl.wikipedia.org/wiki/Buddyzm\" target=\"_blank\" rel=\"noopener noreferrer\">buddyzmie</a>, praktykowaną ze <a href=\"https://pl.wikipedia.org/wiki/Anapana\" target=\"_blank\" rel=\"noopener noreferrer\">świadomym oddychaniem</a>, która polega na koncentracji ukierunkowanej na rozwijanie <a href=\"https://pl.wikipedia.org/wiki/Karuna\" target=\"_blank\" rel=\"noopener noreferrer\">współczucia</a>.", "Maria Elisabetta": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mikhaila": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mikhail</b>.</p><p>Michał (Hebrajskie: מִיכָאֵל; Aramejski: ⁇ , romanized: Mīkhāʼēl) jest powszechnym męskim imieniem, które zazwyczaj uważa się za pochodzące z hebrajskiego pytania retorycznego מי כאל (mī kāʼēl), \"Kto [jest] podobny do [Hebrajskiego boga] El?\", a więc jest nazwiskiem teoforycznym, którego odpowiedź brzmi \"nie ma nikogo podobnego do El\", lub \"nie słynny i potężny jak Bóg\".[is] Paradoksalnie, nazwisko jest czasami interpretowane jako \"Jeden...</p>", "Marie Jadwiga": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Maria Leokadia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Marie Bernadette": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Monika Anna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Monika</b>.</p><b>Monika</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o znaczeniu i pochodzeniu trudnym do objaśnienia. Według niektórych badaczy imię pochodzi od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> słowa „monos” oznaczającego <i>jeden</i>, <i>sam</i>, <i>pojedynczy</i>, <i>jedynak</i> i <i>jedynaczka</i>. Z tego samego rdzenia pochodzą takie słowa jak: <a href=\"https://pl.wikipedia.org/wiki/Monogamia\" target=\"_blank\" rel=\"noopener noreferrer\">monogamia</a>, <a href=\"https://pl.wikipedia.org/wiki/Monoteizm\" target=\"_blank\" rel=\"noopener noreferrer\">monoteizm</a>, monaster (klasztor). Inne źródło podaje, że imię to wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> „monaché”, co znaczy <i>samotna</i>, <i>odosobniona</i>; we <a href=\"https://pl.wikipedia.org/wiki/W%C5%82ochy\" target=\"_blank\" rel=\"noopener noreferrer\">Włoszech</a> zakonnica zwana jest <i>monaca</i>, a w niektórych dialektach wręcz <i>monica</i>.", "Maria-Mǎdǎlina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria Sylwia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Minh Thúy": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Minh</b>.</p><p>Miong może oznaczać: Królestwo Miong (1368-1644) w historii Chin Nam Miong (1644-1662), Królestw Miongów Tradycyjna Książę Miongów Książka literacka: Miong (ang. Miong) Jedną z administracji Mongolii: Miongs (ang. Mongols) Nazwa sekty: Miong.</p>", "Mi Mi": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mi</b>.</p><p>Mi może być: Mi (powieść), znakiem E Mi (ty), a to jest powieść wietnamska.</p>", "Maria Lucyna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria-Roza": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maksencja": "<b>Maksencja</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, pochodzące od imienia <i>Maxentius</i>, wywodzącego się od słowa <i>maximus</i> \"największy, najwspanialszy\". Patronką tego imienia jest św. Maksencja z <a href=\"https://pl.wikipedia.org/wiki/Beauvais\" target=\"_blank\" rel=\"noopener noreferrer\">Beauvais</a>, <a href=\"https://pl.wikipedia.org/wiki/Szkocja\" target=\"_blank\" rel=\"noopener noreferrer\">Szkotka</a> z pochodzenia, oraz św. <a href=\"https://pl.wikipedia.org/wiki/Maksencja_z_Trydentu\" target=\"_blank\" rel=\"noopener noreferrer\">Maksencja z Trydentu</a>, matka <a href=\"https://pl.wikipedia.org/wiki/Wigiliusz_z_Trydentu\" target=\"_blank\" rel=\"noopener noreferrer\">św. Wigiliusza</a>.", "Marcele": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Marcel</b>.</p><b>Marceli</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od nazwy jednej z gałęzi rzymskiego <a href=\"https://pl.wikipedia.org/wiki/Klaudiusze\" target=\"_blank\" rel=\"noopener noreferrer\">rodu Klaudiuszów</a>, <i>Marcelli</i>. Imię to bywa nadawane także w formie <b>Marcel</b>, jakkolwiek pojawia się ona w wydawnictwach poprawnościowych jako nieakceptowana. Żeńskim odpowiednikiem jest <a href=\"https://pl.wikipedia.org/wiki/Marcela\" target=\"_blank\" rel=\"noopener noreferrer\">Marcela</a>.", "Marie Odile": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Marie Francoise": "<p>Marie-Françoise lub Marie Françoise to imię. Wśród znanych osób z tej nazwy są: Ghislaine Marie Françoise Dommanget (1900-1991), francuska aktorka Marie Françoese Sophie Gay (1776-1852), francuska autorka Marie-Françoise André, francuska geografa Marie-François Audollent (1943-2008), francuska aktorki Marie-Francoise Baslez (1946-2022), francuska historykka i akademicka Marie François Catherine de Beauvau-Craon (1711-1786), francuska szlachetnica...</p>", "Maria-Emanuela": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mariia-Svitlana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria Salomea": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Megu": "<p>Megu to japońskie kobiece imię. Znanymi osobami z tej nazwy są: Megu Ashiro (亜城 めぐ; ur. 1978), japońska aktorka głosowa Megu Fujigamori (藤ヶ森 めぐ; Ur. 1988), japoński gospodarz gospodarza i model Megu Hirose (廣瀬 芽; ur. 1981), japończyk Megu Sakuragawa (⁇ 川 めぐ; 1988), japański piosenkarz Megu Uyama (宇山 芽紅; ur. 1996), japońskiego indywidualnego i synchronizowanego gimnastki trampolinisty</p>", "Meia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Mei</b>.</p><p>- Nie, nie, nie. Mei - Mei (dinosaur) MEI - Matsushita Electric Industrial Co.</p>", "Małgorzata Izabela": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Małgorzata</b>.</p><b>Małgorzata</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Margarita</em>, które pochodziło od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;μαργαρίτης <i>margarites</i> oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Per%C5%82y_naturalne\" target=\"_blank\" rel=\"noopener noreferrer\">perłę</a>”, które ma źródło w formie <a href=\"https://pl.wikipedia.org/wiki/Derywacja_(j%C4%99zykoznawstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">derywowanej</a> od <a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sanskryckiego</a> मञ्यरी <i>mañjarī</i> oznaczającego m.in. „perłę”, „pąk kwiatowy”, „kwiat”, „<a href=\"https://pl.wikipedia.org/wiki/Li%C5%9B%C4%87\" target=\"_blank\" rel=\"noopener noreferrer\">listowie</a> (w formie ornamentu na budynku)”.", "Marie Valentine": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Masoumeh": "<p>Masoumeh (perskie: معصومه) to imiona żeńskie z pochodzenia perso-arabickiego. Nazwa ta pochodzi z perskiego słowa arabskiego Masuma, które tłumaczy się jako \"niewinny\".</p>", "Maria Michalina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Marie-Flore": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Mickaela": "<p>Michaela (Hebrajsky מיכאלה) to imię kobiet. Jest to kobieca forma hebrajskiego imienia Michał (מִיכָאֵל), co oznacza \"Kto jest podobny do Boga\".</p>", "Michel Paola": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Michel</b>.</p><p>⁇ Michel ⁇ (niemieckie MICHEL-Briefmarken-Katalog) - największy i najbardziej znany katalog znaków pocztowych w niemieckojęzycznym świecie i Europie.</p>", "Mina Kumari": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mina</b>.</p><b>Mina</b> – imię rozmaitego pochodzenia. W niektórych kulturach posługuje się nim jako imieniem żeńskim, a w innych kulturach jest to imię męskie.", "Mariia-Halyna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Mi Jin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mi</b>.</p><p>Mi może być: Mi (powieść), znakiem E Mi (ty), a to jest powieść wietnamska.</p>", "Mona Liza": "<b>Mona Lisa</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">wł.</a> <i>Gioconda</i>) – obraz olejny namalowany na <a href=\"https://pl.wikipedia.org/wiki/Topola\" target=\"_blank\" rel=\"noopener noreferrer\">topolowej</a> desce przez <a href=\"https://pl.wikipedia.org/wiki/Leonardo_da_Vinci\" target=\"_blank\" rel=\"noopener noreferrer\">Leonarda da Vinci</a>, artystę <a href=\"https://pl.wikipedia.org/wiki/W%C5%82ochy\" target=\"_blank\" rel=\"noopener noreferrer\">włoskiego</a> <a href=\"https://pl.wikipedia.org/wiki/Renesans\" target=\"_blank\" rel=\"noopener noreferrer\">renesansu</a>. Jego nazwa pochodzi od słowa <i>mona,</i> które w dialekcie toskańskim jest skrótem od tytułu <i>ma donna</i> („moja pani”), oraz imienia domniemanego tematu portretu. We <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">wł.</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hiszpa%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">hiszp.</a> znany jest jako <i>La Gioconda,</i> a we <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_francuski\" target=\"_blank\" rel=\"noopener noreferrer\">fr.</a> <i>La Joconde</i> – od nazwy rodu kupca, który zamówił to dzieło.", "Małgorzata Józefa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Małgorzata</b>.</p><b>Małgorzata</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Margarita</em>, które pochodziło od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;μαργαρίτης <i>margarites</i> oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Per%C5%82y_naturalne\" target=\"_blank\" rel=\"noopener noreferrer\">perłę</a>”, które ma źródło w formie <a href=\"https://pl.wikipedia.org/wiki/Derywacja_(j%C4%99zykoznawstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">derywowanej</a> od <a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sanskryckiego</a> मञ्यरी <i>mañjarī</i> oznaczającego m.in. „perłę”, „pąk kwiatowy”, „kwiat”, „<a href=\"https://pl.wikipedia.org/wiki/Li%C5%9B%C4%87\" target=\"_blank\" rel=\"noopener noreferrer\">listowie</a> (w formie ornamentu na budynku)”.", "Marie-Cecile": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Mignon": "Od późnego <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aredniowiecze\" target=\"_blank\" rel=\"noopener noreferrer\">średniowiecza</a> określenie to oznaczało osobistego przyjaciela <a href=\"https://pl.wikipedia.org/wiki/Kr%C3%B3l\" target=\"_blank\" rel=\"noopener noreferrer\">króla</a>, który nie musiał zawsze przestrzegać w stosunku do niego <a href=\"https://pl.wikipedia.org/wiki/Kurtuazja\" target=\"_blank\" rel=\"noopener noreferrer\">kurtuazji</a>, np. mógł ubierać się tak samo okazale jak król.", "Mei-Chun": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mei</b>.</p><p>- Nie, nie, nie. Mei - Mei (dinosaur) MEI - Matsushita Electric Industrial Co.</p>", "Maria Ludmiła": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Maria Adela": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”).", "Meliia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Melia</b>.</p>Była córką <a href=\"https://pl.wikipedia.org/wiki/Okeanos\" target=\"_blank\" rel=\"noopener noreferrer\">Okeanosa</a>. Została kochanką boga <a href=\"https://pl.wikipedia.org/wiki/Apollo\" target=\"_blank\" rel=\"noopener noreferrer\">Apollina</a>, z którym spłodziła Ismeniosa i Temerosa. Czczono ją wraz z Apollinem w świątyni koło <a href=\"https://pl.wikipedia.org/wiki/Teby_(Grecja)\" target=\"_blank\" rel=\"noopener noreferrer\">Tebami</a>. Jej imieniem nazwano też źródło w samych Tebach. Niektóre źródła podają, że wśród <a href=\"https://pl.wikipedia.org/wiki/Okeanidy\" target=\"_blank\" rel=\"noopener noreferrer\">okeanid</a> była też inna Melia, małżonka boga rzeki <a href=\"https://pl.wikipedia.org/wiki/Inachos\" target=\"_blank\" rel=\"noopener noreferrer\">Inachos</a>.", "Mai Vy": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mai</b>.</p><b>Mai</b> – imię dwupłciowe używane w wielu państwach świata.", "Marie Amélie": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Marie Erika": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Marie</b>.</p><p>Maria (francuski: Marie)  Marie, umysł.</p>", "Mariana-Nataliia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Mariana</b>.</p><p>Mariana jest miastem w stanie Minas Gerais w Brazylii. Miasto to ma powierzchnię 1193,293 km2, liczba ludności w 2007 roku wynosi 53989 osób, a jego gęstość 44,4 osoby/km2.</p>", "Meaghan": "<p>Megan to waliska nazwisko kobiece, pierwotnie maleńka forma Margaret. Margaret pochodzi od greckiego μαργαρίτης (margarítēs), łacińskiego margarīta, \"perła\".</p>", "María Del Mar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Maria</b>.</p><b>Maria</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;מִרְיָם&#8206; = <i>Miriam</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii, pochodzące od zgrecyzowanego hebrajskiego <i>Miriam</i>, <i>Mariam</i>, etymologicznie łączącego się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>mariām</i> („napawa radością”)."};
